-- Данные учебника Петерсон 3 класс, часть 1
-- PostgreSQL compatible

VALUES ('math', 3, 'Петерсон Л.Г.', 'Математика 3 класс', 1, 2022, 'Просвещение', 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik')
ON CONFLICT (subject, grade, authors, part) DO UPDATE SET year = EXCLUDED.year;

-- Задачи
DO $$
DECLARE
    v_textbook_id BIGINT;
    v_task_id BIGINT;
BEGIN
    SELECT id INTO v_textbook_id FROM textbooks WHERE subject = 'math' AND grade = 3 AND authors = 'Петерсон Л.Г.' AND part = 1;

    VALUES (v_textbook_id, 3, '1', 0, 'Придумай названия для предметов и животных, собранных вместе:', '</p>\n\n<p class="text">Придумай названия для предметов и животных, собранных вместе:</p>\n\n<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica3-nomer1.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 3, номер 1, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 3, номер 1, год 2022."/>\n</div>', '', '<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica3-nomer1-1.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 3, номер 1, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 3, номер 1, год 2022."/>', 'Множество    Когда какие-нибудь объекты собирают вместе, в математике для их названия используют общее слово – множество .    Сказать «стадо чашек» нельзя, а множество чашек – можно.    Можно сказать: множество коров, множество птиц, множество цветов, множество марок, множество учеников и т. д.', '<div class="recomended-block">\n<span class="title">Множество</span>\n<p>   Когда какие-нибудь объекты собирают вместе, в математике для их названия используют общее слово – <b class="black">множество</b>.<br/>\n   Сказать «стадо чашек» нельзя, а множество чашек – можно.<br/>\n   Можно сказать: множество коров, множество птиц, множество цветов, множество марок, множество учеников и т. д.</p>\n</div>', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-3/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, 'condition', 0, NULL, 'https://gdz-raketa.ru/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica3-nomer1.jpg', 'peterson/3/part1/page3/task1_condition_0.jpg', '');

    VALUES (v_task_id, 'solution', 0, NULL, 'https://gdz-raketa.ru/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica3-nomer1-1.jpg', 'peterson/3/part1/page3/task1_solution_0.jpg', '');

    VALUES (v_task_id, v_textbook_id, 3, 'e98555c107b25360b9fa708d4a1cf15c7f9c04db7fd26e74b5952696ffc53f9d', NULL, NULL, 'придумай названия для предметов и животных, собранных вместе');

    VALUES (v_textbook_id, 3, '2', 1, 'а) Как может называться множество овец? б) Как может называться множество лошадей? в) Как может называться множество пчёл, летящих вместе? г) Как может называться множество футболистов, собравшихся вместе для игры? Какие ещё командные игры ты знаешь? д) Как может называться множество кораблей, плывущих вместе?', '</p>\n\n<p class="text">а) Как может называться множество овец?<br/>\nб) Как может называться множество лошадей?<br/>\nв) Как может называться множество пчёл, летящих вместе?<br/>\nг) Как может называться множество футболистов, собравшихся  вместе для игры? Какие ещё командные игры ты знаешь?<br/>\nд) Как может называться множество кораблей, плывущих вместе?</p>', 'а) отара. б) табун. в) рой. г) команда. волейбол д) флот.', '<p>а) отара. б) табун. в) рой. г) команда. волейбол д) флот.</p>', 'Элементы множества    Предметы или живые существа, входящие в множества, называют элементами этого множества.    Например, берёза – элемент множества деревьев, ласточка – элемент множества птиц.    В то же время лист берёзы не является элементом множества деревьев, а хвост ласточки не является элементом множества птиц.', '<div class="recomended-block">\n<span class="title">Элементы множества</span>\n<p>   Предметы или живые существа, входящие в множества, называют <b class="black">элементами</b> этого множества.<br/>\n   Например, берёза – элемент множества деревьев, ласточка – элемент множества птиц.<br/>\n   В то же время лист берёзы не является элементом множества деревьев, а хвост ласточки не является элементом множества птиц.</p>\n</div>', TRUE, '[{"letter":"а","condition":"Как может называться множество овец?","solution":"отара."},{"letter":"б","condition":"Как может называться множество лошадей?","solution":"табун."},{"letter":"в","condition":"Как может называться множество пчёл, летящих вместе?","solution":"рой."},{"letter":"г","condition":"Как может называться множество футболистов, собравшихся вместе для игры? Какие ещё командные игры ты знаешь?","solution":"команда. волейбол"},{"letter":"д","condition":"Как может называться множество кораблей, плывущих вместе?","solution":"флот."}]'::jsonb, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-3/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '65c3520dda6e421843c6a682997bdfa98879e80b900fd709e28a93d431b1f14a', NULL, NULL, 'а) как может называться множество овец? б) как может называться множество лошадей? в) как может называться множество пчёл, летящих вместе? г) как может называться множество футболистов, собравшихся вместе для игры? какие ещё командные игры ты знаешь? д) как может называться множество кораблей, плывущих вместе');

    VALUES (v_textbook_id, 4, '3', 0, 'Опиши множества, которые можно назвать: хор, оркестр, бригада, класс, коллекция, библиотека.', '</p>\n\n<p class="text">Опиши множества, которые можно назвать: хор, оркестр, бригада, класс, коллекция, библиотека.</p>', 'Хор – певцы, оркестр – музыканты, бригада – рабочие, класс – ученики, коллекция – собрание предметов, объединённое по какому-то конкретному признаку, библиотека – книги.', '<p>Хор – певцы, оркестр – музыканты, бригада – рабочие, класс – ученики, коллекция – собрание предметов, объединённое по какому-то конкретному признаку, библиотека – книги.</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-4/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '181dc9859a4a5b8441a8b7c94e60a09dd2724676006b7c2ac68bcd61b184a91a', NULL, NULL, 'опиши множества, которые можно назвать:хор, оркестр, бригада, класс, коллекция, библиотека');

    VALUES (v_textbook_id, 4, '4', 1, 'Назови двух учеников твоего класса. Элементами какого множества они являются? Принадлежат ли этому множеству портфели учеников?', '</p>\n\n<p class="text">Назови двух учеников твоего класса. Элементами какого множества они являются? Принадлежат ли этому множеству портфели учеников?</p>', 'Ученики класса являются элементами множества всех учеников. Портфели учеников к этому множеству не принадлежат.', '<p>Ученики класса являются элементами множества всех учеников. Портфели учеников к этому множеству не принадлежат.</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-4/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '85124afd6077202cb54a340f249d6f05dda64eaea786d818a996836399631e50', NULL, NULL, 'назови двух учеников твоего класса. элементами какого множества они являются? принадлежат ли этому множеству портфели учеников');

    VALUES (v_textbook_id, 4, '5', 2, 'Перечисли членов твоей семьи. Принадлежишь ли ты этому множеству? А твой друг?', '</p>\n\n<p class="text">Перечисли членов твоей семьи. Принадлежишь ли ты этому множеству? А твой друг?</p>', 'Мама, папа, брат и я. Я являюсь частью семьи, поэтому принадлежу к этому множеству. Друг не является частью семьи нашей, поэтому не принадлежит к этому множеству.', '<p>Мама, папа, брат и я. Я являюсь частью семьи, поэтому принадлежу к этому множеству. Друг не является частью семьи нашей, поэтому не принадлежит к этому множеству.</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-4/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '5827e1c9a34d42e35ceb7ca9cfb119b71946e111ea38737de70daf8756a102d1', NULL, NULL, 'перечисли членов твоей семьи. принадлежишь ли ты этому множеству? а твой друг');

    VALUES (v_textbook_id, 4, '6', 3, 'На рисунке изображены портреты семьи Ивановых. Перечисли элементы этого множества. Из каких элементов состоит множество детей этой семьи, множество взрослых этой семьи? Как будут звать Петю, когда он вырастет? Как будут звать Аню? Чьим отцом является Сергей Васильевич? Чьей бабушкой является Ирина Семёновна?', '</p>\n\n<p class="text">На рисунке изображены портреты семьи Ивановых. Перечисли элементы этого множества.</p>\n\n<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica4-nomer6.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 4, номер 6, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 4, номер 6, год 2022."/>\n</div>\n\n<p class="text">Из каких элементов состоит множество детей этой семьи, множество взрослых этой семьи? Как будут звать Петю, когда он вырастет? Как будут звать Аню? Чьим отцом является Сергей Васильевич? Чьей бабушкой является Ирина Семёновна?</p>', 'Сын Петя, бабушка Ирина Семеновна, дедушка Сергей Васильевич, отец Иван Сергеевич, мать Елена Александровна, дочь Анна.    Множество детей этой семьи состоит из четырёх, множество взрослых из четверых. Петю когда он вырастет будут звать Петр Иванович. Анна Ивановна. Ивана Сергеевича. Пети и Ани.', '<p>   Сын Петя, бабушка Ирина Семеновна, дедушка Сергей Васильевич, отец Иван Сергеевич, мать Елена Александровна, дочь Анна.<br/>\n   Множество детей этой семьи состоит из четырёх, множество взрослых из четверых. Петю когда он вырастет будут звать Петр Иванович. Анна Ивановна. Ивана Сергеевича. Пети и Ани.</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-4/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, 'condition', 0, NULL, 'https://gdz-raketa.ru/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica4-nomer6.jpg', 'peterson/3/part1/page4/task6_condition_0.jpg', '');

    VALUES (v_task_id, v_textbook_id, 3, '7b0f125b54ca5cb6890d2ff61974067ce7e5c763f1f012c1853075086a8b74e1', NULL, NULL, 'на рисунке изображены портреты семьи ивановых. перечисли элементы этого множества. из каких элементов состоит множество детей этой семьи, множество взрослых этой семьи? как будут звать петю, когда он вырастет? как будут звать аню? чьим отцом является сергей васильевич? чьей бабушкой является ирина семёновна');

    VALUES (v_textbook_id, 4, '7', 4, 'С каких деревьев взяты эти листья? Назови ещё три элемента множества видов деревьев. Всегда ли на деревьях есть листья? У всех ли деревьев есть листья?', '</p>\n\n<p class="text">С каких деревьев взяты эти листья? Назови ещё три элемента множества видов деревьев. Всегда ли на деревьях есть листья? У всех ли деревьев есть листья?</p>\n\n<div class="img-wrapper-460">\n<img width="150" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica4-nomer7.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 4, номер 7, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 4, номер 7, год 2022."/>\n</div>', 'Дуб. Клен, береза, сосна. Зимой нету листьев на деревьях. Не у всех деревьев есть листья.', '<p>Дуб. Клен, береза, сосна. Зимой нету листьев на деревьях. Не у всех деревьев есть листья.</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-4/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, 'condition', 0, NULL, 'https://gdz-raketa.ru/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica4-nomer7.jpg', 'peterson/3/part1/page4/task7_condition_0.jpg', '');

    VALUES (v_task_id, v_textbook_id, 3, '4218de3d3bb78b405ff6993f4057823457450cee1c51239559cc4357c264dac9', NULL, NULL, 'с каких деревьев взяты эти листья? назови ещё три элемента множества видов деревьев. всегда ли на деревьях есть листья? у всех ли деревьев есть листья');

    VALUES (v_textbook_id, 4, '8', 5, 'По какому признаку подобраны слова: роза, фиалка, гвоздика, василёк, тюльпан? Назови ещё 2 элемента множества цветов. Принадлежат ли ему сосна, баран, ромашка, шипы от розы? Какие цветы растут на клумбах? Какие растут в поле? Какие растут на лугу?', '</p>\n\n<p class="text">По какому признаку подобраны слова: роза, фиалка, гвоздика, василёк, тюльпан? Назови ещё 2 элемента множества цветов. Принадлежат ли ему сосна, баран, ромашка, шипы от розы? Какие цветы растут на клумбах? Какие растут в поле? Какие растут на лугу?</p>', 'У всех этих цветов есть бутон. Ромашка, пион. Ромашка принадлежит к этому множеству, а остальное не принадлежит. На клумбах растут: роза, тюльпан. В поле: гвоздика, василек. На лугу: ромашка, фиалка.', '<p>У всех этих цветов есть бутон. Ромашка, пион. Ромашка принадлежит к этому множеству, а остальное не принадлежит. На клумбах растут: роза, тюльпан. В поле: гвоздика, василек. На лугу: ромашка, фиалка.</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-4/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '622c8bfd6bef19f1146888f256168e4784a1f06c27ca2f81884af4dce440ad4e', '2', NULL, 'по какому признаку подобраны слова:роза, фиалка, гвоздика, василёк, тюльпан? назови ещё 2 элемента множества цветов. принадлежат ли ему сосна, баран, ромашка, шипы от розы? какие цветы растут на клумбах? какие растут в поле? какие растут на лугу');

    VALUES (v_textbook_id, 4, '9', 6, 'На рисунке изображены некоторые элементы множества плодов. Назови их. В каких из этих плодов одно семечко или одна косточка, а в каких – много семян или косточек? Все ли плоды растут на деревьях? Какие ещё элементы множества плодов ты знаешь?', '</p>\n\n<p class="text">На рисунке изображены некоторые элементы множества плодов. Назови их. В каких из этих плодов одно семечко или одна косточка, а в каких – много семян или косточек? Все ли плоды растут на деревьях? Какие ещё элементы множества плодов ты знаешь?</p>\n\n<div class="img-wrapper-460">\n<img width="180" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica4-nomer9.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 4, номер 9, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 4, номер 9, год 2022."/>\n</div>', 'У всех этих цветов есть бутон. Ромашка, пион. Ромашка принадлежит к этому множеству, а остальное не принадлежит. На клумбах растут: роза, тюльпан. В поле: гвоздика, василек. На лугу: ромашка, фиалка.', '<p>У всех этих цветов есть бутон. Ромашка, пион. Ромашка принадлежит к этому множеству, а остальное не принадлежит. На клумбах растут: роза, тюльпан. В поле: гвоздика, василек. На лугу: ромашка, фиалка.</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-4/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, 'condition', 0, NULL, 'https://gdz-raketa.ru/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica4-nomer9.jpg', 'peterson/3/part1/page4/task9_condition_0.jpg', '');

    VALUES (v_task_id, v_textbook_id, 3, '8f287ef1a0895a58aa835360bfae037907635cc028455e52f76bf20047b7cc76', NULL, NULL, 'на рисунке изображены некоторые элементы множества плодов. назови их. в каких из этих плодов одно семечко или одна косточка, а в каких-много семян или косточек? все ли плоды растут на деревьях? какие ещё элементы множества плодов ты знаешь');

    VALUES (v_textbook_id, 5, '10', 0, 'а) Ласточка пролетает в час 70 км, а стриж – в 2 раза больше. Сколько километров в час пролетает стриж? б) Сосна живёт примерно 600 лет. Это на 250 лет больше, чем живёт ель. Сколько лет живёт ель? в) Для нормальной жизни рыбок скалярий им требуется по 3 л воды на каждую. Сколько рыбок могут нормально жить в аквариуме, вмещающем 24 л воды? г) Масса пингвина папы 42 кг, пингвина мамы – 32 кг, а их детёныша – 8 кг. Чему равна масса этой пингвиньей семьи? На сколько папа тяжелее, чем мама с детёнышем вместе? Придумай и реши свою задачу о жизни растений и животных.', '</p>\n\n<p class="text">а) Ласточка пролетает в час 70 км, а стриж – в 2 раза больше. Сколько километров в час пролетает стриж?<br/>\nб) Сосна живёт примерно 600 лет. Это на 250 лет больше, чем живёт ель. Сколько лет живёт ель?<br/>\nв) Для нормальной жизни рыбок скалярий им требуется по 3 л воды на каждую. Сколько рыбок могут нормально жить в аквариуме, вмещающем 24 л воды?<br/>\nг) Масса пингвина папы 42 кг, пингвина мамы – 32 кг, а их детёныша – 8 кг. Чему равна масса этой пингвиньей семьи? На сколько папа тяжелее, чем мама с детёнышем вместе?<br/>\nПридумай и реши свою задачу о жизни растений и животных.</p>\n\n<div class="img-wrapper-460">\n<img width="150" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica5-nomer10.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 5, номер 10, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 5, номер 10, год 2022."/>\n</div>', 'а) 70км · 2 = 140 (км)      Ответ: 140 километров в час пролетает стриж. б) 600 – 250 = 350 (лет)      Ответ: 350 лет живет ель. в) 24 : 3 = 8 (р)      Ответ: 8 рыбок. г) 42 + 32 + 8 = 82 (кг), 42 – (32 + 8) = 42 – 40 = 2 (кг).      Ответ: 82 килограмма весит вся семья пингвинов, на 2 килограмма папа тяжелее мамы с детенышем вместе.     Гренландский кит может жить до 200 лет, а дельфин – в 5 раз меньше. На сколько лет гренландский кит может прожить дольше, чем дельфин?     200 · 5 = 1000 (л)      Ответ: гренландский кит живет меньше чем дельфин.', '<p><span>а) 70км · 2 = 140 (км)</span>\n<span>    <b>Ответ:</b> 140 километров в час пролетает стриж.</span>\n<br/>\n<span>б) 600 – 250 = 350 (лет)</span>\n<span>    <b>Ответ:</b> 350 лет живет ель.</span>\n<br/>\n<span>в) 24 : 3 = 8 (р)</span>\n<span>    <b>Ответ:</b> 8 рыбок.</span>\n<br/>\n<span>г) 42 + 32 + 8 = 82 (кг), 42 – (32 + 8) = 42 – 40 = 2 (кг).</span>\n<span>    <b>Ответ:</b> 82 килограмма весит вся семья пингвинов, на 2 килограмма папа тяжелее мамы с детенышем вместе.</span>\n<br/>\n<span>    Гренландский кит может жить до 200 лет, а дельфин – в 5 раз меньше. На сколько лет гренландский кит может прожить дольше, чем дельфин?</span>\n<span>    200 · 5 = 1000 (л)<!-- span-->\n<span>    <b>Ответ:</b> гренландский кит живет меньше чем дельфин.</span></span></p>', '', '', TRUE, '[{"letter":"а","condition":"Ласточка пролетает в час 70 км, а стриж – в 2 раза больше. Сколько километров в час пролетает стриж?","solution":"70км · 2 = 140 (км)      Ответ: 140 километров в час пролетает стриж."},{"letter":"б","condition":"Сосна живёт примерно 600 лет. Это на 250 лет больше, чем живёт ель. Сколько лет живёт ель?","solution":"600 – 250 = 350 (лет)      Ответ: 350 лет живет ель."},{"letter":"в","condition":"Для нормальной жизни рыбок скалярий им требуется по 3 л воды на каждую. Сколько рыбок могут нормально жить в аквариуме, вмещающем 24 л воды?","solution":"24 : 3 = 8 (р)      Ответ: 8 рыбок."},{"letter":"г","condition":"Масса пингвина папы 42 кг, пингвина мамы – 32 кг, а их детёныша – 8 кг. Чему равна масса этой пингвиньей семьи? На сколько папа тяжелее, чем мама с детёнышем вместе? Придумай и реши свою задачу о жизни растений и животных.","solution":"42 + 32 + 8 = 82 (к"}]'::jsonb, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-5/')
    RETURNING id INTO v_task_id;

