    VALUES (v_task_id, v_textbook_id, 3, '84d1bfa286a737993546e3fdac4b658498ab5da04bc08a2d789fabcd847f8508', '2,3,8,24,32,42,70,250,600', '["реши","больше","раз","раза"]'::jsonb, 'а) ласточка пролетает в час 70 км, а стриж-в 2 раза больше. сколько километров в час пролетает стриж? б) сосна живёт примерно 600 лет. это на 250 лет больше, чем живёт ель. сколько лет живёт ель? в) для нормальной жизни рыбок скалярий им требуется по 3 л воды на каждую. сколько рыбок могут нормально жить в аквариуме, вмещающем 24 л воды? г) масса пингвина папы 42 кг, пингвина мамы-32 кг, а их детёныша-8 кг. чему равна масса этой пингвиньей семьи? на сколько папа тяжелее, чем мама с детёнышем вместе? придумай и реши свою задачу о жизни растений и животных');

    VALUES (v_textbook_id, 5, '11', 1, 'Сравни выражения. Что в них интересного? Найди устно их значения. Какое выражение следующее? 32 + 8      32 + 18      32 + 28      32 + 38      32 + 48', '</p>\n\n<p class="text">Сравни выражения. Что в них интересного? Найди устно их значения. Какое выражение следующее?</p>\n\n<p class="description-text">\n32 + 8      32 + 18      32 + 28      32 + 38      32 + 48</p>', 'Каждое следующее второе слагаемое суммы или сама сумма больше предыдущего на 10. 32 + 8 = 40, 32 + 18 = 50, 32 + 28 = 60, 32 + 38 = 70, 32 + 48 = 80, 90 – 32 = 58 или 48 + 10 = 58, 32 + 58 – следующее выражение.', '<p>Каждое следующее второе слагаемое суммы или сама сумма больше предыдущего на 10. 32 + 8 = 40, 32 + 18 = 50, 32 + 28 = 60, 32 + 38 = 70, 32 + 48 = 80, 90 – 32 = 58 или 48 + 10 = 58, 32 + 58 – следующее выражение.</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-5/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, 'c821f89f092c846b1fc8454045814188d33f01faf3c1b367b19130e6ae36b81c', '8,18,28,32,38,48', '["найди","сравни"]'::jsonb, 'сравни выражения. что в них интересного? найди устно их значения. какое выражение следующее? 32+8      32+18      32+28      32+38      32+48');

    VALUES (v_textbook_id, 5, '12', 2, 'Пират нашёл клад из 900 монет. Чтобы побыстрее его унести, он положил 186 монет в шапку, 215 – в правый карман, 74 – в левый карман, 125 – в правую ладонь, а 68 – в левую. Сколько монет он не смог унести?', '</p>\n\n<p class="text">Пират нашёл клад из 900 монет. Чтобы побыстрее его унести, он положил 186 монет в шапку, 215 – в правый карман, 74 – в левый карман, 125 – в правую ладонь, а 68 – в левую. Сколько монет он не смог унести?</p>\n\n<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica5-nomer12.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 5, номер 12, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 5, номер 12, год 2022."/>\n</div>', '900 – 186 – 215 – 74 – 125 – 68 = 714 – 74 – 340 – 68 = 640 – 340 – 68 = 300 – 68 = 232 (монет)', '<p>900 – 186 – 215 – 74 – 125 – 68 = 714 – 74 – 340 – 68 = 640 – 340 – 68 = 300 – 68 = 232 (монет)</p>\n\n<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica5-nomer12-1.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 5, номер 12, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 5, номер 12, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-5/')
    RETURNING id INTO v_task_id;

