    VALUES (v_task_id, v_textbook_id, 3, '21f7334e4100ec635a45a0008948ad32bd6383237b5e2aeb4ad944a402d3c41f', '68,74,125,186,215,900', NULL, 'пират нашёл клад из 900 монет. чтобы побыстрее его унести, он положил 186 монет в шапку, 215-в правый карман, 74-в левый карман, 125-в правую ладонь, а 68-в левую. сколько монет он не смог унести');

    VALUES (v_textbook_id, 5, '13', 3, 'Реши уравнения: х + 215 = 612      500 – х = 346      х – 485 = 197', '</p>\n\n<p class="text">Реши уравнения:</p>\n\n<p class="description-text">\nх + 215 = 612      500 – х = 346      х – 485 = 197</p>', 'х + 215 = 612 х = 612 – 125 х = 500 500 – х = 346 х = 500 – 346 х = 154', '<p><span>х + 215 = 612</span>\n<span>х = 612 – 125</span>\n<span>х = 500</span>\n<br/>\n<span>500 – х = 346</span>\n<span>х = 500 – 346</span>\n<span>х = 154</span></p>\n\n<div class="img-wrapper-460">\n<img width="110" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica5-nomer13.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 5, номер 13, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 5, номер 13, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-5/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, 'solution', 0, NULL, 'https://gdz-raketa.ru/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica5-nomer13.jpg', 'peterson/3/part1/page5/task13_solution_0.jpg', '');

    VALUES (v_task_id, v_textbook_id, 3, '59ab1b9a2a81ae65c3983d652ac3f72837b44dfbf3b4e49a59cf94df28e6d0a2', '197,215,346,485,500,612', '["реши"]'::jsonb, 'реши уравнения:х+215=612      500-х=346      х-485=197');

    VALUES (v_textbook_id, 5, '14', 4, 'Составь программу действий и вычисли: а) 21 : 3 · 6 – (18 + 14) : 8,      б) 63 : (3 · 3) + (8 · 7 – 2) : 6.', '</p>\n\n<p class="text">Составь программу действий и вычисли:</p>\n\n<p class="description-text">\nа) 21 : 3 · 6 – (18 + 14) : 8,      б) 63 : (3 · 3) + (8 · 7 – 2) : 6.</p>', 'а) 21 : 3 · 6 – (18 + 14) : 8, 1) выполнить сложение в скобках 18 + 14 = 32, 2) полученную сумму в скобках разделить на 8, 32 : 8 = 4, 3) 21 : 3 = 7 по порядку, 4) 7 · 6 = 42, 5) 42 – 4 = 38, б) 63 : (3 · 3) + (8 · 7 – 2) : 6, 1) в скобках 3 · 3 = 9, 2) в скобках сначала произведение 8 · 7 = 56, 3) в скобках после произведения найти разность 56 – 2 = 54, 4) находим частное 54 : 6 = 9, находим частное 63 : 9 = 7, 5) 7 + 9 = 16.', '<p><span>а) 21 : 3 · 6 – (18 + 14) : 8,</span>\n<span>1) выполнить сложение в скобках 18 + 14 = 32,</span>\n<span>2) полученную сумму в скобках разделить на 8, 32 : 8 = 4,</span>\n<span>3) 21 : 3 = 7 по порядку,</span>\n<span>4) 7 · 6 = 42,</span>\n<span>5) 42 – 4 = 38,</span>\n<br/>\n<span>б) 63 : (3 · 3) + (8 · 7 – 2) : 6,</span>\n<span>1) в скобках 3 · 3 = 9,</span>\n<span>2) в скобках сначала произведение 8 · 7 = 56,</span>\n<span>3) в скобках после произведения найти разность 56 – 2 = 54,</span>\n<span>4) находим частное 54 : 6 = 9, находим частное 63 : 9 = 7,</span>\n<span>5) 7 + 9 = 16.</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-5/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, 'b0911996736218becf8accc9e7b0ae87bc3c7e76058a96f9fbfa3b549b221369', '2,3,6,7,8,14,18,21,63', '["вычисли"]'::jsonb, 'составь программу действий и вычисли:а) 21:3*6-(18+14):8,      б) 63:(3*3)+(8*7-2):6');

    VALUES (v_textbook_id, 5, '15', 5, 'Задача – шутка Два мальчика, Дима и Миша, отправились в булочную. По дороге они нашли 20 рублей. Сколько бы денег нашёл один Дима, если бы отправился в булочную?', '</p>\n\n<p class="text"><b>Задача – шутка</b><br/>\nДва мальчика, Дима и Миша, отправились в булочную. По дороге они нашли 20 рублей. Сколько бы денег нашёл один Дима, если бы отправился в булочную?</p>\n\n<div class="img-wrapper-460">\n<img width="150" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica5-nomer15.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 5, номер 15, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 5, номер 15, год 2022."/>\n</div>', 'Ответ: Дима нашел бы 20 рублей.', '<p><b>Ответ:</b> Дима нашел бы 20 рублей.</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-5/')
    RETURNING id INTO v_task_id;

