    VALUES (v_task_id, v_textbook_id, 3, '89352e22b5b2b56df3c1245accc905ab7cba9172194e5bcc867ef1b391de8f8e', '20', NULL, 'задача-шутка два мальчика, дима и миша, отправились в булочную. по дороге они нашли 20 рублей. сколько бы денег нашёл один дима, если бы отправился в булочную');

