    VALUES (v_task_id, v_textbook_id, 3, 'fac3590676dd8d3baf8bc5bdef14eab7bb83e25b12f5310e2769f5b7b171a76a', '5,10,603,608', NULL, 'задай множество перечислением:а) а-множество букв в слове "лиса"; б) в-множество однозначных чисел, меньших 5; в) с-множество двузначных чисел, кратных 10; г) d-множество трёхзначных чисел, больших 603, но меньших 608');

    VALUES (v_textbook_id, 8, '9', 0, 'Вычисли устно. Какие правила действий с числами ты вспоминаешь? 6 + 9        20 + 8      17 + 8        39 + 57 9 + 6        8 + 20      8 + 17        57 + 39 15 – 6      28 – 20    25 – 17      96 – 39 15 – 9      28 – 8      25 – 8         96 – 57', '</p>\n\n<p class="text">Вычисли устно. Какие правила действий с числами ты вспоминаешь?</p>\n\n<p class="description-text">\n<span>6 + 9        20 + 8      17 + 8        39 + 57</span>\n<span>9 + 6        8 + 20      8 + 17        57 + 39</span>\n<span>15 – 6      28 – 20    25 – 17      96 – 39</span>\n<span>15 – 9      28 – 8      25 – 8         96 – 57</span></p>', '6 + 9 = 15      20 + 8 = 28      17 + 8 = 25      39 + 57 = 96 9 + 6 = 15      8 + 20 = 28      8 + 17 = 25      57 + 39 = 96 От перестановки слагаемых сумма не меняется. 15 – 6 = 9      28 – 20 = 8      25 – 17 = 8      96 – 39 = 57 15 – 9 = 6      28 – 8 = 20      25 – 8 = 17      96 – 57 = 39 Чтобы из одного числа вычесть другое, надо к уменьшаемому прибавить число, противоположное вычитаемому.', '<p><span>6 + 9 = 15      20 + 8 = 28      17 + 8 = 25      39 + 57 = 96</span>\n<span>9 + 6 = 15      8 + 20 = 28      8 + 17 = 25      57 + 39 = 96</span>\n<span>От перестановки слагаемых сумма не меняется.</span>\n<span>15 – 6 = 9      28 – 20 = 8      25 – 17 = 8      96 – 39 = 57</span>\n<span>15 – 9 = 6      28 – 8 = 20      25 – 8 = 17      96 – 57 = 39</span>\n<span>Чтобы из одного числа вычесть другое, надо к уменьшаемому прибавить число, противоположное вычитаемому.</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-8/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '3faf1b2a28a1b899b7a1b3dc443841894130eae123466fbc8bbe18823a8fcf74', '6,8,9,15,17,20,25,28,39,57', '["вычисли"]'::jsonb, 'вычисли устно. какие правила действий с числами ты вспоминаешь? 6+9        20+8      17+8        39+57 9+6        8+20      8+17        57+39 15-6      28-20    25-17      96-39 15-9      28-8      25-8         96-57');

    VALUES (v_textbook_id, 8, '10', 1, 'В первый день Ира прочитала 21 страницу, во второй – в 2 раза больше, чем в первый, а в третий – на 15 страниц меньше, чем во второй день. Сколько страниц прочитала Ира за все три дня?', '</p>\n\n<p class="text">В первый день Ира прочитала 21 страницу, во второй – в 2 раза больше, чем в первый, а в третий – на 15 страниц меньше, чем во второй день. Сколько страниц прочитала Ира за все три дня?</p>\n\n<div class="img-wrapper-460">\n<img width="150" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica8-nomer10.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 8, номер 10, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 8, номер 10, год 2022."/>\n</div>', '21 + 21 · 2 + 21 · 2 – 15 = 21 + 42 + 42 – 15 = 63 + 27 = 100 (стр) Ответ: 100 страниц прочитала Ира за все три дня.', '<p><span>21 + 21 · 2 + 21 · 2 – 15 = 21 + 42 + 42 – 15 = 63 + 27 = 100 (стр)</span>\n<span><b>Ответ:</b> 100 страниц прочитала Ира за все три дня.</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-8/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, 'condition', 0, NULL, 'https://gdz-raketa.ru/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica8-nomer10.jpg', 'peterson/3/part1/page8/task10_condition_0.jpg', '');

    VALUES (v_task_id, v_textbook_id, 3, 'de502172f3de48a4e041b2839660c74e3d44719fa749ae8649a6f5ed870b699f', '2,15,21', '["больше","меньше","раз","раза"]'::jsonb, 'в первый день ира прочитала 21 страницу, во второй-в 2 раза больше, чем в первый, а в третий-на 15 страниц меньше, чем во второй день. сколько страниц прочитала ира за все три дня');

    VALUES (v_textbook_id, 8, '11', 2, 'Измерь своими шагами ширину класса. Как измениться результат измерения, если шаг увеличить, уменьшить? Зачем нужны общие для всех единицы длины? Какие единицы длины ты знаешь?', '</p>\n\n<p class="text">Измерь своими шагами ширину класса. Как измениться результат измерения, если шаг увеличить, уменьшить? Зачем нужны общие для всех единицы длины? Какие единицы длины ты знаешь?</p>', 'Если шаг увеличить, то количество шагов станет меньше, если шаг уменьшить, то количество шагов возрастет. Общие единицы длины нужны для того, чтобы у всех измеряющих получалась одинаковая длина. Сантиметр, миллиметр, километр, дециметр, метр.', '<p>Если шаг увеличить, то количество шагов станет меньше, если шаг уменьшить, то количество шагов возрастет. Общие единицы длины нужны для того, чтобы у всех измеряющих получалась одинаковая длина. Сантиметр, миллиметр, километр, дециметр, метр.</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-8/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '9b59ff36660338d2146b76a0e879260901429f59d36d766f8f756e61b9f51e0d', NULL, NULL, 'измерь своими шагами ширину класса. как измениться результат измерения, если шаг увеличить, уменьшить? зачем нужны общие для всех единицы длины? какие единицы длины ты знаешь');

    VALUES (v_textbook_id, 8, '12', 3, 'Вырази в сантиметрах и вычисли: а) 3м 7дм 6см + 4м 3дм 8см б) 1м 6дм 9см + 47дм 2см в) 9м 72см – 5дм 9см г) 7м 4см – 32дм 6см', '</p>\n\n<p class="text">Вырази в сантиметрах и вычисли:</p>\n\n<p class="description-text">\n<span>а) 3м 7дм 6см + 4м 3дм 8см</span>\n<span>б) 1м 6дм 9см + 47дм 2см</span>\n<span>в) 9м 72см – 5дм 9см</span>\n<span>г) 7м 4см – 32дм 6см</span></p>', 'а) 3м 7дм 6см + 4м 3дм 8см = 376см + 438см = 814см, б) 1м 6дм 9см + 47дм 2см = 169см + 472см = 641см, в) 9м 72см – 5дм 9см = 972см – 59см = 913см, г) 7м 4см – 32дм 6см = 704см – 326см = 1030см.', '<p><span>а) 3м 7дм 6см + 4м 3дм 8см = 376см + 438см = 814см,</span>\n<span>б) 1м 6дм 9см + 47дм 2см = 169см + 472см = 641см,</span>\n<span>в) 9м 72см – 5дм 9см = 972см – 59см = 913см,</span>\n<span>г) 7м 4см – 32дм 6см = 704см – 326см = 1030см.</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-8/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '6a05231534e13588244b0c2095818e336d0279a688dc977a1d8d78738fda83ce', '1,2,3,4,5,6,7,8,9,32', '["вычисли","раз"]'::jsonb, 'вырази в сантиметрах и вычисли:а) 3м 7дм 6см+4м 3дм 8см б) 1м 6дм 9см+47дм 2см в) 9м 72см-5дм 9см г) 7м 4см-32дм 6см');

    VALUES (v_textbook_id, 8, '13', 4, 'Периметр треугольника равен 7 дм 8 см. Длина первой стороны равна 2 дм 1 см, длина второй стороны – 3 дм 4 см. Найди длину третьей стороны этого треугольника.', '</p>\n\n<p class="text">Периметр треугольника равен 7 дм 8 см. Длина первой стороны равна 2 дм 1 см, длина второй стороны – 3 дм 4 см. Найди длину третьей стороны этого треугольника.</p>', '1) 2дм 1см + 3дм 4см = 5дм 5см – общая длинна двух сторон. 2) 7дм 8см – 5дм 5см = 2дм 3см – длина третьей стороны       Ответ: 2дм 3см длина третьей стороны треугольника.', '<p><span>1) 2дм 1см + 3дм 4см = 5дм 5см – общая длинна двух сторон.</span>\n<span>2) 7дм 8см – 5дм 5см = 2дм 3см – длина третьей стороны</span>\n<span>     <b>Ответ:</b> 2дм 3см длина третьей стороны треугольника.</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-8/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '490e0d692f27287eb8a593e5a32a2c0e6a2b42165571e1843e86034d690616cf', '1,2,3,4,7,8', '["найди","периметр"]'::jsonb, 'периметр треугольника равен 7 дм 8 см. длина первой стороны равна 2 дм 1 см, длина второй стороны-3 дм 4 см. найди длину третьей стороны этого треугольника');

    VALUES (v_textbook_id, 8, '14', 5, 'Найди пропущенные цифры и сделай проверку*:', '</p>\n\n<p class="text">Найди пропущенные цифры и сделай проверку*:</p>\n\n<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica8-nomer14.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 8, номер 14, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 8, номер 14, год 2022."/>\n</div>', '', '<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica8-nomer14-1.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 8, номер 14, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 8, номер 14, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-8/')
