    VALUES (v_textbook_id, 8, '15', 6, 'Выполни действия. Положи на точки прозрачную плёнку и соедини последовательно ответы примеров. Что получилось?', '</p>\n\n<p class="text">Выполни действия. Положи на точки прозрачную плёнку и соедини последовательно ответы примеров. Что получилось?</p>\n\n<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica8-nomer15.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 8, номер 15, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 8, номер 15, год 2022."/>\n</div>', '1) 20 · 9 = 180 2) 34 · 5 = 170 3) 360 : 4 = 90 4) 480 : 60 = 8 5) 52 : 4 = 13 6) 86 : 43 = 2', '<p><span>1) 20 · 9 = 180</span>\n<span>2) 34 · 5 = 170</span>\n<span>3) 360 : 4 = 90</span>\n<span>4) 480 : 60 = 8</span>\n<span>5) 52 : 4 = 13</span>\n<span>6) 86 : 43 = 2</span></p>\n\n<div class="img-wrapper-460">\n<img width="290" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica8-nomer15-1.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 8, номер 15, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 8, номер 15, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-8/')
    RETURNING id INTO v_task_id;

