    VALUES (v_textbook_id, 9, '1', 0, 'а) Сравни элементы множеств в первом и во втором рядах. Есть ли в первом ряду элемент, которого нет во втором ряду? Есть ли во втором ряду элемент, которого нет в первом ряду? б) Сравни множества в первом и во втором рядах. В каком ряду есть «лишний» элемент?', '</p>\n\n<p class="text">а) Сравни элементы множеств в первом и во втором рядах. Есть ли в первом ряду элемент, которого нет во втором ряду? Есть ли во втором ряду элемент, которого нет в первом ряду?</p>\n\n<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica9-nomer1.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 9, номер 1, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 9, номер 1, год 2022."/>\n</div>\n\n<p class="text">б) Сравни множества в первом и во втором рядах. В каком ряду есть «лишний» элемент?</p>\n\n<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica9-nomer1-1.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 9, номер 1, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 9, номер 1, год 2022."/>\n</div>', 'а) В первом ряду нету элемента, которого нет во втором ряду. Во втором ряду нету элемента, которого нет в первом ряду. б) Во втором ряду есть «лишний» элемент – мышка.', '<p><span>а) В первом ряду нету элемента, которого нет во втором ряду. Во втором ряду нету элемента, которого нет в первом ряду.</span>\n<span>б) Во втором ряду есть «лишний» элемент – мышка.</span></p>', 'Равные множества Два множества равны , если они состоят из одних и тех же элементов. Если множества А и В равны, то пишут А = В, а если они не равны, то пишут А ≠ В. Пример: Пусть А = {малина; земляника; смородина}, В = {земляника; малина; смородина}, С = {смородина; малина; вишня}, D = {малина; земляника; смородина; крыжовник}. А = В (в них одни и те же элементы, но стоят в разном порядке); А ≠ С (в А есть земляника, а в С её нет); А ≠ D (в D есть крыжовник, а в А его нет).', '<div class="recomended-block">\n<span class="title">Равные множества</span>\n<p>Два множества <b class="black">равны</b>, если они состоят из одних и тех же элементов. Если множества А и В равны, то пишут А = В, а если они не равны, то пишут А ≠ В.<br/>\n<b class="black">Пример:</b><br/>\nПусть А = {малина; земляника; смородина},<br/>\nВ = {земляника; малина; смородина},<br/>\nС = {смородина; малина; вишня},<br/>\nD = {малина; земляника; смородина; крыжовник}.<br/>\nА = В (в них одни и те же элементы, но стоят в разном порядке);<br/>\nА ≠ С (в А есть земляника, а в С её нет);<br/>\nА ≠ D (в D есть крыжовник, а в А его нет).</p>\n</div>', TRUE, '[{"letter":"а","condition":"Сравни элементы множеств в первом и во втором рядах. Есть ли в первом ряду элемент, которого нет во втором ряду? Есть ли во втором ряду элемент, которого нет в первом ряду?","solution":"В первом ряду нету элемента, которого нет во втором ряду. Во втором ряду нету элемента, которого нет в первом ряду."},{"letter":"б","condition":"Сравни множества в первом и во втором рядах. В каком ряду есть «лишний» элемент?","solution":"Во втором ряду есть «лишний» элемент – мышка."}]'::jsonb, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-9/')
    RETURNING id INTO v_task_id;

