    VALUES (v_textbook_id, 9, '3', 2, 'А = {0; 1; 2}. Какие из множеств В = {2; 0; 1}, C = {1; 0}, D = {3; 2; 1; 0} равны множеству А, а какие ему не равны? Сделай записи.', '</p>\n\n<p class="text">А = {0; 1; 2}. Какие из множеств В = {2; 0; 1}, C = {1; 0}, D = {3; 2; 1; 0} равны множеству А, а какие ему не равны? Сделай записи.</p>', 'А = {0; 1; 2}. В = {2; 0; 1} = А = {0; 1; 2}, так как все составляющие множеств А и В равны, C = {1; 0} ≠ А = {0; 1; 2}, так как в множестве С не хватает одного составляющего из множества А, D = {3; 2; 1; 0} ≠ А = {0; 1; 2}, так как в множестве больше составляющих по сравнению с множеством А.', '<p>А = {0; 1; 2}.\nВ = {2; 0; 1} = А = {0; 1; 2}, так как все составляющие множеств А и В равны,\nC = {1; 0} ≠ А = {0; 1; 2}, так как в множестве С не хватает одного составляющего из множества А,\nD = {3; 2; 1; 0} ≠ А = {0; 1; 2}, так как в множестве больше составляющих по сравнению с множеством А.</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-9/')
    RETURNING id INTO v_task_id;

