    VALUES (v_textbook_id, 10, '4', 0, 'Верны ли записи? Обоснуй свой ответ.', '</p>\n\n<p class="text">Верны ли записи? Обоснуй свой ответ.</p>\n\n<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica10-nomer4.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 10, номер 4, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 10, номер 4, год 2022."/>\n</div>', 'а) Запись верна, так как все составляющие множеств равны. б) Запись не верна, так как множества имеют разное количество составляющих. в) Запись верна, так как множества имеют различные составляющие.', '<p><span>а) Запись верна, так как все составляющие множеств равны.</span>\n<span>б) Запись не верна, так как множества имеют разное количество составляющих.</span>\n<span>в) Запись верна, так как множества имеют различные составляющие.</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-10/')
