    VALUES (v_textbook_id, 10, '6', 2, 'Сколько элементов содержит: а) множество дней недели; б) множество букв русского алфавита; в) множество хвостов у кошки Мурки; г) множество носов у Пети; д) множество коров, пасущихся на Луне?', '</p>\n\n<p class="text">Сколько элементов содержит:</p>\n\n<p class="description-text">\nа) множество дней недели;<br/>\nб) множество букв русского алфавита;<br/>\nв) множество хвостов у кошки Мурки;<br/>\nг) множество носов у Пети;<br/>\nд) множество коров, пасущихся на Луне?</p>\n\n<div class="img-wrapper-460">\n<img width="170" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica10-nomer6.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 10, номер 6, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 10, номер 6, год 2022."/>\n</div>', 'а) множество дней недели содержит 7 элементов; б) множество букв русского алфавита содержит 33 элемента; в) множество хвостов у кошки Мурки содержит один элемент; г) множество носов у Пети содержит один элемент; д) множество коров, пасущихся на Луне не содержит элементов, так на Луне нету травы и воздуха для коров.', '<p><span>а) множество дней недели содержит 7 элементов;</span>\n<span>б) множество букв русского алфавита содержит 33 элемента;</span>\n<span>в) множество хвостов у кошки Мурки содержит один элемент;</span>\n<span>г) множество носов у Пети содержит один элемент;</span>\n<span>д) множество коров, пасущихся на Луне не содержит элементов, так на Луне нету травы и воздуха для коров.</span></p>', 'Пустое множество Если множество не содержит ни одного элемента, то говорят, что оно пустое . Пустое множество обозначается так: Ø.', '<div class="recomended-block">\n<span class="title">Пустое множество</span>\n<p>Если множество не содержит ни одного элемента, то говорят, что оно <b class="black">пустое</b>. Пустое множество обозначается так: Ø.</p>\n</div>', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-10/')
    RETURNING id INTO v_task_id;

