    VALUES (v_textbook_id, 10, '7', 3, 'а) Растут ли около вашей школы тропические пальмы? Каким является множество пальм, растущих около вашей школы? б) Каким является множество шестиногих лошадей? Двухлетних детей в вашем классе? Крокодилов в Москве-реке? в) Назови свой пример описания пустого множества.', '</p>\n\n<p class="text">а) Растут ли около вашей школы тропические пальмы? Каким является множество пальм, растущих около вашей школы?<br/>\nб) Каким является множество шестиногих лошадей? Двухлетних детей в вашем классе? Крокодилов в Москве-реке?<br/>\nв) Назови свой пример описания пустого множества.</p>\n\n<div class="img-wrapper-460">\n<img width="170" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica10-nomer7.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 10, номер 7, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 10, номер 7, год 2022."/>\n</div>', 'а) Пальмы не растут, пустое множество является множество пальм, растущих около нашей школы. б) пустое множество является множество шестиногих лошадей. Пустое множество является множество двухлетних детей в нашем классе. Пустое множество является множество крокодилов в Москве-реке. в) пустое множество является множество кофейных зерен в чае.', '<p><span>а) Пальмы не растут, пустое множество является множество пальм, растущих около нашей школы.</span>\n<span>б) пустое множество является множество шестиногих лошадей. Пустое множество является множество двухлетних детей в нашем классе. Пустое множество является множество крокодилов в Москве-реке.</span>\n<span>в) пустое множество является множество кофейных зерен в чае.</span></p>', '', '', TRUE, '[{"letter":"а","condition":"Растут ли около вашей школы тропические пальмы? Каким является множество пальм, растущих около вашей школы?","solution":"Пальмы не растут, пустое множество является множество пальм, растущих около нашей школы."},{"letter":"б","condition":"Каким является множество шестиногих лошадей? Двухлетних детей в вашем классе? Крокодилов в Москве-реке?","solution":"пустое множество является множество шестиногих лошадей. Пустое множество является множество двухлетних детей в нашем классе. Пустое множество является множество крокодилов в Москве-реке."},{"letter":"в","condition":"Назови свой пример описания пустого множества.","solution":"пустое множество является множество кофейных зерен в чае."}]'::jsonb, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-10/')
    RETURNING id INTO v_task_id;

