    VALUES (v_textbook_id, 10, '9', 5, 'Как найти площадь прямоугольника? Как найти его неизвестную сторону? Найди х по рисункам:', '</p>\n\n<p class="text">Как найти площадь прямоугольника? Как найти его неизвестную сторону? Найди <b>х</b> по рисункам:</p>\n\n<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica10-nomer9.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 10, номер 9, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 10, номер 9, год 2022."/>\n</div>', 'S = а · b, 16 = 8 · х, х = 16 : 8, х = 2 (см). S = а · b, х = 6 · 3, х = 18 (см 2 ). S = а · b, 20 = х · 4, х = 20 : 4, х = 5 (см).', '<p><span>S = а · b,</span>\n<span>16 = 8 · х,</span>\n<span>х = 16 : 8,</span>\n<span>х = 2 (см).</span>\n<br/>\n<span>S = а · b,</span>\n<span>х = 6 · 3,</span>\n<span>х = 18 (см<sup>2</sup>).</span>\n<br/>\n<span>S = а · b,</span>\n<span>20 = х · 4,</span>\n<span>х = 20 : 4,</span>\n<span>х = 5 (см).</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-10/')
    RETURNING id INTO v_task_id;

