    VALUES (v_textbook_id, 11, '13', 2, 'Составь выражение и найди его значение, если a = 12, b = 3, c = 2: «Володя высадил на первой грядке a кустов клубники, на второй грядке – на b кустов больше, чем на первой, а на третьей – на c кустов меньше, чем на первой грядке. Сколько всего кустов клубники посадил Володя?»', '</p>\n\n<p class="text">Составь выражение и найди его значение, если a = 12, b = 3, c = 2: «Володя высадил на первой грядке <b>a</b> кустов клубники, на второй грядке – на <b>b</b> кустов больше, чем на первой, а на третьей – на <b>c</b> кустов меньше, чем на первой грядке. Сколько всего кустов клубники посадил Володя?»</p>', 'а + (а + b) + (a – c) 12 + (12 + 3) + (12 – 2) = 12 + 15 + 10 = 37 (кустов) Ответ: 37 кустов клубники всего посадил Володя.', '<p><span>а + (а + b) + (a – c)</span>\n<span>12 + (12 + 3) + (12 – 2) = 12 + 15 + 10 = 37 (кустов)</span>\n<span><b>Ответ:</b> 37 кустов клубники всего посадил Володя.</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-11/')
    RETURNING id INTO v_task_id;

