    VALUES (v_textbook_id, 12, '4', 3, 'На садовом участке огород занимает 84 м 2 . Площадь цветника на 36 м 2 меньше площади огорода. Площадь фруктового сада в 5 раз больше площади цветника. Чему равна площадь фруктового сада?', '</p>\n\n<p class="text">На садовом участке огород занимает 84 м<sup>2</sup>. Площадь цветника на 36 м<sup>2</sup> меньше площади огорода. Площадь фруктового сада в 5 раз больше площади цветника. Чему равна площадь фруктового сада?</p>\n\n<div class="img-wrapper-460">\n<img width="290" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica12-nomer4.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 12, номер 4, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 12, номер 4, год 2022."/>\n</div>', '(84 – 36) · 5 = 48 · 5 = 240 (м 2 )', '<p>(84 – 36) · 5 = 48 · 5 = 240 (м<sup>2</sup>)</p>\n\n<div class="img-wrapper-460">\n<img width="240" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica12-nomer4-1.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 12, номер 4, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 12, номер 4, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-12/')
    RETURNING id INTO v_task_id;

