    VALUES (v_textbook_id, 12, '6', 5, 'Составь программу действий и вычисли. Проверь результаты с помощью калькулятора. а) 526 – (401 – 294) + 381      б) (694 + 76) – (253 + 472) + 146', '</p>\n\n<p class="text">Составь программу действий и вычисли. Проверь результаты с помощью калькулятора.</p>\n\n<p class="description-text">\nа) 526 – (401 – 294) + 381      б) (694 + 76) – (253 + 472) + 146</p>', 'а) 526 – (401 – 294) + 381 = 526 – 107 + 381 = 419 + 381 = 800', '<p>а) 526 – (401 – 294) + 381 = 526 – 107 + 381 = 419 + 381 = 800</p>\n\n<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica12-nomer6.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 12, номер 6, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 12, номер 6, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-12/')
