    VALUES (v_textbook_id, 12, '7', 6, 'Найди пропущенные цифры. Сделай проверку, используя связь между сложением и вычитанием.', '</p>\n\n<p class="text">Найди пропущенные цифры. Сделай проверку, используя связь между сложением и вычитанием.</p>\n\n<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica12-nomer7.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 12, номер 7, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 12, номер 7, год 2022."/>\n</div>', '', '<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica12-nomer7-1.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 12, номер 7, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 12, номер 7, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-12/')
