    VALUES (v_textbook_id, 12, '8', 7, 'Вычисли устно: 7 + 8       16 + 4      9 + 15      27 + 43     36 + 17 12 – 5      30 – 9      42 – 8      50 – 32      85 – 39', '</p>\n\n<p class="text">Вычисли устно:</p>\n\n<p class="description-text">\n<span>7 + 8       16 + 4      9 + 15      27 + 43     36 + 17</span>\n<span>12 – 5      30 – 9      42 – 8      50 – 32      85 – 39</span></p>', '7 + 8 = 15     16 + 4 = 20      9 + 15 = 24      27 + 43 = 70     36 + 17 = 53 12 – 5 = 7      30 – 9 = 21      42 – 8 = 34      50 – 32 = 18      85 – 39 = 46', '<p><span>7 + 8 = 15     16 + 4 = 20      9 + 15 = 24      27 + 43 = 70     36 + 17 = 53</span>\n<span>12 – 5 = 7      30 – 9 = 21      42 – 8 = 34      50 – 32 = 18      85 – 39 = 46</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-12/')
