    VALUES (v_textbook_id, 13, '11', 2, 'Реши уравнения с комментированием: х · 20 = 160      х : 7 = 42      92 : х = 46', '</p>\n\n<p class="text">Реши уравнения с комментированием:</p>\n\n<p class="description-text">\nх · 20 = 160      х : 7 = 42      92 : х = 46</p>', 'х · 20 = 160 Что бы найти х разделим число произведения на множитель х = 160 : 20 х = 8 х : 7 = 42 Что бы найти делимое х перемножим число частного на делитель х = 42 · 7 х = 294', '<p><span>х · 20 = 160</span>\n<span>Что бы найти х разделим число произведения на множитель</span>\n<span>х = 160 : 20</span>\n<span>х = 8</span>\n<br/>\n<span>х : 7 = 42</span>\n<span>Что бы найти делимое х перемножим число частного на делитель</span>\n<span>х = 42 · 7</span>\n<span>х = 294</span></p>\n\n<div class="img-wrapper-460">\n<img width="100" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica13-nomer11.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 13, номер 11, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 13, номер 11, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-13/')
    RETURNING id INTO v_task_id;

