    VALUES (v_task_id, v_textbook_id, 3, 'd428dcd1a00e2cff15d5a680e05eb1f79f76feb6fd3ba121fd2cb8fe96b5889b', '7,20,42,46,92,160', '["реши"]'::jsonb, 'реши уравнения с комментированием:х*20=160      х:7=42      92:х=46');

    VALUES (v_textbook_id, 13, '12', 3, 'БЛИЦтурнир* а) Масса арбуза а кг, а масса тыквы на 2 кг меньше. Какова общая масса арбуза и тыквы? б) Шапка стоит b р., а пальто – в 9 раз дороже. Сколько стоят пальто и шапка вместе? в) В ведро входит с л воды, а в кастрюлю – в 7 раз меньше. На сколько объём этого ведра больше объёма этой кастрюли? г) В куске было d м ткани. Из этой ткани сшили 8 одинаковых платьев, расходуя на каждое платье по n м. Сколько метров ткани осталось в куске? *В БЛИЦтурнирах записи делаются на листках бумаги, которые накладываются на цветную плашку справа от текста задач.', '</p>\n\n<p class="text"><span><b>БЛИЦтурнир*</b></span>\n<span>а) Масса арбуза <b>а</b> кг, а масса тыквы на 2 кг меньше. Какова общая масса арбуза и тыквы?</span>\n<span>б) Шапка стоит <b>b</b> р., а пальто – в 9 раз дороже. Сколько стоят пальто и шапка вместе?</span>\n<span>в) В ведро входит <b>с</b> л воды, а в кастрюлю – в 7 раз меньше. На сколько объём этого ведра больше объёма этой кастрюли?</span>\n<span>г) В куске было <b>d</b> м ткани. Из этой ткани сшили 8 одинаковых платьев, расходуя на каждое платье по <b>n</b> м. Сколько метров ткани осталось в куске?</span></p>\n\n<p class="description-text">\n<b>*В БЛИЦтурнирах</b> записи делаются на листках бумаги, которые накладываются на цветную плашку справа от текста задач.</p>\n\n<div class="img-wrapper-460">\n<img width="180" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica13-nomer12.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 13, номер 12, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 13, номер 12, год 2022."/>\n</div>', 'а) а + а – 2 = 2а – 2 (кг) – общая масса арбуза и тыквы. б) b + 9b = 10b (р) – стоят пальто и шапка вместе. в) с – с : 7 (л) – на столько объём этого ведра больше объёма этой кастрюли. г) d – 8n (м) – ткани осталось в куске.', '<p><span>а) а + а – 2 = 2а – 2 (кг) – общая масса арбуза и тыквы.</span>\n<span>б) b + 9b = 10b (р) – стоят пальто и шапка вместе.</span>\n<span>в) с – с : 7 (л) – на столько объём этого ведра больше объёма этой кастрюли.</span>\n<span>г) d – 8n (м) – ткани осталось в куске.</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-13/')
    RETURNING id INTO v_task_id;

