    VALUES (v_task_id, v_textbook_id, 3, 'de3466d0f302740736bcf491f24701f0938be716dd97cecff737adcdaf56b375', '2,7,8,9', '["больше","меньше","раз"]'::jsonb, 'блицтурнир*а) масса арбуза а кг, а масса тыквы на 2 кг меньше. какова общая масса арбуза и тыквы? б) шапка стоит b р., а пальто-в 9 раз дороже. сколько стоят пальто и шапка вместе? в) в ведро входит с л воды, а в кастрюлю-в 7 раз меньше. на сколько объём этого ведра больше объёма этой кастрюли? г) в куске было d м ткани. из этой ткани сшили 8 одинаковых платьев, расходуя на каждое платье по n м. сколько метров ткани осталось в куске?*в блицтурнирах записи делаются на листках бумаги, которые накладываются на цветную плашку справа от текста задач');

    VALUES (v_textbook_id, 13, '13', 4, 'Периметр квадрата равен 36 м. Чему равна его площадь?', '</p>\n\n<p class="text">Периметр квадрата равен 36 м. Чему равна его площадь?</p>', '36 = 4a а = 36 : 4 а = 9 (м) S = a 2 S = 9 2 S = 81 (м).', '<p><span>36 = 4a</span>\n<span>а = 36 : 4</span>\n<span>а = 9 (м)</span>\n<span>S = a<sup>2</sup></span>\n<span>S = 9<sup>2</sup></span>\n<span>S = 81 (м).</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-13/')
    RETURNING id INTO v_task_id;

