    VALUES (v_textbook_id, 13, '14', 5, 'Запиши множество чётных трёхзначных чисел, сумма цифр которых равна 3.', '</p>\n\n<p class="text">Запиши множество чётных трёхзначных чисел, сумма цифр которых равна 3.</p>', '102 : 1 + 0 + 2 = 3 111 : 1 + 1 + 1 = 3 120 : 1 + 2 + 0 = 3 201 : 2 + 0 + 1 = 3 210 : 2 + 1 + 0 = 3 300 : 3 + 0 + 0 = 3', '<p><span>102 : 1 + 0 + 2 = 3</span>\n<span>111 : 1 + 1 + 1 = 3</span>\n<span>120 : 1 + 2 + 0 = 3</span>\n<span>201 : 2 + 0 + 1 = 3</span>\n<span>210 : 2 + 1 + 0 = 3</span>\n<span>300 : 3 + 0 + 0 = 3</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-13/')
    RETURNING id INTO v_task_id;

