    VALUES (v_textbook_id, 14, '1', 0, 'Назови каждый элемент множества В = {2; m;     }. Принадлежит ли этому множеству число 2, буква а ? Запиши предложения, заполнив пропуски: Число 2 ... множеству В Буква а ... множеству В', '</p>\n\n<p class="text"><span>Назови каждый элемент множества В = {2; m; <span class="okon">   </span>}. Принадлежит ли этому множеству число 2, буква <b>а</b>?</span>\n<span>Запиши предложения, заполнив пропуски:</span>\n<span>Число 2 ... множеству В</span>\n<span>Буква <b>а</b> ... множеству В</span></p>\n\n<div class="img-wrapper-460">\n<img width="150" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica14-nomer1.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 14, номер 1, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 14, номер 1, год 2022."/>\n</div>', 'Элемент множества В – 2, элемент множества В – m, элемент множества В –     . Число 2 принадлежит множеству В. Буква а принадлежит множеству В.', '<p><span>Элемент множества В – 2, элемент множества В – m, элемент множества В – <span class="okon">   </span>.</span>\n<span>Число 2 принадлежит множеству В.</span>\n<span>Буква а принадлежит множеству В.</span></p>', 'Диаграмма Эйлера–Венна. Знаки ∈ и ∉    Чтобы лучше представить себе множество, можно использовать рисунок, называемый диаграммой Эйлера–Венна. Это замкнутая линия, внутри которой расположены элементы данного множества, а снаружи – элементы, не принадлежащие множеству.    Например, диаграмму множества В = {2; m;     } можно нарисовать так:', '<div class="recomended-block">\n<span class="title">Диаграмма Эйлера–Венна. Знаки ∈ и ∉</span>\n<p>   Чтобы лучше представить себе множество, можно использовать рисунок, называемый диаграммой Эйлера–Венна. Это замкнутая линия, внутри которой расположены элементы данного множества, а снаружи – элементы, не принадлежащие множеству.<br/>\n   Например, диаграмму множества В = {2; m; <span class="okon">   </span>} можно нарисовать так:</p>\n\n<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica14-recomended-block.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 14, номер 1, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 14, номер 1, год 2022."/>\n</div>', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-14/')
