    VALUES (v_textbook_id, 14, '2', 1, 'На рисунке изображена диаграмма множества А. Какие элементы принадлежат множеству А, а какие ему не принадлежат? Сделай записи, используя знаки ∈ и ∉:', '</p>\n\n<p class="text">На рисунке изображена диаграмма множества А. Какие элементы принадлежат множеству А, а какие ему не принадлежат? Сделай записи, используя знаки ∈ и ∉:</p>\n\n<div class="img-wrapper-460">\n<img width="290" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica14-nomer2.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 14, номер 2, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 14, номер 2, год 2022."/>\n</div>\n\n<div class="img-wrapper-460">\n<img width="180" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica14-nomer2-1.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 14, номер 2, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 14, номер 2, год 2022."/>\n</div>', '', '<div class="img-wrapper-460">\n<img width="290" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica14-nomer2-2.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 14, номер 2, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 14, номер 2, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-14/')
