    VALUES (v_textbook_id, 15, '5', 0, 'D – множество двузначных чисел. а) Принадлежат ли множеству D числа 26, 307, 8, 940, 15, 60? Отметь их на диаграмме множества D. Сделай записи, используя знаки ∈ и ∉. б) Сколько элементов содержит множество D? в) Укажи самое маленькое и самое большое число, принадлежащее множеству D.', '</p>\n\n<p class="text">D – множество двузначных чисел.</p>\n\n<p class="description-text">\n<span>а) Принадлежат ли множеству D числа 26, 307, 8, 940, 15, 60? Отметь их на диаграмме множества D. Сделай записи, используя знаки ∈ и ∉.</span>\n<span>б) Сколько элементов содержит множество D?</span>\n<span>в) Укажи самое маленькое и самое большое число, принадлежащее множеству D.</span></p>\n\n<div class="img-wrapper-460">\n<img width="150" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica15-nomer5.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 15, номер 5, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 15, номер 5, год 2022."/>\n</div>', 'а) Принадлежат множеству D числа 26, 15, 60.', '<p>а) Принадлежат множеству D числа 26, 15, 60.</p>\n\n<div class="img-wrapper-460">\n<img width="200" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica15-nomer5-1.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 15, номер 5, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 15, номер 5, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-15/')
