    VALUES (v_textbook_id, 15, '7', 2, 'Найди общее свойство элементов множества А и общее свойство элементов множества В. Сколько девочек принадлежит А, но не принадлежит В? Сколько девочек принадлежит В, но не принадлежит А? Сколько общих элементов у множеств А и В?', '</p>\n\n<p class="text">Найди общее свойство элементов множества А и общее свойство элементов множества В.</p>\n\n<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica15-nomer6.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 15, номер 6, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 15, номер 6, год 2022."/>\n</div>\n\n<p class="text">Сколько девочек принадлежит А, но не принадлежит В? Сколько девочек принадлежит В, но не принадлежит А? Сколько общих элементов у множеств А и В?</p>', 'Цветочек у девочек – общее свойство элементов множества А и мячик у девочек – общее свойство элементов множества В. Три девочек принадлежит А, но не принадлежит В. Три девчек принадлежит В, но не принадлежит А. Один общий элемент у множеств А и В.', '<p>Цветочек у девочек – общее свойство элементов множества А и мячик у девочек – общее свойство элементов множества В.<br/>\nТри девочек принадлежит А, но не принадлежит В. Три девчек принадлежит В, но не принадлежит А. Один общий элемент у множеств А и В.</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-15/')
