    VALUES (v_task_id, v_textbook_id, 3, '515a19220b6e2e95dc2799caffe955e11b58abf85444da2526edf43cf1afbe57', NULL, '["найди"]'::jsonb, 'найди общее свойство элементов множества а и общее свойство элементов множества в. сколько девочек принадлежит а, но не принадлежит в? сколько девочек принадлежит в, но не принадлежит а? сколько общих элементов у множеств а и в');

    VALUES (v_textbook_id, 15, '8', 3, 'Объясни по чертежу, как выполнено деление с остатком. Назови делимое, делитель, частное и остаток. Запиши равенства в тетради. Вспомни и расскажи алгоритм деления с остатком.', '</p>\n\n<p class="text">Объясни по чертежу, как выполнено деление с остатком. Назови делимое, делитель, частное и остаток. Запиши равенства в тетради.</p>\n\n<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica15-nomer7.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 15, номер 7, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 15, номер 7, год 2022."/>\n</div>\n\n<ul class="rus2">\n<li><span>Вспомни и расскажи алгоритм деления с остатком.</span></li>\n</ul>', 'Число 35 разделили на 4 равных отрезка и один отрезок числа 3 в остатке. Делимое – 35, делитель – 8, остаток – 3. 35 = 8 · 4 + 3 35 : 8 = 4 (ост. 3) Определи в числовом выражении компоненты деления (делимое, делитель). В делимом определи, какое самое большое число можно разделить без остатка на делитель. Выполни деление. Раздели самое большое полученное число на делитель. Результат деления запиши в частном. Вычисли остаток. Для этого из делимого вычти то, число которое, разделили без остатка на делитель. Запиши, чему равен остаток.', '<p><span>Число 35 разделили на 4 равных отрезка и один отрезок числа 3 в остатке. Делимое – 35, делитель – 8, остаток – 3.</span>\n<span>35 = 8 · 4 + 3</span>\n<span>35 : 8 = 4 (ост. 3)</span>\n<span>Определи в числовом выражении компоненты деления (делимое, делитель).</span>\n<span>В делимом определи, какое самое большое число можно разделить без остатка на делитель.</span>\n<span>Выполни деление. Раздели самое большое полученное число на делитель. Результат деления запиши в частном.</span>\n<span>Вычисли остаток. Для этого из делимого вычти то, число которое, разделили без остатка на делитель. Запиши, чему равен остаток.</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-15/')
    RETURNING id INTO v_task_id;

