    VALUES (v_textbook_id, 16, '11', 0, 'Бабушка Гамми приготовила 45 л яблочного сока и 85 л вишнёвого. Из них на завтрак медведи израсходовали 18 л, а на обед – в 2 раза больше, чем на завтрак. Сколько сока у медведей ещё осталось?', '</p>\n\n<p class="text">Бабушка Гамми приготовила 45 л яблочного сока и 85 л вишнёвого. Из них на завтрак медведи израсходовали 18 л, а на обед – в 2 раза больше, чем на завтрак. Сколько сока у медведей ещё осталось?</p>\n\n<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica16-nomer11.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 16, номер 11, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 16, номер 11, год 2022."/>\n</div>', '45 + 85 – 18 – 18 · 2 = 130 – 18 – 36 = 112 – 36 = 76 (л)', '<p>45 + 85 – 18 – 18 · 2 = 130 – 18 – 36 = 112 – 36 = 76 (л)</p>\n\n<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica16-nomer11-1.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 16, номер 11, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 16, номер 11, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-16/')
    RETURNING id INTO v_task_id;

