    VALUES (v_task_id, v_textbook_id, 3, '9f559a2b2b7a91e6386e3d938088a4204ecfdf2049f3889f93f745d25bc0f300', '2,18,45,85', '["больше","раз","раза"]'::jsonb, 'бабушка гамми приготовила 45 л яблочного сока и 85 л вишнёвого. из них на завтрак медведи израсходовали 18 л, а на обед-в 2 раза больше, чем на завтрак. сколько сока у медведей ещё осталось');

    VALUES (v_textbook_id, 16, '12', 1, 'Вычисли устно и объясни приёмы вычислений: 5 · 100      800 : 10      200 · 3      560 : 7      270 : 90 10 · 70      400 : 100    40 · 18      400 : 5      320 : 160', '</p>\n\n<p class="text">Вычисли устно и объясни приёмы вычислений:</p>\n\n<p class="description-text">\n<span>5 · 100      800 : 10      200 · 3      560 : 7      270 : 90</span>\n<span>10 · 70      400 : 100    40 · 18      400 : 5      320 : 160</span></p>', '5 · 100 = 500 – добавляем нули от 100 числу 5, 800 : 10 = 80 – убираем от 800 сколько нолей у делителя – у 10 один, 200 · 3 = 600 – умножаем 2 на 3 и подставляем нули от 200, 560 : 7 = 80 – делим 56 на 7 и подставляем ноль от 560, 270 : 90 = 3 – делим 27 на 3 и убираем ноль сколько нолей у делителя, 10 · 70 = 700 – добавляем одни ноль к 70, 400 : 100 = 4 – убираем ноли от 400 сколько нолей у делителя, 40 · 18 = 720 – умножаем 4 на 18 и подставляем ноль от 40, 400 : 5 = 80 – 4 не делиться на 5, поэтому 40 делим на пять о остается подставить один оставшийся ноль, 320 : 160 = 2 – 32 делим на 16 и убираем ноли сколько нолей у делителя.', '<p><span>5 · 100  = 500 – добавляем нули от 100 числу 5,</span>\n<span>800 : 10 = 80 – убираем от 800 сколько нолей у делителя – у 10 один,</span>\n<span>200 · 3 = 600 – умножаем 2 на 3 и подставляем нули от 200,</span>\n<span>560 : 7 = 80 – делим 56 на 7 и подставляем ноль от 560,</span>\n<span>270 : 90 = 3 – делим 27 на 3 и убираем ноль сколько нолей у делителя,</span>\n<span>10 · 70 = 700 – добавляем одни ноль к 70,</span>\n<span>400 : 100 = 4 – убираем ноли от 400 сколько нолей у делителя,</span>\n<span>40 · 18 = 720 – умножаем 4 на 18 и подставляем ноль от 40,</span>\n<span>400 : 5 = 80 – 4 не делиться на 5, поэтому 40 делим на пять о остается подставить один оставшийся ноль,</span>\n<span>320 : 160 = 2 – 32 делим на 16 и убираем ноли сколько нолей у делителя.</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-16/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '1d89b0db56629076c29733ee8b7b804e9b1ae98567fcc469d815fc299f82c35b', '3,5,7,10,18,40,70,90,100,160', '["вычисли"]'::jsonb, 'вычисли устно и объясни приёмы вычислений:5*100      800:10      200*3      560:7      270:90 10*70      400:100    40*18      400:5      320:160');

    VALUES (v_textbook_id, 16, '13', 2, 'Найди значения выражений: а) 360 : 6 · 5 – 450 : (25 · 2) – 70 · 6 : 3 б) 4 · (30 · 8) – 9 · 8 : 12 – (100 – 8 · 8)', '</p>\n\n<p class="text">Найди значения выражений:</p>\n\n<p class="description-text">\n<span>а) 360 : 6 · 5 – 450 : (25 · 2) – 70 · 6 : 3</span>\n<span>б) 4 · (30 · 8) – 9 · 8 : 12 – (100 – 8 · 8)</span></p>', 'а) 360 : 6 · 5 – 450 : (25 · 2) – 70 · 6 : 3 = 60 · 5 – 450 : 50 – 70 · 2 = 300 – 9 – 140 = 160 – 9 = 151 б) 4 · (30 · 8) – 9 · 8 : 12 – (100 – 8 · 8) = 4 · 24 – 72 : 12 – (100 – 64) = 96 – 6 – 36 = 60 – 6 = 54.', '<p><span>а) 360 : 6 · 5 – 450 : (25 · 2) – 70 · 6 : 3 = 60 · 5 – 450 : 50 – 70 · 2 = 300 – 9 – 140 = 160 – 9 = 151</span>\n<span>б) 4 · (30 · 8) – 9 · 8 : 12 – (100 – 8 · 8) = 4 · 24 – 72 : 12 – (100 – 64) = 96 – 6 – 36 = 60 – 6 = 54.</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-16/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '6f9d6588b6b91c3630f55a107b653789dc234b151968ce21b40120b935272b3b', '2,3,4,5,6,8,9,12,25,30', '["найди"]'::jsonb, 'найди значения выражений:а) 360:6*5-450:(25*2)-70*6:3 б) 4*(30*8)-9*8:12-(100-8*8)');

    VALUES (v_textbook_id, 16, '14', 3, 'БЛИЦтурнира а) У Вадима а открыток. Их в 2 раза меньше, чем у Алёши. Сколько открыток у Алёши? б) У Лены b марок. Их на с марок меньше, чем у её сестры. Сколько марок у них вместе? в) Артём нашёл n ягод земляники. Из них сестре он подарил k ягод, а бабушке – в 3 раза больше. Сколько ягод у него осталось? г) Из x белых и у красных гвоздик сделали букеты по 5 гвоздик в каждом. Сколько получилось букетов?', '</p>\n\n<p class="text"><span><b>БЛИЦтурнира</b></span>\n<span>а) У Вадима <b>а</b> открыток. Их в 2 раза меньше, чем у Алёши. Сколько открыток у Алёши?</span>\n<span>б) У Лены <b>b</b> марок. Их на <b>с</b> марок меньше, чем у её сестры. Сколько марок у них вместе?</span>\n<span>в) Артём нашёл <b>n</b> ягод земляники. Из них сестре он подарил <b>k</b> ягод, а бабушке – в 3 раза больше. Сколько ягод у него осталось?</span>\n<span>г) Из <b>x</b> белых и <b>у</b> красных гвоздик сделали букеты по 5 гвоздик в каждом. Сколько получилось букетов?</span></p>', 'а) 2а открыток у Алёши. б) b + b + с = 2b + c марок у них вместе. в) n – k – 3k = n – 4k ягод у него осталось. г) (x + у) : 5 получилось букетов.', '<p><span>а) 2а открыток у Алёши.</span>\n<span>б) b + b + с = 2b + c марок у них вместе.</span>\n<span>в) n – k – 3k = n – 4k ягод у него осталось.</span>\n<span>г) (x + у) : 5 получилось букетов.</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-16/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '00295ab46d4ac98d949220a8f9f2b82b61bea82af774332ddade434507249f3e', '2,3,5', '["больше","меньше","раз","раза"]'::jsonb, 'блицтурнира а) у вадима а открыток. их в 2 раза меньше, чем у алёши. сколько открыток у алёши? б) у лены b марок. их на с марок меньше, чем у её сестры. сколько марок у них вместе? в) артём нашёл n ягод земляники. из них сестре он подарил k ягод, а бабушке-в 3 раза больше. сколько ягод у него осталось? г) из x белых и у красных гвоздик сделали букеты по 5 гвоздик в каждом. сколько получилось букетов');

    VALUES (v_textbook_id, 16, '15', 4, 'Определи, какие знаки действий можно вставить вместо звёздочек. Есть ли другие решения? 31 * 1 = 31      25 * 0 = 25      0 * 26 = 0 1 * 58 = 58      0 * 49 = 49      74 * 0 = 0', '</p>\n\n<p class="text">Определи, какие знаки действий можно вставить вместо звёздочек. Есть ли другие решения?</p>\n\n<p class="description-text">\n<span>31 * 1 = 31      25 * 0 = 25      0 * 26 = 0</span>\n<span>1 * 58 = 58      0 * 49 = 49      74 * 0 = 0</span></p>', '31 · 1 = 31      25 + 0 = 25      0 · 26 = 0 1 · 58 = 58      0 + 49 = 49      74 · 0 = 0', '<p><span>31 · 1 = 31      25 + 0 = 25      0 · 26 = 0</span>\n<span>1 · 58 = 58      0 + 49 = 49      74 · 0 = 0</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-16/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, 'd7ea6c0016f88c45f6f086ee823a73abb6aa9cfe739dbe1f53ba6832cdf2b3b0', '0,1,25,26,31,49,58,74', NULL, 'определи, какие знаки действий можно вставить вместо звёздочек. есть ли другие решения? 31*1=31      25*0=25      0*26=0 1*58=58      0*49=49      74*0=0');

    VALUES (v_textbook_id, 16, '16', 5, 'Три купца хотят поделить между собой 21 бочонок кваса, из которых 7 полных, 7 наполовину полных и 7 пустых. Как им это сделать, не переливая квас, чтобы у каждого оказалось одинаковое количество кваса и бочонков (вместимость всех бочонков одинаковая)?', '</p>\n\n<p class="text">Три купца хотят поделить между собой 21 бочонок кваса, из которых 7 полных, 7 наполовину полных и 7 пустых. Как им это сделать, не переливая квас, чтобы у каждого оказалось одинаковое количество кваса и бочонков (вместимость всех бочонков одинаковая)?</p>\n\n<div class="img-wrapper-460">\n<img width="150" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica16-nomer16.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 16, номер 16, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 16, номер 16, год 2022."/>\n</div>', '7 : 3 = 2 + 1 – двум купцам по два полных, а третьему три полных. Поэтому что бы уровнять двум купцам по две половинки от 7 : 7 – 2 – 2 = 7 – 4 = 3. 3 : 3 = 1 – по одной половинке трём купцам. Двум купцам 2 + 1 = 3 половинки 3 + 2 = 5 бочонков и одному купцу с тремя полными 1 половинку. 3 + 1 = 4 бочонка. Двум купцам с 5 бочонками по 2 пустых бочонка и третьему купцу с 4 бочонками 7 – 2 – 2 = 7 – 4 = 3 бочонка. И у него тоже получиться 4 + 3 = 7 бочонок.', '<p>7 : 3 = 2 + 1 – двум купцам по два полных, а третьему три полных. Поэтому что бы уровнять двум купцам по две половинки от 7 : 7 – 2 – 2 = 7 – 4 = 3. 3 : 3 = 1 – по одной половинке трём купцам. Двум купцам 2 + 1 = 3 половинки 3 + 2 = 5 бочонков и одному купцу с тремя полными 1 половинку. 3 + 1 = 4 бочонка. Двум купцам с 5 бочонками по 2 пустых бочонка и третьему купцу с 4 бочонками 7 – 2 – 2 = 7 – 4 = 3 бочонка. И у него тоже получиться 4 + 3 = 7 бочонок.</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-16/')
    RETURNING id INTO v_task_id;

