    VALUES (v_textbook_id, 17, '2', 1, 'А – множество двузначных чисел, сумма цифр которых равна 5. Принадлежат ли этому множеству числа 5, 14, 25, 32, 50? Сделай записи, используя знаки ∈ и ∉.', '</p>\n\n<p class="text">А – множество двузначных чисел, сумма цифр которых равна 5. Принадлежат ли этому множеству числа 5, 14, 25, 32, 50? Сделай записи, используя знаки ∈ и ∉.</p>', '14 – 1 + 4 = 5, 23 – 2 + 3 = 5, 32 – 3 + 2 = 5, 41 – 4 + 1 = 5, 50 – 5 + 0 = 5 5 ∉ А, 14 ∈ А, 25 ∉ А, 32 ∈ А, 50 ∈ А.', '<p><span>14 – 1 + 4 = 5, 23 – 2 + 3 = 5, 32 – 3 + 2 = 5, 41 – 4 + 1 = 5, 50 – 5 + 0 = 5</span>\n<span>5 ∉ А, 14 ∈ А, 25 ∉ А, 32 ∈ А, 50 ∈ А.</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-17/')
    RETURNING id INTO v_task_id;

