    VALUES (v_textbook_id, 17, '4', 3, 'Фермер купил 64 саженца фруктовых деревьев. Из них 40 саженцев – для сада, а остальные – для трёх земельных участков поровну. Сколько фруктовых деревьев посадили на каждом из этих участков?', '</p>\n\n<p class="text">Фермер купил 64 саженца фруктовых деревьев. Из них 40 саженцев – для сада, а остальные – для трёх земельных участков поровну. Сколько фруктовых деревьев посадили на каждом из этих участков?</p>\n\n<div class="img-wrapper-460">\n<img width="290" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica17-nomer4.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 17, номер 4, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 17, номер 4, год 2022."/>\n</div>', '(64 – 40) : 3 = 24 : 3 = 8 Ответ: 8 фруктовых деревьев посадили на каждом из этих участков фермер.', '<p><span>(64 – 40) : 3 = 24 : 3 = 8</span>\n<span><b>Ответ:</b> 8 фруктовых деревьев посадили на каждом из этих участков фермер.</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-17/')
    RETURNING id INTO v_task_id;

