    VALUES (v_textbook_id, 17, '5', 4, 'Выполни деление с остатком и сделай проверку: 39 : 5      48 : 7      25 : 2      63 : 4      92 : 7', '</p>\n\n<p class="text">Выполни деление с остатком и сделай проверку:</p>\n\n<p class="description-text">\n39 : 5      48 : 7      25 : 2      63 : 4      92 : 7</p>', '39 : 5 = 7 + 4, 5 · 7 + 4 = 35 + 4 = 39', '<p>39 : 5 = 7 + 4, 5 · 7 + 4 = 35 + 4 = 39</p>\n\n<div class="img-wrapper-460">\n<img width="220" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica17-nomer5.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 17, номер 5, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 17, номер 5, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-17/')
