    VALUES (v_textbook_id, 17, '6', 5, 'а) Пользуясь числовым лучом, составь множество двузначных чисел, кратных 11. б) Выполни деление с остатком: 25 : 11      39 : 11      54 : 11      75 : 11      90 : 11 в) Выучи двузначные числа, кратные 11. Проверь себя, работая в паре.', '</p>\n\n<p class="text">а) Пользуясь числовым лучом, составь множество двузначных чисел, кратных 11.</p>\n\n<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica17-nomer6.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 17, номер 6, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 17, номер 6, год 2022."/>\n</div>\n\n<p class="text">б) Выполни деление с остатком:</p>\n\n<p class="description-text">\n25 : 11      39 : 11      54 : 11      75 : 11      90 : 11</p>\n\n<p class="text">в) Выучи двузначные числа, кратные 11. Проверь себя, работая в паре.</p>', 'а) {11; 22; 33; 44; 55; 66; 77; 88; 99} б) 25 : 11 = 2 + 3', '<p><span>а) {11; 22; 33; 44; 55; 66; 77; 88; 99}</span>\n<br/>\n<span>б) 25 : 11 = 2 + 3</span></p>\n\n<div class="img-wrapper-460">\n<img width="80" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica17-nomer6-1.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 17, номер 6, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 17, номер 6, год 2022."/>', '', '', TRUE, '[{"letter":"а","condition":"Пользуясь числовым лучом, составь множество двузначных чисел, кратных 11.","solution":"{11; 22; 33; 44; 55; 66; 77; 88; 99}"},{"letter":"б","condition":"Выполни деление с остатком: 25 : 11      39 : 11      54 : 11      75 : 11      90 : 11","solution":"25 : 11 = 2 + 3"},{"letter":"в","condition":"Выучи двузначные числа, кратные 11. Проверь себя, работая в паре.","solution":""}]'::jsonb, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-17/')
