    VALUES (v_textbook_id, 18, '8', 1, 'Составь выражения. Найди их значения при данных значениях а и b . Что ты замечаешь? а) Мама купила к празднику а конфет. Из них b конфет она положила в вазу, а остальные раздала поровну двум детям. Сколько конфет досталось каждому из них? (а = 30, b = 24) б) В мешке было а кг крупы. Из них израсходовали b кг, а остальную крупу рассыпали поровну в 2 пакета. Сколько килограммов крупы в каждом из этих пакетов? (а = 42, b = 36) в) Во 2 классе а человек. Из них b человек заболели, а остальные разделились поровну на две команды для игры в КВН. Сколько человек в каждой команде? (а = 28, b = 4)', '</p>\n\n<p class="text">Составь выражения. Найди их значения при данных значениях <b>а</b> и <b>b</b>. Что ты замечаешь?</p>\n\n<p class="description-text">\n<span>а) Мама купила к празднику <b>а</b> конфет. Из них <b>b</b> конфет она положила в вазу, а остальные раздала поровну двум детям. Сколько конфет досталось каждому из них? (а = 30, b = 24)</span>\n<span>б) В мешке было <b>а</b> кг крупы. Из них израсходовали <b>b</b> кг, а остальную крупу рассыпали поровну в 2 пакета. Сколько килограммов крупы в каждом из этих пакетов? (а = 42, b = 36)</span>\n<span>в) Во 2 классе <b>а</b> человек. Из них <b>b</b> человек заболели, а остальные разделились поровну на две команды для игры в КВН. Сколько человек в каждой команде? (а = 28, b = 4)</span></p>\n\n<div class="img-wrapper-460">\n<img width="200" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica18-nomer8.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 18, номер 8, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 18, номер 8, год 2022."/>\n</div>', 'а) (а – b) : 2     (30 – 24) : 2 = 6 : 2 = 3 (конфет)     Ответ: по три конфеты досталось каждому из них. б) (а – b) : 2     (42 – 36) : 2 = 6 : 2 = 3 (кг)     Ответ: по 3 килограммов крупы в каждом из этих пакетов. в) (а – b) : 2     (28 – 4) : 2 = 24 : 2 = 12 (человек)     Ответ: по 12 человек в каждой команде. Составленные выражения оказались одним и тем же.', '<p><span>а) (а – b) : 2</span>\n<span>    (30 – 24) : 2 = 6 : 2 = 3 (конфет)</span>\n<span>    Ответ: по три конфеты досталось каждому из них.</span>\n<br/>\n<span>б) (а – b) : 2</span>\n<span>    (42 – 36) : 2 = 6 : 2 = 3 (кг)</span>\n<span>    Ответ: по 3 килограммов крупы в каждом из этих пакетов.</span>\n<br/>\n<span>в) (а – b) : 2</span>\n<span>    (28 – 4) : 2 = 24 : 2 = 12 (человек)</span>\n<span>    Ответ: по 12 человек в каждой команде.</span>\n<br/>\n<span>Составленные выражения оказались одним и тем же.</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-18/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, 'condition', 0, NULL, 'https://gdz-raketa.ru/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica18-nomer8.jpg', 'peterson/3/part1/page18/task8_condition_0.jpg', '');

    VALUES (v_task_id, v_textbook_id, 3, '8b6ab34baba3676833bc561cbd9bc91f98f916f6698b06525e44ad2f2ccfeb65', '2,4,24,28,30,36,42', '["раздели","найди","раз"]'::jsonb, 'составь выражения. найди их значения при данных значениях а и b . что ты замечаешь? а) мама купила к празднику а конфет. из них b конфет она положила в вазу, а остальные раздала поровну двум детям. сколько конфет досталось каждому из них? (а=30, b=24) б) в мешке было а кг крупы. из них израсходовали b кг, а остальную крупу рассыпали поровну в 2 пакета. сколько килограммов крупы в каждом из этих пакетов? (а=42, b=36) в) во 2 классе а человек. из них b человек заболели, а остальные разделились поровну на две команды для игры в квн. сколько человек в каждой команде? (а=28, b=4)');

    VALUES (v_textbook_id, 18, '9', 2, 'Составь задачу, которая решается так: (а – b) : 2 Подбери для а и b подходящие значения и найди ответ.', '</p>\n\n<p class="text">Составь задачу, которая решается так:</p>\n\n<p class="description-text">\n(а – b) : 2</p>\n\n<p class="text">Подбери для <b>а</b> и <b>b</b> подходящие значения и найди ответ.</p>', 'На тарелке разложено а конфет. Из них съели b конфет, а остальные разделили поровну на двоих учеников взять с собой. Сколько конфет у каждого из учеников? (а = 12, b = 6) (12 – 6) : 2 = 6 : 2 = 3 (конфет) Ответ: по три конфеты у каждого ученика.', '<p><span>На тарелке разложено а конфет. Из них съели b конфет, а остальные разделили поровну на двоих учеников взять с собой. Сколько конфет у каждого из учеников? (а = 12, b = 6)</span>\n<span>(12 – 6) : 2 = 6 : 2 = 3 (конфет)</span>\n<span><b>Ответ:</b> по три конфеты у каждого ученика.</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-18/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '4057a6575674fb71784e629a9c04844a98c7f3a6cd11efaff88bf8c3b729b21a', '2', '["найди"]'::jsonb, 'составь задачу, которая решается так:(а-b):2 подбери для а и b подходящие значения и найди ответ');

    VALUES (v_textbook_id, 18, '10', 3, 'Вспомни правила действий с 0 и 1. Допиши равенства в тетради: а + 0 = ...      а · 0 = ... а – 0 = ...      0 : а = ... а – а = ...      а · 1 = ...', '</p>\n\n<p class="text">Вспомни правила действий с 0 и 1. Допиши равенства в тетради:</p>\n\n<p class="description-text">\n<span>а + 0 = ...      а · 0 = ...</span>\n<span>а – 0 = ...      0 : а = ...</span>\n<span>а – а = ...      а · 1 = ...</span></p>\n\n<div class="img-wrapper-460">\n<img width="280" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica18-nomer10.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 18, номер 10, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 18, номер 10, год 2022."/>\n</div>', 'а + 0 = а      а · 0 = 0      а : 1 = а а – 0 = а      0 : а = 0      а : а = 1 а – а = 0      а · 1 = а', '<p><span>а + 0 = а      а · 0 = 0      а : 1 = а</span>\n<span>а – 0 = а      0 : а = 0      а : а = 1</span>\n<span>а – а = 0      а · 1 = а</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-18/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, 'condition', 0, NULL, 'https://gdz-raketa.ru/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica18-nomer10.jpg', 'peterson/3/part1/page18/task10_condition_0.jpg', '');

    VALUES (v_task_id, v_textbook_id, 3, 'ec7d81dba9af90b4a79675c57a60bfa72e916dc3ad679b27f2b0f9b1a166d03d', '0,1', NULL, 'вспомни правила действий с 0 и 1. допиши равенства в тетради:а+0=...      а*0=... а-0=...      0:а=... а-а=...      а*1=');

    VALUES (v_textbook_id, 18, '11', 4, 'Составь программу действий и вычисли: а) 5 · 0 : 25 + (72 : 1 – 0) : 9 + 6 : 6 б) 24 : (3 · 8) – (7 · 0 + 1) · 1 + 8 : 1', '</p>\n\n<p class="text">Составь программу действий и вычисли:</p>\n\n<p class="description-text">\n<span>а) 5 · 0 : 25 + (72 : 1 – 0) : 9 + 6 : 6</span>\n<span>б) 24 : (3 · 8) – (7 · 0 + 1) · 1 + 8 : 1</span></p>', 'а) 5 · 0 : 25 + (72 : 1 – 0) : 9 + 6 : 6 1) 72 : 1 = 72 2) 72 – 0 = 72 3) 72 : 9 = 8 4) 5 · 0 = 0 5) 0 : 25 = 0 6) 6 : 6 = 1 7) 0 + 8 = 8 8) 8 + 1 = 9 б) 24 : (3 · 8) – (7 · 0 + 1) · 1 + 8 : 1 1) 3 · 8 = 24 2) 7 · 0 = 0 3) 0 + 1 = 1 4) 24 : 24 = 1 5) 1 · 1 = 1 6) 8 : 1 = 8 7) 1 – 1 = 0 8) 0 + 8 = 8', '<p><span>а) 5 · 0 : 25 + (72 : 1 – 0) : 9 + 6 : 6</span>\n<span>1) 72 : 1 = 72</span>\n<span>2) 72 – 0 = 72</span>\n<span>3) 72 : 9 = 8</span>\n<span>4) 5 · 0 = 0</span>\n<span>5) 0 : 25 = 0</span>\n<span>6) 6 : 6 = 1</span>\n<span>7) 0 + 8 = 8</span>\n<span>8) 8 + 1 = 9</span>\n<br/>\n<span>б) 24 : (3 · 8) – (7 · 0 + 1) · 1 + 8 : 1</span>\n<span>1) 3 · 8 = 24</span>\n<span>2) 7 · 0 = 0</span>\n<span>3) 0 + 1 = 1</span>\n<span>4) 24 : 24 = 1</span>\n<span>5) 1 · 1 = 1</span>\n<span>6) 8 : 1 = 8</span>\n<span>7) 1 – 1 = 0</span>\n<span>8) 0 + 8 = 8</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-18/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '91f989eccf9f1e52289fd44d38063827d456041bd69f01b22c9347092589e96f', '0,1,3,5,6,7,8,9,24,25', '["вычисли"]'::jsonb, 'составь программу действий и вычисли:а) 5*0:25+(72:1-0):9+6:6 б) 24:(3*8)-(7*0+1)*1+8:1');

    VALUES (v_textbook_id, 18, '12', 5, 'Рассмотри уравнения. Какие из них имеют решения, а какие – нет? Сколько решений? Назови их. х + 0 = 8      х – х = 5      х · 0 = 7      0 : х = 0', '</p>\n\n<p class="text">Рассмотри уравнения. Какие из них имеют решения, а какие – нет? Сколько решений? Назови их.</p>\n\n<p class="description-text">\nх + 0 = 8      х – х = 5      х · 0 = 7      0 : х = 0</p>', 'х + 0 = 8, при х = 8 х – х = 5, не имеет решения, так как при любом х разность должна равняться 0. х · 0 = 7, не имеет решения, так как при любом х разность должна равняться 0. 0 : х = 0, при любом х будет иметь решение.', '<p><span>х + 0 = 8, при х = 8</span>\n<span>х – х = 5, не имеет решения, так как при любом х разность должна равняться 0.</span>\n<span>х · 0 = 7, не имеет решения, так как при любом х разность должна равняться 0.</span>\n<span>0 : х = 0, при любом х будет иметь решение.</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-18/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, 'daec90116b30927666387a881b2fd0f72848a50fe6529716328de4dbdf6ff428', '0,5,7,8', NULL, 'рассмотри уравнения. какие из них имеют решения, а какие-нет? сколько решений? назови их. х+0=8      х-х=5      х*0=7      0:х=0');

    VALUES (v_textbook_id, 19, '13', 0, 'Назови фигуры на рисунке. Запиши с помощью фигурных скобок: 1) множество А фигур, расположенных внутри замкнутой линии: А = ... 2) множество В фигур, расположенных снаружи замкнутой линии: В = ... Что общего у всех этих фигур?', '</p>\n\n<p class="text">Назови фигуры на рисунке. Запиши с помощью фигурных скобок:</p>\n\n<p class="description-text">\n1) множество А фигур, расположенных внутри замкнутой линии: А = ...<br/>\n2) множество В фигур, расположенных снаружи замкнутой линии: В = ... Что общего у всех этих фигур?</p>\n\n<div class="img-wrapper-460">\n<img width="200" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica19-nomer13.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 19, номер 13, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 19, номер 13, год 2022."/>\n</div>', 'Цилиндр, пирамида, конус, куб, шар, параллелепипед. 1) множество А фигур, расположенных внутри замкнутой линии: А = {a; b; f; e} 2) множество В фигур, расположенных снаружи замкнутой линии: В = {c; d} Общего у всех этих фигур – наличие объема.', '<p><span>Цилиндр, пирамида, конус, куб, шар, параллелепипед.</span>\n<span>1) множество А фигур, расположенных внутри замкнутой линии: А = {a; b; f; e}</span>\n<span>2) множество В фигур, расположенных снаружи замкнутой линии: В = {c; d}</span>\n<span>Общего у всех этих фигур – наличие объема.</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-19/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, 'condition', 0, NULL, 'https://gdz-raketa.ru/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica19-nomer13.jpg', 'peterson/3/part1/page19/task13_condition_0.jpg', '');

    VALUES (v_task_id, v_textbook_id, 3, '12d6844ce797854718436517ea8e4eae2aa2f3966694884a178d4371dfec55e1', '1,2', NULL, 'назови фигуры на рисунке. запиши с помощью фигурных скобок:1) множество а фигур, расположенных внутри замкнутой линии:а=... 2) множество в фигур, расположенных снаружи замкнутой линии:в=... что общего у всех этих фигур');

    VALUES (v_textbook_id, 19, '14', 1, 'Запиши множества С и D с помощью фигурных скобок. Найди общее свойство элементов каждого из этих множеств. Какое из множеств С и D является частью другого? Принадлежат ли элементы множества С множеству D? А наоборот?', '</p>\n\n<p class="text">Запиши множества С и D с помощью фигурных скобок. Найди общее свойство элементов каждого из этих множеств.</p>\n\n<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica19-nomer14.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 19, номер 14, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 19, номер 14, год 2022."/>\n</div>\n\n<p class="text">Какое из множеств С и D является частью другого? Принадлежат ли элементы множества С множеству D? А наоборот?</p>', 'С = {а; b; c; d; e; f}, D = {a; b}, общее свойство элементов каждого из этих множеств – геометрические фигуры. Множество D является частью С. Принадлежат элементы множества D множеству С. Элементы множества С не принадлежат множеству D.', '<p>С = {а; b; c; d; e; f}, D = {a; b}, общее свойство элементов каждого из этих множеств – геометрические фигуры. Множество D является частью С. Принадлежат элементы множества D множеству С. Элементы множества С не принадлежат множеству D.</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-19/')
    RETURNING id INTO v_task_id;

