    VALUES (v_task_id, v_textbook_id, 3, '4da125200ecb8197317ad20a40bd6fcd91207213e02fc6a7c5d9806c14101e9f', NULL, '["найди"]'::jsonb, 'запиши множества с и d с помощью фигурных скобок. найди общее свойство элементов каждого из этих множеств. какое из множеств с и d является частью другого? принадлежат ли элементы множества с множеству d? а наоборот');

    VALUES (v_textbook_id, 19, '15', 2, 'Найди общее свойство фигур множества А, множества В, общей части (пересечения) множеств А и В. Сделай записи в тетради, используя знаки ∈ и ∉: а ... А      c ... A      f ... А      k ... A а ... В      c ... B      f ... В       k ... B', '</p>\n\n<p class="text">Найди общее свойство фигур множества А, множества В, общей части (пересечения) множеств А и В.</p>\n\n<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica19-nomer15.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 19, номер 15, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 19, номер 15, год 2022."/>\n</div>\n\n<p class="text"><span>Сделай записи в тетради, используя знаки ∈ и ∉:</span>\n<span>а ... А      c ... A      f ... А      k ... A</span>\n<span>а ... В      c ... B      f ... В       k ... B</span></p>', 'Общее свойство фигур множества А, множества В, общей части (пересечения) множеств А и В – оба элемента квадраты. а ∈ А      c ∈ A      f ∈ А      k ∉ A а ∉ В      c ∈ B      f ∈ В       k ∈ B', '<p><span>Общее свойство фигур множества А, множества В, общей части (пересечения) множеств А и В – оба элемента квадраты.</span>\n<span>а ∈ А      c ∈ A      f ∈ А      k ∉ A</span>\n<span>а ∉ В      c ∈ B      f ∈ В       k ∈ B</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-19/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, 'condition', 0, NULL, 'https://gdz-raketa.ru/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica19-nomer15.jpg', 'peterson/3/part1/page19/task15_condition_0.jpg', '');

    VALUES (v_task_id, v_textbook_id, 3, 'a923c24357a74041cb1c9744cc062e3b1c0dbbd7e2d15282e29186c0e8044902', NULL, '["найди"]'::jsonb, 'найди общее свойство фигур множества а, множества в, общей части (пересечения) множеств а и в. сделай записи в тетради, используя знаки ∈ и ∉:а ... а      c ... a      f ... а      k ... a а ... в      c ... b      f ... в       k ... b');

    VALUES (v_textbook_id, 19, '16', 3, 'В одной вазе лежат апельсин, мандарин и банан, в другой – яблоко и груша, а в третьей – персик и слива. Найди все способы, которыми можно взять два фрукта – по одному из разных ваз. Сколько всего различных способов?', '</p>\n\n<p class="text">В одной вазе лежат апельсин, мандарин и банан, в другой – яблоко и груша, а в третьей – персик и слива. Найди все способы, которыми можно взять два фрукта – по одному из разных ваз. Сколько всего различных способов?</p>', '2 ваза: я, г 3 ваза: п, с 1) а, я, п      2) а, я, с 3) а, г, п       4) а, г, с 5) м, я, п      6) м, я, с 7) м, г, п       8) м, г, с 9) б, я, п      10) б, я, с 11) б, г, п     12) б, г, с      Ответ: 12 всего различных способов.', '<p><span>2 ваза: я, г</span>\n<span>3 ваза: п, с</span>\n<span>1) а, я, п      2) а, я, с</span>\n<span>3) а, г, п       4) а, г, с</span>\n<span>5) м, я, п      6) м, я, с</span>\n<span>7) м, г, п       8) м, г, с</span>\n<span>9) б, я, п      10) б, я, с</span>\n<span>11) б, г, п     12) б, г, с</span>\n<span>    <b>Ответ:</b> 12 всего различных способов.</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-19/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, 'fbdae5ce08970a4295cf7d44051acd9132304ab09282f0b81fdfb697313a5c94', NULL, '["найди","раз"]'::jsonb, 'в одной вазе лежат апельсин, мандарин и банан, в другой-яблоко и груша, а в третьей-персик и слива. найди все способы, которыми можно взять два фрукта-по одному из разных ваз. сколько всего различных способов');

    VALUES (v_textbook_id, 20, '1', 0, 'Пусть А – множество зайцев, В – множество животных. На диаграмме изображены некоторые элементы этих множеств. Каждый ли заяц является животным? Всякое ли животное является зайцем? Какое из этих множеств является частью другого?', '</p>\n\n<p class="text">Пусть А – множество зайцев, В – множество животных. На диаграмме изображены некоторые элементы этих множеств.</p>\n\n<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica20-nomer1.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 20, номер 1, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 20, номер 1, год 2022."/>\n</div>\n\n<p class="text">Каждый ли заяц является животным? Всякое ли животное является зайцем? Какое из этих множеств является частью другого?</p>', 'Каждый заяц является животным. Не всякое животное является зайцем. Множество А является частью множества В.', '<p>Каждый заяц является животным. Не всякое животное является зайцем. Множество А является частью множества В.</p>', 'Подмножество. Знаки ⊂ и ⊄ Множество А называют подмножеством множества В, если каждый элемент множества А является также элементом В. Если А является подмножеством В, то между ними ставят знак ⊂, а если нет, то знак ⊄. Запись А ⊂ В читают: А является подмножеством В;                                         А включено в В;                                         А содержится в В. Аналогично запись А ⊄ В читают: «А не является подмножеством В», «А не включено в В», «А не содержится в В».', '<div class="recomended-block">\n<span class="title">Подмножество. Знаки ⊂ и ⊄</span>\n<p>Множество А называют <b class="black">подмножеством</b> множества В, если каждый элемент множества А является также элементом В.<br/>\nЕсли А является подмножеством В, то между ними ставят знак ⊂, а если нет, то знак ⊄.<br/>\nЗапись А ⊂ В читают: А является подмножеством В;<br/>\n                                        А включено в В;<br/>\n                                        А содержится в В.<br/>\nАналогично запись А ⊄ В читают: «А не является подмножеством В», «А не включено в В», «А не содержится в В».</p>\n</div>', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-20/')
    RETURNING id INTO v_task_id;

