    VALUES (v_task_id, v_textbook_id, 3, 'ed901df81c0e4c763905ab48231eb197a26026a273286324c7c4e95cd80412f3', NULL, NULL, 'пусть а-множество зайцев, в-множество животных. на диаграмме изображены некоторые элементы этих множеств. каждый ли заяц является животным? всякое ли животное является зайцем? какое из этих множеств является частью другого');

    VALUES (v_textbook_id, 20, '2', 1, 'Задай свойством множества, изображённые на рисунках. Какое из них является подмножеством другого? Сделай записи. Как расположены относительно друг друга диаграммы множества и подмножества?', '</p>\n\n<p class="text">Задай свойством множества, изображённые на рисунках. Какое из них является подмножеством другого? Сделай записи.</p>\n\n<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica20-nomer2.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 20, номер 2, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 20, номер 2, год 2022."/>\n</div>\n\n<p class="text">Как расположены относительно друг друга диаграммы множества и подмножества?</p>', 'а) М – множество грибов, С – множество съедобных грибов     С подмножество множества М б) Р – множество прямоугольников, К – множество квадратов     К подмножество множества Р в) D – множество деревьев, В – множество хвойных деревьев     В подмножество множества D г) Е – множество фигур, F – множество зеленых фигур     F подмножество множества Е Диаграммы подмножества расположены внутри диаграмм множества.', '<p><span>а) М – множество грибов, С – множество съедобных грибов</span>\n<span>    С подмножество множества М</span>\n<br/>\n<span>б) Р – множество прямоугольников, К – множество квадратов</span>\n<span>    К подмножество множества Р</span>\n<br/>\n<span>в) D – множество деревьев, В – множество хвойных деревьев</span>\n<span>    В подмножество множества D</span>\n<br/>\n<span>г) Е – множество фигур, F – множество зеленых фигур</span>\n<span>    F подмножество множества Е</span>\n<br/>\n<span>Диаграммы подмножества расположены внутри диаграмм множества.</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-20/')
    RETURNING id INTO v_task_id;

