    VALUES (v_textbook_id, 21, '3', 0, 'Определи по диаграмме, какое из множеств является подмножеством другого:', '</p>\n\n<p class="text">Определи по диаграмме, какое из множеств является подмножеством другого:</p>\n\n<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica21-nomer3.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 21, номер 3, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 21, номер 3, год 2022."/>\n</div>', 'а) множество М является подмножеством множества Р б) множество F является подмножеством множества К, а множество Е не является подмножество К и F в) множества А и В пересекаются и являются подмножествами множества С г) множества S и Т являются подмножествами множества D', '<p><span>а) множество М является подмножеством множества Р</span>\n<span>б) множество F является подмножеством множества К, а множество Е не является подмножество К и F</span>\n<span>в) множества А и В пересекаются и являются подмножествами множества С</span>\n<span>г) множества S и Т являются подмножествами множества D</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-21/')
    RETURNING id INTO v_task_id;

