    VALUES (v_task_id, v_textbook_id, 3, '44517bd975e40360b1138af5b5bfc6805e0c3976fe21c44ff9edb33020b92934', NULL, NULL, 'определи по диаграмме, какое из множеств является подмножеством другого');

    VALUES (v_textbook_id, 21, '4', 1, 'Определи, какое из указанных двух множеств является подмножеством другого. Сделай записи и нарисуй диаграммы Эйлера–Венна. а) В – множество учеников некоторой школы,     С – множество отличников этой школы. б) D – множество девочек некоторого класса,     Е – множество всех учеников этого класса. в) К – множество рыб,     О – множество окуней. г) N – множество натуральных чисел,     М – множество чётных чисел.', '</p>\n\n<p class="text">Определи, какое из указанных двух множеств является подмножеством другого. Сделай записи и нарисуй диаграммы Эйлера–Венна.</p>\n\n<p class="description-text">\n<span>а) В – множество учеников некоторой школы,</span>\n<span>    С – множество отличников этой школы.</span>\n<span>б) D – множество девочек некоторого класса,</span>\n<span>    Е – множество всех учеников этого класса.</span>\n<span>в) К – множество рыб,</span>\n<span>    О – множество окуней.</span>\n<span>г) N – множество натуральных чисел,</span>\n<span>    М – множество чётных чисел.</span></p>\n\n<div class="img-wrapper-460">\n<img width="150" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica21-nomer4.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 21, номер 4, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 21, номер 4, год 2022."/>\n</div>', 'а) В – множество учеников некоторой школы,     С – множество отличников этой школы.', '<p><span>а) В – множество учеников некоторой школы,</span>\n<span>    С – множество отличников этой школы.</span></p>\n\n<div class="img-wrapper-460">\n<img width="200" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica21-nomer4-1.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 21, номер 4, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 21, номер 4, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-21/')
