    VALUES (v_textbook_id, 22, '9', 0, 'Составь задачу по картинке и реши её: На сколько рублей груша дороже яблока? Во сколько раз яблоко дешевле груши?', '</p>\n\n<p class="text">Составь задачу по картинке и реши её:</p>\n\n<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica22-nomer9.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 22, номер 9, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 22, номер 9, год 2022."/>\n</div>\n\n<p class="text">На сколько рублей груша дороже яблока? Во сколько раз яблоко дешевле груши?</p>', 'В одной коробке 5 яблок и две груши стоимостью 108 рублей. Во второй коробке 2 яблока и две груши стоимостью 72 рубля. Сколько стоит яблоко и груша? 108 – 72 = 36 (р) – стоит три яблока', '<p><span>В одной коробке 5 яблок и две груши стоимостью 108 рублей. Во второй коробке 2 яблока и две груши стоимостью 72 рубля. Сколько стоит яблоко и груша?</span>\n<span>108 – 72 = 36 (р) – стоит три яблока</span></p>\n\n<div class="img-wrapper-460">\n<img width="100" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica22-nomer9-1.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 22, номер 9, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 22, номер 9, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-22/')
    RETURNING id INTO v_task_id;

