    VALUES (v_textbook_id, 22, '10', 1, 'Составь выражение и найди его значение: а) На одной улице 18 одноэтажных домов и 3 двухэтажных. Во сколько раз одноэтажных домов на этой улице больше, чем двухэтажных? б) В одном доме 10 квартир. Это в 5 раз меньше, чем в другом. Сколько квартир в этих двух домах? в) На каждом этаже 7 – этажного дома по 6 квартир, а на каждом этаже 9 – этажного дома по 4 квартиры. В каком из этих домов больше квартир и на сколько? г) В первом доме 56 квартир, а во втором – в 7 раз меньше. На сколько квартир в первом доме больше, чем во втором?', '</p>\n\n<p class="text">Составь выражение и найди его значение:</p>\n\n<p class="description-text">\n<span>а) На одной улице 18 одноэтажных домов и 3 двухэтажных. Во сколько раз одноэтажных домов на этой улице больше, чем двухэтажных?</span>\n<span>б) В одном доме 10 квартир. Это в 5 раз меньше, чем в другом. Сколько квартир в этих двух домах?</span>\n<span>в) На каждом этаже 7 – этажного дома по 6 квартир, а на каждом  этаже 9 – этажного дома по 4 квартиры. В каком из этих домов больше квартир и на сколько?</span>\n<span>г) В первом доме 56 квартир, а во втором – в 7 раз меньше. На сколько квартир в первом доме больше, чем во втором?</span></p>\n\n<div class="img-wrapper-460">\n<img width="150" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica22-nomer10.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 22, номер 10, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 22, номер 10, год 2022."/>\n</div>', 'а) 18 : 3 = 6 – в 6 раз одноэтажных домов на этой улице больше, чем двухэтажных. б) 10 + 10 : 5 = 10 + 2 = 12 – квартир в этих двух домах. в) 7 · 6 = 42 (квартиры), а 9 · 4 = 36 (квартиры). 42 – 36 = 6 – в 7 – этажном доме больше квартир чем в 9 – этажном доме на 6 квартир.', '<p><span>а) 18 : 3 = 6 – в 6 раз одноэтажных домов на этой улице больше, чем двухэтажных.</span>\n<span>б) 10 + 10 : 5 = 10 + 2 = 12 – квартир в этих двух домах.</span>\n<span>в) 7 · 6 = 42 (квартиры), а 9 · 4 = 36 (квартиры). 42 – 36 = 6 – в 7 – этажном доме больше квартир чем в 9 – этажном доме на 6 квартир.</span></p>\n\n<div class="img-wrapper-460">\n<img width="100" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica22-nomer10-1.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 22, номер 10, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 22, номер 10, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-22/')
    RETURNING id INTO v_task_id;

