    VALUES (v_task_id, v_textbook_id, 3, 'e988c013dc800eab1c5fa64193290e81f3cdd75291ef1ad77853cf53ea1af46f', '3,4,5,6,7,9,10,18,56', '["найди","больше","меньше","раз"]'::jsonb, 'составь выражение и найди его значение:а) на одной улице 18 одноэтажных домов и 3 двухэтажных. во сколько раз одноэтажных домов на этой улице больше, чем двухэтажных? б) в одном доме 10 квартир. это в 5 раз меньше, чем в другом. сколько квартир в этих двух домах? в) на каждом этаже 7-этажного дома по 6 квартир, а на каждом этаже 9-этажного дома по 4 квартиры. в каком из этих домов больше квартир и на сколько? г) в первом доме 56 квартир, а во втором-в 7 раз меньше. на сколько квартир в первом доме больше, чем во втором');

    VALUES (v_textbook_id, 22, '11', 2, 'Вычисли: а) 91 : 7      д) (39 + 29) : 4     и) 19 + 17 · 3 – 46 б) 80 : 5      е) (60 – 5) : 5        к) 54 – 26 + 38 · 3 в) 64 : 4      ж) 63 : (3 · 7)        л) 48 : 2 + 60 : 2 г) 78 : 3       з) 240 : (80 : 2)    м) (19 · 5 – 5) : 30', '</p>\n\n<p class="text">Вычисли:</p>\n\n<p class="description-text">\n<span>а) 91 : 7      д) (39 + 29) : 4     и) 19 + 17 · 3 – 46</span>\n<span>б) 80 : 5      е) (60 – 5) : 5        к) 54 – 26 + 38 · 3</span>\n<span>в) 64 : 4      ж) 63 : (3 · 7)        л) 48 : 2 + 60 : 2</span>\n<span>г) 78 : 3       з) 240 : (80 : 2)    м) (19 · 5 – 5) : 30</span></p>', 'а) 91 : 7 = 13', '<p>а) 91 : 7 = 13</p>\n\n<div class="img-wrapper-460">\n<img width="210" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica22-nomer11.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 22, номер 11, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 22, номер 11, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-22/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, 'solution', 0, NULL, 'https://gdz-raketa.ru/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica22-nomer11.jpg', 'peterson/3/part1/page22/task11_solution_0.jpg', '');

    VALUES (v_task_id, v_textbook_id, 3, '2edbd25d409027afb02f52e015a72ddf7b02e18d651b15b5107a85a2bba5132b', '2,3,4,5,7,17,19,26,29,30', '["вычисли"]'::jsonb, 'вычисли:а) 91:7      д) (39+29):4     и) 19+17*3-46 б) 80:5      е) (60-5):5        к) 54-26+38*3 в) 64:4      ж) 63:(3*7)        л) 48:2+60:2 г) 78:3       з) 240:(80:2)    м) (19*5-5):30');

    VALUES (v_textbook_id, 22, '12', 3, 'Найди значения х и составь таблицу в тетради. Расположи ответы в порядке убывания и расшифруй слово. Что это?', '</p>\n\n<p class="text">Найди значения х и составь таблицу в тетради. Расположи ответы в порядке убывания и расшифруй слово. Что это?</p>\n\n<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica22-nomer12.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 22, номер 12, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 22, номер 12, год 2022."/>\n</div>', '4 · 10 = 40, – «нет»: 40 + 39 = 79, х = 79', '<p>4 · 10 = 40, – «нет»: 40 + 39 = 79, х = 79</p>\n\n<div class="img-wrapper-460">\n<img width="220" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica22-nomer12-1.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 22, номер 12, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 22, номер 12, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-22/')
    RETURNING id INTO v_task_id;

