    VALUES (v_textbook_id, 23, '1', 0, 'а) Прочитай задачу, назови её условие и вопрос: «Три одинаковых яблока стоят 42 рубля. Сколько рублей стоят 5 таких яблок?» Реши задачу, используя схему и таблицу: б) Почему задачи такого типа называют задачами « на приведение к единице »? Как их удобнее решать – с помощью схемы или таблицы?', '</p>\n\n<p class="text"><span>а) Прочитай задачу, назови её условие и вопрос:</span>\n<span>«Три одинаковых яблока стоят 42 рубля. Сколько рублей стоят 5 таких яблок?»</span>\n<span>Реши задачу, используя схему и таблицу:</span></p>\n\n<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica23-nomer1.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 23, номер 1, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 23, номер 1, год 2022."/>\n</div>\n\n<p class="text">б) Почему задачи такого типа называют задачами «<b>на приведение к единице</b>»? Как их удобнее решать – с помощью схемы или таблицы?</p>', 'а) 42 : 3 = 14 (р) – стоит одно яблоко     14 · 5 = 70 (р)      Ответ: 70 рублей стоят 5 яблок. б) Задачи такого типа называют задачами «на приведение к единице», так как искомое находим через приведение к одной единице исчисления. С помощью таблицы.', '<p><span>а) 42 : 3 = 14 (р) – стоит одно яблоко</span>\n<span>    14 · 5 = 70 (р)</span>\n<span>    <b>Ответ:</b> 70 рублей стоят 5 яблок.</span>\n<br/>\n<span>б) Задачи такого типа называют задачами «на приведение к единице», так как искомое находим через приведение к одной единице исчисления. С помощью таблицы.</span></p>', '', '', TRUE, '[{"letter":"а","condition":"Прочитай задачу, назови её условие и вопрос: «Три одинаковых яблока стоят 42 рубля. Сколько рублей стоят 5 таких яблок?» Реши задачу, используя схему и таблицу:","solution":"42 : 3 = 14 (р) – стоит одно яблоко     14 · 5 = 70 (р)      Ответ: 70 рублей стоят 5 яблок."},{"letter":"б","condition":"Почему задачи такого типа называют задачами « на приведение к единице »? Как их удобнее решать – с помощью схемы или таблицы?","solution":"Задачи такого типа называют задачами «на приведение к единице», так как искомое находим через приведение к одной единице исчисления. С помощью таблицы."}]'::jsonb, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-23/')
    RETURNING id INTO v_task_id;

