    VALUES (v_task_id, v_textbook_id, 3, 'c4dd85ea7b54694606b4679da53da233bc4e74934cea757293f9151337ad9bd1', '5,42', '["реши"]'::jsonb, 'а) прочитай задачу, назови её условие и вопрос:"три одинаковых яблока стоят 42 рубля. сколько рублей стоят 5 таких яблок?" реши задачу, используя схему и таблицу:б) почему задачи такого типа называют задачами " на приведение к единице "? как их удобнее решать-с помощью схемы или таблицы');

    VALUES (v_textbook_id, 23, '2', 1, 'а) В 7 одинаковых ящиках 56 кг винограда. Сколько килограммов винограда в 10 таких ящиках? б) Составь задачу по выражению и реши её: (16 : 8) · 6.', '</p>\n\n<p class="text">а) В 7 одинаковых ящиках 56 кг винограда. Сколько килограммов винограда в 10 таких ящиках?</p>\n\n<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica23-nomer2.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 23, номер 2, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 23, номер 2, год 2022."/>\n</div>\n\n<p class="text">б) Составь задачу по выражению и реши её: (16 : 8) · 6.</p>', 'а) 56 : 7 = 8 (кг) – 1 ящик     8 · 10 = 80 (кг)      Ответ: 80 килограммов винограда в 10 ящиках. б) В 8 одинаковых ящиках 16 кг винограда. Сколько килограммов винограда в 6 таких ящиках?     (16 : 8) · 6 = 2 · 6 = 12 (кг)      Ответ: 12 килограммов винограда в 6 таких ящиках.', '<p><span>а) 56 : 7 = 8 (кг) – 1 ящик</span>\n<span>    8 · 10 = 80 (кг)</span>\n<span>    <b>Ответ:</b> 80 килограммов винограда в 10 ящиках.</span>\n<br/>\n<span>б) В 8 одинаковых ящиках 16 кг винограда. Сколько килограммов винограда в 6 таких ящиках?</span>\n<span>    (16 : 8) · 6 = 2 · 6 = 12 (кг)</span>\n<span>    <b>Ответ:</b> 12 килограммов винограда в 6 таких ящиках.</span></p>', '', '', TRUE, '[{"letter":"а","condition":"В 7 одинаковых ящиках 56 кг винограда. Сколько килограммов винограда в 10 таких ящиках?","solution":"56 : 7 = 8 (к"},{"letter":"б","condition":"Составь задачу по выражению и реши её: (16 : 8) · 6.","solution":"В 8 одинаковых ящиках 16 кг винограда. Сколько килограммов винограда в 6 таких ящиках?     (16 : 8) · 6 = 2 · 6 = 12 (к"},{"letter":"г","condition":"","solution":"– 1 ящик     8 · 10 = 80 (к"}]'::jsonb, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-23/')
    RETURNING id INTO v_task_id;

