    VALUES (v_task_id, v_textbook_id, 3, '7f7f60c5c16970250d97df65be053d553c0fde058b12d4b093459730f008dcf6', '6,7,8,10,16,56', '["реши"]'::jsonb, 'а) в 7 одинаковых ящиках 56 кг винограда. сколько килограммов винограда в 10 таких ящиках? б) составь задачу по выражению и реши её:(16:8)*6');

    VALUES (v_textbook_id, 23, '3', 2, 'а) Из 36 метров ткани можно сшить 9 одинаковых костюмов. Сколько метров этой ткани потребуется на 15 таких костюмов? б) За 7 билетов в театр заплатили 2100 р. Сколько денег надо заплатить за 12 таких билетов, если цена билетов одинаковая?', '</p>\n\n<p class="text"><span>а) Из 36 метров ткани можно сшить 9 одинаковых костюмов. Сколько метров этой ткани потребуется на 15 таких костюмов?</span>\n<span>б) За 7 билетов в театр заплатили 2100 р. Сколько денег надо заплатить за 12 таких билетов, если цена билетов одинаковая?</span></p>', 'а) 36 : 9 · 15 = 4 · 15 = 60 (м)', '<p>а) 36 : 9 · 15 = 4 · 15 = 60 (м)</p>\n\n<div class="img-wrapper-460">\n<img width="100" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica23-nomer3.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 23, номер 3, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 23, номер 3, год 2022."/>', '', '', TRUE, '[{"letter":"а","condition":"Из 36 метров ткани можно сшить 9 одинаковых костюмов. Сколько метров этой ткани потребуется на 15 таких костюмов?","solution":"36 : 9 · 15 = 4 · 15 = 60 (м)"},{"letter":"б","condition":"За 7 билетов в театр заплатили 2100 р. Сколько денег надо заплатить за 12 таких билетов, если цена билетов одинаковая?","solution":""}]'::jsonb, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-23/')
