    VALUES (v_textbook_id, 23, '4', 3, 'а) В трёх одинаковых банках 15 л мёда. Сколько литров в бочонке, вмещающем 12 таких банок? б) Для строительства двух одинаковых домов требуется 120 м 3 леса. Сколько кубических метров леса потребуется для строительства 6 таких домов?', '</p>\n\n<p class="text">а) В трёх одинаковых банках 15 л мёда. Сколько литров в бочонке, вмещающем 12 таких банок?</p>\n\n<div class="img-wrapper-460">\n<img width="180" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica23-nomer4.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 23, номер 4, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 23, номер 4, год 2022."/>\n</div>\n\n<p class="text">б) Для строительства двух одинаковых домов требуется 120 м<sup>3</sup> леса. Сколько кубических метров леса потребуется для строительства 6 таких домов?</p>', 'а) В трёх одинаковых банках 15 : 3 · 12 = 5 · 12 = 60 (л) – мёда, 60 литров в бочонке, вмещающем 12 таких банок.', '<p>а) В трёх одинаковых банках 15 : 3 · 12 =  5 · 12 = 60 (л) – мёда, 60 литров в бочонке, вмещающем 12 таких банок.</p>\n\n<div class="img-wrapper-460">\n<img width="100" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica23-nomer4-1.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 23, номер 4, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 23, номер 4, год 2022."/>', '', '', TRUE, '[{"letter":"а","condition":"В трёх одинаковых банках 15 л мёда. Сколько литров в бочонке, вмещающем 12 таких банок?","solution":"В трёх одинаковых банках 15 : 3 · 12 = 5 · 12 = 60 (л) – мёда, 60 литров в бочонке, вмещающем 12 таких банок."},{"letter":"б","condition":"Для строительства двух одинаковых домов требуется 120 м 3 леса. Сколько кубических метров леса потребуется для строительства 6 таких домов?","solution":""}]'::jsonb, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-23/')
