    VALUES (v_textbook_id, 23, '6', 5, 'Назови какое-нибудь подмножество: а) множества учеников школы; б) множества птиц; в) множества легковых автомобилей; г) множества натуральных чисел.', '</p>\n\n<p class="text">Назови какое-нибудь подмножество:</p>\n\n<p class="description-text">\n<span>а) множества учеников школы;</span>\n<span>б) множества птиц;</span>\n<span>в) множества легковых автомобилей;</span>\n<span>г) множества натуральных чисел.</span></p>', 'а) подмножество учеников первого класса множества учеников школы; б) подмножество голубей множества птиц; в) подмножество черных легковых автомобилей множества легковых автомобилей; г) подмножество чётных натуральных чисел множества натуральных чисел.', '<p><span>а) подмножество учеников первого класса множества учеников школы;</span>\n<span>б) подмножество голубей множества птиц;</span>\n<span>в) подмножество черных легковых автомобилей множества легковых автомобилей;</span>\n<span>г) подмножество чётных натуральных чисел множества натуральных чисел.</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-23/')
