    VALUES (v_textbook_id, 24, '7', 0, 'На диаграмме отмечены все элементы множеств А, В и С. а) Запиши эти множества с помощью фигурных скобок. б) Найди подмножества. Сделай записи, вставляя знаки ⊂ или ⊄:     А ... В      С ... В      А ... С', '</p>\n\n<p class="text">На диаграмме отмечены все элементы множеств А, В и С.</p>\n\n<p class="description-text">\n<span>а) Запиши эти множества с помощью фигурных скобок.</span>\n<span>б) Найди подмножества. Сделай записи, вставляя знаки ⊂ или ⊄:</span>\n<span>    А ... В      С ... В      А ... С</span></p>\n\n<div class="img-wrapper-460">\n<img width="200" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica24-nomer7.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 24, номер 7, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 24, номер 7, год 2022."/>\n</div>', 'а) А = {д; е}, В = {м; к}, С = {а; р; м}. б) А ⊂ В      С ⊄ В      А ⊄ С', '<p><span>а) А = {д; е}, В = {м; к}, С = {а; р; м}.</span>\n<span>б) А ⊂ В      С ⊄ В      А ⊄ С</span></p>', 'Справка Знак ∈ ставится между элементом и множеством, а знак ⊂ ставится между двумя множествами. Например , к ∈ В, А ⊂ В.', '<div class="recomended-block">\n<span class="title">Справка</span>\n<p>Знак ∈ ставится между элементом и множеством, а знак ⊂ ставится между двумя множествами.<br/>\n<b class="black">Например</b>, к ∈ В, А ⊂ В.</p>\n</div>', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-24/')
    RETURNING id INTO v_task_id;

