    VALUES (v_textbook_id, 24, '9', 2, 'Вычисли и расположи ответы в порядке возрастания. Кто это?', '</p>\n\n<p class="text">Вычисли и расположи ответы в порядке возрастания. Кто это?</p>\n\n<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica24-nomer9.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 24, номер 9, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 24, номер 9, год 2022."/>\n</div>', '40 : 4 = 10, 10 – 7 = 3, 3 · 9 = 27 – П 18 : 3 = 6, 6 + 9 = 15, 15 · 5 = 75 – Д 500 : 5 = 100, 100 – 64 = 36, 36 · 2 = 72 – Р 5 · 80 = 400, 400 – 120 = 280, 280 : 40 = 7 – Е 140 – 60 = 80, 80 : 40 = 2, 2 + 68 = 70 – А 68 : 17 = 4, 4 · 8 = 32, 32 – 32 =0 – Г ГЕПАРД', '<p><span>40 : 4 = 10, 10 – 7 = 3, 3 · 9 = 27 – П</span>\n<span>18 : 3 = 6, 6 + 9 = 15, 15 · 5 = 75 – Д</span>\n<span>500 : 5 = 100, 100 – 64 = 36, 36 · 2 = 72 – Р</span>\n<span>5 · 80 = 400, 400 – 120 = 280, 280 : 40 = 7 – Е</span>\n<span>140 – 60 = 80, 80 : 40 = 2, 2 + 68 = 70 – А</span>\n<span>68 : 17 = 4, 4 · 8 = 32, 32 – 32 =0 – Г</span>\n<span>ГЕПАРД</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-24/')
    RETURNING id INTO v_task_id;

