    VALUES (v_textbook_id, 24, '10', 3, 'а) Пользуясь числовым лучом, составь множество двузначных чисел, кратных 12. б) Выполни деление с остатком: 37 : 12      50 : 12      68 : 12      75 : 12      99 : 12 в) Выучи двузначные числа, кратные 12. Проверь себя, работая в паре.', '</p>\n\n<p class="text">а) Пользуясь числовым лучом, составь множество двузначных чисел, кратных 12.</p>\n\n<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica24-nomer10.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 24, номер 10, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 24, номер 10, год 2022."/>\n</div>\n\n<p class="text">б) Выполни деление с остатком:</p>\n\n<p class="description-text">\n37 : 12      50 : 12      68 : 12      75 : 12      99 : 12</p>\n\n<p class="text">в) Выучи двузначные числа, кратные 12. Проверь себя, работая в паре.</p>', 'а) {12; 24; 36; 48; 60; 72; 84; 96; 108; 120} б) 37 : 12 = 3 + 1', '<p><span>а) {12; 24; 36; 48; 60; 72; 84; 96; 108; 120}</span>\n<span>б) 37 : 12 = 3 + 1</span></p>\n\n<div class="img-wrapper-460">\n<img width="80" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica24-nomer10-1.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 24, номер 10, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 24, номер 10, год 2022."/>', '', '', TRUE, '[{"letter":"а","condition":"Пользуясь числовым лучом, составь множество двузначных чисел, кратных 12.","solution":"{12; 24; 36; 48; 60; 72; 84; 96; 108; 120}"},{"letter":"б","condition":"Выполни деление с остатком: 37 : 12      50 : 12      68 : 12      75 : 12      99 : 12","solution":"37 : 12 = 3 + 1"},{"letter":"в","condition":"Выучи двузначные числа, кратные 12. Проверь себя, работая в паре.","solution":""}]'::jsonb, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-24/')
    RETURNING id INTO v_task_id;

