    VALUES (v_textbook_id, 25, '15', 3, 'Для запуска 4-местного и 8-местного космических кораблей в отряд космонавтов набрали группу из 52 человек. К полёту на 4-местном корабле готовятся 3 команды. Сколько команд готовятся для полёта на 8-местном корабле?', '</p>\n\n<p class="text">Для запуска 4-местного и 8-местного космических кораблей в отряд космонавтов набрали группу из 52 человек. К полёту на 4-местном корабле готовятся 3 команды. Сколько команд готовятся для полёта на 8-местном корабле?</p>\n\n<div class="img-wrapper-460">\n<img width="290" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica25-nomer15.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 25, номер 15, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 25, номер 15, год 2022."/>\n</div>', '8 : 4 = 2, 8-местный корабль вмещает в 2 раза больше, поэтому 3 · 2 = 6 (команд) Ответ: 6 команд готовятся для полёта на 8-местном корабле.', '<p><span>8 : 4 = 2, 8-местный корабль вмещает в 2 раза больше, поэтому 3 · 2 = 6 (команд)</span>\n<span><b>Ответ:</b> 6 команд готовятся для полёта на 8-местном корабле.</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-25/')
    RETURNING id INTO v_task_id;

