    VALUES (v_textbook_id, 25, '16', 4, 'В первом аквариуме на 16 рыбок больше, чем во втором. Сколько рыбок надо переселить из первого аквариума во второй, чтобы рыбок в них стало поровну? * Во всех заданиях на сравнение значения букв – натуральные числа и все действия выполнимы.', '</p>\n\n<p class="text"><span>В первом аквариуме на 16 рыбок больше, чем во втором. Сколько рыбок надо переселить из первого аквариума во второй, чтобы рыбок в них стало поровну?</span>\n<span>* Во всех заданиях на сравнение значения букв – натуральные числа и все действия выполнимы.</span></p>', '16 : 2 = 8 (рыбок) Ответ: 8 рыбок надо переселить из первого аквариума во второй, чтобы рыбок в них стало поровну.', '<p><span>16 : 2 = 8 (рыбок)</span>\n<span><b>Ответ:</b> 8 рыбок надо переселить из первого аквариума во второй, чтобы рыбок в них стало поровну.</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-25/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '1155a77fbe5e1733ca95b288814a2297406f9e89cc8773630688c46db69b344e', '16', '["больше"]'::jsonb, 'в первом аквариуме на 16 рыбок больше, чем во втором. сколько рыбок надо переселить из первого аквариума во второй, чтобы рыбок в них стало поровну?*во всех заданиях на сравнение значения букв-натуральные числа и все действия выполнимы');

    VALUES (v_textbook_id, 26, '1', 0, 'Реши задачи двумя способами: а) Антон прошёл 240 м за 4 минуты. Сколько метров он пройдёт за 8 минут, если будет идти с той же скоростью? б) Рабочий сделал за 2 часа 18 одинаковых деталей. Сколько деталей, работая так же, он изготовит за 8 часов?', '</p>\n\n<p class="text">Реши задачи двумя способами:</p>\n\n<p class="description-text">\n<span>а) Антон прошёл 240 м за 4 минуты. Сколько метров он пройдёт за 8 минут, если будет идти с той же скоростью?</span>\n<span>б) Рабочий сделал за 2 часа 18 одинаковых деталей. Сколько деталей, работая так же, он изготовит за 8 часов?</span></p>', 'а) 1 способ: 8 : 4 = 2 (раза) 240 · 2 = 480 (м) 2 способ: 240 : 4 = 60 (м) – в 1 минуту 80 · 8 = 480 (м) Ответ: 480 метров он пройдёт за 8 минут, если будет идти с той же скоростью. б) 1 способ: 8 : 2 = 4 (раза) 18 · 4 = 72 (детали)', '<p><span>а)</span>\n<span><b>1 способ:</b></span>\n<span>8 : 4 = 2 (раза)</span>\n<span>240 · 2 = 480 (м)</span>\n<span><b>2 способ:</b></span>\n<span>240 : 4 = 60 (м) – в 1 минуту</span>\n<span>80 · 8 = 480 (м)</span>\n<span><b>Ответ:</b> 480 метров он пройдёт за 8 минут, если будет идти с той же скоростью.</span>\n<br/>\n<span>б)</span>\n<span><b>1 способ:</b></span>\n<span>8 : 2 = 4 (раза)</span>\n<span>18 · 4 = 72 (детали)</span></p>\n\n<div class="img-wrapper-460">\n<img width="100" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica26-nomer1.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 26, номер 1, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 26, номер 1, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-26/')
    RETURNING id INTO v_task_id;

