    VALUES (v_task_id, v_textbook_id, 3, '42e1e402fafbc08107cfc10bb935eb43cd8d26e063b0d7ce46f0c9b0191b5f9c', '2,4,8,18,240', '["реши"]'::jsonb, 'реши задачи двумя способами:а) антон прошёл 240 м за 4 минуты. сколько метров он пройдёт за 8 минут, если будет идти с той же скоростью? б) рабочий сделал за 2 часа 18 одинаковых деталей. сколько деталей, работая так же, он изготовит за 8 часов');

    VALUES (v_textbook_id, 26, '2', 1, 'Составь программу действий и вычисли: а) 3 · (9 : 9) · 10 – 0 : 5 · 18 – 6 · (4 : 1) б) (7 · 9 – 0) : 21 + 6 · (0 : 8) – 45 : (15 · 1)', '</p>\n\n<p class="text">Составь программу действий и вычисли:</p>\n\n<p class="description-text">\n<span>а) 3 · (9 : 9) · 10 – 0 : 5 · 18 – 6 · (4 : 1)</span>\n<span>б) (7 · 9 – 0) : 21 + 6 · (0 : 8) – 45 : (15 · 1)</span></p>', 'а) 3 · (9 : 9) · 10 – 0 : 5 · 18 – 6 · (4 : 1) = 2406 1) 9 : 9 = 81 2) 4 : 1 = 4 3) 3 · 81 = 243', '<p><span>а) 3 · (9 : 9) · 10 – 0 : 5 · 18 – 6 · (4 : 1) = 2406</span>\n<span>1) 9 : 9 = 81</span>\n<span>2) 4 : 1 = 4</span>\n<span>3) 3 · 81 = 243</span></p>\n\n<div class="img-wrapper-460">\n<img width="100" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica26-nomer2.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 26, номер 2, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 26, номер 2, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-26/')
    RETURNING id INTO v_task_id;

