    VALUES (v_textbook_id, 26, '3', 2, 'Пользуясь диаграммой Эйлера–Венна, запиши множества А и В с помощью фигурных скобок. Заполни пропуски, используя знаки ∈, ∉, ⊂, ⊄:', '</p>\n\n<p class="text">Пользуясь диаграммой Эйлера–Венна, запиши множества А и В с помощью фигурных скобок. Заполни пропуски, используя знаки ∈, ∉, ⊂, ⊄:</p>\n\n<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica26-nomer3.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 26, номер 3, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 26, номер 3, год 2022."/>\n</div>', 'А ⊄ В      m ∈ A В ⊂ А      m ∈ В 2 ∈ А      9 ∉ А 2 ∉ В      9 ∉ В', '<p><span>А ⊄ В      m ∈ A</span>\n<span>В ⊂ А      m ∈ В</span>\n<span>2 ∈ А      9 ∉ А</span>\n<span>2 ∉ В      9 ∉ В</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-26/')
    RETURNING id INTO v_task_id;

