    VALUES (v_textbook_id, 26, '4', 3, 'С – множество всех спортсменов, Ф – множество футболистов, В – множество вратарей футбольных команд. Нарисуй на одном рисунке диаграммы множеств С, Ф и В. Найди подмножества и сделай записи с помощью знака ⊂.', '</p>\n\n<p class="text">С – множество всех спортсменов, Ф – множество футболистов, В – множество вратарей футбольных команд. Нарисуй на одном рисунке диаграммы множеств С, Ф и В. Найди подмножества и сделай записи с помощью знака ⊂.</p>', '', '<div class="img-wrapper-460">\n<img width="290" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica26-nomer4.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 26, номер 4, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 26, номер 4, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-26/')
