    VALUES (v_textbook_id, 27, '6', 0, 'Вычисли устно: 700 – 160 : 2      (525 – 525) · (396 + 489) 584 + 0 : 216      (800 – 200 + 40) : (201 – 200)', '</p>\n\n<p class="text">Вычисли устно:</p>\n\n<p class="description-text">\n<span>700 – 160 : 2      (525 – 525) · (396 + 489)</span>\n<span>584 + 0 : 216      (800 – 200 + 40) : (201 – 200)</span></p>', '700 – 160 : 2 = 700 – 80 = 620      (525 – 525) · (396 + 489) = 0 – 885 = 885 584 + 0 : 216 = 584 + 0 = 584       (800 – 200 + 40) : (201 – 200) = 640 : 1 = 640', '<p><span>700 – 160 : 2 = 700 – 80 = 620      (525 – 525) · (396 + 489) = 0 – 885 = 885</span>\n<span>584 + 0 : 216 = 584 + 0 = 584       (800 – 200 + 40) : (201 – 200) = 640 : 1 = 640</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-27/')
    RETURNING id INTO v_task_id;

