    VALUES (v_textbook_id, 27, '7', 1, 'Составь выражения. Найди их значения при данных значениях букв: а) В трёх одинаковых коробках n кг изюма. Сколько изюма в 8 таких коробках? (n = 12) б) Для изготовления а одинаковых компьютеров требуется 30 кг металла. Сколько металла пойдёт на изготовление b таких компьютеров? (а = 10, b = 7)', '</p>\n\n<p class="text">Составь выражения. Найди их значения при данных значениях букв:</p>\n\n<p class="description-text">\nа) В трёх одинаковых коробках <b>n</b> кг изюма. Сколько изюма в 8 таких коробках? (n = 12)</p>\n\n<div class="img-wrapper-460">\n<img width="150" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica27-nomer7.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 27, номер 7, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 27, номер 7, год 2022."/>\n</div>\n\n<p class="description-text">\nб) Для изготовления <b>а</b> одинаковых компьютеров требуется 30 кг металла. Сколько металла пойдёт на изготовление <b>b</b> таких компьютеров? (а = 10, b = 7)</p>', 'а) n : 3 · 8 = 12 : 3 · 8 = 4 · 8 = 32 (кг)      Ответ: 32 килограмма изюма в 8 таких коробках. б)30 : а · b = b = 30 : 10 · 7 = 3 · 7 = 21 (кг)      Ответ: 21 килограмм металла пойдёт на изготовление b таких компьютеров.', '<p><span>а) n : 3 · 8 = 12 : 3 · 8 = 4 · 8 = 32 (кг)</span>\n<span>    <b>Ответ:</b> 32 килограмма изюма в 8 таких коробках.</span>\n<span>б)30 : а · b = b = 30 : 10 · 7 = 3 · 7 = 21 (кг)</span>\n<span>    <b>Ответ:</b> 21 килограмм металла пойдёт на изготовление b таких компьютеров.</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-27/')
    RETURNING id INTO v_task_id;

