    VALUES (v_task_id, v_textbook_id, 3, '6c7c43f462cb416a18f3a8b45f5d1291c1b71dc89068b9be3179acc27b645095', '7,8,10,12,30', '["найди"]'::jsonb, 'составь выражения. найди их значения при данных значениях букв:а) в трёх одинаковых коробках n кг изюма. сколько изюма в 8 таких коробках? (n=12) б) для изготовления а одинаковых компьютеров требуется 30 кг металла. сколько металла пойдёт на изготовление b таких компьютеров? (а=10, b=7)');

    VALUES (v_textbook_id, 27, '8', 2, 'Сарай имеет форму прямоугольного параллелепипеда. Длина сарая равна 10 м, ширина – 4 м, а высота – 3 м. Найди объём этого сарая и площадь его стен.', '</p>\n\n<p class="text">Сарай имеет форму прямоугольного параллелепипеда. Длина сарая равна 10 м, ширина – 4 м, а высота – 3 м. Найди объём этого сарая и площадь его стен.</p>', 'V = a · b · c S = а · b V = 10 · 4 · 3 V = 120 (м 3 ) S = 10 · 4 = 40 (м 2 ), S = 4 · 3 = 12 (м 2 ), S = 10 · 3 = 30 (м 2 ). Ответ: объём сарая 120 м 3 , площади сарая 40 м 2 , 12 м 2 и 30 м 2 .', '<p><span>V = a · b · c</span>\n<span>S = а · b</span>\n<span>V = 10 · 4 · 3</span>\n<span>V = 120 (м<sup>3</sup>)</span>\n<span>S = 10 · 4 = 40 (м<sup>2</sup>), S = 4 · 3 = 12 (м<sup>2</sup>), S = 10 · 3 = 30 (м<sup>2</sup>).</span>\n<span><b>Ответ:</b> объём сарая 120 м<sup>3</sup>, площади сарая 40 м<sup>2</sup>, 12 м<sup>2</sup> и 30 м<sup>2</sup>.</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-27/')
    RETURNING id INTO v_task_id;

