    VALUES (v_textbook_id, 27, '9', 3, 'Реши уравнения с комментированием и сделай проверку: х – 38 = 712      524 – х = 198      х + 275 = 900', '</p>\n\n<p class="text">Реши уравнения с комментированием и сделай проверку:</p>\n\n<p class="description-text">\nх – 38 = 712      524 – х = 198      х + 275 = 900</p>', 'х – 38 = 712, что бы найти х, нужно сложить разность и вычитаемое х = 712 + 38 х = 750', '<p><span>х – 38 = 712, что бы найти х, нужно сложить разность и вычитаемое</span>\n<span>х = 712 + 38</span>\n<span>х = 750</span></p>\n\n<div class="img-wrapper-460">\n<img width="120" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica27-nomer9.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 27, номер 9, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 27, номер 9, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-27/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, 'solution', 0, NULL, 'https://gdz-raketa.ru/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica27-nomer9.jpg', 'peterson/3/part1/page27/task9_solution_0.jpg', '');

    VALUES (v_task_id, v_textbook_id, 3, 'de2356273e8382f30c8f43f431372b26fd825b5c52c93e8e8d99274c72b07ca7', '38,198,275,524,712,900', '["реши"]'::jsonb, 'реши уравнения с комментированием и сделай проверку:х-38=712      524-х=198      х+275=900');

    VALUES (v_textbook_id, 27, '10', 4, 'Вычисли. Расположи ответы в порядке убывания, и ты узнаешь имя созвездия в Северном полушарии.', '</p>\n\n<p class="text">Вычисли. Расположи ответы в порядке убывания, и ты узнаешь имя созвездия в Северном полушарии.</p>\n\n<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica27-nomer10.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 27, номер 10, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 27, номер 10, год 2022."/>\n</div>', '', '<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica27-nomer10-1.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 27, номер 10, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 27, номер 10, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-27/')
