    VALUES (v_textbook_id, 27, '11', 5, 'Подбери вместо звёздочек цифры так, чтобы равенство было верно: * + * = ** Сколько решений имеет эта задача?', '</p>\n\n<p class="text">Подбери вместо звёздочек цифры так, чтобы равенство было верно:</p>\n\n<p class="description-text">\n* + * = **</p>\n\n<p class="text">Сколько решений имеет эта задача?</p>', '1 + 9 = 10, 2 + 8 = 10, 3 + 7 = 10, 4 + 6 = 10, 5 + 5 = 10, 5 + 6 = 11, 5 + 7 = 12, 5 + 8 = 13, 5 + 9 = 14, 6 + 6 = 12, 6 + 7 = 13, 6 + 8 = 14, 6 + 9 = 15, 7 + 4 = 11, 7 + 5 = 12, 7 + 6 = 13, 7 + 7 = 14, 7 + 8 = 15, 7 + 9 = 16, 8 + 3 = 11, 8 + 4 = 12. 8 + 5 = 13, 8 + 6 = 14, 8 + 7 = 15, 8 + 8 = 16, 8 + 9 = 17, 9 + 2 = 11, 9 + 3 = 12, 9 + 4 = 13, 9 + 5 = 14, 9 + 6 = 15, 9 + 7 = 16, 9 + 8 = 17, 9 + 9 = 18.', '<p>1 + 9 = 10, 2 + 8 = 10, 3 + 7 = 10, 4 + 6 = 10, 5 + 5 = 10, 5 + 6 = 11, 5 + 7 = 12, 5 + 8 = 13, 5 + 9 = 14, 6 + 6 = 12, 6 + 7 = 13, 6 + 8 = 14, 6 + 9 = 15, 7 + 4 = 11, 7 + 5 = 12, 7 + 6 = 13, 7 + 7 = 14, 7 + 8 = 15, 7 + 9 = 16, 8 + 3 = 11, 8 + 4 = 12. 8 + 5 = 13, 8 + 6 = 14, 8 + 7 = 15, 8 + 8 = 16, 8 + 9 = 17, 9 + 2 = 11, 9 + 3 = 12, 9 + 4 = 13, 9 + 5 = 14, 9 + 6 = 15, 9 + 7 = 16, 9 + 8 = 17, 9 + 9 = 18.</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-27/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '44f99924e7171f8c432d708d13e9efa8a8997bb4b294b863f575f5be1e2efe4d', NULL, NULL, 'подбери вместо звёздочек цифры так, чтобы равенство было верно:*+*=**сколько решений имеет эта задача');

    VALUES (v_textbook_id, 28, '1', 0, 'Построй в тетради, как показано на рисунке, диаграммы множеств А и В. Раскрась жёлтым цветом область А, а синим – область В. Какую часть этих областей пришлось закрасить дважды? Обведи её границу красным цветом. Это – пересечение , или общая часть, двух областей.', '</p>\n\n<p class="text">Построй в тетради, как показано на рисунке, диаграммы множеств А и В. Раскрась жёлтым цветом область А, а синим – область В.</p>\n\n<div class="img-wrapper-460">\n<img width="290" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica28-nomer1.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 28, номер 1, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 28, номер 1, год 2022."/>\n</div>\n\n<p class="text">Какую часть этих областей пришлось закрасить дважды? Обведи её границу красным цветом. Это – <b>пересечение</b>, или общая часть, двух областей.</p>', '', '<div class="img-wrapper-460">\n<img width="290" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica28-nomer1-1.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 28, номер 1, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 28, номер 1, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-28/')
    RETURNING id INTO v_task_id;

