    VALUES (v_task_id, v_textbook_id, 3, '486b2fa9d6561845282805d6879e27ea5056bc4737f3b57b816ec8af1c542c02', NULL, NULL, 'построй в тетради, как показано на рисунке, диаграммы множеств а и в. раскрась жёлтым цветом область а, а синим-область в. какую часть этих областей пришлось закрасить дважды? обведи её границу красным цветом. это-пересечение , или общая часть, двух областей');

    VALUES (v_textbook_id, 28, '2', 1, 'К – множество детей на дне рождения у Коли, а Т – множество детей на дне рождения у Тани. Из каких элементов они состоят? Найди пересечение множеств K и Т. Как можно найти пересечение множеств К и Т, не рисуя диаграммы? Сделай вывод.', '</p>\n\n<p class="text">К – множество детей на дне рождения у Коли, а Т – множество детей на дне рождения у Тани. Из каких элементов они состоят? Найди пересечение множеств K и Т.</p>\n\n<div class="img-wrapper-460">\n<img width="290" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica28-nomer2.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 28, номер 2, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 28, номер 2, год 2022."/>\n</div>\n\n<p class="text">Как можно найти пересечение множеств К и Т, не рисуя диаграммы? Сделай вывод.</p>', '', '<div class="img-wrapper-460">\n<img width="290" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica28-nomer2-1.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 28, номер 2, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 28, номер 2, год 2022."/>', 'Пересечение множеств Пересечение множеств А и В – это их общая часть. Пересечение множеств обозначается знаком ∩.', '<div class="recomended-block">\n<span class="title">Пересечение множеств</span>\n<p>Пересечение множеств А и В – это их общая часть. Пересечение множеств обозначается знаком ∩.</p>\n\n<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica28-recomended-block.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 28, Рекомендательный блок, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 28, Рекомендательный блок, год 2022."/>\n</div>', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-28/')
