    VALUES (v_textbook_id, 28, '3', 2, 'А – множество учеников, изучающих английский язык. F – множество учеников, изучающих французский язык. Что представляет собой множество А ∩ F?', '</p>\n\n<p class="text">А – множество учеников, изучающих английский язык. F – множество учеников, изучающих французский язык. Что представляет собой множество  А ∩ F?</p>', 'А ∩ F – множество учеников, изучающие английский и французский языки.', '<p>А ∩ F – множество учеников, изучающие английский и французский языки.</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-28/')
