    VALUES (v_textbook_id, 29, '8', 4, 'Начерти два треугольника так, что бы их пересечением были: а) шести угольник; б) пятиугольник; в) четырёхугольник; г) треугольник; д) отрезок; е) точка; ж) пустое множество.', '</p>\n\n<p class="text">Начерти два треугольника так, что бы их пересечением были: а) шести угольник; б) пятиугольник; в) четырёхугольник; г) треугольник; д) отрезок; е) точка; ж) пустое множество.</p>', '', '<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica29-nomer8.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 29, номер 8, год 2022, ответ." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 29, номер 8, год 2022, ответ."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-29/')
