    VALUES (v_task_id, v_textbook_id, 3, 'f0b5d750c9ca1a52477bafdb2ce22680379a577948da20da940285c8cf74729f', NULL, NULL, 'начерти два треугольника так, что бы их пересечением были:а) шести угольник; б) пятиугольник; в) четырёхугольник; г) треугольник; д) отрезок; е) точка; ж) пустое множество');

    VALUES (v_textbook_id, 29, '9', 5, 'Улитка проползла утром 3 см 6 мм, днём – 1 дм 4 мм, а вечером – на 4 см меньше, чем утром и днём вместе. Какое расстояние проползла улитка за всё это время?', '</p>\n\n<p class="text">Улитка проползла утром 3 см 6 мм, днём – 1 дм 4 мм, а вечером – на 4 см меньше, чем утром и днём вместе. Какое расстояние проползла улитка за всё это время?</p>\n\n<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica29-nomer9.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 29, номер 9, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 29, номер 9, год 2022."/>\n</div>', '3 см 6 мм + 1 дм 4 мм + (3 см 6 мм + 1 дм 4 мм – 4 см) = 3 см 6 мм + 10 см 4 мм + (3 см 6 мм + 10 см 4 мм – 4 см) = (3 см + 10 см) + (6 мм + 4 мм) + ((3 см + 10 см) + (6 мм + 4 мм) – 4 см) = 13 см + 10 мм + (13 см + 10 мм – 4 см) = 13 см + 1 см + (13 см + 1 см – 4 см) = 14 см + 10 см = 24 см Ответ: 24 сантиметров проползла улитка за всё это время.', '<p><span>3 см 6 мм + 1 дм 4 мм + (3 см 6 мм + 1 дм 4 мм – 4 см) = 3 см 6 мм + 10 см 4 мм + (3 см 6 мм + 10 см 4 мм – 4 см) = (3 см + 10 см) + (6 мм + 4 мм) + ((3 см + 10 см) + (6 мм + 4 мм) – 4 см) = 13 см + 10 мм + (13 см + 10 мм – 4 см) = 13 см + 1 см + (13 см + 1 см – 4 см) = 14 см + 10 см = 24 см</span>\n<span><b>Ответ:</b> 24 сантиметров проползла улитка за всё это время.</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-29/')
    RETURNING id INTO v_task_id;

