    VALUES (v_task_id, v_textbook_id, 3, '16a746b2cbdc920083ad0df26b568e7b5866b79493ddfd9b2afc721d37f93ea9', '1,3,4,6', '["меньше"]'::jsonb, 'улитка проползла утром 3 см 6 мм, днём-1 дм 4 мм, а вечером-на 4 см меньше, чем утром и днём вместе. какое расстояние проползла улитка за всё это время');

    VALUES (v_textbook_id, 30, '10', 0, 'Подбери корни уравнений: а) 15 · а = 15 : а      в) y + y = y · y б) x · 10 = x : 10      г) b + b + b = b · b', '</p>\n\n<p class="text">Подбери корни уравнений:</p>\n\n<p class="description-text">\n<span>а) 15 · а = 15 : а      в) y + y = y · y</span>\n<span>б) x · 10 = x : 10      г) b + b + b = b · b</span></p>', 'а) 15 · а = 15 : а, а = 1      в) y + y = y · y, у = 2 б) x · 10 = x : 10, х = 1      г) b + b + b = b · b, b = 3', '<p><span>а) 15 · а = 15 : а, а = 1      в) y + y = y · y, у = 2</span>\n<span>б) x · 10 = x : 10, х = 1      г) b + b + b = b · b, b = 3</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-30/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '6a67c518474d75e2a5d9a71b980c21398e64281df0585af1d6e8cc59734020ac', '10,15', NULL, 'подбери корни уравнений:а) 15*а=15:а      в) y+y=y*y б) x*10=x:10      г) b+b+b=b*b');

    VALUES (v_textbook_id, 30, '11', 1, 'БЛИЦтурнира а) Оля испекла а пирожков, а её сестра – b пирожков. Эти пирожки они разложили поровну на 3 тарелки. Сколько пирожков в каждой тарелке? б) В 7 одинаковых банках d литров сока. Сколько сока в 20 таких банках? в) С первой грядки собрали с огурцов, а со второй – на b огурцов меньше. Во сколько раз больше огурцов собрано с первой грядки, чем со второй? г) В коробке было n конфет. Четверо ребят взяли по а конфет. Сколько конфет осталось в коробке? д) В вазе лежало с яблок, а груш – в 3 раза больше, чем яблок. Сколько всего яблок и груш лежало в вазе?', '</p>\n\n<p class="text"><span><b>БЛИЦтурнира</b></span>\n<span>а) Оля испекла а пирожков, <b>а</b> её сестра – <b>b</b> пирожков. Эти пирожки они разложили поровну на 3 тарелки. Сколько пирожков в каждой тарелке?</span>\n<span>б) В 7 одинаковых банках <b>d</b> литров сока. Сколько сока в 20 таких банках?</span>\n<span>в) С первой грядки собрали <b>с</b> огурцов, а со второй – на <b>b</b> огурцов меньше. Во сколько раз больше огурцов собрано с первой грядки, чем со второй?</span>\n<span>г) В коробке было <b>n</b> конфет. Четверо ребят взяли по <b>а</b> конфет. Сколько конфет осталось в коробке?</span>\n<span>д) В вазе лежало <b>с</b> яблок, а груш – в 3 раза больше, чем яблок. Сколько всего яблок и груш лежало в вазе?</span></p>', 'а) (а + b) : 3 – пирожков в каждой тарелке. б) d : 7 · 20 – сока в 20 таких банках. в) с : (с – b) – во столько раз больше огурцов собрано с первой грядки, чем со второй. г) n - 4а – конфет осталось в коробке. д) с + 3с – всего яблок и груш лежало в вазе.', '<p><span>а) (а + b) : 3 – пирожков в каждой тарелке.</span>\n<span>б) d : 7 · 20 – сока в 20 таких банках.</span>\n<span>в) с : (с – b) – во столько раз больше огурцов собрано с первой грядки, чем со второй.</span>\n<span>г) n - 4а – конфет осталось в коробке.</span>\n<span>д) с + 3с – всего яблок и груш лежало в вазе.</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-30/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '341fa94339ae19e367f9676ea0dfc4506f686d3ec17ad1c41e8e4e83dfe81e3e', '3,7,20', '["больше","меньше","раз","раза"]'::jsonb, 'блицтурнира а) оля испекла а пирожков, а её сестра-b пирожков. эти пирожки они разложили поровну на 3 тарелки. сколько пирожков в каждой тарелке? б) в 7 одинаковых банках d литров сока. сколько сока в 20 таких банках? в) с первой грядки собрали с огурцов, а со второй-на b огурцов меньше. во сколько раз больше огурцов собрано с первой грядки, чем со второй? г) в коробке было n конфет. четверо ребят взяли по а конфет. сколько конфет осталось в коробке? д) в вазе лежало с яблок, а груш-в 3 раза больше, чем яблок. сколько всего яблок и груш лежало в вазе');

    VALUES (v_textbook_id, 30, '12', 2, 'Найди значения выражений: а) 76 · 5        д) 48 : 3        и) 80 : 16           н) 75 : 25 + 3 · 17 б) 8 · 49        е) 52 : 4        к) 57 : 19           о) 200 – 80 : 5 в) 130 · 6     ж) 950 : 5     л) 780 : 13         п) (160 – 70) : 18 г) 3 · 290      з) 660 : 6      м) 560 : 140      р) (29 + 25) : (72 : 8)', '</p>\n\n<p class="text">Найди значения выражений:</p>\n\n<p class="description-text">\n<span>а) 76 · 5        д) 48 : 3        и) 80 : 16           н) 75 : 25 + 3 · 17</span>\n<span>б) 8 · 49        е) 52 : 4        к) 57 : 19           о) 200 – 80 : 5</span>\n<span>в) 130 · 6     ж) 950 : 5     л) 780 : 13         п) (160 – 70) : 18</span>\n<span>г) 3 · 290      з) 660 : 6      м) 560 : 140      р) (29 + 25) : (72 : 8)</span></p>', 'а) 76 · 5 = 380 12 ч – 3ч 30 мин = 9 ч – 30 мин = 8 ч 30 мин Ответ: сейчас 8 часов 30 минут. 3 · 4 = 12 Ответ: 12 способами можно дойти от Бабы Яги до Кикиморы по этим дорогам.', '<p>а) 76 · 5 = 380</p>\n\n<div class="img-wrapper-460">\n<img width="100" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica30-nomer12.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 30, номер 12, год 2022, ответ." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 30, номер 12, год 2022, ответ."/>\n\n\n<p><span>12 ч – 3ч 30 мин = 9 ч – 30 мин = 8 ч 30 мин</span>\n<span><b>Ответ:</b> сейчас 8 часов 30 минут.</span></p>\n\n\n<p><span>3 · 4 = 12</span>\n<span><b>Ответ:</b> 12 способами можно дойти от Бабы Яги до Кикиморы по этим дорогам.</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-30/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, 'solution', 0, NULL, 'https://gdz-raketa.ru/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica30-nomer12.jpg', 'peterson/3/part1/page30/task12_solution_0.jpg', '');

    VALUES (v_task_id, v_textbook_id, 3, '15a5847eadeb965590e06b748a7a7a40b8f8e6097e41d5982d44e7190d44de69', '3,4,5,6,8,13,16,17,18,19', '["найди"]'::jsonb, 'найди значения выражений:а) 76*5        д) 48:3        и) 80:16           н) 75:25+3*17 б) 8*49        е) 52:4        к) 57:19           о) 200-80:5 в) 130*6     ж) 950:5     л) 780:13         п) (160-70):18 г) 3*290      з) 660:6      м) 560:140      р) (29+25):(72:8)');

    VALUES (v_textbook_id, 31, '1', 0, 'а) Назови записанные свойства сложения и умножения. В чём их смысл? б) Обладают ли этими свойствами вычитание и деление? Обоснуй свой ответ.', '</p>\n\n<p class="text">а) Назови записанные свойства сложения и умножения. В чём их смысл?</p>\n\n<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica31-nomer1.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 31, номер 1, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 31, номер 1, год 2022."/>\n</div>\n\n<p class="text">б) Обладают ли этими свойствами вычитание и деление? Обоснуй свой ответ.</p>', 'а) Сложение – это арифметическое действие, в котором единицы двух чисел объединяются в одно новое число. Для записи сложения используют знак «+» (плюс), который ставят между слагаемыми. Слагаемые – это числа, единицы которых складываются. Сумма – это число, которое получается в результате сложения.    Переместительное свойство сложения. От перестановки мест слагаемых сумма не меняется. a + b = b + a    Сочетательное свойство сложения. Чтобы к сумме двух чисел прибавить третье нужно к первому числу прибавить сумму второго и третьего числа. (a + b) + c = a + (b + c)    Умножение – это повторение, складывание одинаковых чисел (умножение заменяет неоднократно повторенное сложение). Компоненты произведения – первый множитель, второй множитель, произведение. Первое число (первый множитель) повторяют несколько раз, а сколько именно раз – показывает второе число (второй множитель). Результат умножения – произведение.    Умножение натуральных чисел и его свойства. Переместительное свойство умножения: а · b = b · a. Сочетательное свойство умножения: а · (b · с) = (a · b) · с б) При вычитании натуральных чисел уменьшаемое всегда должно быть больше вычитаемого. Разность показывает на сколько больше уменьшаемое больше вычитаемого. При делении любого числа на 1 получается это же число: а : 1 = а    При делении числа на это же число, получается единица: а : а = 1.    Поэтому не обладают этими свойствами вычитание и деление.', '<p><span>а) Сложение – это арифметическое действие, в котором единицы двух чисел объединяются в одно новое число. Для записи сложения используют знак «+» (плюс), который ставят между слагаемыми. Слагаемые – это числа, единицы которых складываются. Сумма – это число, которое получается в результате сложения.</span>\n<span>   Переместительное свойство сложения. От перестановки мест слагаемых сумма не меняется. a + b = b + a</span>\n<span>   Сочетательное свойство сложения. Чтобы к сумме двух чисел прибавить третье нужно к первому числу прибавить сумму второго и третьего числа. (a + b) + c = a + (b + c)</span>\n<span>   Умножение – это повторение, складывание одинаковых чисел (умножение заменяет неоднократно повторенное сложение). Компоненты произведения – первый множитель, второй множитель, произведение. Первое число (первый множитель) повторяют несколько раз, а сколько именно раз – показывает второе число (второй множитель). Результат умножения – произведение.</span>\n<span>   Умножение натуральных чисел и его свойства. Переместительное свойство умножения: а · b = b · a. Сочетательное свойство умножения: а · (b · с) = (a · b) · с</span>\n<span>б) При вычитании натуральных чисел уменьшаемое всегда должно быть больше вычитаемого. Разность показывает на сколько больше уменьшаемое больше вычитаемого. При делении любого числа на 1 получается это же число: а : 1 = а</span>\n<span>   При делении числа на это же число, получается единица: а : а = 1.</span>\n<span>   Поэтому не обладают этими свойствами вычитание и деление.</span></p>', '', '', TRUE, '[{"letter":"а","condition":"Назови записанные свойства сложения и умножения. В чём их смысл?","solution":"Сложение – это арифметическое действие, в котором единицы двух чисел объединяются в одно новое число. Для записи сложения используют знак «+» (плюс), который ставят между слагаемыми. Слагаемые – это числа, единицы которых складываются. Сумма – это число, которое получается в результате сложения.    Переместительное свойство сложения. От перестановки мест слагаемых сумма не меняется. a + b = b + a    Сочетательное свойство сложения. Чтобы к сумме двух чисел прибавить третье нужно к первому числу прибавить сумму второго и третьего числа. (a + b) + c = a + (b + c)    Умножение – это повторение, складывание одинаковых чисел (умножение заменяет неоднократно повторенное сложени"},{"letter":"б","condition":"Обладают ли этими свойствами вычитание и деление? Обоснуй свой ответ.","solution":"При вычитании натуральных чисел уменьшаемое всегда должно быть больше вычитаемого. Разность показывает на сколько больше уменьшаемое больше вычитаемого. При делении любого числа на 1 получается это же число: а : 1 = а    При делении числа на это же число, получается единица: а : а = 1.    Поэтому не обладают этими свойствами вычитание и деление."},{"letter":"е","condition":"","solution":". Компоненты произведения – первый множитель, второй множитель, произведение. Первое число (первый множитель) повторяют несколько раз, а сколько именно раз – показывает второе число (второй множитель). Результат умножения – произведение.    Умножение натуральных чисел и его свойства. Переместительное свойство умножения: а · b = b · a. Сочетательное свойство умножения: а · (b · с) = (a · b) · с"}]'::jsonb, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-31/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, 'condition', 0, NULL, 'https://gdz-raketa.ru/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica31-nomer1.jpg', 'peterson/3/part1/page31/task1_condition_0.jpg', '');

    VALUES (v_task_id, v_textbook_id, 3, '10190b02f80d602b5517333489f0c25bdc17f0e93e0b219026da5275bcd2d138', NULL, NULL, 'а) назови записанные свойства сложения и умножения. в чём их смысл? б) обладают ли этими свойствами вычитание и деление? обоснуй свой ответ');

    VALUES (v_textbook_id, 31, '2', 1, 'А = {1; 2; 3; 4}, В = {3; 4; 5}. Запиши с помощью фигурных скобок множества А ∩ В и В ∩ А. Покажи их на диаграмме Эйлера–Венна. Что ты замечаешь?       А ∩ В = ...      B ∩ A = ... Сделай вывод.', '</p>\n\n<p class="text"><span>А = {1; 2; 3; 4}, В = {3; 4; 5}. Запиши с помощью фигурных скобок множества А ∩ В и В ∩ А. Покажи их на диаграмме Эйлера–Венна. Что ты замечаешь?</span>\n<span>      А ∩ В = ...      B ∩ A = ...</span></p>\n\n<div class="img-wrapper-460">\n<img width="290" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica31-nomer2.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 31, номер 2, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 31, номер 2, год 2022."/>\n</div>\n\n<p class="text">Сделай вывод.</p>', '', '<div class="img-wrapper-460">\n<img width="290" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica31-nomer2-1.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 31, номер 2, год 2022, ответ." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 31, номер 2, год 2022, ответ."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-31/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, 'condition', 0, NULL, 'https://gdz-raketa.ru/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica31-nomer2.jpg', 'peterson/3/part1/page31/task2_condition_0.jpg', '');

    VALUES (v_task_id, 'solution', 0, NULL, 'https://gdz-raketa.ru/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica31-nomer2-1.jpg', 'peterson/3/part1/page31/task2_solution_0.jpg', '');

    VALUES (v_task_id, v_textbook_id, 3, 'bd6a28d6727aa2d215b5078916f597562a1337a127080000731a68a56919b6de', '1,2,3,4,5', NULL, 'а={1; 2; 3; 4}, в={3; 4; 5}. запиши с помощью фигурных скобок множества а ∩ в и в ∩ а. покажи их на диаграмме эйлера-венна. что ты замечаешь?       а ∩ в=...      b ∩ a=... сделай вывод');

    VALUES (v_textbook_id, 31, '3', 2, 'Нарисуй диаграмму множеств А, В и С. Закрась на ней сначала А ∩ В, потом С, а затем обведи их пересечение (А ∩ В) ∩ C. Аналогично построй диаграмму множества А ∩ (В ∩ C). Сравни полученные множества. Что ты замечаешь? Сделай вывод.', '</p>\n\n<p class="text">Нарисуй диаграмму множеств А, В и С. Закрась на ней сначала А ∩ В, потом С, а затем обведи их пересечение (А ∩ В) ∩ C. Аналогично построй диаграмму множества А ∩ (В ∩ C).</p>\n\n<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica31-nomer3.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 31, номер 3, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 31, номер 3, год 2022."/>\n</div>\n\n<p class="text">Сравни полученные множества. Что ты замечаешь? Сделай вывод.</p>', '', '<div class="img-wrapper-460">\n<img width="290" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica31-nomer3-1.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 31, номер 3, год 2022, ответ." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 31, номер 3, год 2022, ответ."/>', 'Свойства пересечения множеств Пересечение множеств обладает переместительным и сочетательным свойствами. Переместительное свойство: А ∩ В = В ∩ А Сочетательное свойство: (А ∩ В) ∩ C = А ∩ (В ∩ C) Значит, результат пересечения множеств не зависит от порядка множеств и от порядка действий .', '<div class="recomended-block">\n<span class="title">Свойства пересечения множеств</span>\n<p>Пересечение множеств обладает переместительным и сочетательным свойствами.<br/>\n<b class="black">Переместительное свойство:</b> А ∩ В = В ∩ А<br/>\n<b class="black">Сочетательное свойство:</b> (А ∩ В) ∩ C = А ∩ (В ∩ C)<br/>\nЗначит, <b class="black">результат</b> <b class="black">пересечения</b> <b class="black">множеств</b> <b class="black">не зависит</b> <b class="black">от порядка</b> <b class="black">множеств</b> <b class="black">и от порядка</b> <b class="black">действий</b>.</p>\n</div>', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-31/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, 'condition', 0, NULL, 'https://gdz-raketa.ru/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica31-nomer3.jpg', 'peterson/3/part1/page31/task3_condition_0.jpg', '');

