    VALUES (v_task_id, v_textbook_id, 3, 'd79973c0c2c5a2a00d6782044a7a25df4a7ab5bafcf374d0942326289d1995f1', NULL, '["сравни"]'::jsonb, 'нарисуй диаграмму множеств а, в и с. закрась на ней сначала а ∩ в, потом с, а затем обведи их пересечение (а ∩ в) ∩ c. аналогично построй диаграмму множества а ∩ (в ∩ c). сравни полученные множества. что ты замечаешь? сделай вывод');

    VALUES (v_textbook_id, 31, '4', 3, 'Допиши в тетради равенства, выражающие свойства пересечения множеств. Назови эти свойства и объясни их смысл.       М ∩ К = ...      (М ∩ К) ∩ Т = ...', '</p>\n\n<p class="text"><span>Допиши в тетради равенства, выражающие свойства пересечения множеств. Назови эти свойства и объясни их смысл.</span>\n<span>      М ∩ К = ...      (М ∩ К) ∩ Т = ...</span></p>', 'М ∩ К = множество К в множестве М (М ∩ К) ∩ Т = М ∩ К в множестве Т', '<p><span>М ∩ К = множество К в множестве М</span>\n<span>(М ∩ К) ∩ Т = М ∩ К в множестве Т</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-31/')
    RETURNING id INTO v_task_id;

