    VALUES (v_task_id, v_textbook_id, 3, '30805bc1824f2c1cb5522019200789ba92d4d177df00ab6f0ae92f6e448aaaa4', NULL, NULL, 'в-множество машин марки "волга", с-множество синих машин, м-множество машин у жителей москвы. что представляют собой множества:а) м ∩ в; б) в ∩ с; в) м ∩ с; г) (м ∩ в) ∩ с');

    VALUES (v_textbook_id, 32, '6', 1, 'Выполни действия наиболее удобным способом. Какие свойства чисел при этом используются? а) (298 + 386) + 102     489 + (256 + 11)     258 + 475 + 42 + 125 б) 19 · 2 · 5     8 · 2 · 25     14 · 45', '</p>\n\n<p class="text">Выполни действия наиболее удобным способом. Какие свойства чисел при этом используются?</p>\n\n<p class="description-text">\n<span>а) (298 + 386) + 102</span>\n<span>    489 + (256 + 11)</span>\n<span>    258 + 475 + 42 + 125</span>\n<br/>\n<span>б) 19 · 2 · 5</span>\n<span>    8 · 2 · 25</span>\n<span>    14 · 45</span></p>', 'а) (298 + 386) + 102 = (298 + 102) + 386 = 400 + 386 = 786     489 + (256 + 11) = 256 + (489 + 11) = 256 + 500 = 756     258 + 475 + 42 + 125 = 300 + 600 = 900 Сочетательное свойство сложения. б) 19 · 2 · 5 = 19 · 10 = 190     8 · 2 · 25 = 8 · 50 = 400     14 · 45 = 2 · 7 · 7 · 5 = 49 · 10 = 490 Переместительное свойство умножения. Сочетательное свойство умножения.', '<p><span>а) (298 + 386) + 102 = (298 + 102) + 386 = 400 + 386 = 786</span>         \n<span>    489 + (256 + 11) = 256 + (489 + 11) = 256 + 500 = 756</span>                \n<span>    258 + 475 + 42 + 125 = 300 + 600 = 900</span>\n<span>Сочетательное свойство сложения.</span>         \n<span>б) 19 · 2 · 5 = 19 · 10 = 190</span>\n<span>    8 · 2 · 25 = 8 · 50 = 400</span>\n<span>    14 · 45 = 2 · 7 · 7 · 5 = 49 · 10 = 490</span>\n<span>Переместительное свойство умножения. Сочетательное свойство умножения.</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-32/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '5367ca7e4f2be56567b8e587b551c69fd79666685e3866ec4d98fe4ba453f80f', '2,5,8,11,14,19,25,42,45,102', NULL, 'выполни действия наиболее удобным способом. какие свойства чисел при этом используются? а) (298+386)+102     489+(256+11)     258+475+42+125 б) 19*2*5     8*2*25     14*45');

    VALUES (v_textbook_id, 32, '7', 2, 'Найди значения х и составь таблицу в тетради. Расположи ответы в порядке убывания и расшифруй слово. Кто это?', '</p>\n\n<p class="text">Найди значения <b>х</b> и составь таблицу в тетради. Расположи ответы в порядке убывания и расшифруй слово. Кто это?</p>\n\n<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica32-nomer7.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 32, номер 7, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 32, номер 7, год 2022."/>\n</div>', '1 · 80 = 80, 80 ˂ 480, 80 · 2 = 160', '<p>1 · 80 = 80, 80 ˂ 480, 80 · 2 = 160</p>\n\n<div class="img-wrapper-460">\n<img width="290" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica32-nomer7-1.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 32, номер 7, год 2022, ответ." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 32, номер 7, год 2022, ответ."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-32/')
    RETURNING id INTO v_task_id;

