    VALUES (v_textbook_id, 32, '8', 3, 'Составь выражения. Найди их значения при данных значениях букв: а) В студии рисования с девочек, а мальчиков – в 3 раза меньше. На сколько девочек в этой студии больше, чем мальчиков? (с = 15, 21, 27) б) В 4 одинаковых банках m литров сока. Сколько литров сока в 9 таких банках? (m = 8, 12, 20)', '</p>\n\n<p class="text">Составь выражения. Найди их значения при данных значениях букв:</p>\n\n<p class="description-text">\n<span>а) В студии рисования с девочек, а мальчиков – в 3 раза меньше. На сколько девочек в этой студии больше, чем мальчиков? (с = 15, 21, 27)</span>\n<span>б) В 4 одинаковых банках m литров сока. Сколько литров сока в 9 таких банках? (m = 8, 12, 20)</span></p>', 'а) с : с : 3     15 : 15 : 3 = 15 : 5 = 3     21 : 21 : 3 = 21 : 7 = 3     27 : 27 : 3 = 27 : 9 = 3 б) m : 4 · 9     8 : 4 · 9 = 2 · 9 = 18     12 : 4 · 9 = 3 · 9 = 27     20 : 4 · 9 = 5 · 9 = 45', '<p><span>а) с : с : 3</span>\n<span>    15 : 15 : 3 = 15 : 5 = 3</span>\n<span>    21 : 21 : 3 = 21 : 7 = 3</span>\n<span>    27 : 27 : 3 = 27 : 9 = 3</span>\n<br/>\n<span>б) m : 4 · 9</span>\n<span>    8 : 4 · 9 = 2 · 9 = 18</span>\n<span>    12 : 4 · 9 = 3 · 9 = 27</span>\n<span>    20 : 4 · 9 = 5 · 9 = 45</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-32/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '2a49b9a339563776921405e49da5ecbcd4cf4610ccc47e16d0d555c19e84f3c6', '3,4,8,9,12,15,20,21,27', '["найди","больше","меньше","раз","раза"]'::jsonb, 'составь выражения. найди их значения при данных значениях букв:а) в студии рисования с девочек, а мальчиков-в 3 раза меньше. на сколько девочек в этой студии больше, чем мальчиков? (с=15, 21, 27) б) в 4 одинаковых банках m литров сока. сколько литров сока в 9 таких банках? (m=8, 12, 20)');

    VALUES (v_textbook_id, 32, '9', 4, 'В начале лета рост щенка Тимошки был равен 2 дм 7 см. В июне Тимошка вырос на 6 см, в июле – на 2 см меньше, чем в июне. На сколько сантиметров вырос Тимошка в августе, если в конце лета его рост составил 4 дм?', '</p>\n\n<p class="text">В начале лета рост щенка Тимошки был равен 2 дм 7 см. В июне Тимошка вырос на 6 см, в июле – на 2 см меньше, чем в июне. На сколько сантиметров вырос Тимошка в августе, если в конце лета его рост составил 4 дм?</p>\n\n<div class="img-wrapper-460">\n<img width="290" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica32-nomer8.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 32, номер 8, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 32, номер 8, год 2022."/>\n</div>', '4 дм – 2 дм 7 см + 6 см – 2 см = 2 дм 7см + 4 см = 3 дм 1 см Ответ: на 31 сантиметров вырос Тимошка в августе.', '<p><span>4 дм – 2 дм 7 см + 6 см – 2 см = 2 дм 7см + 4 см = 3 дм 1 см</span>\n<span><b>Ответ:</b> на 31 сантиметров вырос Тимошка в августе.</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-32/')
    RETURNING id INTO v_task_id;

