    VALUES (v_task_id, v_textbook_id, 3, '8c0f8be731a100e3e93ec3803be79a8787c64f9f72183250cc236efc648b0d5f', '2,4,6,7', '["меньше"]'::jsonb, 'в начале лета рост щенка тимошки был равен 2 дм 7 см. в июне тимошка вырос на 6 см, в июле-на 2 см меньше, чем в июне. на сколько сантиметров вырос тимошка в августе, если в конце лета его рост составил 4 дм');

    VALUES (v_textbook_id, 32, '10', 5, 'Общий вес Миши, Саши и Тани равен 54 кг. Миша весит столько же, сколько Саша и Таня вместе. Сколько весит Миша?', '</p>\n\n<p class="text">Общий вес Миши, Саши и Тани равен 54 кг. Миша весит столько же, сколько Саша и Таня вместе. Сколько весит Миша?</p>', '54 : 2 = 27 (кг) – вес Миши и Тани Ответ: 27 килограмм весит Миша.', '<p><span>54 : 2 = 27 (кг) – вес Миши и Тани</span>\n<span><b>Ответ:</b> 27 килограмм весит Миша.</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-32/')
