    VALUES (v_textbook_id, 33, '2', 1, 'Составь выражения. Найди их значения при данных значениях букв: а) В четырёх одинаковых подъездах дома n квартир. Сколько квартир в 6 таких же подъездах этого дома? (n = 64) б) На k одинаковых этажах дома 56 окон. Сколько окон на r таких же этажах этого дома? (k = 7, r = 12)', '</p>\n\n<p class="text">Составь выражения. Найди их значения при данных значениях букв:</p>\n\n<p class="description-text">\n<span>а) В четырёх одинаковых подъездах дома <b>n</b> квартир. Сколько квартир в 6 таких же подъездах этого дома? (n = 64)</span>\n<span>б) На <b>k</b> одинаковых этажах дома 56 окон. Сколько окон на <b>r</b> таких же этажах этого дома? (k = 7, r = 12)</span></p>', 'а) n : 4 · 6     64 : 4 ∙ 6 = 16 · 6 = 96 (квартир)      Ответ: 96 квартир в 6 таких же подъездах этого дома. б) 56 : k ∙ r     56 : 7 · 12 = 8 · 12 = 96 (окон)      Ответ: 56 окон на r таких же этажах этого дома.', '<p><span>а) n : 4 · 6</span>\n<span>    64 : 4 ∙ 6 = 16 · 6 = 96 (квартир)</span>\n<span>    <b>Ответ:</b> 96 квартир в 6 таких же подъездах этого дома.</span>\n<br/>\n<span>б) 56 : k ∙ r</span>\n<span>    56 : 7 · 12 = 8 · 12 = 96 (окон)</span>\n<span>    <b>Ответ:</b> 56 окон на r таких же этажах этого дома.</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-33/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '7643d47535e7ab0d9c0c2b45d0d7e6d46fbbb95e4799361dcb4124b6d34dc56e', '6,7,12,56,64', '["найди"]'::jsonb, 'составь выражения. найди их значения при данных значениях букв:а) в четырёх одинаковых подъездах дома n квартир. сколько квартир в 6 таких же подъездах этого дома? (n=64) б) на k одинаковых этажах дома 56 окон. сколько окон на r таких же этажах этого дома? (k=7, r=12)');

    VALUES (v_textbook_id, 33, '3', 2, 'Вычисли удобным способом: а) 427 + (84 + 173) б) 35 + 541 + 19 + 165 в) 2 · 16 · 5 · 6 г) 25 · 2 · 18', '</p>\n\n<p class="text">Вычисли удобным способом:</p>\n\n<p class="description-text">\n<span>а) 427 + (84 + 173)</span>\n<span>б) 35 + 541 + 19 + 165</span>\n<span>в) 2 · 16 · 5 · 6</span>\n<span>г) 25 · 2 · 18</span></p>', 'а) 427 + (84 + 173) = 84 + (427 + 173) = 84 + 600 = 684 б) 35 + 541 + 19 + 165 = 200 + 560 = 760 в) 2 · 16 · 5 · 6 = 32 · 30 = 960 г) 25 · 2 · 18 = 50 · 18 = 900', '<p><span>а) 427 + (84 + 173) = 84 + (427 + 173) = 84 + 600 = 684</span>\n<span>б) 35 + 541 + 19 + 165 = 200 + 560 = 760</span>\n<span>в) 2 · 16 · 5 · 6 = 32 · 30 = 960</span>\n<span>г) 25 · 2 · 18 = 50 · 18 = 900</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-33/')
    RETURNING id INTO v_task_id;

