    VALUES (v_textbook_id, 33, '4', 3, 'БЛИЦтурнир а) На первой ёлке с игрушек, а на второй – на 15 игрушек меньше. Во сколько раз больше игрушек на первой ёлке, чем на второй? б) В первом доме d жильцов, а во втором – в 4 раза больше. На сколько меньше жильцов в первом доме, чем во втором? в) Мама заготовила на зиму а двухлитровых и b трёхлитровых банок варенья. Сколько всего литров варенья заготовила мама?', '</p>\n\n<p class="text"><span><b>БЛИЦтурнир</b></span>\n<span>а) На первой ёлке <b>с</b> игрушек, а на второй – на 15 игрушек меньше. Во сколько раз больше игрушек на первой ёлке, чем на второй?</span>\n<span>б) В первом доме <b>d</b> жильцов, а во втором – в 4 раза больше. На сколько меньше жильцов в первом доме, чем во втором?</span>\n<span>в) Мама заготовила на зиму <b>а</b> двухлитровых и <b>b</b> трёхлитровых банок варенья. Сколько всего литров варенья заготовила мама?</span></p>', 'а) с : (с – 15) – во столько раз больше игрушек на первой ёлке, чем на второй. б) d – (d – 4) – на столько меньше жильцов в первом доме, чем во втором. в) 2а + 3b – всего литров варенья заготовила мама.', '<p><span>а) с : (с – 15) – во столько раз больше игрушек на первой ёлке, чем на второй.</span>\n<span>б) d – (d – 4) – на столько меньше жильцов в первом доме, чем во втором.</span>\n<span>в) 2а + 3b – всего литров варенья заготовила мама.</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-33/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '6c06527ecf3214487cd78083266efe11cf33a9466164e255f13bf6071036c6be', '4,15', '["больше","меньше","раз","раза"]'::jsonb, 'блицтурнир а) на первой ёлке с игрушек, а на второй-на 15 игрушек меньше. во сколько раз больше игрушек на первой ёлке, чем на второй? б) в первом доме d жильцов, а во втором-в 4 раза больше. на сколько меньше жильцов в первом доме, чем во втором? в) мама заготовила на зиму а двухлитровых и b трёхлитровых банок варенья. сколько всего литров варенья заготовила мама');

    VALUES (v_textbook_id, 33, '5', 4, 'Найди значения выражений. Проверь результаты по действиям с помощью калькулятора. а) 29 · 2 + 26      в) 72 : 3 – 17        д) 540 : 9 + 280 : (14 · 5) б) 37 + 42 · 4      г) 63 + 100 : 4      е) 300 : (5 · 60) · (78 : 13)', '</p>\n\n<p class="text">Найди значения выражений. Проверь результаты по действиям с помощью калькулятора.</p>\n\n<p class="description-text">\n<span>а) 29 · 2 + 26      в) 72 : 3 – 17        д) 540 : 9 + 280 : (14 · 5)</span>\n<span>б) 37 + 42 · 4      г) 63 + 100 : 4      е) 300 : (5 · 60) · (78 : 13)</span></p>', 'а) 29 · 2 + 26 = 58 + 26 = 84', '<p>а) 29 · 2 + 26 = 58 + 26 = 84</p>\n\n<div class="img-wrapper-460">\n<img width="200" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica33-nomer5.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 33, номер 5, год 2022, ответ." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 33, номер 5, год 2022, ответ."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-33/')
    RETURNING id INTO v_task_id;

