    VALUES (v_task_id, v_textbook_id, 3, 'f0f8abeb4da1f3825462a0e19c811e2cd89beb9262426a78334f5e96f078fec6', '2,3,4,5,9,13,14,17,26,29', '["найди"]'::jsonb, 'найди значения выражений. проверь результаты по действиям с помощью калькулятора. а) 29*2+26      в) 72:3-17        д) 540:9+280:(14*5) б) 37+42*4      г) 63+100:4      е) 300:(5*60)*(78:13)');

    VALUES (v_textbook_id, 33, '6', 5, 'Составь уравнение, реши его и сделай проверку: а) Из какого числа надо вычесть 394, чтобы получить 286? б) На сколько надо уменьшить число 604, чтобы получить 178? в) Какое число надо увеличить на 573, чтобы получить 850?', '</p>\n\n<p class="text">Составь уравнение, реши его и сделай проверку:</p>\n\n<p class="description-text">\n<span>а) Из какого числа надо вычесть 394, чтобы получить 286?</span>\n<span>б) На сколько надо уменьшить число 604, чтобы получить 178?</span>\n<span>в) Какое число надо увеличить на 573, чтобы получить 850?</span></p>', 'а) 394 + 286 = 680', '<p>а) 394 + 286 = 680</p>\n\n<div class="img-wrapper-460">\n<img width="120" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica33-nomer6.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 33, номер 6, год 2022, ответ." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 33, номер 6, год 2022, ответ."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-33/')
    RETURNING id INTO v_task_id;

