    VALUES (v_task_id, v_textbook_id, 3, '6caff1547223857e28386def1b79139b6f50e7ac15576b680d36c5794ef6c079', '178,286,394,573,604,850', '["реши","уравнение"]'::jsonb, 'составь уравнение, реши его и сделай проверку:а) из какого числа надо вычесть 394, чтобы получить 286? б) на сколько надо уменьшить число 604, чтобы получить 178? в) какое число надо увеличить на 573, чтобы получить 850');

    VALUES (v_textbook_id, 33, '7', 6, 'Найди значения выражений: а) (13 + 8 · 4) : 5 – (27 : 3 – 0 · 6) б) 40 : (24 : 6) + 7 · (12 – 2 · 2) – 5 · 5', '</p>\n\n<p class="text">Найди значения выражений:</p>\n\n<p class="description-text">\n<span>а) (13 + 8 · 4) : 5 – (27 : 3 – 0 · 6)</span>\n<span>б) 40 : (24 : 6) + 7 · (12 – 2 · 2) – 5 · 5</span></p>', 'а) (13 + 8 · 4) : 5 – (27 : 3 – 0 · 6) = (13 + 32) : 5 – (9 – 0) = 45 : 5 – 9 = 9 – 9 = 0 б) 40 : (24 : 6) + 7 · (12 – 2 · 2) – 5 · 5 = 40 : 4 + 7 · (12 – 4) = 10 + 7 · 8 = 10 + 56 = 66', '<p><span>а) (13 + 8 · 4) : 5 – (27 : 3 – 0 · 6) = (13 + 32) : 5 – (9 – 0) = 45 : 5 – 9 = 9 – 9 = 0</span>\n<span>б) 40 : (24 : 6) + 7 · (12 – 2 · 2) – 5 · 5 = 40 : 4 + 7 · (12 – 4) = 10 + 7 · 8 = 10 + 56 = 66</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-33/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, 'bf0d802e4eccce49b2b4e6e39cb3f7b443e73f2e3ff492f21eab295bb8b4a63c', '0,2,3,4,5,6,7,8,12,13', '["найди"]'::jsonb, 'найди значения выражений:а) (13+8*4):5-(27:3-0*6) б) 40:(24:6)+7*(12-2*2)-5*5');

    VALUES (v_textbook_id, 34, '8', 0, 'Рассмотри рисунок. Сравни по площади фигуры А и В, В и С, А и С. 1) Верно ли, что на рисунке все фигуры равны между собой? 2) Верно ли, некоторые фигуры равны между собой? 3) Имеются ли фигуры, площадь которых равна 11 клеточкам? 4) Верно ли, что площадь каждой фигуры больше 10 клеточек? Обоснуй свой ответ.', '</p>\n\n<p class="text">Рассмотри рисунок. Сравни по площади фигуры А и В, В и С, А и С.</p>\n\n<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica34-nomer8.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 34, номер 8, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 34, номер 8, год 2022."/>\n</div>\n\n<p class="description-text">\n<span>1) Верно ли, что на рисунке все фигуры равны между собой?</span>\n<span>2) Верно ли, некоторые фигуры равны между собой?</span>\n<span>3) Имеются ли фигуры, площадь которых равна 11 клеточкам?</span>\n<span>4) Верно ли, что площадь каждой фигуры больше 10 клеточек?</span></p>\n\n<p class="text">Обоснуй свой ответ.</p>', 'По площади фигуры А и В – не равны, В и С – не равны, А и С – не равны. 1) не верно, так как у всех фигур различны площади. 2) верно, некоторые фигуры имеют равные площади. 3) имеются фигуры, площадь которых равна 11 клеточкам. 4) не верно, площадь не всех фигур равна 10 клеточкам.', '<p><span>По площади фигуры А и В – не равны, В и С – не равны, А и С – не равны.</span>\n<span>1) не верно, так как у всех фигур различны площади.</span>\n<span>2) верно, некоторые фигуры имеют равные площади.</span>\n<span>3) имеются фигуры, площадь которых равна 11 клеточкам.</span>\n<span>4) не верно, площадь не всех фигур равна 10 клеточкам.</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-34/')
    RETURNING id INTO v_task_id;

