    VALUES (v_task_id, v_textbook_id, 3, '8c16e23e4b0aa899e33ed380bab51d947201449a662edfa96e5524311e7bf98f', '1,2,3,4,10,11', '["сравни","площадь","больше"]'::jsonb, 'рассмотри рисунок. сравни по площади фигуры а и в, в и с, а и с. 1) верно ли, что на рисунке все фигуры равны между собой? 2) верно ли, некоторые фигуры равны между собой? 3) имеются ли фигуры, площадь которых равна 11 клеточкам? 4) верно ли, что площадь каждой фигуры больше 10 клеточек? обоснуй свой ответ');

    VALUES (v_textbook_id, 34, '9', 1, 'а) Пользуясь числовым лучом, составь множество двузначных чисел, кратных 13. б) Выполни деление с остатком: 28 : 13      40 : 13      56 : 13      72 : 13      94 : 13 в) Выучи двузначные числа, кратные 13. Проверь себя, работая в паре.', '</p>\n\n<p class="text">а) Пользуясь числовым лучом, составь множество двузначных чисел, кратных 13.</p>\n\n<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica34-nomer9.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 34, номер 9, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 34, номер 9, год 2022."/>\n</div>\n\n<p class="text">б) Выполни деление с остатком:</p>\n\n<p class="description-text">\n28 : 13      40 : 13      56 : 13      72 : 13      94 : 13</p>\n\n<p class="text">в) Выучи двузначные числа, кратные 13. Проверь себя, работая в паре.</p>', 'а) {13; 26; 39; 52; 65; 78; 91; 104; 117; 130} б) 28 : 13 = 2 + 2      40 : 13 = 3 + 1      56 : 13 = 4 + 4      72 : 13 = 5 + 7      94 : 13 = 7 + 3 в) 13, 26, 39, 52, 65, 78, 91, 104, 117, 130.', '<p><span>а) {13; 26; 39; 52; 65; 78; 91; 104; 117; 130}</span>\n<span>б) 28 : 13 = 2 + 2      40 : 13 = 3 + 1      56 : 13 = 4 + 4      72 : 13 = 5 + 7      94 : 13 = 7 + 3</span>\n<span>в) 13, 26, 39, 52, 65, 78, 91, 104, 117, 130.</span></p>', '', '', TRUE, '[{"letter":"а","condition":"Пользуясь числовым лучом, составь множество двузначных чисел, кратных 13.","solution":"{13; 26; 39; 52; 65; 78; 91; 104; 117; 130}"},{"letter":"б","condition":"Выполни деление с остатком: 28 : 13      40 : 13      56 : 13      72 : 13      94 : 13","solution":"28 : 13 = 2 + 2      40 : 13 = 3 + 1      56 : 13 = 4 + 4      72 : 13 = 5 + 7      94 : 13 = 7 + 3"},{"letter":"в","condition":"Выучи двузначные числа, кратные 13. Проверь себя, работая в паре.","solution":"13, 26, 39, 52, 65, 78, 91, 104, 117, 130."}]'::jsonb, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-34/')
    RETURNING id INTO v_task_id;

