    VALUES (v_task_id, v_textbook_id, 3, '5b7b685a66dbcc4d6d7b4cb5d9f71a9d5229e48d40efcc4b21d9ba0549084a04', '13,28,40,56,72,94', NULL, 'а) пользуясь числовым лучом, составь множество двузначных чисел, кратных 13. б) выполни деление с остатком:28:13      40:13      56:13      72:13      94:13 в) выучи двузначные числа, кратные 13. проверь себя, работая в паре');

    VALUES (v_textbook_id, 34, '10', 2, 'Практическая работа Вырежи из плотной бумаги два квадрата: один со стороной 3 см, а другой – со стороной 2 см. Начерти различные случаи пересечения квадратов, обводя модели карандашом.', '</p>\n\n<p class="text"><span><b>Практическая работа</b></span>\n<span>Вырежи из плотной бумаги два квадрата: один со стороной 3 см, а другой – со стороной 2 см. Начерти различные случаи пересечения квадратов, обводя модели карандашом.</span></p>', '', '<div class="img-wrapper-460">\n<img width="360" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica34-nomer10.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 34, номер 10, год 2022, ответ." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 34, номер 10, год 2022, ответ."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-34/')
    RETURNING id INTO v_task_id;

