    VALUES (v_textbook_id, 34, '11', 3, 'Как расположить 4 элемента на диаграммах множеств А и В, чтобы в каждом из них было соответственно: а) 2 и 4 элемента; б) по 3 элемента; в) 4 и 3 элемента; г) 0 и 4 элемента; д) по 4 элемента; е) по 2 элемента?', '</p>\n\n<p class="text">Как расположить 4 элемента на диаграммах множеств А и В, чтобы в каждом из них было соответственно: </p>\n\n<p class="description-text">\n<span>а) 2 и 4 элемента;</span>\n<span>б) по 3 элемента;</span>\n<span>в) 4 и 3 элемента;</span>\n<span>г) 0 и 4 элемента;</span>\n<span>д) по 4 элемента;</span>\n<span>е) по 2 элемента?</span></p>\n\n<div class="img-wrapper-460">\n<img width="290" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica34-nomer11.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 34, номер 11, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 34, номер 11, год 2022."/>\n</div>', '', '<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica34-nomer11-1.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 34, номер 11, год 2022, ответ." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 34, номер 11, год 2022, ответ."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-34/')
    RETURNING id INTO v_task_id;

