    VALUES (v_textbook_id, 34, '12', 4, 'Послезавтра будет четверг. Позавчера у Тани был день рождения. Какой это был день недели?', '</p>\n\n<p class="text">Послезавтра будет четверг. Позавчера у Тани был день рождения. Какой это был день недели?</p>\n\n<div class="img-wrapper-460">\n<img width="200" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica34-nomer12.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 34, номер 12, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 34, номер 12, год 2022."/>\n</div>', 'Завтра день до четверга – среда, сегодня – вторник, вчера – понедельник и позавчера – день до понедельника было воскресенье. Ответ: это было воскресенье.', '<p><span>Завтра день до четверга – среда, сегодня – вторник, вчера – понедельник и позавчера – день до понедельника было воскресенье.</span>\n<span><b>Ответ:</b> это было воскресенье.</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-34/')
    RETURNING id INTO v_task_id;

