    VALUES (v_textbook_id, 35, '1', 0, 'Реши задачи, составляя выражения. Сравни их. Что ты замечаешь? Почему такие задачи называют взаимно обратными? Чем отличаются их краткие записи и решения?', '</p>\n\n<p class="text">Реши задачи, составляя выражения. Сравни их. Что ты замечаешь?</p>\n\n<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica35-nomer1.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 35, номер 1, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 35, номер 1, год 2022."/>\n</div>\n\n<p class="text">Почему такие задачи называют взаимно обратными? Чем отличаются их краткие записи и решения?</p>', '36 : 3 · 5 = 12 · 5 = 60 (пуговиц), 12 пуговиц в 1 наборе 60 : 36 : 3 = 60 : 12 = 5 (наборов), 12 пуговиц в 1 наборе Сравнивая их, заметно 12 пуговиц в 1 наборе получилось в обоих задачах. Такие задачи называют взаимно обратными, потому что из одной можно найти другую. Отличаются их краткие записи и решения тем что необходимо найти.', '<p><span>36 : 3 · 5 = 12 · 5 = 60 (пуговиц), 12 пуговиц в 1 наборе</span>\n<span>60 : 36 : 3 = 60 : 12 = 5 (наборов), 12 пуговиц в 1 наборе</span>\n<span>Сравнивая их, заметно 12 пуговиц в 1 наборе получилось в обоих задачах.</span>\n<span>Такие задачи называют взаимно обратными, потому что из одной можно найти другую. Отличаются их краткие записи и решения тем что необходимо найти.</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-35/')
