    VALUES (v_textbook_id, 35, '2', 1, 'а) Реши задачу, используя схему и таблицу. Какой способ удобнее? «На 2 м 2 земли посадили 16 кустов клубники. На какой площади, высаживая клубнику так же, можно разместить 80 кустов?» б) Составь и реши обратную задачу.', '</p>\n\n<p class="text">а) Реши задачу, используя схему и таблицу. Какой способ удобнее?  «На 2 м<sup>2</sup> земли посадили 16 кустов клубники. На какой площади, высаживая клубнику так же, можно разместить 80 кустов?»</p>\n\n<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica35-nomer2.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 35, номер 2, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 35, номер 2, год 2022."/>\n</div>\n\n<p class="text">б) Составь и реши обратную задачу.</p>', 'а) 16 : 2 = 8 (кустов) – на 1 м 2     80 : 8 = 10 (м 2 )      Ответ: на 10 м 2 земли, высаживая клубнику так же, можно разместить 80 кустов. б) На 2 м 2 земли посадили 16 кустов клубники. Сколько кустов можно разместить на 10 м 2 земли, высаживая клубнику так же?     2 м 2 – 16 к.     10 м 2 – ? к.     1 м 2 – ? к.     16 : 2 = 8 (кустов) – на 1 м 2     10 · 8 = 80 (кустов)      Ответ: 80 кустов можно разместить на 10 м 2 земли, высаживая клубнику так же.', '<p><span>а) 16 : 2 = 8 (кустов) – на 1 м<sup>2</sup></span>\n<span>    80 : 8 = 10 (м<sup>2</sup>)</span>\n<span>    <b>Ответ:</b> на 10 м<sup>2</sup> земли, высаживая клубнику так же, можно разместить 80 кустов.</span>\n<span>б) На 2 м<sup>2</sup> земли посадили 16 кустов клубники. Сколько кустов можно разместить на 10 м<sup>2</sup> земли, высаживая клубнику так же?</span>\n<span>    2 м<sup>2</sup> – 16 к.</span>\n<span>    10 м<sup>2</sup> – ? к.</span>\n<span>    1 м<sup>2</sup> – ? к.</span>\n<span>    16 : 2 = 8 (кустов) – на 1 м<sup>2</sup></span>\n<span>    10 · 8 = 80 (кустов)</span>\n<span>    <b>Ответ:</b> 80 кустов можно разместить на 10 м<sup>2</sup> земли, высаживая клубнику так же.</span></p>', '', '', TRUE, '[{"letter":"а","condition":"Реши задачу, используя схему и таблицу. Какой способ удобнее? «На 2 м 2 земли посадили 16 кустов клубники. На какой площади, высаживая клубнику так же, можно разместить 80 кустов?»","solution":"16 : 2 = 8 (кусто"},{"letter":"б","condition":"Составь и реши обратную задачу.","solution":"На 2 м 2 земли посадили 16 кустов клубники. Сколько кустов можно разместить на 10 м 2 земли, высаживая клубнику так же?     2 м 2 – 16 к.     10 м 2 – ? к.     1 м 2 – ? к.     16 : 2 = 8 (кусто"},{"letter":"в","condition":"","solution":"– на 1 м 2     80 : 8 = 10 (м 2 )      Ответ: на 10 м 2 земли, высаживая клубнику так же, можно разместить 80 кустов."}]'::jsonb, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-35/')
    RETURNING id INTO v_task_id;

