    VALUES (v_task_id, v_textbook_id, 3, '8fff0dc5569676a24141f375cc83d4d05baa65d6f131de6418ce580d9a464a75', '2,16,80', '["реши","раз"]'::jsonb, 'а) реши задачу, используя схему и таблицу. какой способ удобнее? "на 2 м 2 земли посадили 16 кустов клубники. на какой площади, высаживая клубнику так же, можно разместить 80 кустов?" б) составь и реши обратную задачу');

    VALUES (v_textbook_id, 35, '3', 2, 'Составь и реши задачи на приведение к единице по выражениям: (15 : 5) · 9 и 27 : (15 : 5). Что ты замечаешь?', '</p>\n\n<p class="text">Составь и реши задачи на приведение к единице по выражениям: (15 : 5) · 9 и 27 : (15 : 5). Что ты замечаешь?</p>', 'Задача 1. На 5 м 2 земли посадили 15 кустов клубники. Сколько кустов можно разместить на 9 м 2 земли, высаживая клубнику так же? (15 : 5) · 9 = 3 · 9 = 27 (кустов) Ответ: 27 кустов можно разместить на 9 м 2 земли, высаживая клубнику так же. Задача 2. На 5 м 2 земли посадили 15 кустов клубники. На какой площади, высаживая клубнику так же, можно разместить 27 кустов? 27 : (15 : 5) = 27 : 3 = 9 (м 2 ) Ответ: на 9 м 2 земли, высаживая клубнику так же, можно разместить 27 кустов.', '<p><span><b>Задача 1.</b></span>\n<span>На 5 м<sup>2</sup> земли посадили 15 кустов клубники. Сколько кустов можно разместить на 9 м<sup>2</sup> земли, высаживая клубнику так же?</span>\n<span>(15 : 5) · 9 = 3 · 9 = 27 (кустов)</span>\n<span><b>Ответ:</b> 27 кустов можно разместить на 9 м<sup>2</sup> земли, высаживая клубнику так же.</span>\n<br/>\n<span><b>Задача 2.</b></span>\n<span>На 5 м<sup>2</sup> земли посадили 15 кустов клубники. На какой площади, высаживая клубнику так же, можно разместить 27 кустов?</span>\n<span>27 : (15 : 5) = 27 : 3 = 9 (м<sup>2</sup>)</span>\n<span><b>Ответ:</b> на 9 м<sup>2</sup> земли, высаживая клубнику так же, можно разместить 27 кустов.</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-35/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '6e728fc6d81993cc803f06cd2d9d0dd42707cbceba417be7820809140fe4cb3d', '5,9,15,27', '["реши"]'::jsonb, 'составь и реши задачи на приведение к единице по выражениям:(15:5)*9 и 27:(15:5). что ты замечаешь');

    VALUES (v_textbook_id, 35, '4', 3, 'а) За 5 одинаковых конвертов заплатили 45 р. Сколько таких конвертов можно купить на 72 р.? б) Из 27 м ткани сшили 9 одинаковых платьев. Сколько таких платьев можно сшить из 60 м этой ткани?', '</p>\n\n<p class="text"><span>а) За 5 одинаковых конвертов заплатили 45 р. Сколько таких конвертов можно купить на 72 р.?</span>\n<span>б) Из 27 м ткани сшили 9 одинаковых платьев. Сколько таких платьев можно сшить из 60 м этой ткани?</span></p>\n\n<div class="img-wrapper-460">\n<img width="150" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica35-nomer4.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 35, номер 4, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 35, номер 4, год 2022."/>\n</div>', 'а) 72 : 45 : 5 = 72 : 9 = 8 (конвертов)      Ответ: 8 таких конвертов можно купить на 72 р. б) 60 : 27 : 9 = 60 : 3 = 20 (платьев)      Ответ: 20 таких платьев можно сшить из 60 м этой ткани.', '<p><span>а) 72 : 45 : 5 = 72 : 9 = 8 (конвертов)</span>\n<span>    <b>Ответ:</b> 8 таких конвертов можно купить на 72 р.</span>\n<span>б) 60 : 27 : 9 = 60 : 3 = 20 (платьев)</span>\n<span>    <b>Ответ:</b> 20 таких платьев можно сшить из 60 м этой ткани.</span></p>', '', '', TRUE, '[{"letter":"а","condition":"За 5 одинаковых конвертов заплатили 45 р. Сколько таких конвертов можно купить на 72 р.?","solution":"72 : 45 : 5 = 72 : 9 = 8 (конверто"},{"letter":"б","condition":"Из 27 м ткани сшили 9 одинаковых платьев. Сколько таких платьев можно сшить из 60 м этой ткани?","solution":"60 : 27 : 9 = 60 : 3 = 20 (платье"},{"letter":"в","condition":"","solution":"Ответ: 8 таких конвертов можно купить на 72 р."}]'::jsonb, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-35/')
