    VALUES (v_textbook_id, 36, '7', 0, 'Реши уравнения с комментированием и сделай проверку: 14 · х = 840      х : 70 = 13      960 : х = 160', '</p>\n\n<p class="text">Реши уравнения с комментированием и сделай проверку:</p>\n\n<p class="description-text">\n14 · х = 840      х : 70 = 13      960 : х = 160</p>', '14 · х = 840 Что бы найти множитель х необходимо произведение разделить на известный множитель: х = 840 : 14 х = 60', '<p><span>14 · х = 840</span>\n<span>Что бы найти множитель х необходимо произведение разделить на известный множитель:</span>\n<span>х = 840 : 14</span>\n<span>х = 60</span></p>\n\n<div class="img-wrapper-460">\n<img width="220" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica36-nomer7.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 36, номер 7, год 2022, ответ." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 36, номер 7, год 2022, ответ."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-36/')
