    VALUES (v_textbook_id, 36, '8', 1, 'Реши примеры. Расшифруй и отгадай загадку:', '</p>\n\n<p class="text">Реши примеры. Расшифруй и отгадай загадку:</p>\n\n<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica36-nomer8.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 36, номер 8, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 36, номер 8, год 2022."/>\n</div>', 'Х – 32 + 51 = 83 О – 82 – 40 = 42 Р – 47 + 33 = 80 Д – 90 – 46 = 44 Ы – 25 + 36 = 61 Н – 52 – 18 = 34 Я – 35 : 7 · 9 = 5 · 9 = 45 Б – 54 : 6 · 2 = 9 · 2 = 18 Е – 48 : 6 · 5 = 8 · 5 = 40 Г – 56 : 8 · 9 = 7 · 9 = 63 Ю – 64 : 8 · 9 = 8 · 9 = 72 С – 30 : 6 · 5 = 5 · 5 = 25 У – (6 + 3) · 9 = 9 · 9 = 81 Ь – 6 + 3 · 9 = 6 + 27 = 33 Т – 10 · 3 – 2 = 30 – 2 = 28 П – 180 : 90 = 2 А – 45 : 15 = 3 Л – 70 : 14 = 5 В – 64 : 16 = 4 Ё – 78 : 6 = 13 К – 51 : 3 = 17 Ж – 38 : 2 = 19 И – 84 : 7 = 12 М – 48 : 3 = 16 Ц – 92 : 4 = 23', '<p><span>Х – 32 + 51 = 83</span>\n<span>О – 82 – 40 = 42</span>\n<span>Р – 47 + 33 = 80</span>\n<span>Д – 90 – 46 = 44</span>\n<span>Ы – 25 + 36 = 61</span>\n<span>Н – 52 – 18 = 34</span>\n<span>Я – 35 : 7 · 9 = 5 · 9 = 45</span>\n<span>Б – 54 : 6 · 2 = 9 · 2 = 18</span>\n<span>Е – 48 : 6 · 5 = 8 · 5 = 40</span>\n<span>Г – 56 : 8 · 9 = 7 · 9 = 63</span>\n<span>Ю – 64 : 8 · 9 = 8 · 9 = 72</span>\n<span>С – 30 : 6 · 5 = 5 · 5 = 25</span>\n<span>У – (6 + 3) · 9 = 9 · 9 = 81</span>\n<span>Ь – 6 + 3 · 9 = 6 + 27 = 33</span>\n<span>Т – 10 · 3 – 2 = 30 – 2 = 28</span>\n<span>П – 180 : 90 = 2</span>\n<span>А – 45 : 15 = 3</span>\n<span>Л – 70 : 14 = 5</span>\n<span>В – 64 : 16 = 4</span>\n<span>Ё – 78 : 6 = 13</span>\n<span>К – 51 : 3 = 17</span>\n<span>Ж – 38 : 2 = 19</span>\n<span>И – 84 : 7 = 12</span>\n<span>М – 48 : 3 = 16</span>\n<span>Ц – 92 : 4 = 23</span></p>\n\n<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica36-nomer8-1.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 36, номер 8, год 2022, ответ." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 36, номер 8, год 2022, ответ."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-36/')
