    VALUES (v_textbook_id, 36, '9', 2, 'Задач – шутка Два отца и два сына делили 3 апельсина. Возможен ли случай, когда каждому достанется по одному апельсину?', '</p>\n\n<p class="text"><span><b>Задач – шутка</b></span>\n<span>Два отца и два сына делили 3 апельсина. Возможен ли случай, когда каждому достанется по одному апельсину?</span></p>', 'Возможен случай, когда каждому достанется по одному апельсину если один из них является и отцом, и сыном. Тогда дедушке один, отцу один и внуку один апельсин.', '<p>Возможен случай, когда каждому достанется по одному апельсину если один из них является и отцом, и сыном. Тогда дедушке один, отцу один и внуку один апельсин.</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-36/')
    RETURNING id INTO v_task_id;

