    VALUES (v_textbook_id, 37, '1', 0, 'Построй в тетради диаграмму множеств А и В. Раскрась область А жёлтым цветом, а область В – синим. Обведи красным карандашом всю закрашенную область. Это – объединение множеств А и В.', '</p>\n\n<p class="text">Построй в тетради диаграмму множеств А и В. Раскрась область А жёлтым цветом, а область В – синим. Обведи красным карандашом всю закрашенную область. Это – объединение множеств А и В.</p>\n\n<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica37-nomer1.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 37, номер 1, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 37, номер 1, год 2022."/>\n</div>', '', '<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica37-nomer1-1.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 37, номер 1, год 2022, ответ." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 37, номер 1, год 2022, ответ."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-37/')
    RETURNING id INTO v_task_id;

