    VALUES (v_task_id, v_textbook_id, 3, 'b3612d206adbe6eb4b8300749540eef7d35741ff8a77b52599e3cdcafd4c0349', NULL, NULL, 'построй в тетради диаграмму множеств а и в. раскрась область а жёлтым цветом, а область в-синим. обведи красным карандашом всю закрашенную область. это-объединение множеств а и в');

    VALUES (v_textbook_id, 37, '2', 1, 'В классе проводился шахматно-шашечный турнир. А – множество победителей шахматного турнира, а В – шашечного турнира. Назови элементы множеств А и В. Чему равно их объединение? Как можно найти объединение множеств А и В, не рисуя диаграммы? Сделай вывод.', '</p>\n\n<p class="text">В классе проводился шахматно-шашечный турнир. А – множество победителей шахматного турнира, а В – шашечного турнира. Назови элементы множеств А и В. Чему равно их объединение?</p>\n\n<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica37-nomer2.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 37, номер 2, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 37, номер 2, год 2022."/>\n</div>\n\n<p class="text">Как можно найти объединение множеств А и В, не рисуя диаграммы? Сделай вывод.</p>', 'А = {Петя; Миша; Коля}, В = {Коля; Саша; Дима} А U В = {Петя; Миша; Коля; Саша; Дима} Для того чтобы найти объединение множеств А и В, можно взять все элементы множества А и добавить к ним элементы В, которые не принадлежат А.', '<p><span>А = {Петя; Миша; Коля}, В = {Коля; Саша; Дима}</span>\n<span>А U В = {Петя; Миша; Коля; Саша; Дима}</span>\n<span>Для того чтобы найти объединение множеств А и В, можно взять все элементы множества А и добавить к ним элементы В, которые не принадлежат А.</span></p>', 'Объединение множеств. Знак ∪ Объединение множеств А и В составляют все элементы множеств А и В, взятые вместе. Объединение множеств обозначается знаком ∪. Для того чтобы найти объединение множеств А и В, можно взять все элементы множества А и добавить к ним элементы В, которые не принадлежат А.', '<div class="recomended-block">\n<span class="title">Объединение множеств. Знак ∪</span>\n<p><b class="black">Объединение</b> множеств А и В составляют все элементы множеств А и В, взятые вместе.<br/>\nОбъединение множеств обозначается знаком ∪.<br/>\nДля того чтобы найти объединение множеств А и В, можно взять все элементы множества А и добавить к ним элементы В, которые не принадлежат А.</p>\n</div>', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-37/')
    RETURNING id INTO v_task_id;

