    VALUES (v_task_id, v_textbook_id, 3, '115ebdf058664f629fbb8236af87e09408d048426b9d37283a852ed0995ff07a', NULL, '["равно"]'::jsonb, 'в классе проводился шахматно-шашечный турнир. а-множество победителей шахматного турнира, а в-шашечного турнира. назови элементы множеств а и в. чему равно их объединение? как можно найти объединение множеств а и в, не рисуя диаграммы? сделай вывод');

    VALUES (v_textbook_id, 37, '3', 2, 'А – множество людей, умеющих плавать, В – множество людей, умеющих играть на скрипке. Что представляют собой множества А U В и А ∪ В?', '</p>\n\n<p class="text">А – множество людей, умеющих плавать, В – множество людей, умеющих играть на скрипке. Что представляют собой множества А U В и А ∪ В?</p>', 'множества А U В и А ∪ В представляют собой множество людей, умеющих плавать и, или множество людей, умеющих играть на скрипке.', '<p>множества А U В и А ∪ В представляют собой множество людей, умеющих плавать и, или множество людей, умеющих играть на скрипке.</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-37/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, 'd7fd4fc6ab93ed42d88b6f8d28c80b0b26da4465d0b79e8a3eb1aaffb610c08e', NULL, NULL, 'а-множество людей, умеющих плавать, в-множество людей, умеющих играть на скрипке. что представляют собой множества а u в и а ∪ в');

    VALUES (v_textbook_id, 38, '4', 0, 'Известно, что С = {1; 3; 5; 7}, D = {4; 5; 6}. Найди их объединение С U D. Построй диаграмму множеств С и D и отметь их элементы. Обведи на диаграмме множество С U D.', '</p>\n\n<p class="text">Известно, что С = {1; 3; 5; 7}, D = {4; 5; 6}. Найди их объединение С U D. Построй диаграмму множеств С и D и отметь их элементы. Обведи на диаграмме множество С U D.</p>', 'С U D = {5}.', '<p>С U D = {5}.</p>\n\n<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica38-nomer4.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 38, номер 4, год 2022, ответ." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 38, номер 4, год 2022, ответ."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-38/')
    RETURNING id INTO v_task_id;

