    VALUES (v_task_id, v_textbook_id, 3, '541644bebaa39104daa5b5cca170d0eaea85957ec26d5ac85aece883aa4d439a', '1,3,4,5,6,7', '["найди"]'::jsonb, 'известно, что с={1; 3; 5; 7}, d={4; 5; 6}. найди их объединение с u d. построй диаграмму множеств с и d и отметь их элементы. обведи на диаграмме множество с u d');

    VALUES (v_textbook_id, 38, '5', 1, 'Известно, что М = {а; е; м; к}, E = {а; б; м}. Найди их пересечение М ∩ E и объединение М U E. Нарисуй диаграмму множеств М и E и отметь их элементы. Закрась множество М ∩ E и обведи М U E.', '</p>\n\n<p class="text">Известно, что М = {а; е; м; к}, E = {а; б; м}. Найди их пересечение М ∩ E и объединение М U E. Нарисуй диаграмму множеств М и E и отметь их элементы. Закрась множество М ∩ E и обведи М U E.</p>', 'М ∩ E = {а; м} М U E = {а; б; е; м; к}', '<p><span>М ∩ E = {а; м}</span>\n<span>М U E = {а; б; е; м; к}</span></p>\n\n<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica38-nomer5.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 38, номер 5, год 2022, ответ." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 38, номер 5, год 2022, ответ."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-38/')
    RETURNING id INTO v_task_id;

