    VALUES (v_textbook_id, 38, '6', 2, 'Нарисуй в тетради диаграмму множеств А и В. Закрась на ней множество А ∩ В и обведи А U В.', '</p>\n\n<p class="text">Нарисуй в тетради диаграмму множеств А и В. Закрась на ней множество А ∩ В и обведи А U В.</p>\n\n<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica38-nomer6.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 38, номер 6, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 38, номер 6, год 2022."/>\n</div>', '', '<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica38-nomer6-1.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 38, номер 6, год 2022, ответ." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 38, номер 6, год 2022, ответ."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-38/')
