    VALUES (v_task_id, v_textbook_id, 3, 'e8a860533d72723e5ab41e2f68bb8e22e08cffdf464240ab61be4a645daa5a33', '12,18,72', '["реши","сравни","раз"]'::jsonb, 'реши задачи, составляя выражения:а) с трёх одинаковых овец состригли 18 кг шерсти. сколько таких овец надо постричь, чтобы получить 72 кг шерсти? б) с трёх одинаковых овец состригли 18 кг шерсти. сколько килограммов шерсти можно состричь с 12 таких овец? сравни задачи. чем они похожи и чем различаются? как называют такие задачи');

    VALUES (v_textbook_id, 38, '8', 4, 'Составь и реши взаимно обратные задачи по выражениям: (28 : 4) · 8 и 56 : (28 : 4).', '</p>\n\n<p class="text">Составь и реши взаимно обратные задачи по выражениям:</p>\n\n<p class="description-text">\n(28 : 4) · 8  и  56 : (28 : 4).</p>', 'Задача 1. (28 : 4) ∙ 8 = 7 ∙ 8 = 56 (кг) С четырёх одинаковых овец состригли 28 кг шерсти. Сколько килограммов шерсти можно состричь с 8 таких овец? Задача 2. 56 : (28 : 4) = 56 : 7 = 8 (овец) С четырёх одинаковых овец состригли 28 кг шерсти. Сколько таких овец надо постричь, чтобы получить 56 кг шерсти?', '<p><span><b>Задача 1.</b></span>\n<span>(28 : 4) ∙ 8 = 7 ∙ 8 = 56 (кг)</span>\n<span>С четырёх одинаковых овец состригли 28 кг шерсти. Сколько килограммов шерсти можно состричь с 8 таких овец?</span>\n<br/>\n<span><b>Задача 2.</b></span>\n<span>56 : (28 : 4) = 56 : 7 = 8 (овец)</span>\n<span>С четырёх одинаковых овец состригли 28 кг шерсти. Сколько таких овец надо постричь, чтобы получить 56 кг шерсти?</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-38/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '3ae3a31c2479ca8e674d54dbce2add28f8082cb02a03112c58889ec2d5091d96', '4,8,28,56', '["реши"]'::jsonb, 'составь и реши взаимно обратные задачи по выражениям:(28:4)*8 и 56:(28:4)');

    VALUES (v_textbook_id, 38, '9', 5, 'а) Реши задачу, составляя выражение: «Велосипедист проехал за 2 часа 30 км. За сколько часов, двигаясь так же, он преодолеет 90 км?» б) Составь обратную задачу, которая решается так: (30 : 2) · 15.', '</p>\n\n<p class="text"><span>а) Реши задачу, составляя выражение:</span>\n<span>«Велосипедист проехал за 2 часа 30 км. За сколько часов, двигаясь так же, он преодолеет 90 км?»</span>\n<span>б) Составь обратную задачу, которая решается так: (30 : 2) · 15.</span></p>', 'а) 90 : 30 · 2 = 3 · 2 = 6 (ч)      Ответ: за 6 часов, двигаясь так же, он преодолеет 90 км. б) (30 : 2) · 15 = 15 · 15 = 225 (км)', '<p><span>а) 90 : 30 · 2 = 3 · 2 = 6 (ч)</span>\n<span>    <b>Ответ:</b> за 6 часов, двигаясь так же, он преодолеет 90 км.</span>\n<br/>\n<span>б) (30 : 2) · 15 = 15 · 15 = 225 (км)</span></p>\n\n<div class="img-wrapper-460">\n<img width="100" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica38-nomer9.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 38, номер 9, год 2022, ответ." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 38, номер 9, год 2022, ответ."/>', '', '', TRUE, '[{"letter":"а","condition":"Реши задачу, составляя выражение: «Велосипедист проехал за 2 часа 30 км. За сколько часов, двигаясь так же, он преодолеет 90 км?»","solution":"90 : 30 · 2 = 3 · 2 = 6 (ч)      Ответ: за 6 часов, двигаясь так же, он преодолеет 90 км."},{"letter":"б","condition":"Составь обратную задачу, которая решается так: (30 : 2) · 15.","solution":"(30 : 2) · 15 = 15 · 15 = 225 (км)"}]'::jsonb, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-38/')
    RETURNING id INTO v_task_id;

