    VALUES (v_task_id, v_textbook_id, 3, '013374472a280af62102b5ce393ce7e07a4eed6c49e38744b60f4861eb9972eb', '2,15,30,90', '["реши"]'::jsonb, 'а) реши задачу, составляя выражение:"велосипедист проехал за 2 часа 30 км. за сколько часов, двигаясь так же, он преодолеет 90 км?" б) составь обратную задачу, которая решается так:(30:2)*15');

    VALUES (v_textbook_id, 38, '10', 6, 'Составь выражения. Найди их значения при данных значениях букв: а) В зоопарке пони съедает в неделю с кг травы. На сколько дней для пони хватит запаса травы в d кг (расход травы в день одинаковый)? (с = 98, d = 420) б) В n одинаковых бочек вошло 96 кг огурцов. Сколько таких бочек потребуется для засолки а кг огурцов? (n = 3, а = 320)', '</p>\n\n<p class="text">Составь выражения. Найди их значения при данных значениях букв:</p>\n\n<p class="description-text">\n<span>а) В зоопарке пони съедает в неделю <b>с</b> кг травы. На сколько дней для пони хватит запаса травы в <b>d</b> кг (расход травы в день одинаковый)? (с = 98, d = 420)</span>\n<span>б) В <b>n</b> одинаковых бочек вошло 96 кг огурцов. Сколько таких бочек потребуется для засолки <b>а</b> кг огурцов? (n = 3, а = 320)</span></p>', 'а) d : c : 7 = 420 : 98 : 7 = 420 : 14 = 30 (дней)', '<p>а) d : c : 7 = 420 : 98 : 7 = 420 : 14 = 30 (дней)</p>\n\n<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica38-nomer10.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 38, номер 10, год 2022, ответ." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 38, номер 10, год 2022, ответ."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-38/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, 'solution', 0, NULL, 'https://gdz-raketa.ru/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica38-nomer10.jpg', 'peterson/3/part1/page38/task10_solution_0.jpg', '');

    VALUES (v_task_id, v_textbook_id, 3, '7cd48abc9aa932274c7b5de1a7b5e4669b9393a3ded35a373ace3b608b6dabcd', '3,96,98,320,420', '["найди"]'::jsonb, 'составь выражения. найди их значения при данных значениях букв:а) в зоопарке пони съедает в неделю с кг травы. на сколько дней для пони хватит запаса травы в d кг (расход травы в день одинаковый)? (с=98, d=420) б) в n одинаковых бочек вошло 96 кг огурцов. сколько таких бочек потребуется для засолки а кг огурцов? (n=3, а=320)');

    VALUES (v_textbook_id, 39, '11', 0, 'Вычисли. Объясни для каждого столбика приёмы вычислений: 48 · 5      92 : 4      56 : 14      30 · 9        850 : 5 3 · 74      84 : 7      98 : 49      8 · 120      720 : 60', '</p>\n\n<p class="text">Вычисли. Объясни для каждого столбика приёмы вычислений:</p>\n\n<p class="description-text">\n<span>48 · 5      92 : 4      56 : 14      30 · 9        850 : 5</span>\n<span>3 · 74      84 : 7      98 : 49      8 · 120      720 : 60</span></p>', '48 · 5 = 240 3 · 74 = 222 сначала записываем двузначное число 48 в виде суммы разрядных слагаемых: 40 + 8, то есть просто разбиваем число 48 на сумму четырёх десятков и восьми единиц. Затем умножаем сумму 40 + 8 на число 5: (40 + 8) · 5 = 40 · 5 + 8 · 5 = 200 + 40 = 240, значит 48 · 5 = 240. 92 : 4 = 23 84 : 7 = 12 сначала записываем двузначное число 92 в виде суммы разрядных слагаемых: 90 + 2, то есть просто разбиваем число 92 на сумму девяти десятков и двух единиц. В данном случае разрядные слагаемые числа 92 (90 и 2) не делятся на 4. Тогда можно подобрать ближайшее к 92 круглое число, которое делится на 4, это будет число 80. Заменяем делимое 92 на сумму: 80 + 12. Затем делим сумму 80 + 12 на число 4: (80 + 12) : 4 = 80 : 4 + 12 : 4 = 20 + 3 = 23, значит 92 : 4 = 23. 56 : 14 = 4 98 : 49 = 2 Смотрим на единицы (6 и 4) Определяем, можно ли разделить 6 на 4. Подбираем такое двузначное число, чтобы оно заканчивалось на 6 и делилось на 4, например 16 : 4 = 4 Пробуем 56 : 14 = 4 Проверяем 14 · 4 = 56 30 · 9 = 270 8 · 120 = 960 Сначала записываем двузначное число 30 · 9 = 3 десятка · 9 = 27 десятка = 270 850 : 5 = 170 720 : 60 = 12 Сначала записываем трёхзначное число 850 : 5 = 85 десятка : 5, Определяем, можно разделить 85 на 5, 8 : 5 = 1 + 3, 35 : 5 = 7, 85 десятка : 5 = 17 десятка = 170. Пробуем 850 : 5 = 170 Проверяем 170 · 5 = 850', '<p><span>48 · 5 = 240</span>\n<span>3 · 74 = 222</span>\n<span>сначала записываем двузначное число  48  в виде суммы разрядных слагаемых: 40 + 8, то есть просто разбиваем число  48  на сумму четырёх десятков и восьми единиц. Затем умножаем сумму  40 + 8  на число  5:</span>\n<span>(40 + 8) · 5 = 40 · 5 + 8 · 5 = 200 + 40 = 240, значит  48 · 5 = 240.</span>\n<br/>\n<span>92 : 4 = 23</span>\n<span>84 : 7 = 12</span>\n<span>сначала записываем двузначное число  92  в виде суммы разрядных слагаемых: 90 + 2, то есть просто разбиваем число 92 на сумму девяти десятков и двух единиц.</span>\n<span>В данном случае разрядные слагаемые числа  92 (90  и  2)  не делятся на  4. Тогда можно подобрать ближайшее к 92 круглое число, которое делится на 4, это будет число 80. Заменяем делимое 92 на сумму: 80 + 12.</span>\n<span>Затем делим сумму 80 + 12  на число  4:</span>\n<span>(80 + 12) : 4 = 80 : 4 + 12 : 4 = 20 + 3 = 23, значит  92 : 4 = 23.</span>\n<br/>\n<span>56 : 14 = 4</span>\n<span>98 : 49 = 2</span>\n<span>Смотрим на единицы (6 и 4)</span>\n<span>Определяем, можно ли разделить 6 на 4.</span>\n<span>Подбираем такое двузначное число, чтобы оно заканчивалось на 6 и делилось на 4, например 16 : 4 = 4</span>\n<span>Пробуем 56 : 14 = 4</span>\n<span>Проверяем 14 · 4 = 56</span>\n<br/>\n<span>30 · 9 = 270</span>\n<span>8 · 120 = 960</span>\n<span>Сначала записываем двузначное число</span>\n<span>30 · 9 = 3 десятка · 9 = 27 десятка = 270 </span>\n<br/>\n<span>850 : 5 = 170</span>\n<span>720 : 60 = 12</span>\n<span>Сначала записываем трёхзначное число 850 : 5 = 85 десятка : 5,</span>\n<span>Определяем, можно разделить 85 на 5, 8 : 5 = 1 + 3, 35 : 5 = 7, 85 десятка : 5 = 17 десятка = 170.</span>\n<span>Пробуем 850 : 5 = 170</span>\n<span>Проверяем 170 · 5 = 850</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-39/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, 'd731d3aa650f1db2959158c3edfc5319aa1c62549fab5a50afcdc557fe5eb323', '3,4,5,7,8,9,14,30,48,49', '["вычисли","столбик"]'::jsonb, 'вычисли. объясни для каждого столбика приёмы вычислений:48*5      92:4      56:14      30*9        850:5 3*74      84:7      98:49      8*120      720:60');

    VALUES (v_textbook_id, 39, '12', 1, 'а) Пользуясь числовым лучом, составь множество двузначных чисел, кратных б) Выполни деление с остатком: 45 : 14      60 : 14      78 : 14      86 : 14 в) Выучи двузначные числа, кратные 14. Проверь себя, работая в паре.', '</p>\n\n<p class="text">а) Пользуясь числовым лучом, составь множество двузначных чисел, кратных</p>\n\n<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica39-nomer12.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 39, номер 12, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 39, номер 12, год 2022."/>\n</div>\n\n<p class="text">б) Выполни деление с остатком:</p>\n\n<p class="description-text">\n45 : 14      60 : 14      78 : 14      86 : 14</p>\n\n<p class="text">в) Выучи двузначные числа, кратные 14. Проверь себя, работая в паре.</p>', 'а) {14; 28; 42; 56; 70; 84; 98; 112; 126; 140} б) 45 : 14 = 3 + 3', '<p><span>а) {14; 28; 42; 56; 70; 84; 98; 112; 126; 140}</span>\n<span>б) 45 : 14 = 3 + 3</span></p>\n\n<div class="img-wrapper-460">\n<img width="70" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica39-nomer12-1.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 39, номер 12, год 2022, ответ." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 39, номер 12, год 2022, ответ."/>', '', '', TRUE, '[{"letter":"а","condition":"Пользуясь числовым лучом, составь множество двузначных чисел, кратных","solution":"{14; 28; 42; 56; 70; 84; 98; 112; 126; 140}"},{"letter":"б","condition":"Выполни деление с остатком: 45 : 14      60 : 14      78 : 14      86 : 14","solution":"45 : 14 = 3 + 3"},{"letter":"в","condition":"Выучи двузначные числа, кратные 14. Проверь себя, работая в паре.","solution":""}]'::jsonb, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-39/')
    RETURNING id INTO v_task_id;

