    VALUES (v_task_id, v_textbook_id, 3, '45c0911113ea18168aed4b216c38e812c074d61017c2e26eeb71aaf67e40b1e1', '14,45,60,78,86', NULL, 'а) пользуясь числовым лучом, составь множество двузначных чисел, кратных б) выполни деление с остатком:45:14      60:14      78:14      86:14 в) выучи двузначные числа, кратные 14. проверь себя, работая в паре');

    VALUES (v_textbook_id, 39, '13', 2, 'Составь программу действий и вычисли: а) (714 – 649) · 7 – (95 : 19) · (68 : 2) б) 6 · (532 – 478) + (300 – 38 · 7) : 17 · 100', '</p>\n\n<p class="text">Составь программу действий и вычисли:</p>\n\n<p class="description-text">\n<span>а) (714 – 649) · 7 – (95 : 19) · (68 : 2)</span>\n<span>б) 6 · (532 – 478) + (300 – 38 · 7) : 17 · 100</span></p>', 'а) (714 – 649) · 7 – (95 : 19) · (68 : 2) = 285     найти разность в первой скобке 714 – 649 = 65', '<p><span>а) (714 – 649) · 7 – (95 : 19) · (68 : 2) = 285</span>\n<span>    найти разность в первой скобке 714 – 649 = 65</span></p>\n\n<div class="img-wrapper-460">\n<img width="120" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica39-nomer13.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 39, номер 13, год 2022, ответ." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 39, номер 13, год 2022, ответ."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-39/')
    RETURNING id INTO v_task_id;

