    VALUES (v_task_id, v_textbook_id, 3, '5e8ec082f58d233ff0135e3979e382afb536a517d14820964b0c902b24435b04', '2,6,7,17,19,38,68,95,100,300', '["вычисли"]'::jsonb, 'составь программу действий и вычисли:а) (714-649)*7-(95:19)*(68:2) б) 6*(532-478)+(300-38*7):17*100');

    VALUES (v_textbook_id, 39, '14', 3, 'а) Множество М содержит 5 элементов, множество К – 4 элемента, а их пересечение М ∩ К – 2 элемента. Сколько элементов содержит объединение М U К этих множеств? б) Множества А и В содержат соответственно а и b элементов, а их пересечение А ∩ В – с элементов. Сколько элементов содержит объединение А U В этих множеств?', '</p>\n\n<p class="text"><span>а) Множество М содержит 5 элементов, множество К – 4 элемента, а их пересечение М ∩ К – 2 элемента. Сколько элементов содержит объединение М U К этих множеств?</span>\n<span>б) Множества А и В содержат соответственно а и b элементов, а их пересечение А ∩ В – с элементов. Сколько элементов содержит объединение А U В этих множеств?</span></p>', 'а) 5 + 4 = 9 (элементов)      Ответ: 9 элементов содержит объединение М U К этих множеств. б) a + b      Ответ: a + b элементов содержит объединение А U В этих множеств.', '<p><span>а) 5 + 4 = 9 (элементов)</span>\n<span>    <b>Ответ:</b> 9 элементов содержит объединение М U К этих множеств.</span>\n<span>б) a + b</span>\n<span>    <b>Ответ:</b> a + b элементов содержит объединение А U В этих множеств.</span></p>', '', '', TRUE, '[{"letter":"а","condition":"Множество М содержит 5 элементов, множество К – 4 элемента, а их пересечение М ∩ К – 2 элемента. Сколько элементов содержит объединение М U К этих множеств?","solution":"5 + 4 = 9 (элементо"},{"letter":"б","condition":"Множества А и В содержат соответственно а и b элементов, а их пересечение А ∩ В – с элементов. Сколько элементов содержит объединение А U В этих множеств?","solution":"a + b      Ответ: a + b элементов содержит объединение А U В этих множеств."},{"letter":"в","condition":"","solution":"Ответ: 9 элементов содержит объединение М U К этих множеств."}]'::jsonb, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-39/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '6532c5825e7f8797cf23da28fee29310dc75268b18cecac9340a454f5323fd31', '2,4,5', NULL, 'а) множество м содержит 5 элементов, множество к-4 элемента, а их пересечение м ∩ к-2 элемента. сколько элементов содержит объединение м u к этих множеств? б) множества а и в содержат соответственно а и b элементов, а их пересечение а ∩ в-с элементов. сколько элементов содержит объединение а u в этих множеств');

    VALUES (v_textbook_id, 39, '15', 4, 'В классе английский язык изучают 25 детей, а немецкий – 27 детей. Из них 18 детей изучают одновременно английский и немецкий языки. Сколько всего детей в классе изучают эти иностранные языки? Сколько детей изучают только один из этих языков?', '</p>\n\n<p class="text">В классе английский язык изучают 25 детей, а немецкий – 27 детей. Из них 18 детей изучают одновременно английский и немецкий языки. Сколько всего детей в классе изучают эти иностранные языки? Сколько детей изучают только один из этих языков?</p>\n\n<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica39-nomer15.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 39, номер 15, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 39, номер 15, год 2022."/>\n</div>', '25 + 27 = 52 (ребёнка) 52 – 18 = 34 (ребёнка) Ответ: 52 всего детей в классе изучают эти иностранные языки, 34 ребёнка изучают только один из этих языков.', '<p><span>25 + 27 = 52 (ребёнка)</span>\n<span>52 – 18 = 34 (ребёнка)</span>\n<span><b>Ответ:</b> 52 всего детей в классе изучают эти иностранные языки, 34 ребёнка изучают только один из этих языков.</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-39/')
    RETURNING id INTO v_task_id;

