    VALUES (v_textbook_id, 40, '2', 1, 'А = {3; 6; 9; 12}, В = {2; 4; 6}. Запиши с помощью фигурных скобок пересечение и объединение множеств А и В. Построй диаграмму этих множеств и отметь на ней их элементы.', '</p>\n\n<p class="text">А = {3; 6; 9; 12}, В = {2; 4; 6}. Запиши с помощью фигурных скобок пересечение и объединение множеств А и В. Построй диаграмму этих множеств и отметь на ней их элементы.</p>', 'А U В = {2; 3; 4; 6; 9; 12} объединение', '<p>А U В = {2; 3; 4; 6; 9; 12} объединение</p>\n\n<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica40-nomer2.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 40, номер 2, год 2022, ответ." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 40, номер 2, год 2022, ответ."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-40/')
