    VALUES (v_textbook_id, 41, '8', 1, 'Первая сторона треугольника равна 60 см, вторая – в 3 раза меньше первой. Третья сторона на 27 см меньше суммы первой и второй сторон вместе. Чему равен периметр треугольника?', '</p>\n\n<p class="text">Первая сторона треугольника равна 60 см, вторая – в 3 раза меньше первой. Третья сторона на 27 см меньше суммы первой и второй сторон вместе. Чему равен периметр треугольника?</p>', '60 : 3 = 20 (см) – вторая сторона треугольника. (60 + 20) – 27 = 53 (см) – третья сторона треугольника. Р = 60 + 20 + 53 = 133 (см). Ответ: 133 сантиметра периметр треугольника.', '<p><span>60 : 3 = 20 (см) – вторая сторона треугольника.</span>\n<span>(60 + 20) – 27 = 53 (см) – третья сторона треугольника.</span>\n<span>Р = 60 + 20 + 53 = 133 (см).</span>\n<span><b>Ответ:</b> 133 сантиметра периметр треугольника.</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-41/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '57c3ec95083e3238daac87407ce3d52ade619f2c63dafff15036fc2a76d82312', '3,27,60', '["периметр","сторона","меньше","раз","раза"]'::jsonb, 'первая сторона треугольника равна 60 см, вторая-в 3 раза меньше первой. третья сторона на 27 см меньше суммы первой и второй сторон вместе. чему равен периметр треугольника');

    VALUES (v_textbook_id, 41, '9', 2, 'Сравни: 4 м 3 дм     5 дм 8 см                 8 дм 73 мм     15 см 6 мм 3 м 6 дм 4 см     27 дм 9 см      1 м     984 мм', '</p>\n\n<p class="text">Сравни:</p>\n\n<p class="description-text">\n<span>4 м 3 дм <span class="okon">   </span> 5 дм 8 см                 8 дм 73 мм <span class="okon">   </span> 15 см 6 мм</span>\n<span>3 м 6 дм 4 см <span class="okon">   </span> 27 дм 9 см      1 м <span class="okon">   </span> 984 мм</span></p>', '4 м 3 дм     5 дм 8 см                 8 дм 73 мм     15 см 6 мм 130 см ˃ 58 см                            873 мм ˃ 156 мм 3 м 6 дм 4 см     27 дм 9 см      1 м     984 мм 364 см ˃ 279 см                          1000 мм ˃ 984 мм', '<p><span>4 м 3 дм <span class="okon">   </span> 5 дм 8 см                 8 дм 73 мм <span class="okon">   </span> 15 см 6 мм</span>\n<span>130 см ˃ 58 см                            873 мм ˃ 156 мм</span>\n<span>3 м 6 дм 4 см <span class="okon">   </span> 27 дм 9 см      1 м <span class="okon">   </span> 984 мм</span>\n<span>364 см ˃ 279 см                          1000 мм ˃ 984 мм</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-41/')
