    VALUES (v_textbook_id, 41, '11', 4, 'Вычисли, используя запись в столбик. Узнай, как прочитать эти числа: 4085 + 3274      9215 – 1703      47325 + 29580      82730 – 34159', '</p>\n\n<p class="text">Вычисли, используя запись в столбик. Узнай, как прочитать эти числа:</p>\n\n<p class="description-text">\n4085 + 3274      9215 – 1703      47325 + 29580      82730 – 34159</p>', '4085 + 3274 = 7359', '<p>4085 + 3274 = 7359</p>\n\n<div class="img-wrapper-460">\n<img width="130" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica41-nomer11.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 41, номер 11, год 2022, ответ." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 41, номер 11, год 2022, ответ."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-41/')
