    VALUES (v_textbook_id, 42, '1', 0, 'Вычисли. Какие способы сложения и вычитания трёхзначных чисел ты знаешь? Чем удобна запись в столбик? 378 + 127      513 – 69', '</p>\n\n<p class="text">Вычисли. Какие способы сложения и вычитания трёхзначных чисел ты знаешь? Чем удобна запись в столбик?</p>\n\n<p class="description-text">\n378 + 127      513 – 69</p>', 'Алгоритм письменного сложения и вычитания двузначных чисел. Способ сложения и вычитания чисел с переходом через разряд столбиком. 378 + 127 = 505', '<p><span>Алгоритм письменного сложения и вычитания двузначных чисел. Способ сложения и вычитания чисел с переходом через разряд столбиком.</span>\n<span>378 + 127 = 505</span></p>\n\n<div class="img-wrapper-460">\n<img width="130" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica42-nomer1.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 42, номер 1, год 2022, ответ." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 42, номер 1, год 2022, ответ."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-42/')
