    VALUES (v_textbook_id, 42, '3', 2, 'В рамке записано умножение чисел 24 · 8 в столбик. Объясни с помощью рисунка, как получена эта запись:', '</p>\n\n<p class="text">В рамке записано умножение чисел 24 · 8 в столбик. Объясни с помощью рисунка, как получена эта запись:</p>\n\n<div class="img-wrapper-460">\n<img width="400" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica42-nomer3.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 42, номер 3, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 42, номер 3, год 2022."/>\n</div>', 'Для умножения двузначного числа 24 на число 8 разложим число 24 на десятичную часть 20 и часть единиц 4. По отдельности сначало умножим десятые 20 · 8 = 160 и 4 · 8 = 32. После сложим произведение десятых и единиц 160 + 32 = 192.', '<p>Для умножения двузначного числа 24 на число 8 разложим число 24 на десятичную часть 20 и часть единиц 4. По отдельности сначало умножим десятые 20 · 8 = 160 и 4 · 8 = 32. После сложим произведение десятых и единиц 160 + 32 = 192.</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-42/')
    RETURNING id INTO v_task_id;

