    VALUES (v_textbook_id, 42, '7', 6, 'а) Построй диаграмму множеств С и D и отметь на ней их элементы. Найди множества С ∩ D и С U D. б) Обведи на диаграмме красным карандашом множество С ∩ D и раскрась жёлтым цветом С U D.', '</p>\n\n<div class="img-wrapper-460">\n<img width="240" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica42-nomer7.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 42, номер 7, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 42, номер 7, год 2022."/>\n</div>\n\n<p class="text"><span>а) Построй диаграмму множеств С и D и отметь на ней их элементы. Найди множества С ∩ D и С U D.</span>\n<span>б) Обведи на диаграмме красным карандашом множество С ∩ D и раскрась жёлтым цветом С U D.</span></p>', '', '<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica42-nomer7-1.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 42, номер 7, год 2022, ответ." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 42, номер 7, год 2022, ответ."/>', '', '', TRUE, '[{"letter":"а","condition":"Построй диаграмму множеств С и D и отметь на ней их элементы. Найди множества С ∩ D и С U D.","solution":""},{"letter":"б","condition":"Обведи на диаграмме красным карандашом множество С ∩ D и раскрась жёлтым цветом С U D.","solution":""}]'::jsonb, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-42/')
