    VALUES (v_textbook_id, 43, '8', 0, 'Как увеличить число на 3 единицы, в 10 раз? Как уменьшить число на 5 единиц, в 2 раза? Составь и заполни таблицу в тетради:', '</p>\n\n<p class="text">Как увеличить число на 3 единицы, в 10 раз? Как уменьшить число на 5 единиц, в 2 раза? Составь и заполни таблицу в тетради:</p>\n\n<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica43-nomer8.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 43, номер 8, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 43, номер 8, год 2022."/>\n</div>', '', '<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica43-nomer8-1.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 43, номер 8, год 2022, ответ." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 43, номер 8, год 2022, ответ."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-43/')
