    VALUES (v_task_id, v_textbook_id, 3, 'd243a8f8650b6533924079ec8cff3039513b19695e32348246c8988b71267bf0', NULL, NULL, 'а={к; м; п}, в={а; м; к; р}. запиши с помощью фигурных скобок множества а u в и в u а. покажи их на диаграмме эйлера-венна. что ты замечаешь? а u в=...      в u а=... сделай вывод');

    VALUES (v_textbook_id, 44, '3', 2, 'Нарисуй диаграмму множеств А, В и С. Раскрась на ней сначала множество А U В, потом множество С, а затем обведи их объединение (А U В) U C. Аналогично построй диаграмму множества А U (В U C). Сравни полученные множества. Что ты замечаешь? Сделай вывод.', '</p>\n\n<p class="text">Нарисуй диаграмму множеств А, В и С. Раскрась на ней сначала множество А U В, потом множество С, а затем обведи их объединение (А U В) U C. Аналогично построй диаграмму множества А U (В U C).</p>\n\n<div class="img-wrapper-460">\n<img width="330" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica44-nomer3.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 44, номер 3, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 44, номер 3, год 2022."/>\n</div>\n\n<p class="text">Сравни полученные множества. Что ты замечаешь? Сделай вывод.</p>', '', '<div class="img-wrapper-460">\n<img width="340" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica44-nomer3-1.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 44, номер 3, год 2022, ответ." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 44, номер 3, год 2022, ответ."/>', 'Свойства объединения множеств Объединение множеств обладает переместительным и сочетательным свойствами. Переместительное свойство: А U В = В U А Сочетательное свойство: (А U В) U C = А U (В U C) Значит, результат объединения множеств не зависит от порядка множеств и от порядка действий .', '<div class="recomended-block">\n<span class="title">Свойства объединения множеств</span>\n<p>Объединение множеств обладает переместительным и сочетательным свойствами.<br/>\n<b class="black">Переместительное свойство:</b> А U В = В U А<br/>\n<b class="black">Сочетательное свойство:</b> (А U В) U C = А U (В U C)<br/>\nЗначит, <b class="black">результат</b> <b class="black">объединения</b> <b class="black">множеств не</b> <b class="black">зависит от порядка множеств и от порядка действий</b>.</p>\n</div>', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-44/')
    RETURNING id INTO v_task_id;

