    VALUES (v_task_id, 'solution', 0, NULL, 'https://gdz-raketa.ru/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica44-nomer3-1.jpg', 'peterson/3/part1/page44/task3_solution_0.jpg', '');

    VALUES (v_task_id, v_textbook_id, 3, 'af3fb7c655146bd3d9b0ba3d43992bf059a9b0bc78456149203f3d1616b719d7', NULL, '["сравни"]'::jsonb, 'нарисуй диаграмму множеств а, в и с. раскрась на ней сначала множество а u в, потом множество с, а затем обведи их объединение (а u в) u c. аналогично построй диаграмму множества а u (в u c). сравни полученные множества. что ты замечаешь? сделай вывод');

    VALUES (v_textbook_id, 44, '4', 3, 'Допиши в тетради равенства, выражающие свойства объединения множеств. Назови эти свойства и объясни их смысл. М U К = ...      (М U К) U Т = ...', '</p>\n\n<p class="text"><span>Допиши в тетради равенства, выражающие свойства объединения множеств. Назови эти свойства и объясни их смысл.</span>\n<span>М U К = ...      (М U К) U Т = ...</span></p>', 'М U К = К U М – Переместительное свойство (М U К) U Т = М U (К U Т) – Сочетательное свойство Значит, результат объединения множеств не зависит от порядка множеств и от порядка действий.', '<p><span>М U К = К U М – Переместительное свойство</span>\n<span>(М U К) U Т = М U (К U Т) – Сочетательное свойство</span>\n<span>Значит, результат объединения множеств не зависит от порядка множеств и от порядка действий.</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-44/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '19e89a085de6abff137c92af1fd93bc1dc0fbe0fa1ac0b1e1703c962a53a6d94', NULL, NULL, 'допиши в тетради равенства, выражающие свойства объединения множеств. назови эти свойства и объясни их смысл. м u к=...      (м u к) u т=');

