    VALUES (v_textbook_id, 45, '6', 1, 'а) Пусть А – множество машин, В – множество легковых машин, С – множество машин красного цвета, D – множество гаражей. Найди на диаграмме, где какое множество расположено. Что означает раскрашенное множество? б) Пусть А – множество цветов, В – множество роз, С – множество жёлтых цветов, D – множество деревьев. Нарисуй диаграмму множеств А, В, С и D. Раскрась на ней множество жёлтых роз.', '</p>\n\n<p class="text">а) Пусть А – множество машин, В – множество легковых машин, С – множество машин красного цвета, D – множество гаражей. Найди на диаграмме, где какое множество расположено. Что означает раскрашенное множество?</p>\n\n<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica45-nomer6.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 45, номер 6, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 45, номер 6, год 2022."/>\n</div>\n\n<p class="text">б) Пусть А – множество цветов, В – множество роз, С – множество жёлтых цветов, D – множество деревьев. Нарисуй диаграмму множеств А, В, С и D. Раскрась на ней множество жёлтых роз.</p>', 'а) раскрашенное множество означает что легковые машины могут быть красного цвета.', '<p>а) раскрашенное множество означает что легковые машины могут быть красного цвета.</p>\n\n<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica45-nomer6-1.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 45, номер 6, год 2022, ответ." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 45, номер 6, год 2022, ответ."/>', '', '', TRUE, '[{"letter":"а","condition":"Пусть А – множество машин, В – множество легковых машин, С – множество машин красного цвета, D – множество гаражей. Найди на диаграмме, где какое множество расположено. Что означает раскрашенное множество?","solution":"раскрашенное множество означает что легковые машины могут быть красного цвета."},{"letter":"б","condition":"Пусть А – множество цветов, В – множество роз, С – множество жёлтых цветов, D – множество деревьев. Нарисуй диаграмму множеств А, В, С и D. Раскрась на ней множество жёлтых роз.","solution":""}]'::jsonb, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-45/')
    RETURNING id INTO v_task_id;

