    VALUES (v_task_id, v_textbook_id, 3, 'f996f4a60239210dc6032229489785526b9a58e5397769af6041e176ad58925a', NULL, '["найди"]'::jsonb, 'а) пусть а-множество машин, в-множество легковых машин, с-множество машин красного цвета, d-множество гаражей. найди на диаграмме, где какое множество расположено. что означает раскрашенное множество? б) пусть а-множество цветов, в-множество роз, с-множество жёлтых цветов, d-множество деревьев. нарисуй диаграмму множеств а, в, с и d. раскрась на ней множество жёлтых роз');

    VALUES (v_textbook_id, 45, '7', 2, 'Выполни действия наиболее удобным способом. Какие свойства чисел при этом используются? а) (373 + 56) + 127     602 + (98 + 245)     84 + 71 + 429 + 16 б) 2 · 39 · 2 · 5 · 5     25 · 7 · 4     16 · 35', '</p>\n\n<p class="text">Выполни действия наиболее удобным способом. Какие свойства чисел при этом используются?</p>\n\n<p class="description-text">\n<span>а) (373 + 56) + 127</span>\n<span>    602 + (98 + 245)</span>\n<span>    84 + 71 + 429 + 16</span>\n<br/>\n<span>б) 2 · 39 · 2 · 5 · 5</span>\n<span>    25 · 7 · 4</span>\n<span>    16 · 35</span></p>', 'а) (373 + 56) + 127 = 400 + 56 = 456     602 + (98 + 245) = 700 + 245 = 945     84 + 71 + 429 + 16 = 100 + 500 = 600 б) 2 · 39 · 2 · 5 · 5 = 39 · 10 · 10 = 3900     25 · 7 · 4 = 100 · 7 = 700     16 · 35 = 8 · 2 · 35 = 8 · 70 = 560', '<p><span>а) (373 + 56) + 127 = 400 + 56 = 456</span>\n<span>    602 + (98 + 245) = 700 + 245 = 945</span>\n<span>    84 + 71 + 429 + 16 = 100 + 500 = 600</span>\n<br/>\n<span>б) 2 · 39 · 2 · 5 · 5 = 39 · 10 · 10 = 3900</span>\n<span>    25 · 7 · 4 = 100 · 7 = 700</span>\n<span>    16 · 35 = 8 · 2 · 35 = 8 · 70 = 560</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-45/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '3788ab5457c86f088b68d3377ade3ae7167284d6b1855bc1aa1695e9c648b1eb', '2,4,5,7,16,25,35,39,56,71', NULL, 'выполни действия наиболее удобным способом. какие свойства чисел при этом используются? а) (373+56)+127     602+(98+245)     84+71+429+16 б) 2*39*2*5*5     25*7*4     16*35');

    VALUES (v_textbook_id, 45, '8', 3, 'а) В 4 одинаковых коробках 24 карандаша. Сколько карандашей в 9 таких коробках? б) На 5 одинаковых костюмов пошло 35 м ткани. Сколько таких костюмов можно сшить из 56 м этой ткани? в) Около дома растёт 8 тополей, а лип – в 2 раза меньше. Сколько лип и тополей растёт около дома? г) Саша купил 4 пирожка по 16 р. и 2 буханки хлеба по 18 р. Сколько денег заплатил он за всю покупку?', '</p>\n\n<p class="text"><span>а) В 4 одинаковых коробках 24 карандаша. Сколько карандашей в 9 таких коробках?</span>\n<span>б) На 5 одинаковых костюмов пошло 35 м ткани. Сколько таких костюмов можно сшить из 56 м этой ткани?</span>\n<span>в) Около дома растёт 8 тополей, а лип – в 2 раза меньше. Сколько лип и тополей растёт около дома?</span>\n<span>г) Саша купил 4 пирожка по 16 р. и 2 буханки хлеба по 18 р. Сколько денег заплатил он за всю покупку?</span></p>\n\n<div class="img-wrapper-460">\n<img width="160" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica45-nomer8.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 45, номер 8, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 45, номер 8, год 2022."/>\n</div>', 'а) 24 : 4 · 9 = 6 · 9 = 54 (карандаша)      Ответ: 54 карандашей в 9 таких коробках. б) 56 : 35 : 5 = 56 : 7 = 8 (костюмов)      Ответ: 8 таких костюмов можно сшить из 56 м этой ткани. в) 8 + 8 : 2 = 8 + 4 = 12 (деревьев)      Ответ: 12 лип и тополей растёт около дома. г) 4 · 16 + 2 · 18 = 56 + 36 = 72 (р)      Ответ: денег заплатил он за всю покупку.', '<p><span>а) 24 : 4 · 9 = 6 · 9 = 54 (карандаша)</span>\n<span>    <b>Ответ:</b> 54 карандашей в 9 таких коробках.</span>\n<span>б) 56 : 35 : 5 = 56 : 7 = 8 (костюмов)</span>\n<span>    <b>Ответ:</b> 8 таких костюмов можно сшить из 56 м этой ткани.</span>\n<span>в) 8 + 8 : 2 = 8 + 4 = 12 (деревьев)</span>\n<span>    <b>Ответ:</b> 12 лип и тополей растёт около дома.</span>\n<span>г) 4 · 16 + 2 · 18 = 56 + 36 = 72 (р)</span>\n<span>    <b>Ответ:</b>  денег заплатил он за всю покупку.</span></p>', '', '', TRUE, '[{"letter":"а","condition":"В 4 одинаковых коробках 24 карандаша. Сколько карандашей в 9 таких коробках?","solution":"24 : 4 · 9 = 6 · 9 = 54 (карандаша)      Ответ: 54 карандашей в 9 таких коробках."},{"letter":"б","condition":"На 5 одинаковых костюмов пошло 35 м ткани. Сколько таких костюмов можно сшить из 56 м этой ткани?","solution":"56 : 35 : 5 = 56 : 7 = 8 (костюмо"},{"letter":"в","condition":"Около дома растёт 8 тополей, а лип – в 2 раза меньше. Сколько лип и тополей растёт около дома?","solution":"Ответ: 8 таких костюмов можно сшить из 56 м этой ткани."},{"letter":"г","condition":"Саша купил 4 пирожка по 16 р. и 2 буханки хлеба по 18 р. Сколько денег заплатил он за всю покупку?","solution":"4 · 16 + 2 · 18 = 56 + 36 = 72 (р)      Ответ: денег заплатил он за всю покупку."}]'::jsonb, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-45/')
    RETURNING id INTO v_task_id;

