    VALUES (v_task_id, v_textbook_id, 3, 'd549c511465c3d01dd32fdb8aa3080e50e476ac3814f1091f28ea557ef16fe9f', '2,4,5,8,9,16,18,24,35,56', '["меньше","раз","раза"]'::jsonb, 'а) в 4 одинаковых коробках 24 карандаша. сколько карандашей в 9 таких коробках? б) на 5 одинаковых костюмов пошло 35 м ткани. сколько таких костюмов можно сшить из 56 м этой ткани? в) около дома растёт 8 тополей, а лип-в 2 раза меньше. сколько лип и тополей растёт около дома? г) саша купил 4 пирожка по 16 р. и 2 буханки хлеба по 18 р. сколько денег заплатил он за всю покупку');

    VALUES (v_textbook_id, 45, '9', 4, 'В равенствах вместо некоторых цифр стоят звёздочки. Объясни, почему эти равенства не верны. * + 2 * = *      * 5 + * 7 = * 8         3 * * – * * = * * * + * = 6 *      * * 5 + * 7 = * 2      * * 9 – * 4 = * * 3', '</p>\n\n<p class="text">В равенствах вместо некоторых цифр стоят звёздочки. Объясни, почему эти равенства не верны.</p>\n\n<p class="description-text">\n<span>* + 2 * = *      * 5 + * 7 = * 8         3 * * – * * = * *</span>\n<span>* + * = 6 *      * * 5 + * 7 = * 2      * * 9 – * 4 = * * 3</span></p>', '* + 2 * = * – к двузначному прибавляют однозначное, при любых цифрах должно получиться не менее двузначного числа. * + * = 6 * – при любых числах сумма однозначных чисел не может равняться двузначному числу в десятых с 6. * 5 + * 7 = * 8 – 5 + 7 = 12, в единицах цифра 2, и 8 не может быть. * * 5 + * 7 = * 2 – к трёхзначному числу прибавляют двухзначное число и в результате не менее трёхзначного должно получиться. 3 * * – * * = * * – что бы проверить получиться ли в результате двузначное число отнимая от трёхзначного числа в сотых имеющее 3 двузначное подставим наименьшее трёхзначное 300 и наибольшее двузначное 99: 300 – 99 = 201, получаем всё равно трёхзначное. * * 9 – * 4 = * * 3 – 9 – 4 = 5 в единицах должно быть не цифра 3.', '<p><span>* + 2 * = * – к двузначному прибавляют однозначное, при любых цифрах должно получиться не менее двузначного числа.</span>\n<span>* + * = 6 * – при любых числах сумма однозначных чисел не может равняться двузначному числу в десятых с 6.</span>\n<span>* 5 + * 7 = * 8 – 5 + 7 = 12, в единицах цифра 2, и 8 не может быть.</span>\n<span>* * 5 + * 7 = * 2 – к трёхзначному числу прибавляют двухзначное число и в результате не менее трёхзначного должно получиться.</span>\n<span>3 * * – * * = * * – что бы проверить получиться ли в результате двузначное число отнимая от трёхзначного числа в сотых имеющее 3 двузначное подставим наименьшее трёхзначное 300 и наибольшее двузначное 99: 300 – 99 = 201, получаем всё равно трёхзначное.</span>\n<span>* * 9 – * 4 = * * 3 – 9 – 4 = 5 в единицах должно быть не цифра 3.</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-45/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '43a011ed07670ecd855b3b67d28af2f9894384b154cf5999661a5aa0fc7fb075', '2,3,4,5,6,7,8,9', NULL, 'в равенствах вместо некоторых цифр стоят звёздочки. объясни, почему эти равенства не верны.*+2*=*      *5+*7=*8         3**-**=***+*=6*      **5+*7=*2      **9-*4=**3');

    VALUES (v_textbook_id, 46, '10', 0, 'а) Пользуясь числовым лучом, составь множество двузначных чисел, кратных 15. б) Выполни деление с остатком: 34 : 15      47 : 15      76 : 15      98 : 15 в) Выучи двузначные числа, кратные 15. Проверь себя, работая в паре.', '</p>\n\n<p class="text">а) Пользуясь числовым лучом, составь множество двузначных чисел, кратных 15.</p>\n\n<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica46-nomer10.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 46, номер 10, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 46, номер 10, год 2022."/>\n</div>\n\n<p class="text">б) Выполни деление с остатком:</p>\n\n<p class="description-text">\n34 : 15      47 : 15      76 : 15      98 : 15</p>\n\n<p class="text">в) Выучи двузначные числа, кратные 15. Проверь себя, работая в паре.</p>', 'а) {15; 30; 45; 60; 75; 90; 105; 120; 135; 150} б) 34 : 15 = 2 + 4      47 : 15 = 3 + 2      76 : 15 = 5 + 1      98 : 15 = 6 + 8 в) 15, 30, 45, 60, 75, 90, 105, 120, 135, 150', '<p><span>а) {15; 30; 45; 60; 75; 90; 105; 120; 135; 150}</span>\n<span>б) 34 : 15 = 2 + 4      47 : 15 = 3 + 2      76 : 15 = 5 + 1      98 : 15 = 6 + 8</span>\n<span>в) 15, 30, 45, 60, 75, 90, 105, 120, 135, 150</span></p>', '', '', TRUE, '[{"letter":"а","condition":"Пользуясь числовым лучом, составь множество двузначных чисел, кратных 15.","solution":"{15; 30; 45; 60; 75; 90; 105; 120; 135; 150}"},{"letter":"б","condition":"Выполни деление с остатком: 34 : 15      47 : 15      76 : 15      98 : 15","solution":"34 : 15 = 2 + 4      47 : 15 = 3 + 2      76 : 15 = 5 + 1      98 : 15 = 6 + 8"},{"letter":"в","condition":"Выучи двузначные числа, кратные 15. Проверь себя, работая в паре.","solution":"15, 30, 45, 60, 75, 90, 105, 120, 135, 150"}]'::jsonb, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-46/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, 'condition', 0, NULL, 'https://gdz-raketa.ru/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica46-nomer10.jpg', 'peterson/3/part1/page46/task10_condition_0.jpg', '');

    VALUES (v_task_id, v_textbook_id, 3, '06cb5134e5e6a453aa0b2e300c4353cf92824cbf01950014402e7285defef925', '15,34,47,76,98', NULL, 'а) пользуясь числовым лучом, составь множество двузначных чисел, кратных 15. б) выполни деление с остатком:34:15      47:15      76:15      98:15 в) выучи двузначные числа, кратные 15. проверь себя, работая в паре');

    VALUES (v_textbook_id, 46, '11', 1, 'Найди значения выражений: а) (80 : 4 – 60 : 30) · 5 + 96 : 3 – 117 б) 56 : 4 + 2 · (120 : 6 – 80 : 20) + 17 · 8', '</p>\n\n<p class="text">Найди значения выражений:</p>\n\n<p class="description-text">\n<span>а) (80 : 4 – 60 : 30) · 5 + 96 : 3 – 117</span>\n<span>б) 56 : 4 + 2 · (120 : 6 – 80 : 20) + 17 · 8</span></p>', 'а) (80 : 4 – 60 : 30) · 5 + 96 : 3 – 117 = (20 – 2) · 5 + 32 = 18 · 5 + 32 = 90 + 32 = 122 б) 56 : 4 + 2 · (120 : 6 – 80 : 20) + 17 · 8 = 14 + 2 · (20 – 4) + 136 = 14 + 2 · 16 + 136 = 14 + 32 + 136 = 150 + 32 =182', '<p><span>а) (80 : 4 – 60 : 30) · 5 + 96 : 3 – 117 = (20 – 2) · 5 + 32 = 18 · 5 + 32 = 90 + 32 = 122</span>\n<span>б) 56 : 4 + 2 · (120 : 6 – 80 : 20) + 17 · 8 = 14 + 2 · (20 – 4) + 136 = 14 + 2 · 16 + 136 = 14 + 32 + 136 = 150 + 32 =182</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-46/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '1ff0c8fb71b4f595acb7a581f4fea9f6da81337b74a1ed8be1e344b971ccae40', '2,3,4,5,6,8,17,20,30,56', '["найди"]'::jsonb, 'найди значения выражений:а) (80:4-60:30)*5+96:3-117 б) 56:4+2*(120:6-80:20)+17*8');

