    VALUES (v_textbook_id, 46, '13', 3, 'Построй прямоугольник, ширина которого равна 3 клеточкам, а длина – 4 клеточкам. Закрась на нём ровно: а) половину клеточек б) треть клеточек в) четверть клеточек г) шестую часть клеточек', '</p>\n\n<p class="text">Построй прямоугольник, ширина которого равна 3 клеточкам, а длина – 4 клеточкам. Закрась на нём ровно:</p>\n\n<p class="description-text">\n<span>а) половину клеточек</span>\n<span>б) треть клеточек</span>\n<span>в) четверть клеточек</span>\n<span>г) шестую часть клеточек</span></p>', '', '<div class="img-wrapper-460">\n<img width="200" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica46-nomer13.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 46, номер 13, год 2022, ответ." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 46, номер 13, год 2022, ответ."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-46/')
