    VALUES (v_textbook_id, 47, '1', 0, 'Сосчитай число элементов в множестве А и его подмножествах. Что ты замечаешь? Сделай вывод.', '</p>\n\n<p class="text">Сосчитай число элементов в множестве А и его подмножествах. Что ты замечаешь? Сделай вывод.</p>\n\n<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica47-nomer1.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 47, номер 1, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 47, номер 1, год 2022."/>\n</div>', 'а) в множестве А 6 элементов и его подмножествах В – 4 элемента, С – 2 элемента. Легко заметить что 4 + 2 = 6, сумма элементов подмножеств равна числу элементов множества. б) в множестве А 6 элементов и его подмножествах В – 4 элемента, D – 3 элемента, при этом у подмножеств один элемент общий. Легко заметить что 3 + 2 + 1 = 6, сумма элементов подмножеств и общих элементов равна числу элементов множества.', '<p><span>а) в множестве А 6 элементов и его подмножествах В – 4 элемента, С – 2 элемента. Легко заметить что 4 + 2 = 6, сумма элементов подмножеств равна числу элементов множества.</span>\n<span>б) в множестве А 6 элементов и его подмножествах В – 4 элемента, D – 3 элемента, при этом у подмножеств один элемент общий. Легко заметить что 3 + 2 + 1 = 6, сумма элементов подмножеств и общих элементов равна числу элементов множества.</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-47/')
    RETURNING id INTO v_task_id;

