    VALUES (v_textbook_id, 47, '2', 1, 'Разбей множества А и В на части: съедобные и несъедобные предметы. Сколько предметов в каждой части, во всём множестве? Что ты замечаешь? Можно ли разбить множество А на части: несъедобные предметы и грибы? Можно ли разбить множество В на части: овощи и фрукты? Почему?', '</p>\n\n<p class="text">Разбей множества А и В на части: съедобные и несъедобные предметы. Сколько предметов в каждой части, во всём множестве? Что ты замечаешь?</p>\n\n<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica47-nomer2.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 47, номер 2, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 47, номер 2, год 2022."/>\n</div>\n\n<ul class="rus2">\n<li><span>Можно ли разбить множество А на части: несъедобные предметы и грибы?</span></li>\n<li><span>Можно ли разбить множество В на части: овощи и фрукты? Почему?</span></li>\n</ul>', 'Разобьем множества А на части: съедобные: белый гриб, лисичка и несъедобные: бабочка, стрекоза, мухомор и В на части: съедобные: груша, огурец, яблоко, томат и несъедобные: бабочка, стрекоза. А: 2 предмета в съедобной части и 3 предмета в не съедобной части, В: 4 предмета в съедобной части и 2 предмета в не съедобной части. В множестве А 5 предметов и в множестве В 6 предметов. Можно разбить множество А на части: несъедобные предметы и грибы. Можно разбить множество В на части: овощи и фрукты. Яблоко и груша это фрукт, а томат и огурец овощ.', '<p><span>Разобьем множества А на части: съедобные: белый гриб, лисичка и несъедобные: бабочка, стрекоза, мухомор и В на части: съедобные: груша, огурец, яблоко, томат и несъедобные: бабочка, стрекоза.</span>\n<span>А: 2 предмета в съедобной части и 3 предмета в не съедобной части, В: 4 предмета в съедобной части и 2 предмета в не съедобной части. В множестве А 5 предметов и в множестве В 6 предметов.</span>\n<span>Можно разбить множество А на части: несъедобные предметы и грибы. Можно разбить множество В на части: овощи и фрукты. Яблоко и груша это фрукт, а томат и огурец овощ.</span></p>', 'Разбиение множества на части по свойству (классификация) Множество разбито на части , если каждый его элемент попадает ровно в одну часть. Разбиение множества на части по некоторому свойству является своеобразным «наведением порядка» в множестве. Это разбиение называют также классификацией . Свойство, по которому множество разбито на части, называют основанием классификации .', '<div class="recomended-block">\n<span class="title">Разбиение множества на части по свойству (классификация)</span>\n<p>Множество <b class="black">разбито на части</b>, если каждый его элемент попадает ровно в одну часть.<br/>\nРазбиение множества на части по некоторому свойству является своеобразным «наведением порядка» в множестве. Это разбиение называют также <b class="black">классификацией</b>.<br/>\nСвойство, по которому множество разбито на части, называют <b class="black">основанием классификации</b>.</p>\n\n<div class="img-wrapper-460">\n<img width="200" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica47-recomended-block.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 47, рекомендательный блок, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 47, рекомендательный блок, год 2022."/>\n</div>', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-47/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, 'condition', 0, NULL, 'https://gdz-raketa.ru/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica47-nomer2.jpg', 'peterson/3/part1/page47/task2_condition_0.jpg', '');

    VALUES (v_task_id, v_textbook_id, 3, 'b4747115d8fbd848e652f1d9511a5ada34488ea4657d524a26d5c7d6f73bd459', NULL, '["раз"]'::jsonb, 'разбей множества а и в на части:съедобные и несъедобные предметы. сколько предметов в каждой части, во всём множестве? что ты замечаешь? можно ли разбить множество а на части:несъедобные предметы и грибы? можно ли разбить множество в на части:овощи и фрукты? почему');

    VALUES (v_textbook_id, 48, '3', 0, 'В каких множествах «наведён порядок»? Докажи. Как об этом можно сказать иначе?', '</p>\n\n<p class="text">В каких множествах «наведён порядок»? Докажи. Как об этом можно сказать иначе?</p>\n\n<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica48-nomer3.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 48, номер 3, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 48, номер 3, год 2022."/>\n</div>', 'а) Множество разбито на части, так как каждый его элемент попадает ровно в одну часть. Линии в подмножестве В, двумерные фигуры в подмножестве С.     Разбиение множества на части по некоторому свойству является своеобразным «наведением порядка» в множестве. б) Множество разбито на части, так как каждый его элемент попадает ровно в одну часть. Зеленые фигуры в подмножестве Е, синие фигуры в подмножестве F и желтые в множестве D.     Разбиение множества на части по некоторому свойству является своеобразным «наведением порядка» в множестве. в) Множество разбито на части, так как каждый его элемент попадает ровно в одну часть. Синие фигуры в подмножестве М, круглые фигуры в подмножестве К.     Разбиение множества на части по некоторому свойству является своеобразным «наведением порядка» в множестве. г) Множество разбито на части, так как каждый его элемент попадает ровно в одну часть. Зелёные прямоугольники в подмножестве Y, цилиндрические фигуры в подмножестве Z.     Разбиение множества на части по некоторому свойству является своеобразным «наведением порядка» в множестве.', '<p>а) Множество разбито на части, так как каждый его элемент попадает ровно в одну часть. Линии в подмножестве В, двумерные фигуры в подмножестве С.<br/>\n    Разбиение множества на части по некоторому свойству является своеобразным «наведением порядка» в множестве.<br/>\nб) Множество разбито на части, так как каждый его элемент попадает ровно в одну часть. Зеленые фигуры в подмножестве Е, синие фигуры в подмножестве F и желтые в множестве D.<br/>\n    Разбиение множества на части по некоторому свойству является своеобразным «наведением порядка» в множестве.<br/>\nв) Множество разбито на части, так как каждый его элемент попадает ровно в одну часть. Синие фигуры в подмножестве М, круглые фигуры в подмножестве К.<br/>\n    Разбиение множества на части по некоторому свойству является своеобразным «наведением порядка» в множестве.<br/>\nг) Множество разбито на части, так как каждый его элемент попадает ровно в одну часть. Зелёные прямоугольники в подмножестве Y, цилиндрические фигуры в подмножестве Z.<br/>\n    Разбиение множества на части по некоторому свойству является своеобразным «наведением порядка» в множестве.</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-48/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, 'condition', 0, NULL, 'https://gdz-raketa.ru/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica48-nomer3.jpg', 'peterson/3/part1/page48/task3_condition_0.jpg', '');

    VALUES (v_task_id, v_textbook_id, 3, '5fd9cb747730201a9c54f642f60c0e7b6fe80feaf150704b2283283c6ac1e548', NULL, NULL, 'в каких множествах "наведён порядок"? докажи. как об этом можно сказать иначе');

    VALUES (v_textbook_id, 48, '4', 1, 'Разбей на части множество чисел А = {5, 50, 84, 104, 435, 507, 930}. Найди несколько решений. Для каждого решения укажи основание классификации, полученные группы и их название. Образец: Основание классификации: делится на 2. I группа: {50, 84, 104, 930} – чётные числа. II группа: {5, 435, 507} – нечётные числа.', '</p>\n\n<p class="text">Разбей на части множество чисел А = {5, 50, 84, 104, 435, 507, 930}. Найди несколько решений. Для каждого решения укажи основание классификации, полученные группы и их название.</p>\n\n<p class="description-text">\n<span><b class="red">Образец:</b></span>\n<span><b>Основание классификации:</b> делится на 2.</span>\n<span><b>I группа:</b> {50, 84, 104, 930} – чётные числа.</span>\n<span><b>II группа:</b> {5, 435, 507} – нечётные числа.</span></p>', 'Основание классификации: делится на 3 1 группа: {5} – однозначные числа 2 группа: {50; 84} – двузначные числа 3 группа: {104; 435; 507; 930} – трёхзначные числа. Или Основание классификации: делится на 3 1 группа: {5; 50; 507} – числа начинаются с цифры 5 2 группа: {84; 104} – числа оканчивающихся на цифру 4 3 группа: {435; 930} – трёхзначные числа с цифрой 3 в десятых.', '<p><span>Основание классификации: делится на 3 </span>\n<span>1 группа: {5} – однозначные числа</span>\n<span>2 группа: {50; 84} – двузначные числа </span>\n<span>3 группа: {104; 435; 507; 930} – трёхзначные числа.</span> \n<span>Или</span>\n<span>Основание классификации: делится на 3 </span>\n<span>1 группа: {5; 50; 507} – числа начинаются с цифры 5</span>\n<span>2 группа: {84; 104} – числа оканчивающихся на цифру 4</span>\n<span>3 группа: {435; 930} – трёхзначные числа с цифрой 3 в десятых.</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-48/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '239dd3265b7ceb4d83d60a7f6d931086bbd59d52cb53bcf4cf49ca4b7fd5f844', '2,5,50,84,104,435,507,930', '["найди","раз","чётн","нечётн"]'::jsonb, 'разбей на части множество чисел а={5, 50, 84, 104, 435, 507, 930}. найди несколько решений. для каждого решения укажи основание классификации, полученные группы и их название. образец:основание классификации:делится на 2. i группа:{50, 84, 104, 930}-чётные числа. ii группа:{5, 435, 507}-нечётные числа');

    VALUES (v_textbook_id, 48, '5', 2, 'Назови элементы множества фигур на рисунке. Нарисуй его в тетради и разбей на части по форме. Составь 4 равенства. На какие ещё части можно разбить множество этих фигур?', '</p>\n\n<p class="text">Назови элементы множества фигур на рисунке. Нарисуй его в тетради и разбей на части по форме. Составь 4 равенства.</p>\n\n<div class="img-wrapper-460">\n<img width="250" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica48-nomer5.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 48, номер 5, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 48, номер 5, год 2022."/>\n</div>\n\n<p class="text">На какие ещё части можно разбить множество этих фигур?</p>', 'Зелёные и жёлтые, большие и маленькие треугольники и квадраты. Основание классификации: делится на 8.', '<p><span>Зелёные и жёлтые, большие и маленькие треугольники и квадраты.</span>\n<span>Основание классификации: делится на 8.</span></p>\n\n<div class="img-wrapper-460">\n<img width="340" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica48-nomer5-1.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 48, номер 5, год 2022, ответ." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 48, номер 5, год 2022, ответ."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-48/')
    RETURNING id INTO v_task_id;

