    VALUES (v_task_id, v_textbook_id, 3, '130fc589b0569eb9315b7a4be22478cfe62f6f6abb14a1cadb7bbf64ff78a16a', '4', '["раз"]'::jsonb, 'назови элементы множества фигур на рисунке. нарисуй его в тетради и разбей на части по форме. составь 4 равенства. на какие ещё части можно разбить множество этих фигур');

    VALUES (v_textbook_id, 48, '6', 3, 'Множества A, B, С и D содержат соответственно a , b , с и d элементов. Найди пропущенные буквы: a + b +     = d       a + c =     –     d – c – b =             c +     =     – a d – a = b +            b =     –     –         – a – b =                – c =     +', '</p>\n\n<p class="text">Множества A, B, С и D содержат соответственно <b>a</b>, <b>b</b>, <b>с</b> и <b>d</b> элементов. Найди пропущенные буквы:</p>\n\n<p class="description-text">\n<span>a + b + <span class="okon">   </span> = d       a + c = <span class="okon">   </span> – <span class="okon">   </span></span>\n<span>d – c – b = <span class="okon">   </span>        c + <span class="okon">   </span> = <span class="okon">   </span> – a</span>\n<span>d – a = b + <span class="okon">   </span>       b = <span class="okon">   </span> – <span class="okon">   </span> – <span class="okon">   </span></span>\n<span> <span class="okon">   </span> – a – b = <span class="okon">   </span>       <span class="okon">   </span> – c = <span class="okon">   </span> + <span class="okon">   </span></span></p>', 'a + b + с = d      a + c = d – b d – c – b = а      c + b = d – a d – a = b + с      b = d – a – c d – a – b = c      d – c = a + b', '<p><span>a + b + с = d      a + c = d – b</span>\n<span>d – c – b = а      c + b = d – a</span>\n<span>d – a = b + с      b = d – a – c</span>\n<span>d – a – b = c      d – c = a + b</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-48/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '7efdb5f98a6da782bc6d14b2381e0041f05d7edca5cac7ffaead764101d9118a', NULL, '["найди"]'::jsonb, 'множества a, b, с и d содержат соответственно a , b , с и d элементов. найди пропущенные буквы:a+b+   =d       a+c=   -    d-c-b=            c+   =   -a d-a=b+           b=   -   -       -a-b=              -c=   +');

    VALUES (v_textbook_id, 49, '7', 0, 'Собралось 6 охотников и 9 рыбаков, а всего 10 человек. Как это может быть?', '</p>\n\n<p class="text">Собралось 6 охотников и 9 рыбаков, а всего 10 человек. Как это может быть?</p>', 'Из собравшихся 10 человек возможно 9 рыбаков, 6 охотников: 10 – 9 = 1 только охотник и 6 – 1 = 5 из них и рыбак и охотник. 9 – 5 = 4 только рыбака. Тогда сложим 4 только рыбака, 1 только охотник и 5 рыбака и охотника: 4 + 1 + 5 = 10 человек.', '<p>Из собравшихся 10 человек возможно 9 рыбаков, 6 охотников: 10 – 9 = 1 только охотник и 6 – 1 = 5 из них и рыбак и охотник. 9 – 5 = 4 только рыбака. Тогда сложим 4 только рыбака, 1 только охотник и 5 рыбака и охотника: 4 + 1 + 5 = 10 человек.</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-49/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '4c8c49ebcf7850af2b165189ab0607e0759a73fa502e856744dbec695878ca48', '6,9,10', NULL, 'собралось 6 охотников и 9 рыбаков, а всего 10 человек. как это может быть');

    VALUES (v_textbook_id, 49, '8', 1, 'а) Охотник убегает от медведя после осечки ружья. За 5 секунд он пробежал 30 м. Сейчас он находится на расстоянии 360 м от домика лесника. Сколько времени нужно охотнику, чтобы добежать до лесника, если скорость его не изменится? б) Павлину в зоопарке за неделю добавляют в корм 350 г пшеницы. Сколько пшеницы при том же расходе в день съедает павлин в зоопарке за месяц (30 дней)?', '</p>\n\n<p class="text"><span>а) Охотник убегает от медведя после осечки ружья. За 5 секунд он пробежал 30 м. Сейчас он находится на расстоянии 360 м от домика лесника. Сколько времени нужно охотнику, чтобы добежать до лесника, если скорость его не изменится?</span>\n<span>б) Павлину в зоопарке за неделю добавляют в корм 350 г пшеницы. Сколько пшеницы при том же расходе в день съедает павлин в зоопарке за месяц (30 дней)?</span></p>', 'а) 360 : 30 · 5 = 12 · 5 = 60 (сек)      Ответ: 60 секунд нужно охотнику, чтобы добежать до лесника, если скорость его не изменится. б) Павлину в зоопарке за 7 дней в неделе добавляют в корм 350 г пшеницы.     350 : 7 = 50 (г) – в один день. 50 · 30 = 1500 (г)      Ответ: 1500 г пшеницы при том же расходе в день съедает павлин в зоопарке за месяц (30 дней).', '<p><span>а) 360 : 30 · 5 = 12 · 5 = 60 (сек)</span>\n<span>    <b>Ответ:</b> 60 секунд нужно охотнику, чтобы добежать до лесника, если скорость его не изменится.</span>\n<span>б) Павлину в зоопарке за 7 дней в неделе добавляют в корм 350 г пшеницы. </span>\n<span>    350 : 7 = 50 (г) – в один день. 50 · 30 = 1500 (г)</span>\n<span>    <b>Ответ:</b> 1500 г пшеницы при том же расходе в день съедает павлин в зоопарке за месяц (30 дней).</span></p>', '', '', TRUE, '[{"letter":"а","condition":"Охотник убегает от медведя после осечки ружья. За 5 секунд он пробежал 30 м. Сейчас он находится на расстоянии 360 м от домика лесника. Сколько времени нужно охотнику, чтобы добежать до лесника, если скорость его не изменится?","solution":"360 : 30 · 5 = 12 · 5 = 60 (сек)      Ответ: 60 секунд нужно охотнику, чтобы добежать до лесника, если скорость его не изменится."},{"letter":"б","condition":"Павлину в зоопарке за неделю добавляют в корм 350 г пшеницы. Сколько пшеницы при том же расходе в день съедает павлин в зоопарке за месяц (30 дней)?","solution":"Павлину в зоопарке за 7 дней в неделе добавляют в корм 350 г пшеницы.     350 : 7 = 50 ("},{"letter":"г","condition":"","solution":"– в один день. 50 · 30 = 1500 ("}]'::jsonb, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-49/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '36275d0f7c9c66d9180506c56b2b32473c6ac09269915e9f8863544166aafa9f', '5,30,350,360', NULL, 'а) охотник убегает от медведя после осечки ружья. за 5 секунд он пробежал 30 м. сейчас он находится на расстоянии 360 м от домика лесника. сколько времени нужно охотнику, чтобы добежать до лесника, если скорость его не изменится? б) павлину в зоопарке за неделю добавляют в корм 350 г пшеницы. сколько пшеницы при том же расходе в день съедает павлин в зоопарке за месяц (30 дней)');

    VALUES (v_textbook_id, 49, '9', 2, 'Вычисли. Объясни для каждого столбика приёмы вычислений: 39 · 8      17 · 50      540 : 3      700 : 35        56 : 9 5 · 76      280 · 2      860 : 2      600 : 120      38 : 15', '</p>\n\n<p class="text">Вычисли. Объясни для каждого столбика приёмы вычислений:</p>\n\n<p class="description-text">\n<span>39 · 8      17 · 50      540 : 3      700 : 35        56 : 9</span>\n<span>5 · 76      280 · 2      860 : 2      600 : 120      38 : 15</span></p>', '39 · 8 = 312 5 · 76 = 380 Умножение двузначного числа на однозначное 17 · 50 = 850 280 · 2 = 560 Умножение числе с цифрой 0 в единицах 540 : 3 = 180 860 : 2 = 430 Деление чисел с цифрой 0 в единицах и десятых на однозначное число 700 : 35 = 20 600 : 120 = 5 Деление чисел с цифрой 0 в единицах и десятых на двухзначное число 56 : 9 = 6 + 2 38 : 15 = 2 + 8 Деление с остатком', '<p><span>39 · 8 = 312</span>\n<span>5 · 76 = 380</span>\n<span>Умножение двузначного числа на однозначное</span>\n<span>17 · 50 = 850</span>\n<span>280 · 2 = 560</span>\n<span>Умножение числе с цифрой 0 в единицах</span>\n<span>540 : 3 = 180</span>\n<span>860 : 2 = 430</span>\n<span>Деление чисел с цифрой 0 в единицах и десятых на однозначное число</span>\n<span>700 : 35 = 20</span>\n<span>600 : 120 = 5</span>\n<span>Деление чисел с цифрой 0 в единицах и десятых на двухзначное число</span>\n<span>56 : 9 = 6 + 2</span>\n<span>38 : 15 = 2 + 8</span>\n<span>Деление с остатком</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-49/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '83f6b1a33605da3ea49319ae5d55045887fc696a38982bb67bdac22b21b3ca22', '2,3,5,8,9,15,17,35,38,39', '["вычисли","столбик"]'::jsonb, 'вычисли. объясни для каждого столбика приёмы вычислений:39*8      17*50      540:3      700:35        56:9 5*76      280*2      860:2      600:120      38:15');

