    VALUES (v_textbook_id, 49, '11', 4, 'Реши уравнения с комментированием и сделай проверку: х + 93 = 517      204 – х = 156      х – 429 = 361', '</p>\n\n<p class="text">Реши уравнения с комментированием и сделай проверку:</p>\n\n<p class="description-text">\nх + 93 = 517      204 – х = 156      х – 429 = 361</p>', 'х + 93 = 517 Что бы найти один из членов суммы х, вычтем из числа суммы известный член суммы х = 517 – 93', '<p><span>х + 93 = 517</span>\n<span>Что бы найти один из членов суммы х, вычтем из числа суммы известный член суммы</span>\n<span>х = 517 – 93</span></p>\n\n<div class="img-wrapper-460">\n<img width="120" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica49-nomer11.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 49, номер 11, год 2022, ответ." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 49, номер 11, год 2022, ответ."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-49/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, 'solution', 0, NULL, 'https://gdz-raketa.ru/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica49-nomer11.jpg', 'peterson/3/part1/page49/task11_solution_0.jpg', '');

    VALUES (v_task_id, v_textbook_id, 3, '463d366cdbd928a450a8c590644639e4f0db79c15b20abd8aece74a26a141f1e', '93,156,204,361,429,517', '["реши"]'::jsonb, 'реши уравнения с комментированием и сделай проверку:х+93=517      204-х=156      х-429=361');

    VALUES (v_textbook_id, 49, '12', 5, 'A – множество детских игрушек, B – множество кукол, C – множество пирамидок, D – множество игрушек в магазине «Малыш». Построй диаграмму множеств A, B, C и D. Раскрась множество кукол в магазине «Малыш».', '</p>\n\n<p class="text">A – множество детских игрушек, B – множество кукол, C – множество пирамидок, D – множество игрушек в магазине «Малыш». Построй диаграмму множеств A, B, C и D. Раскрась множество кукол в магазине «Малыш».</p>', '', '<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica49-nomer12.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 49, номер 12, год 2022, ответ." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 49, номер 12, год 2022, ответ."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-49/')
