    VALUES (v_task_id, v_textbook_id, 3, '26e0bf90ad8036ca9451ceda5e00e833b55105b736495f8e9fe37fb55c6c0bb2', NULL, NULL, 'a-множество детских игрушек, b-множество кукол, c-множество пирамидок, d-множество игрушек в магазине "малыш". построй диаграмму множеств a, b, c и d. раскрась множество кукол в магазине "малыш"');

    VALUES (v_textbook_id, 49, '13', 6, 'Ученики 3 класса ездили на экскурсии в Суздаль и Владимир. В Суздале побывали 12 учеников, а во Владимире – 18 учеников, причём в обоих городах побывали четверо ребят. Сколько учеников приняли участие в этих двух экскурсиях? Что ещё можно спросить?', '</p>\n\n<p class="text">Ученики 3 класса ездили на экскурсии в Суздаль и Владимир. В Суздале побывали 12 учеников, а во Владимире – 18 учеников, причём в обоих городах побывали четверо ребят. Сколько учеников приняли участие в этих двух экскурсиях? Что ещё можно спросить?</p>\n\n<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica49-nomer13.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 49, номер 13, год 2022, ответ." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 49, номер 13, год 2022, ответ."/>\n</div>', '12 – 4 = 8 (учеников) – только в Суздале. 18 – 4 = 14 (учеников) – только во Владимире. 8 + 4 + 14 = 26 (учеников) Ответ: 26 учеников приняли участие в этих двух экскурсиях. Сколько учеников приняли участие в экскурсии только в Суздале, только во Владимире?', '<p><span>12 – 4 = 8 (учеников) – только в Суздале.</span>\n<span>18 – 4 = 14 (учеников) – только во Владимире.</span>\n<span>8 + 4 + 14 = 26 (учеников)</span>\n<span><b>Ответ:</b> 26 учеников приняли участие в этих двух экскурсиях.</span>\n<span>Сколько учеников приняли участие в экскурсии только в Суздале, только во Владимире?</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-49/')
    RETURNING id INTO v_task_id;

