    VALUES (v_task_id, v_textbook_id, 3, 'ae1f4e4bc339f7d3b5d31c2b3518275f84c5feefeef4db57b005940c4285c676', '3,12,18', NULL, 'ученики 3 класса ездили на экскурсии в суздаль и владимир. в суздале побывали 12 учеников, а во владимире-18 учеников, причём в обоих городах побывали четверо ребят. сколько учеников приняли участие в этих двух экскурсиях? что ещё можно спросить');

    VALUES (v_textbook_id, 49, '14', 7, 'Вычисли, используя запись в столбик. Узнай, как прочитать эти числа: а) 12 345 + 98 765      в) 101 010 – 20 202 б) 77 777 + 7777        г) 100 000 – 99 999', '</p>\n\n<p class="text">Вычисли, используя запись в столбик. Узнай, как прочитать эти числа:</p>\n\n<p class="description-text">\n<span>а) 12 345 + 98 765      в) 101 010 – 20 202</span>\n<span>б) 77 777 + 7777        г) 100 000 – 99 999</span></p>', 'а) 12 345 + 98 765 = 111110', '<p>а) 12 345 + 98 765 = 111110</p>\n\n<div class="img-wrapper-460">\n<img width="180" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica49-nomer14.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 49, номер 14, год 2022, ответ." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 49, номер 14, год 2022, ответ."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-49/')
