    VALUES (v_task_id, v_textbook_id, 3, '2b7afc9a753fe8c18bd369add0f8e312ea5b4ee43e68a9f4a7712d6ae41c2e1f', '000,010,12,20,77,98,99,100,101,202', '["вычисли","столбик"]'::jsonb, 'вычисли, используя запись в столбик. узнай, как прочитать эти числа:а) 12 345+98 765      в) 101 010-20 202 б) 77 777+7777        г) 100 000-99 999');

    VALUES (v_textbook_id, 50, '1', 0, 'А = {карандаш, ручка, чашка, мел, блюдце}. Разбей множество А на части по назначению.', '</p>\n\n<p class="text">А = {карандаш, ручка, чашка, мел, блюдце}. Разбей множество А на части по назначению.</p>', 'Основание классификации: делится на 2 части. 1 группа: {карандаш; ручка; мел} – канцелярия. 2 группа: {чашка; блюдце} – посуда.', '<p><span>Основание классификации: делится на 2 части.</span>\n<span>1 группа: {карандаш; ручка; мел} – канцелярия.</span>\n<span>2 группа: {чашка; блюдце} – посуда.</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-50/')
    RETURNING id INTO v_task_id;

