    VALUES (v_textbook_id, 50, '2', 1, 'Множество В = {5, 6, 23, 42, 50, 51, 60} разбито на части. Укажи основание классификации. а) {5, 6} и {23, 42, 50, 51, 60}      в) {50, 60} и {5, 6, 23, 42, 51} б) {5, 23, 50} и {6, 42, 51, 60}      г) {6, 42, 50, 60} и {5, 23, 51}', '</p>\n\n<p class="text">Множество В = {5, 6, 23, 42, 50, 51, 60} разбито на части. Укажи основание классификации.</p>\n\n<p class="description-text">\n<span>а) {5, 6} и {23, 42, 50, 51, 60}      в) {50, 60} и {5, 6, 23, 42, 51}</span>\n<span>б) {5, 23, 50} и {6, 42, 51, 60}      г) {6, 42, 50, 60} и {5, 23, 51}</span></p>', 'а) {5, 6} – однозначные числа и {23, 42, 50, 51, 60} – двузначные числа. б) {5, 23, 50} – чисел сумма цифр которого=5 и {6, 42, 51, 60} – множество чисел, сумма цифр которого = 6. в) {50, 60} – числа с круглыми десятками и {5, 6, 23, 42, 51} – сумма разрядов чисел равна 5 и 6. г) {6, 42, 50, 60} – чётные и {5, 23, 51} – нечётные.', '<p><span>а) {5, 6} – однозначные числа и {23, 42, 50, 51, 60} – двузначные числа.</span>\n<span>б) {5, 23, 50} – чисел сумма цифр которого=5 и {6, 42, 51, 60} – множество чисел, сумма цифр которого = 6.</span>\n<span>в) {50, 60} – числа с круглыми десятками и {5, 6, 23, 42, 51} – сумма разрядов чисел равна 5 и 6.</span>\n<span>г) {6, 42, 50, 60} – чётные и {5, 23, 51} – нечётные.</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-50/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '07a2702f7ea833757327c04d93d0ef2c4518f8ed2c4d2068c6f47cce6d320a7c', '5,6,23,42,50,51,60', '["раз"]'::jsonb, 'множество в={5, 6, 23, 42, 50, 51, 60} разбито на части. укажи основание классификации. а) {5, 6} и {23, 42, 50, 51, 60}      в) {50, 60} и {5, 6, 23, 42, 51} б) {5, 23, 50} и {6, 42, 51, 60}      г) {6, 42, 50, 60} и {5, 23, 51}');

    VALUES (v_textbook_id, 50, '3', 2, 'Выполни умножение в столбик: 42 · 7      94 · 5      73 · 6      89 · 4', '</p>\n\n<p class="text">Выполни умножение в столбик:</p>\n\n<p class="description-text">\n42 · 7      94 · 5      73 · 6      89 · 4</p>', '42 · 7 = 294', '<p>42 · 7 = 294</p>\n\n<div class="img-wrapper-460">\n<img width="100" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica50-nomer3.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 50, номер 3, год 2022, ответ." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 50, номер 3, год 2022, ответ."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-50/')
    RETURNING id INTO v_task_id;

