    VALUES (v_task_id, v_textbook_id, 3, 'c417ad40a4e21572ae88c2a9ef229ac5d7be54a438fbfe95936fe89a766dec42', '4,5,6,7,42,73,89,94', '["столбик"]'::jsonb, 'выполни умножение в столбик:42*7      94*5      73*6      89*4');

    VALUES (v_textbook_id, 50, '4', 3, 'Составь выражения и найди их значения: а) В 4 ящиках 64 кг яблок. Сколько килограммов яблок в 7 таких ящиках? б) Кадушка вмещает 72 л воды, а бочка – 160 л. Кадушку наполняют 9 вёдер воды. Сколько таких вёдер нужно, чтобы наполнить бочку?', '</p>\n\n<p class="text">Составь выражения и найди их значения:</p>\n\n<p class="description-text">\n<span>а) В 4 ящиках 64 кг яблок. Сколько килограммов яблок в 7 таких ящиках?</span>\n<span>б) Кадушка вмещает 72 л воды, а бочка – 160 л. Кадушку наполняют 9 вёдер воды. Сколько  таких вёдер нужно, чтобы наполнить бочку?</span></p>', 'а) 64 : 4 · 7 = 16 · 7 = 112 (кг)      Ответ: 112 килограммов яблок в 7 таких ящиках. б) 72 : 9 = 8 (л) – в 1 ведре, 160 : 8 = 20 (ведёр)      Ответ: 20 таких вёдер нужно, чтобы наполнить бочку.', '<p><span>а) 64 : 4 · 7 = 16 · 7 = 112 (кг)</span>\n<span>    <b>Ответ:</b> 112 килограммов яблок в 7 таких ящиках.</span>\n<span>б) 72 : 9 = 8 (л) – в 1 ведре, 160 : 8 = 20 (ведёр)</span>\n<span>    <b>Ответ:</b> 20 таких вёдер нужно, чтобы наполнить бочку.</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-50/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, 'ee2c2ce68e57c58883bec9d1638a060b61eedfe6d8a9ca03db9df40a715387ec', '4,7,9,64,72,160', '["найди"]'::jsonb, 'составь выражения и найди их значения:а) в 4 ящиках 64 кг яблок. сколько килограммов яблок в 7 таких ящиках? б) кадушка вмещает 72 л воды, а бочка-160 л. кадушку наполняют 9 вёдер воды. сколько таких вёдер нужно, чтобы наполнить бочку');

    VALUES (v_textbook_id, 50, '5', 4, 'Объясни, что означают записанные свойства. Какое свойство пропущено? Запиши его в тетради.', '</p>\n\n<p class="text">Объясни, что означают записанные свойства. Какое свойство пропущено? Запиши его в тетради.</p>\n\n<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica50-nomer5.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 50, номер 5, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 50, номер 5, год 2022."/>\n</div>', 'Переместительное свойство сложения: а + b = b + a От перестановки мест слагаемых сумма не меняется. Сочетательное свойство сложения: (a + b) + c = a + (b + c) Чтобы к сумме прибавить число, можно к первому слагаемому прибавить сумму второго и третьего слагаемых. Переместительное свойство умножения – от перестановки мест множителей произведение не изменяется. a · b = b · a Пропущено: сочетательное свойство умножения. (a · b) · c = a · (b · c) Произведение трех и более множителей не изменится, если какую-то группу множителей заменить их произведением.', '<p><span>Переместительное свойство сложения: а + b = b + a</span>\n<span>От перестановки мест слагаемых сумма не меняется.</span>\n<span>Сочетательное свойство сложения: (a + b) + c = a + (b + c)</span>\n<span>Чтобы к сумме прибавить число, можно к первому слагаемому прибавить сумму второго и третьего слагаемых.</span>\n<span>Переместительное свойство умножения – от перестановки мест множителей произведение не изменяется. a · b = b · a</span>\n<span>Пропущено: сочетательное свойство умножения. (a · b) · c = a · (b · c)</span>\n<span>Произведение трех и более множителей не изменится, если какую-то группу множителей заменить их произведением.</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-50/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, 'condition', 0, NULL, 'https://gdz-raketa.ru/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica50-nomer5.jpg', 'peterson/3/part1/page50/task5_condition_0.jpg', '');

    VALUES (v_task_id, v_textbook_id, 3, '46b9769957ba46a803cd6a91bb27e54b76d71db7c07d8042e4f0bd67ee910fd2', NULL, NULL, 'объясни, что означают записанные свойства. какое свойство пропущено? запиши его в тетради');

    VALUES (v_textbook_id, 50, '6', 5, 'а) Проанализируй равенства и объясни способ умножения круглых чисел: 8 · 60 = 8 · (6 · 10) = (8 · 6) · 10 = 48 · 10 = 480 20 · 30 = (2 · 10) · (3 · 10) = (2 · 3) · (10 · 10) = 6 · 100 = 600 Пользуясь этим способом, объясни, почему умножение круглых чисел в столбик записывают так: б) Запиши в тетради примеры в столбик и вычисли: 28 · 30      490 · 2      36 · 20      160 · 6      25 · 40', '</p>\n\n<p class="text">а) Проанализируй равенства и объясни способ умножения круглых чисел:</p>\n\n<p class="description-text">\n<span>8 · 60 = 8 · (6 · 10) = (8 · 6) · 10 = 48 · 10 = 480</span>\n<span>20 · 30 = (2 · 10) · (3 · 10) = (2 · 3) · (10 · 10) = 6 · 100 = 600</span></p>\n\n<p class="text">Пользуясь этим способом, объясни, почему умножение круглых чисел в столбик записывают так:</p>\n\n<div class="img-wrapper-460">\n<img width="260" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica50-nomer6.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 50, номер 6, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 50, номер 6, год 2022."/>\n</div>\n\n<p class="text">б) Запиши в тетради примеры в столбик и вычисли:</p>\n\n<p class="description-text">\n28 · 30      490 · 2      36 · 20      160 · 6      25 · 40</p>', 'а) Чтобы умножить круглые числа, можно отбросить нули на конце этих чисел, а к произведению приписать столько нулей, сколько их всего было отброшено. б) 28 · 30 = 840', '<p><span>а) Чтобы умножить круглые числа, можно отбросить нули на конце этих чисел, а к произведению приписать столько нулей, сколько их всего было отброшено.</span>\n<br/>\n<span>б) 28 · 30 = 840</span></p>\n\n<div class="img-wrapper-460">\n<img width="120" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica50-nomer6-5.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 50, номер 6, год 2022, ответ." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 50, номер 6, год 2022, ответ."/>', '', '', TRUE, '[{"letter":"а","condition":"Проанализируй равенства и объясни способ умножения круглых чисел: 8 · 60 = 8 · (6 · 10) = (8 · 6) · 10 = 48 · 10 = 480 20 · 30 = (2 · 10) · (3 · 10) = (2 · 3) · (10 · 10) = 6 · 100 = 600 Пользуясь этим способом, объясни, почему умножение круглых чисел в столбик записывают так:","solution":"Чтобы умножить круглые числа, можно отбросить нули на конце этих чисел, а к произведению приписать столько нулей, сколько их всего было отброшено."},{"letter":"б","condition":"Запиши в тетради примеры в столбик и вычисли: 28 · 30      490 · 2      36 · 20      160 · 6      25 · 40","solution":"28 · 30 = 840"}]'::jsonb, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-50/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, 'condition', 0, NULL, 'https://gdz-raketa.ru/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica50-nomer6.jpg', 'peterson/3/part1/page50/task6_condition_0.jpg', '');

    VALUES (v_task_id, 'solution', 0, NULL, 'https://gdz-raketa.ru/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica50-nomer6-5.jpg', 'peterson/3/part1/page50/task6_solution_0.jpg', '');

    VALUES (v_task_id, v_textbook_id, 3, 'cef6b78f8b496fea553e4073235ff28ad493eef1471c96a367bfc31095a73692', '2,3,6,8,10,20,25,28,30,36', '["вычисли","столбик"]'::jsonb, 'а) проанализируй равенства и объясни способ умножения круглых чисел:8*60=8*(6*10)=(8*6)*10=48*10=480 20*30=(2*10)*(3*10)=(2*3)*(10*10)=6*100=600 пользуясь этим способом, объясни, почему умножение круглых чисел в столбик записывают так:б) запиши в тетради примеры в столбик и вычисли:28*30      490*2      36*20      160*6      25*40');

    VALUES (v_textbook_id, 51, '7', 0, 'Андрей поймал 20 раков, Вася – в 2 раза меньше Андрея, Юля – на 12 раков меньше, чем Андрей и Вася вместе, а Даша поймала на 4 рака больше Васи. Сколько всего раков поймали ребята? Кто поймал больше раков – мальчики или девочки, и на сколько?', '</p>\n\n<p class="text">Андрей поймал 20 раков, Вася – в 2 раза меньше Андрея, Юля – на 12 раков меньше, чем Андрей и Вася вместе, а Даша поймала на  4 рака больше Васи. Сколько всего раков поймали ребята? Кто поймал больше раков – мальчики или девочки, и на сколько?</p>\n\n<div class="img-wrapper-460">\n<img width="350" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica51-nomer7.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 51, номер 7, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 51, номер 7, год 2022."/>\n</div>', '20 : 2 = 10 (раков) – Вася (20 : 2 + 20) – 12 = 30 – 12 = 18 (раков) – Юля 20 : 2 + 4 = 10 + 4 = 14 (раков) – Даша 20 + 10 = 30 (раков) – мальчики 18 + 14 = 32 (рака) – девочки 32 ˃ 30, 32 – 30 = 2 (рака) 30 + 32 = 62 (рака) Ответ: 62рака всего поймали ребята. Девочки поймали больше раков, чем мальчики на 2 рака.', '<p><span>20 : 2 = 10 (раков) – Вася</span>\n<span>(20 : 2 + 20) – 12 = 30 – 12 = 18 (раков) – Юля</span>\n<span>20 : 2 + 4 = 10 + 4 = 14 (раков) – Даша</span>\n<span>20 + 10 = 30 (раков) – мальчики</span>\n<span>18 + 14 = 32 (рака) – девочки</span>\n<span>32 ˃ 30, 32 – 30 = 2 (рака)</span>\n<span>30 + 32 = 62 (рака)</span>\n<span><b>Ответ:</b> 62рака всего поймали ребята. Девочки поймали больше раков, чем мальчики на 2 рака.</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-51/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, 'condition', 0, NULL, 'https://gdz-raketa.ru/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica51-nomer7.jpg', 'peterson/3/part1/page51/task7_condition_0.jpg', '');

    VALUES (v_task_id, v_textbook_id, 3, '5fd5db8b47fe44d2a6ceb1970949c94b1f8427c68a85de301394219844f93818', '2,4,12,20', '["больше","меньше","раз","раза"]'::jsonb, 'андрей поймал 20 раков, вася-в 2 раза меньше андрея, юля-на 12 раков меньше, чем андрей и вася вместе, а даша поймала на 4 рака больше васи. сколько всего раков поймали ребята? кто поймал больше раков-мальчики или девочки, и на сколько');

    VALUES (v_textbook_id, 51, '8', 1, 'Составь программу действий и вычисли: а) 48 : (36 : 6) : 1 + (0 · 4 + 3) · 9 – 0 : 12 · 3 б) 16 : (72 : 8 + 7 · 1) – 0 : (8 · 8) : 1 + 56 : 56 · 4', '</p>\n\n<p class="text">Составь программу действий и вычисли:</p>\n\n<p class="description-text">\n<span>а) 48 : (36 : 6) : 1 + (0 · 4 + 3) · 9 – 0 : 12 · 3</span>\n<span>б) 16 : (72 : 8 + 7 · 1) – 0 : (8 · 8) : 1  + 56 : 56 · 4</span></p>', 'а) 48 : (36 : 6) : 1 + (0 · 4 + 3) · 9 – 0 : 12 · 3 = 35     36 : 6 = 6     0 · 4 = 0     0 + 3 = 3     48 : 6 = 8     8 : 1 = 8     3 · 9 = 27     0 : 12 = 0     0 · 3 = 0     8 + 27 = 35     35 – 0 = 35 б) 16 : (72 : 8 + 7 · 1) – 0 : (8 · 8) : 1 + 56 : 56 · 4 = 5     72 : 8 = 9     7 · 1 = 7     9 + 7 = 16     16 : 16 = 1     8 · 8 = 64     0 : 64 = 0     0 : 1 = 0     56 : 56 = 1     1 · 4 = 4     1 – 0 = 1     1 + 4 = 5', '<p><span>а) 48 : (36 : 6) : 1 + (0 · 4 + 3) · 9 – 0 : 12 · 3 = 35</span>\n<span>    36 : 6 = 6</span>\n<span>    0 · 4 = 0</span>\n<span>    0 + 3 = 3</span>\n<span>    48 : 6 = 8</span>\n<span>    8 : 1 = 8</span>\n<span>    3 · 9 = 27</span>\n<span>    0 : 12 = 0</span>\n<span>    0 · 3 = 0</span>\n<span>    8 + 27 = 35</span>\n<span>    35 – 0 = 35</span>\n<span>б) 16 : (72 : 8 + 7 · 1) – 0 : (8 · 8) : 1 + 56 : 56 · 4 = 5</span>\n<span>    72 : 8 = 9</span>\n<span>    7 · 1 = 7</span>\n<span>    9 + 7 = 16</span>\n<span>    16 : 16 = 1</span>\n<span>    8 · 8 = 64</span>\n<span>    0 : 64 = 0</span>\n<span>    0 : 1 = 0</span>\n<span>    56 : 56 = 1</span>\n<span>    1 · 4 = 4</span>\n<span>    1 – 0 = 1</span>\n<span>    1 + 4 = 5</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-51/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '289c7b1ecfb8cf8714f5dd1882a282affe497d4a425b366729029342579ec493', '0,1,3,4,6,7,8,9,12,16', '["вычисли"]'::jsonb, 'составь программу действий и вычисли:а) 48:(36:6):1+(0*4+3)*9-0:12*3 б) 16:(72:8+7*1)-0:(8*8):1+56:56*4');

    VALUES (v_textbook_id, 51, '9', 2, 'А = {4, 8, 12, 16, 20}, В = {8, 16, 24}. Найди пересечение и объединение множеств А и В. Построй диаграмму этих множеств и отметь на ней их элементы.', '</p>\n\n<p class="text">А = {4, 8, 12, 16, 20}, В = {8, 16, 24}. Найди пересечение и объединение множеств А и В. Построй диаграмму этих множеств и отметь на ней их элементы.</p>', 'А ∩ В = {8, 16}', '<p>А ∩ В = {8, 16}</p>\n\n<div class="img-wrapper-460">\n<img width="320" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica51-nomer9.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 51, номер 9, год 2022, ответ." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 51, номер 9, год 2022, ответ."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-51/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, 'solution', 0, NULL, 'https://gdz-raketa.ru/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica51-nomer9.jpg', 'peterson/3/part1/page51/task9_solution_0.jpg', '');

    VALUES (v_task_id, v_textbook_id, 3, 'ed9a11e561ae4bbe4ed0f4744a4b6f7ce1b73116f341a0a0399073910faeb9c8', '4,8,12,16,20,24', '["найди"]'::jsonb, 'а={4, 8, 12, 16, 20}, в={8, 16, 24}. найди пересечение и объединение множеств а и в. построй диаграмму этих множеств и отметь на ней их элементы');

    VALUES (v_textbook_id, 51, '10', 3, 'Объясни решение примеров, записанных в столбик. Используя полученные результаты, устно найди ответы остальных примеров.', '</p>\n\n<p class="text">Объясни решение примеров, записанных в столбик. Используя полученные результаты, устно найди ответы остальных примеров.</p>\n\n<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica51-nomer10.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 51, номер 10, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 51, номер 10, год 2022."/>\n</div>', 'Числа записываются одно под другим, цифры каждого разряда располагаются, соответственно, одна под другой. Слева ставим знак &#34;плюс&#34;, а под числами проводим горизонтальную линию. Теперь мысленно разбиваем запись на столбики по разрядам. остается сделать – сложить однозначные числа в каждом столбике. 319 + 485 = 804 319 больше чем 318 на 1, поэтому сумма будет тоже больше на 1 318 + 484 = 802 484 меньше 485 на 1, поэтому сумма будет тоже меньше на 1 319 + 484 = 803 319 больше 318 на 1 и 484 меньше 485 на 1, поэтому суммы будут равны 328 + 485 = 813 328 больше чем 318 на 10, поэтому сумма будет тоже больше на 10 803 – 485 = 318 При вычитании из суммы одно слагаемое, то получим второе слагаемое 903 – 585 = 318 При вычитании из увеличенной суммы на 10 слагаемое тоже увеличенного на 10 получим второе самое слагаемое. При вычитании столбиком самое главное – правильно записать исходные данные, чтобы единицы вычитаемого были под единицами уменьшаемого. Вычитание столбиком начинаем с самой правой цифры. Вычитаем единицы. Результат записываем в единицах разности (под чертой). Далее вычитаем десятки: 1 десяток минус 0 десятков. Вычитаем сотни. 953 – 587 = 366 953 больше 952 на 1, поэтому разность тоже больше на 1 952 – 588 = 364 588 больше 587 на 1, поэтому разность меньше на 1 953 – 588 = 365 953 больше 352 на 1 и 588 больше 587 на 1, поэтому разность остается той же 852 – 587 = 265 852 меньше 952 на 100, поэтому разность меньше на 100 952 – 687 = 265 687 больше 587 на 100, поэтому разность меньше на 100 365 + 587 = 952 Сумма разности и вычитаемого дает уменьшаемое.', '<p><span>Числа записываются одно под другим, цифры каждого разряда располагаются, соответственно, одна под другой. Слева ставим знак &#34;плюс&#34;, а под числами проводим горизонтальную линию. Теперь мысленно разбиваем запись на столбики по разрядам. остается сделать – сложить однозначные числа в каждом столбике.</span> \n<span>319 + 485 = 804</span>\n<span>319 больше чем 318 на 1, поэтому сумма будет тоже больше на 1</span>\n<span>318 + 484 = 802</span>\n<span>484 меньше 485 на 1, поэтому сумма будет тоже меньше на 1</span>\n<span>319 + 484 = 803</span>\n<span>319 больше 318 на 1 и 484 меньше 485 на 1, поэтому суммы будут равны</span>\n<span>328 + 485 = 813</span>\n<span>328 больше чем 318 на 10, поэтому сумма будет тоже больше на 10</span>\n<span>803 – 485 = 318</span>\n<span>При вычитании из суммы одно слагаемое, то получим второе слагаемое</span>\n<span>903 – 585 = 318</span>\n<span>При вычитании из увеличенной суммы на 10 слагаемое тоже увеличенного на 10 получим второе самое слагаемое.</span>\n<span>При вычитании столбиком самое главное – правильно записать исходные данные, чтобы единицы вычитаемого были под единицами уменьшаемого.</span> \n<span>Вычитание столбиком начинаем с самой правой цифры. Вычитаем единицы. Результат записываем в единицах разности (под чертой).</span>\n<span>Далее вычитаем десятки: 1 десяток минус 0 десятков. Вычитаем сотни. </span>\n<span>953 – 587 = 366</span>\n<span>953 больше 952 на 1, поэтому разность тоже больше на 1</span>\n<span>952 – 588 = 364</span>\n<span>588 больше 587 на 1, поэтому разность меньше на 1</span>\n<span>953 – 588 = 365</span>\n<span>953 больше 352 на 1 и 588 больше 587 на 1, поэтому разность остается той же</span>\n<span>852 – 587 = 265</span>\n<span>852 меньше 952 на 100, поэтому разность меньше на 100</span>\n<span>952 – 687 = 265</span>\n<span>687 больше 587 на 100, поэтому разность меньше на 100</span>\n<span>365 + 587 = 952</span>\n<span>Сумма разности и вычитаемого дает уменьшаемое.</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-51/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, 'condition', 0, NULL, 'https://gdz-raketa.ru/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica51-nomer10.jpg', 'peterson/3/part1/page51/task10_condition_0.jpg', '');

    VALUES (v_task_id, v_textbook_id, 3, '22dbc8988dc24ad67b35fb22c30c09b874cf9ba1173cde6a661576dcba12804d', NULL, '["найди","столбик"]'::jsonb, 'объясни решение примеров, записанных в столбик. используя полученные результаты, устно найди ответы остальных примеров');

    VALUES (v_textbook_id, 51, '11', 4, 'В множестве А два элемента, в множестве В три элемента. При каком условии множество А U В будет содержать 2 + 3 = 5 элементов?', '</p>\n\n<p class="text">В множестве А два элемента, в множестве В три элемента. При каком условии множество А U В будет содержать 2 + 3 = 5 элементов?</p>', 'При условии что два элемента множества А не принадлежат множеству В и три элемента множества В не принадлежат множеству А, то множество А U В будет содержать 2 + 3 = 5 элементов.', '<p>При условии что два элемента множества А не принадлежат множеству В и  три элемента множества В не принадлежат множеству А, то множество А U В будет содержать 2 + 3 = 5 элементов.</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-51/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '49b31e77f95aafa5492c2d613f3542108b4d486857e51c706ae35baac36f0230', '2,3,5', NULL, 'в множестве а два элемента, в множестве в три элемента. при каком условии множество а u в будет содержать 2+3=5 элементов');

    VALUES (v_textbook_id, 51, '12', 5, 'Как расположить 5 элементов на диаграммах множеств А и В, чтобы в каждом из множеств было соответственно: а) 2 и 4 элемента; б) по 4 элемента; в) 4 и 5 элементов; г) по 5 элементов; д) 3 и 2 элемента; е) по 3 элемента?', '</p>\n\n<p class="text">Как расположить 5 элементов на диаграммах множеств А и В, чтобы в каждом из множеств было соответственно: а) 2 и 4 элемента; б) по 4 элемента; в) 4 и 5 элементов; г) по 5 элементов; д) 3 и 2 элемента; е) по 3 элемента?</p>\n\n<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica51-nomer12.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 51, номер 12, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 51, номер 12, год 2022."/>\n</div>', '', '<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica51-nomer12-1.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 51, номер 12, год 2022, ответ." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 51, номер 12, год 2022, ответ."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-51/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, 'condition', 0, NULL, 'https://gdz-raketa.ru/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica51-nomer12.jpg', 'peterson/3/part1/page51/task12_condition_0.jpg', '');

    VALUES (v_task_id, 'solution', 0, NULL, 'https://gdz-raketa.ru/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica51-nomer12-1.jpg', 'peterson/3/part1/page51/task12_solution_0.jpg', '');

    VALUES (v_task_id, v_textbook_id, 3, '60239fb363cf900b865d07d1d25fad6d859e844b6e480ecfdaa527c113a8bbcb', '2,3,4,5', NULL, 'как расположить 5 элементов на диаграммах множеств а и в, чтобы в каждом из множеств было соответственно:а) 2 и 4 элемента; б) по 4 элемента; в) 4 и 5 элементов; г) по 5 элементов; д) 3 и 2 элемента; е) по 3 элемента');

    VALUES (v_textbook_id, 65, '1', 0, 'а) Для чего служат натуральные числа? Назови первые 5 чисел натурального ряда. Чем интересно число 999? Назови подряд следующие 5 чисел. б) Попробуй прочитать число: 456980. Как читают многозначные числа?', '</p>\n\n<p class="text"><span>а) Для чего служат натуральные числа? Назови первые 5 чисел натурального ряда. Чем интересно число 999? Назови подряд следующие 5 чисел.</span>\n<span>б) Попробуй прочитать число: 456980. Как читают многозначные числа?</span></p>', 'а) Натуральные числа служат для счета предметов, объектов. 0, 1, 2, 3, 4. 999 – это самое большое трёхзначное число. 1000, 1001, 1002, 1003, 1004. б) четыреста пятьдесят шесть тысяч девятьсот восемьдесят. Многозначные числа читают слева направо. Разбивают число по 3 цифры с конца на классы, называют все цифры, кроме нуля. Цифра 0 в записи числа означают отсутствие разряда.', '<p><span>а) Натуральные числа служат для счета предметов, объектов. 0, 1, 2, 3, 4. 999 – это самое большое трёхзначное число. 1000, 1001, 1002, 1003, 1004.</span>\n<span>б) четыреста пятьдесят шесть тысяч девятьсот восемьдесят. Многозначные числа читают слева направо. Разбивают число по 3 цифры с конца на классы, называют все цифры, кроме нуля. Цифра 0 в записи числа означают отсутствие разряда.</span></p>', 'Нумерация многозначных чисел При счёте предметов используют натуральные числа . Множество натуральных чисел обозначают буквой N:                N = {1, 2, 3, ...} Мы используем десятичную позиционную систему записи чисел: 1) 10 единиц каждого разряда образуют 1 единицу следующего разряда (10 ед. = 1 дес., 10 дес. = 1 сот. и т.д.); 2) значение цифры зависит от её позиции (цифра 5 в разряде десятков – это 50, а в разряде сотен – 500). Благодаря этому любое натуральное число можно записать с помощью всего лишь 10 цифр: 0, 1, 2, 3, 4, 5, 6, 7, 8 и 9. Число 0 не является натуральным числом . Цифра 0 в записи числа означает отсутствие единиц соответствующего разряда. Для чтения натуральных чисел их разбивают, начиная справа, на группы по 3 цифры в каждой. Эти группы называют классами . В таблице показаны первые четыре класса в записи натуральных чисел – единицы, тысячи, миллионы и миллиарды, а так же разрядные единицы этих классов.', '<div class="recomended-block">\n<span class="title">Нумерация многозначных чисел</span>\n<p>При счёте предметов используют <b class="black">натуральные числа</b>. Множество натуральных чисел обозначают буквой N:<br/>\n               N = {1, 2, 3, ...}<br/>\nМы используем <b class="black">десятичную позиционную</b> систему записи чисел:<br/>\n1) 10 единиц каждого разряда образуют 1 единицу следующего разряда (10 ед. = 1 дес., 10 дес. = 1 сот. и т.д.);<br/>\n2) значение цифры зависит от её позиции (цифра 5 в разряде десятков – это 50, а в разряде сотен – 500).<br/>\nБлагодаря этому любое натуральное число можно записать с  помощью всего лишь 10 цифр: 0, 1, 2, 3, 4, 5, 6, 7, 8 и 9.<br/>\n<b class="black">Число 0 не является натуральным числом</b>. Цифра 0 в записи числа означает отсутствие единиц соответствующего разряда.<br/>\nДля чтения натуральных чисел их разбивают, начиная справа, на группы по 3 цифры в каждой. Эти группы называют <b class="black">классами</b>.<br/>\nВ таблице показаны первые четыре класса в записи натуральных чисел – единицы, тысячи, миллионы и миллиарды, а так же разрядные единицы этих классов.</p>\n\n<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica65-recomended-block.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 65, рекомендательный блок, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 65, рекомендательный блок, год 2022."/>\n</div>', TRUE, '[{"letter":"а","condition":"Для чего служат натуральные числа? Назови первые 5 чисел натурального ряда. Чем интересно число 999? Назови подряд следующие 5 чисел.","solution":"Натуральные числа служат для счета предметов, объектов. 0, 1, 2, 3, 4. 999 – это самое большое трёхзначное число. 1000, 1001, 1002, 1003, 1004."},{"letter":"б","condition":"Попробуй прочитать число: 456980. Как читают многозначные числа?","solution":"четыреста пятьдесят шесть тысяч девятьсот восемьдесят. Многозначные числа читают слева направо. Разбивают число по 3 цифры с конца на классы, называют все цифры, кроме нуля. Цифра 0 в записи числа означают отсутствие разряда."}]'::jsonb, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-65/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '7241b3320045f43b7967071d18a63e093e2b7e5737217a73ceb6be87a4ade50e', '5,999,456980', NULL, 'а) для чего служат натуральные числа? назови первые 5 чисел натурального ряда. чем интересно число 999? назови подряд следующие 5 чисел. б) попробуй прочитать число:456980. как читают многозначные числа');

    VALUES (v_textbook_id, 66, '2', 0, 'Прочитай числа, записанные в таблице. Что обозначает цифра 8 в их записи?', '</p>\n\n<p class="text">Прочитай числа, записанные в таблице. Что обозначает цифра 8 в их записи?</p>\n\n<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica66-nomer2.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 66, номер 2, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 66, номер 2, год 2022."/>\n</div>', 'Восемьсот пять, девятьсот восемьдесят, восемь тысяч триста девятнадцать, пятьдесят тысяч, восемьдесят шесть тысяч семьсот пять, пятьсот тысяч, восемьсот тринадцать тысяч шестьсот семьдесят три, девять миллионов семьсот двадцать одна тысяча двести десять, шестьдесят восемь миллионов сорок пять тысяч девятьсот, восемьсот тридцать миллионов семь, шесть миллиардов девятьсот восемьдесят два миллиона пятьдесят тысяч сто шестьдесят пять, восемьдесят четыре миллиарда триста тридцать четыре миллиона двести семнадцать тысяч пятьсот двадцать девять, восемьсот тридцать восемь миллиардов пятьсот двадцать семь миллионов четыреста сорок четыре тысячи четыреста двенадцать.', '<p>Восемьсот пять, девятьсот восемьдесят, восемь тысяч триста девятнадцать, пятьдесят тысяч, восемьдесят шесть тысяч семьсот пять, пятьсот тысяч, восемьсот тринадцать тысяч шестьсот семьдесят три, девять миллионов семьсот двадцать одна тысяча двести десять, шестьдесят восемь миллионов сорок пять тысяч девятьсот, восемьсот тридцать миллионов семь, шесть миллиардов девятьсот восемьдесят два миллиона пятьдесят тысяч сто шестьдесят пять, восемьдесят четыре миллиарда триста тридцать четыре миллиона двести семнадцать тысяч пятьсот двадцать девять, восемьсот тридцать восемь миллиардов пятьсот двадцать семь миллионов четыреста сорок четыре тысячи четыреста двенадцать.</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-66/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, 'condition', 0, NULL, 'https://gdz-raketa.ru/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica66-nomer2.jpg', 'peterson/3/part1/page66/task2_condition_0.jpg', '');

    VALUES (v_task_id, v_textbook_id, 3, 'a3c6329cbbbe8290033788c12e7ae811376f2f2f12223d6aa7c0fd920f08bc63', '8', NULL, 'прочитай числа, записанные в таблице. что обозначает цифра 8 в их записи');

    VALUES (v_textbook_id, 66, '3', 1, 'Прочитай числа. Сколько в них классов, разрядов? Найди число, в разряде десятков тысяч которого стоит цифра 5. а) 3512, 6032, 8907, 6200, 5555, 8812; б) 12063, 106727, 30009, 485226; в) 7396824, 429157340, 25571630748.', '</p>\n\n<p class="text">Прочитай числа. Сколько в них классов, разрядов? Найди число, в разряде десятков тысяч которого стоит цифра 5.</p>\n\n<p class="description-text">\n<span>а) 3512, 6032, 8907, 6200, 5555, 8812;</span>\n<span>б) 12063, 106727, 30009, 485226;</span>\n<span>в) 7396824, 429157340, 25571630748.</span></p>', 'а) три тысячи пятьсот двенадцать, шесть тысяч тридцать два, восемь тысяч девятьсот семь, шесть тысяч двести, пять тысяч пятьсот пятьдесят пять, восемь тысяч восемьсот двенадцать. Два класса, четыре разряда; б) двенадцать тысяч шестьдесят три, сто шесть тысяч семьсот двадцать семь, тридцать тысяч девять, четыреста восемьдесят пять тысячи двести двадцать шесть. Два класса, пять и шесть разрядов; в) семь миллионов триста девяносто шесть тысяч восемьсот двадцать четыре, четыреста двадцать девять миллиона сто пятьдесят семь тысячи триста сорок, двадцать пять миллиарда пятьсот семьдесят один миллион шестьсот тридцать тысяч семьсот сорок восемь. 429157340.', '<p><span>а) три тысячи пятьсот двенадцать, шесть тысяч тридцать два, восемь тысяч девятьсот семь, шесть тысяч двести, пять тысяч пятьсот пятьдесят пять, восемь тысяч восемьсот двенадцать. Два класса, четыре разряда;</span>\n<span>б) двенадцать тысяч шестьдесят три, сто шесть тысяч семьсот двадцать семь, тридцать тысяч девять, четыреста восемьдесят пять тысячи двести двадцать шесть. Два класса, пять и шесть разрядов;</span>\n<span>в) семь миллионов триста девяносто шесть тысяч восемьсот двадцать четыре, четыреста двадцать девять миллиона сто пятьдесят семь тысячи триста сорок, двадцать пять миллиарда пятьсот семьдесят один миллион шестьсот тридцать тысяч семьсот сорок восемь.</span>\n<span>429157340.</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-66/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '099c2823bca9a2e9d4bf2411ac7736d91fe2a05f541528c2105854594b5af211', '5,3512,5555,6032,6200,8812,8907,12063,30009,106727', '["найди","раз"]'::jsonb, 'прочитай числа. сколько в них классов, разрядов? найди число, в разряде десятков тысяч которого стоит цифра 5. а) 3512, 6032, 8907, 6200, 5555, 8812; б) 12063, 106727, 30009, 485226; в) 7396824, 429157340, 25571630748');

    VALUES (v_textbook_id, 67, '4', 0, 'Сосчитай: а) от 7398 до 7405 б) от 15 002 до 14 996 в) от 200 004 до 199 998 г) от 3 516 997 до 3 517 003', '</p>\n\n<p class="text">Сосчитай:</p>\n\n<p class="description-text">\n<span>а) от 7398 до 7405</span>\n<span>б) от 15 002 до 14 996</span>\n<span>в) от 200 004 до 199 998</span>\n<span>г) от 3 516 997 до 3 517 003</span></p>', 'а) 7398, 7399, 7400, 7401, 7402, 7403, 7404, 7405 б) 15002, 15001, 15000, 14999, 14998, 14997, 14996 в) 200004, 200003, 200002, 200001, 200000, 199999, 199998 г) 3516997, 3516998, 3516999, 3517000, 3517001, 3517002, 3517003', '<p><span>а) 7398, 7399, 7400, 7401, 7402, 7403, 7404, 7405</span>\n<span>б) 15002, 15001, 15000, 14999, 14998, 14997, 14996</span>\n<span>в) 200004, 200003, 200002, 200001, 200000, 199999, 199998</span>\n<span>г) 3516997, 3516998, 3516999, 3517000, 3517001, 3517002, 3517003</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-67/')
