    VALUES (v_task_id, v_textbook_id, 3, '15097d4698acc1585677f900a82e2883455c1697d27f2d9cd74dab44395c5caa', '002,003,3,004,14,15,199,200,516,517', NULL, 'сосчитай:а) от 7398 до 7405 б) от 15 002 до 14 996 в) от 200 004 до 199 998 г) от 3 516 997 до 3 517 003');

    VALUES (v_textbook_id, 67, '5', 1, 'Придумай задачу, которая решается так: 20 + 20 : 4      (n : 2) · 9      35 : (а : 6)', '</p>\n\n<p class="text">Придумай задачу, которая решается так:</p>\n\n<p class="description-text">\n20 + 20 : 4      (n : 2) · 9      35 : (а : 6)</p>', '20 + 20 : 4 – У Пети было 20 р. Мама дала Пети, Мише, Олегу и Васе ещё 20 р. Сколько у Пети стало денег, чем было? (n : 2) · 9 – За 2 одинаковых батона заплатили n р. Сколько денег надо заплатить за 9 таких батонов? 35 : (а : 6) – За 6 одинаковых батона заплатили а р. Сколько таких батонов можно купить на 35 р.?', '<p><span>20 + 20 : 4 – У Пети было 20 р. Мама дала Пети, Мише, Олегу и Васе ещё 20 р. Сколько у Пети стало денег, чем было?</span>\n<span>(n : 2) · 9 – За 2 одинаковых батона заплатили n р. Сколько денег надо заплатить за 9 таких батонов?</span>\n<span>35 : (а : 6) – За 6 одинаковых батона заплатили а р. Сколько таких батонов можно купить на 35 р.?</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-67/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '3127961df890daa3c0141e8e7bb6d17f2bbeb82ec3148c0603be1d5b76a9ba1d', '2,4,6,9,20,35', NULL, 'придумай задачу, которая решается так:20+20:4      (n:2)*9      35:(а:6)');

    VALUES (v_textbook_id, 67, '6', 2, 'БЛИЦтурнир а) За 4 одинаковых батона заплатили а р. Сколько денег надо заплатить за 6 таких батонов? б) За 4 одинаковых батона заплатили а р. Сколько таких батонов можно купить на с р.? в) У Маши было b р. Она купила 5 кексов по d р. Сколько денег у неё осталось? г) Игорь купил 2 мороженых по х р. и 3 пирожных по у р. Сколько денег он заплатил за покупку? д) У Пети было а р. Мама дала ему ещё b р. Во сколько раз больше у него стало денег, чем было?', '</p>\n\n<p class="text"><span><b>БЛИЦтурнир</b></span>\n<span>а) За 4 одинаковых батона заплатили <b>а</b> р. Сколько денег надо заплатить за 6 таких батонов?</span>\n<span>б) За 4 одинаковых батона заплатили <b>а</b> р. Сколько таких батонов можно купить на <b>с</b> р.?</span>\n<span>в) У Маши было <b>b</b> р. Она купила 5 кексов по <b>d</b> р. Сколько денег у неё осталось?</span>\n<span>г) Игорь купил 2 мороженых по <b>х</b> р. и 3 пирожных по <b>у</b> р. Сколько денег он заплатил за покупку?</span>\n<span>д) У Пети было <b>а</b> р. Мама дала ему ещё <b>b</b> р. Во сколько раз больше у него стало денег, чем было?</span></p>', 'а) (а : 4) · 6 р надо заплатить за 6 таких батонов. б) c : (4 : а) таких батонов можно купить на с р. в) У Маши было b р. Она купила 5 кексов по d р. Сколько денег у неё осталось? г) 2х + 3у р он заплатил за покупку. д) (а + b) : а во столько раз больше у него стало денег, чем было.', '<p><span>а) (а : 4) · 6 р надо заплатить за 6 таких батонов.</span>\n<span>б) c : (4 : а) таких батонов можно купить на с р.</span>\n<span>в) У Маши было b р. Она купила 5 кексов по d р. Сколько денег у неё осталось?</span>\n<span>г) 2х + 3у р он заплатил за покупку.</span>\n<span>д) (а + b) : а во столько раз больше у него стало денег, чем было.</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-67/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '19f70631613cc85c43e9f0105d7e6802128b2bc8bb88d0aa00657e73512a1b32', '2,3,4,5,6', '["больше","раз"]'::jsonb, 'блицтурнир а) за 4 одинаковых батона заплатили а р. сколько денег надо заплатить за 6 таких батонов? б) за 4 одинаковых батона заплатили а р. сколько таких батонов можно купить на с р.? в) у маши было b р. она купила 5 кексов по d р. сколько денег у неё осталось? г) игорь купил 2 мороженых по х р. и 3 пирожных по у р. сколько денег он заплатил за покупку? д) у пети было а р. мама дала ему ещё b р. во сколько раз больше у него стало денег, чем было');

    VALUES (v_textbook_id, 67, '7', 3, 'Ручка стоит 27 р., она в 3 раза дороже карандаша. Тетрадь на 7 р. дешевле ручки. Сможет ли Оля купить ручку, карандаш и тетрадь, если у неё есть 60 р.?', '</p>\n\n<p class="text">Ручка стоит 27 р., она в 3 раза дороже карандаша. Тетрадь на 7 р. дешевле ручки. Сможет ли Оля купить ручку, карандаш и тетрадь, если у неё есть 60 р.?</p>', '60 – 27 – 27 : 3 – (27 – 7) = 33 – 9 – 20 = 26 – 20 = 6 (р) – останется после покупки. Ответ: сможет Оля купить ручку, карандаш и тетрадь, если у неё есть 60 р.', '<p><span>60 – 27 – 27 : 3 – (27 – 7) = 33 – 9 – 20 = 26 – 20 = 6 (р) – останется после покупки.</span>\n<span><b>Ответ:</b> сможет Оля купить ручку, карандаш и тетрадь, если у неё есть 60 р.</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-67/')
    RETURNING id INTO v_task_id;

