    VALUES (v_textbook_id, 67, '12', 8, 'Сколько месяцев в году имеют в названии ровно 6 букв?', '</p>\n\n<p class="text">Сколько месяцев в году имеют в названии ровно 6 букв?</p>', 'Январь – 6 Февраль – 7 Март – 4 Апрель – 6 Май – 3 Июнь – 4 Июль – 4 Август – 6 Сентябрь – 8 Октябрь – 7 Ноябрь – 6 Декабрь – 7 Ответ: 4 месяца в году имеют в названии ровно 6 букв.', '<p><span>Январь – 6</span>\n<span>Февраль – 7</span>\n<span>Март – 4</span>\n<span>Апрель – 6</span>\n<span>Май – 3</span>\n<span>Июнь – 4</span>\n<span>Июль – 4</span>\n<span>Август – 6</span>\n<span>Сентябрь – 8</span>\n<span>Октябрь – 7</span>\n<span>Ноябрь – 6</span>\n<span>Декабрь – 7</span>\n<span><b>Ответ:</b> 4 месяца в году имеют в названии ровно 6 букв.</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-67/')
    RETURNING id INTO v_task_id;

