    VALUES (v_textbook_id, 68, '2', 1, 'Прочитай числа. Сколько в них классов, разрядов? В каких разрядах отсутствуют разрядные единицы? Как ты думаешь, какое из чисел таблицы самое маленькое, а какое – самое большое?', '</p>\n\n<p class="text">Прочитай числа. Сколько в них классов, разрядов? В каких разрядах отсутствуют разрядные единицы? Как ты думаешь, какое из чисел таблицы самое маленькое, а какое – самое большое?</p>\n\n<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica68-nomer2.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 68, номер 2, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 68, номер 2, год 2022."/>\n</div>', 'Пятьсот семьдесят девять тысячи триста восемнадцать, 2 класса и 6 разрядов. Три миллиона шестьсот сорок две тысячи три, 3 класса и 7 разрядов, сотни и десятки. Восемнадцать миллионов шестьдесят тысяч семьсот восемьдесят пять, 3 класса и 8 разрядов, сотни и единицы. Семьсот шестьдесят миллионов триста тысяч четырнадцать, 3 класса и 9 разрядов, единицы, сотни и десятки. Шесть миллиардов пятьсот восемьдесят один миллион семь тысяч пятьсот, 4 класса и 10 разрядов, сотни, десятки и единицы . Двадцать семь миллиардов девятьсот девяносто миллионов триста двадцать тысяч четыреста семь, 4 класса и 11 разрядов, десятки и единицы. Шестьсот двадцать миллиардов семь миллионов восемьдесят три, 4 класса и 12 разрядов, сотни, десятки и единицы. По моему мнению, из чисел таблицы самое маленькое – 579318, а 620007000083 – самое большое.', '<p><span>Пятьсот семьдесят девять тысячи триста восемнадцать, 2 класса и 6 разрядов.</span>\n<span>Три миллиона шестьсот сорок две тысячи три, 3 класса и 7 разрядов, сотни и десятки.</span>\n<span>Восемнадцать миллионов шестьдесят тысяч семьсот восемьдесят пять, 3 класса и 8 разрядов, сотни и единицы.</span>\n<span>Семьсот шестьдесят миллионов триста тысяч четырнадцать, 3 класса и 9 разрядов, единицы, сотни и десятки.</span>\n<span>Шесть миллиардов пятьсот восемьдесят один миллион семь тысяч пятьсот, 4 класса и 10 разрядов, сотни, десятки и единицы .</span>\n<span>Двадцать семь миллиардов девятьсот девяносто миллионов триста двадцать тысяч четыреста семь, 4 класса и 11 разрядов, десятки и единицы.</span>\n<span>Шестьсот двадцать миллиардов семь миллионов восемьдесят три, 4 класса и 12 разрядов, сотни, десятки и единицы.</span>\n<span>По моему мнению, из чисел таблицы самое маленькое – 579318, а 620007000083 – самое большое.</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-68/')
    RETURNING id INTO v_task_id;

