    VALUES (v_task_id, v_textbook_id, 3, 'c662652d38a9de2e790f59900a4d76518d332c3fab2450d99653b19eca91d022', NULL, '["раз"]'::jsonb, 'прочитай числа. сколько в них классов, разрядов? в каких разрядах отсутствуют разрядные единицы? как ты думаешь, какое из чисел таблицы самое маленькое, а какое-самое большое');

    VALUES (v_textbook_id, 68, '3', 2, 'Прочитай числа, назови предыдущее и последующее число. Попробуй найти среди этих чисел самое большое и самое маленькое. 50090      50009      90500      59000 Как можно сравнить многозначные числа?', '</p>\n\n<p class="text">Прочитай числа, назови предыдущее и последующее число. Попробуй найти среди этих чисел самое большое и самое маленькое.</p>\n\n<p class="description-text">\n50090      50009      90500      59000</p>\n\n<p class="text">Как можно сравнить многозначные числа?</p>', 'Пятьдесят тысяч девяносто, 50089 – предыдущее, 50091 – следующее. Пятьдесят тысяч девять, 50008 – предыдущее, 50010 – следующее. Девяносто тысяч пятьсот, 90499 – предыдущее, 90501 – следующее. Пятьдесят девять тысяч, 58999 – предыдущее, 59001 – следующее. 90500 – самое большое и 50009 – самое маленькое. Если количество цифр разное, то больше число, у которого цифр больше, и наоборот. Если количество цифр одинаковое, то больше число, у которого больше первая несовпавшая цифра слева, и наоборот.', '<p><span>Пятьдесят тысяч девяносто, 50089 – предыдущее, 50091 – следующее.</span>\n<span>Пятьдесят тысяч девять, 50008 – предыдущее, 50010 – следующее.</span>\n<span>Девяносто тысяч пятьсот, 90499 – предыдущее, 90501 – следующее.</span>\n<span>Пятьдесят девять тысяч, 58999 – предыдущее, 59001 – следующее.</span>\n<span>90500 – самое большое и 50009 – самое маленькое.</span>\n<span>Если количество цифр разное, то больше число, у которого цифр больше, и наоборот. Если количество цифр одинаковое, то больше число, у которого больше первая несовпавшая цифра слева, и наоборот.</span></p>', 'Правила сравнения натуральных чисел Правило 1. Если количество цифр разное, то больше число, у которого цифр больше, и наоборот.                **** > **      ** < **** Правило 2. Если количество цифр одинаковое, то больше число, у которого больше первая несовпавшая цифра слева, и наоборот.                 a b c ** > s b d **      ⇔      c > d', '<div class="recomended-block">\n<span class="title">Правила сравнения натуральных чисел</span>\n<p><b class="black">Правило 1.</b> Если количество цифр разное, то больше число, у которого цифр больше, и наоборот.<br/>\n               **** &gt; **      ** &lt; ****<br/>\n<b class="black">Правило 2.</b> Если количество цифр одинаковое, то больше число, у которого больше первая несовпавшая цифра слева, и наоборот.<br/>\n               <span class="underline">a</span><span class="underline">b</span><span class="okon">c</span>** &gt; <span class="underline">s</span><span class="underline">b</span><span class="okon">d</span>**      ⇔      c &gt; d</p>\n</div>', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-68/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '7799cae9a62ee01e92f2f985a2ca42ba1d0378bb3b4656662cc2d871fab026f6', '50009,50090,59000,90500', '["сравни"]'::jsonb, 'прочитай числа, назови предыдущее и последующее число. попробуй найти среди этих чисел самое большое и самое маленькое. 50090      50009      90500      59000 как можно сравнить многозначные числа');

