    VALUES (v_task_id, v_textbook_id, 3, '055b590c9ac65960536b9b017c90a950022df9ee500bfd3479e5868eea7f6d05', NULL, '["вычисли"]'::jsonb, 'вычисли устно');

    VALUES (v_textbook_id, 69, '6', 1, 'Чем похожи и чем различаются выражения: (30 – d) : 3 и 30 – d : 3? Прочитай эти выражения и найди их значения при d = 0, 6, 18, 30. Что ты замечаешь?', '</p>\n\n<p class="text">Чем похожи и чем различаются выражения:</p>\n\n<p class="description-text">\n(30 – d) : 3 и 30 – d : 3?</p>\n\n<p class="text">Прочитай эти выражения и найди их значения при d = 0, 6, 18, 30. Что ты замечаешь?</p>', 'Похожи слагаемые и действия, отличаются последовательностью выполнения действий. (30 – d) : 3 – В скобках тридцать минус d, полученную разность разделить на три 30 – d : 3 – d разделить на три и результат вычесть из тридцати при d = 0 (30 – 0) : 3 = 10 30 – 0 : 3 = 30 при d = 6 (30 – 6) : 3 = 8 30 – 6 : 3 = 28 при d = 18 (30 – 18) : 3 = 12 : 3 = 4 30 – 18 : 3 = 30 – 6 = 24 при d = 30 (30 – 30) : 3 = 0 30 – 30 : 3 = 20 Различаются результаты на 20.', '<p><span>Похожи слагаемые и действия, отличаются последовательностью выполнения действий.</span>\n<span>(30 – d) : 3 – В скобках тридцать минус d, полученную разность разделить на три</span>\n<span>30 – d : 3 – d разделить на три и результат вычесть из тридцати</span>\n<span>при d = 0</span>\n<span>(30 – 0) : 3 = 10</span>\n<span>30 – 0 : 3 = 30</span>\n<span>при d = 6</span>\n<span>(30 – 6) : 3 = 8</span>\n<span>30 – 6 : 3 = 28</span>\n<span>при d = 18</span>\n<span>(30 – 18) : 3 = 12 : 3 = 4</span>\n<span>30 – 18 : 3 = 30 – 6 = 24</span>\n<span>при d = 30</span>\n<span>(30 – 30) : 3 = 0</span>\n<span>30 – 30 : 3 = 20</span>\n<span>Различаются результаты на 20.</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-69/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '7cfa90d4a05d07ce44a86192e0056ec2eae8339687c88cf7a7713b0a4f58645b', '0,3,6,18,30', '["найди","раз"]'::jsonb, 'чем похожи и чем различаются выражения:(30-d):3 и 30-d:3? прочитай эти выражения и найди их значения при d=0, 6, 18, 30. что ты замечаешь');

    VALUES (v_textbook_id, 69, '7', 2, 'БЛИЦтурнир а) В 5 одинаковых банках а л сока. Сколько литров сока в 12 таких банках? б) В 5 одинаковых банках a л сока. Сколько потребуется таких банок, чтобы разлить в них 12 литров сока? в) В первом мешке с кг крупы, а во втором – в 3 раза больше. На сколько килограммов крупы меньше в первом мешке, чем во втором? г) В магазин привезли m кг картошки по 20 кг в мешке и n кг моркови по 30 кг в мешке. Сколько мешков картошки и моркови привезли в магазин?', '</p>\n\n<p class="text"><span><b>БЛИЦтурнир</b></span>\n<span>а) В 5 одинаковых банках <b>а</b> л сока. Сколько литров сока в 12 таких банках?</span>\n<span>б) В 5 одинаковых банках <b>a</b> л сока. Сколько потребуется таких банок, чтобы разлить в них 12 литров сока?</span>\n<span>в) В первом мешке <b>с</b> кг крупы, а во втором – в 3 раза больше. На сколько килограммов крупы меньше в первом мешке, чем во втором?</span>\n<span>г) В магазин привезли <b>m</b> кг картошки по 20 кг в мешке и <b>n</b> кг моркови по 30 кг в мешке. Сколько мешков картошки и моркови привезли в магазин?</span></p>', 'а) а : 5 · 12 = а : 60 (л)      Ответ: а : 60 литров сока в 12 таких банках. б) 12 : а : 5 (б)      Ответ: 12 : а : 5 потребуется таких банок, чтобы разлить в них 12 литров сока. в) с - 3с = 2с (кг)      Ответ: на 2с килограммов крупы меньше в первом мешке, чем во втором. г) m : 20 + n : 30 (м)      Ответ: m : 20 + n : 30 мешков картошки и моркови при везли в магазин.', '<p><span>а) а : 5 · 12 = а : 60 (л)</span>\n<span>    <b>Ответ:</b> а : 60 литров сока в 12 таких банках.</span>\n<span>б) 12 : а : 5 (б)</span>\n<span>    <b>Ответ:</b> 12 : а : 5 потребуется таких банок, чтобы разлить в них 12 литров сока.</span>\n<span>в) с - 3с = 2с (кг)</span>\n<span>    <b>Ответ:</b> на 2с килограммов крупы меньше в первом мешке, чем во втором.</span>\n<span>г) m : 20 +  n : 30 (м)</span>\n<span>    <b>Ответ:</b> m : 20 + n : 30 мешков картошки и моркови при везли в магазин.</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-69/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, 'c785f5824b43f008280a27cb015edd9826c3656b7cecfd22dd06502068f4eb8d', '3,5,12,20,30', '["больше","меньше","раз","раза"]'::jsonb, 'блицтурнир а) в 5 одинаковых банках а л сока. сколько литров сока в 12 таких банках? б) в 5 одинаковых банках a л сока. сколько потребуется таких банок, чтобы разлить в них 12 литров сока? в) в первом мешке с кг крупы, а во втором-в 3 раза больше. на сколько килограммов крупы меньше в первом мешке, чем во втором? г) в магазин привезли m кг картошки по 20 кг в мешке и n кг моркови по 30 кг в мешке. сколько мешков картошки и моркови привезли в магазин');

    VALUES (v_textbook_id, 69, '8', 3, 'а) Составь в тетради таблицу, заполняя пропуски: б) Запиши арабскими цифрами числа: СССLХII, MDCCXLIV. в) Запиши римскими цифрами числа: 25, 96, 140, 2001.', '</p>\n\n<p class="text">а) Составь в тетради таблицу, заполняя пропуски:</p>\n\n<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica69-nomer8.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 69, номер 8, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 69, номер 8, год 2022."/>\n</div>\n\n<p class="text"><span>б) Запиши арабскими цифрами числа: СССLХII, MDCCXLIV.</span>\n<span>в) Запиши римскими цифрами числа: 25, 96, 140, 2001.</span></p>', 'а)', '<p>а)</p>\n\n<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica69-nomer8-1.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 69, номер 8, год 2022, ответ." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 69, номер 8, год 2022, ответ."/>', '', '', TRUE, '[{"letter":"а","condition":"Составь в тетради таблицу, заполняя пропуски:","solution":""},{"letter":"б","condition":"Запиши арабскими цифрами числа: СССLХII, MDCCXLIV.","solution":""},{"letter":"в","condition":"Запиши римскими цифрами числа: 25, 96, 140, 2001.","solution":""}]'::jsonb, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-69/')
    RETURNING id INTO v_task_id;

