    VALUES (v_textbook_id, 69, '9', 4, 'Через четыре с половиной часа наступит полночь. А сейчас который час?', '</p>\n\n<p class="text">Через четыре с половиной часа наступит полночь. А сейчас который час?</p>', '24 ч – 4 ч 30 мин = (24 ч – 4 ч) – 30 мин = 20 ч – 30 мин = 19 ч + (1 ч – 30 мин) = 19 ч 30 мин. Ответ: сейчас 19 часов 30 минут.', '<p><span>24 ч – 4 ч 30 мин = (24 ч – 4 ч) – 30 мин = 20 ч – 30 мин = 19 ч + (1 ч – 30 мин) = 19 ч 30 мин.</span>\n<span><b>Ответ:</b> сейчас 19 часов 30 минут.</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-69/')
    RETURNING id INTO v_task_id;

