    VALUES (v_textbook_id, 69, '10', 5, 'Сегодня 10 декабря, среда. Какой день будет послезавтра? Как назывался позапрошлый месяц?', '</p>\n\n<p class="text">Сегодня 10 декабря, среда. Какой день будет послезавтра? Как назывался позапрошлый месяц?</p>', 'Завтра 11 декабря – четверг, послезавтра 12 декабря – пятница. Прошлый месяц – ноябрь, позапрошлый месяц – октябрь.', '<p>Завтра 11 декабря – четверг, послезавтра 12 декабря – пятница. Прошлый месяц – ноябрь, позапрошлый месяц – октябрь.</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-69/')
    RETURNING id INTO v_task_id;

