    VALUES (v_textbook_id, 70, '1', 0, 'Прочитай число: 572031006800. Сколько классов в его записи? Назови их. Сколько разрядов? Назови разряды, в которых стоят цифры: 3, 6, 2, 8.', '</p>\n\n<p class="text">Прочитай число: 572031006800. Сколько классов в его записи? Назови их. Сколько разрядов? Назови разряды, в которых стоят цифры: 3, 6, 2, 8.</p>', 'Пятьсот семьдесят два миллиарда тридцать один миллион шесть тысяч восемьсот. 4 класса, миллиарды, миллионы, тысячи и единицы. 3 разряда, сотни, десятки и единицы. Десятки, единицы, единицы, сотни.', '<p>Пятьсот семьдесят два миллиарда тридцать один миллион шесть тысяч восемьсот. 4 класса, миллиарды, миллионы, тысячи и единицы. 3 разряда, сотни, десятки и единицы. Десятки, единицы, единицы, сотни.</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-70/')
    RETURNING id INTO v_task_id;

