    VALUES (v_textbook_id, 70, '2', 1, 'Разбей на классы и прочитай числа: а) 7961, 8520, 93067, 200721, 8629356; б) 324508764, 94351084922, 775613204380.', '</p>\n\n<p class="text">Разбей на классы и прочитай числа:</p>\n\n<p class="description-text">\n<span>а) 7961, 8520, 93067, 200721, 8629356;</span>\n<span>б) 324508764, 94351084922, 775613204380.</span></p>', 'а) 7 – тысячи, 961 – единицы, семь тысяч девятьсот шестьдесят один,     8 – тысячи, 520 – единицы, восемь тысяч пятьсот двадцать,     93 – тысячи, 067 – единицы, девяносто три тысячи шестьдесят семь,     200 – тысячи, 721 – единицы, двести тысяч семьсот двадцать один,     8 – миллионы, 629 – тысячи, 356 – единицы, восемь миллионов шестьсот двадцать девять тысяч триста пятьдесят шесть; б) 324 – миллиона, 508 – тысячи, 764 – единицы, триста двадцать четыре миллиона пятьсот восемь тысяч семьсот шестьдесят четыре,     94 – миллиарды, 351 – миллионы, 084 – тысячи, 922 – единицы, девяносто четыре миллиарда триста пятьдесят один миллион восемьдесят четыре тысячи девятьсот двадцать два,     775 – миллиарда, 613 – миллиона, 204 – тысячи, 380 – единицы, семьсот семьдесят пять миллиарда шестьсот тринадцать миллиона двести четыре тысячи триста восемьдесят.', '<p><span>а) 7 – тысячи, 961 – единицы, семь тысяч девятьсот шестьдесят один,</span>\n<span>    8 – тысячи, 520 – единицы, восемь тысяч пятьсот двадцать,</span>\n<span>    93 – тысячи, 067 – единицы, девяносто три тысячи шестьдесят семь,</span>\n<span>    200 – тысячи, 721 – единицы, двести тысяч семьсот двадцать один,</span>\n<span>    8 – миллионы, 629 – тысячи, 356 – единицы, восемь миллионов шестьсот двадцать девять тысяч триста пятьдесят шесть;</span>\n<span>б) 324 – миллиона, 508 – тысячи, 764 – единицы, триста двадцать четыре миллиона пятьсот восемь тысяч семьсот шестьдесят четыре,</span>\n<span>    94 – миллиарды, 351 – миллионы, 084 – тысячи, 922 – единицы, девяносто четыре миллиарда триста пятьдесят один миллион восемьдесят четыре тысячи девятьсот двадцать два,</span>\n<span>    775 – миллиарда, 613 – миллиона, 204 – тысячи, 380 – единицы, семьсот семьдесят пять миллиарда шестьсот тринадцать миллиона двести четыре тысячи триста восемьдесят.</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-70/')
