    VALUES (v_textbook_id, 70, '3', 2, 'Запиши число: а) 2 млн 48 тыс. 5 ед. подчеркни класс тысяч. б) 36 млн 7 тыс. 94 ед. Подчеркни разряд единиц миллионов. в) 5 млрд 19 млн 208 ед. Подчеркни класс миллиардов. г) 912 млрд 6 млн 45 тыс. Подчеркни разряд десятков тысяч.', '</p>\n\n<p class="text">Запиши число:</p>\n\n<p class="description-text">\n<span>а) 2 млн 48 тыс. 5 ед. подчеркни класс тысяч.</span>\n<span>б) 36 млн 7 тыс. 94 ед. Подчеркни разряд единиц миллионов.</span>\n<span>в) 5 млрд 19 млн 208 ед. Подчеркни класс миллиардов.</span>\n<span>г) 912 млрд 6 млн 45 тыс. Подчеркни разряд десятков тысяч.</span></p>', 'а) 2048005 б) 36007094 в) 5019000208 г) 912006045000', '<p><span>а) 2048005</span>\n<span>б) 36007094</span>\n<span>в) 5019000208</span>\n<span>г) 912006045000</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-70/')
