    VALUES (v_textbook_id, 70, '5', 4, 'а) Какое число следует за число: 99, 899, 999, 4367, 7599, 20300, 38126, 52999, 999999? б) Какое число предшествует числу: 40, 650, 1000, 8324, 9680, 14399, 26700, 80000, 10000000? в) Назови «соседей» числа: 5349, 60237, 589600.', '</p>\n\n<p class="text"><span>а) Какое число следует за число: 99, 899, 999, 4367, 7599, 20300, 38126, 52999, 999999?</span>\n<span>б) Какое число предшествует числу: 40, 650, 1000, 8324, 9680, 14399, 26700, 80000, 10000000?</span>\n<span>в) Назови «соседей» числа: 5349, 60237, 589600.</span></p>', 'а) 100, 900, 1000, 4368, 7600, 20301, 38127, 53000, 1000000. б) 39, 649, 999, 8323, 9679, 14398, 26699, 79999, 9999999. в) 5348 и 5350, 60236 и 60238, 589599 и 589601.', '<p><span>а) 100, 900, 1000, 4368, 7600, 20301, 38127, 53000, 1000000.</span>\n<span>б) 39, 649, 999, 8323, 9679, 14398, 26699, 79999, 9999999.</span>\n<span>в) 5348 и 5350, 60236 и 60238, 589599 и 589601.</span></p>', '', '', TRUE, '[{"letter":"а","condition":"Какое число следует за число: 99, 899, 999, 4367, 7599, 20300, 38126, 52999, 999999?","solution":"100, 900, 1000, 4368, 7600, 20301, 38127, 53000, 1000000."},{"letter":"б","condition":"Какое число предшествует числу: 40, 650, 1000, 8324, 9680, 14399, 26700, 80000, 10000000?","solution":"39, 649, 999, 8323, 9679, 14398, 26699, 79999, 9999999."},{"letter":"в","condition":"Назови «соседей» числа: 5349, 60237, 589600.","solution":"5348 и 5350, 60236 и 60238, 589599 и 589601."}]'::jsonb, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-70/')
