    VALUES (v_textbook_id, 70, '6', 5, 'Периметр четырёхугольника равен 3 м. Первая его сторона равна 72 см, вторая – на 16 см больше первой, а третья – в 2 раза меньше второй. Найди четвёртую сторону этого четырёхугольника.', '</p>\n\n<p class="text">Периметр четырёхугольника равен 3 м. Первая его сторона равна 72 см, вторая – на 16 см больше первой, а третья – в 2 раза меньше второй. Найди четвёртую сторону этого четырёхугольника.</p>\n\n<div class="img-wrapper-460">\n<img width="340" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica70-nomer6.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 70, номер 6, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 70, номер 6, год 2022."/>\n</div>', '300 – (72 + (72 + 16) + (72 + 16) : 2) = 300 – (72 + 88 + 44) = 300 – 204 = 96 (см) Ответ: 96 сантиметров четвёртая сторона этого четырёхугольника.', '<p><span>300 – (72 + (72 + 16) + (72 + 16) : 2) = 300 – (72 + 88 + 44) = 300 – 204 = 96 (см)</span>\n<span><b>Ответ:</b> 96 сантиметров четвёртая сторона этого четырёхугольника.</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-70/')
    RETURNING id INTO v_task_id;

