    VALUES (v_task_id, v_textbook_id, 3, '9f1ef9c56deb04e55dcf09200596082e74b614c601a09d179e6bc7c80d114213', '2,3,16,72', '["найди","периметр","сторона","больше","меньше","раз","раза"]'::jsonb, 'периметр четырёхугольника равен 3 м. первая его сторона равна 72 см, вторая-на 16 см больше первой, а третья-в 2 раза меньше второй. найди четвёртую сторону этого четырёхугольника');

    VALUES (v_textbook_id, 70, '7', 6, 'Все ли выражения сравнили верно? Если есть ошибки, исправь их в тетради. а · 8 + а · 3 ˃ а · 10      52 – с = 25 – с      720 : k ˃ 702 : k b · 5 – b ˂ 4 · b             d – 48 ˃ d – 402    m : 111 ˃ m : 99', '</p>\n\n<p class="text">Все ли выражения сравнили верно? Если есть ошибки, исправь их в тетради.</p>\n\n<p class="description-text">\n<span>а · 8 + а · 3 ˃ а · 10      52 – с = 25 – с      720 : k ˃ 702 : k</span>\n<span>b · 5 – b ˂ 4 · b             d – 48 ˃ d – 402    m : 111 ˃ m : 99</span></p>', 'а · 8 + а · 3 ˃ а · 10 – верно b · 5 – b = 4 · b 52 – с ˃ 25 – с d – 48 ˃ d – 402 – верно 720 : k ˃ 702 : k – верно m : 111 ˃ m : 99 – верно', '<p><span>а · 8 + а · 3 ˃ а · 10 – верно</span>\n<span>b · 5 – b = 4 · b</span>\n<span>52 – с ˃ 25 – с</span>\n<span>d – 48 ˃ d – 402 – верно</span>\n<span>720 : k ˃ 702 : k – верно</span>\n<span>m : 111 ˃ m : 99 – верно</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-70/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, 'c2635c697e34ce251ee6e1817eecfdfa522f852de691e3b2fc7d1e9582229d2a', '3,4,5,8,10,25,48,52,99,111', '["сравни"]'::jsonb, 'все ли выражения сравнили верно? если есть ошибки, исправь их в тетради. а*8+а*3 ˃ а*10      52-с=25-с      720:k ˃ 702:k b*5-b ˂ 4*b             d-48 ˃ d-402    m:111 ˃ m:99');

    VALUES (v_textbook_id, 71, '8', 0, 'Вычисли. Объясни для каждого столбика приёмы вычислений: а) 56 : 7      б) 68 : 2      в) 84 : 12      г) 35 : 8      д) 72 : 17     54 : 9           42 : 3          91 : 13          29 : 6           80 : 15     45 : 5           96 : 4          77 : 11          17 : 4           57 : 18', '</p>\n\n<p class="text">Вычисли. Объясни для каждого столбика приёмы вычислений:</p>\n\n<p class="description-text">\n<span>а) 56 : 7      б) 68 : 2      в) 84 : 12      г) 35 : 8      д) 72 : 17</span>\n<span>    54 : 9           42 : 3          91 : 13          29 : 6           80 : 15</span>\n<span>    45 : 5           96 : 4          77 : 11          17 : 4           57 : 18</span></p>', 'а) 56 : 7 = 8     54 : 9 = 6     45 : 5 = 9     Табличные значения. б) 68 : 2 = 34     42 : 3 = 14     96 : 4 = 24     Деление двузначного числа на однозначное. в) 84 : 12 = 7     91 : 13 = 7     77 : 11 = 7     Деление двузначного на двузначное. г) 35 : 8 = 4 + 3     29 : 6 = 4 + 5     17 : 4 = 4 + 1     Близкое к табличному значению плюс остаток.', '<p><span>а) 56 : 7 = 8</span>\n<span>    54 : 9 = 6</span>\n<span>    45 : 5 = 9</span>\n<span>    Табличные значения.</span>\n<br/>\n<span>б) 68 : 2 = 34</span>\n<span>    42 : 3 = 14</span>\n<span>    96 : 4 = 24</span>\n<span>    Деление двузначного числа на однозначное.</span>\n<br/>\n<span>в) 84 : 12 = 7</span>\n<span>    91 : 13 = 7</span>\n<span>    77 : 11 = 7</span>\n<span>    Деление двузначного на двузначное.</span>\n<br/>\n<span>г) 35 : 8 = 4 + 3</span>\n<span>    29 : 6 = 4 + 5</span>\n<span>    17 : 4 = 4 + 1</span>\n<span>    Близкое к табличному значению плюс остаток.</span></p>\n\n<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica71-nomer8.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 71, номер 8, год 2022, ответ." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 71, номер 8, год 2022, ответ."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-71/')
    RETURNING id INTO v_task_id;

