    VALUES (v_task_id, v_textbook_id, 3, '221abf9c3f2dc8b3111d5d9f39d745d96bd053791fae9f77e896a331495b90c9', '2,3,4,5,6,7,8,9,11,12', '["вычисли","столбик"]'::jsonb, 'вычисли. объясни для каждого столбика приёмы вычислений:а) 56:7      б) 68:2      в) 84:12      г) 35:8      д) 72:17     54:9           42:3          91:13          29:6           80:15     45:5           96:4          77:11          17:4           57:18');

    VALUES (v_textbook_id, 71, '9', 1, 'а) Пользуясь числовым лучом, составь множество двузначных чисел, кратных 16. б) Выполни деление с остатком: 37 : 16      49 : 16      68 : 16      82 : 16 в) Выучи двузначные числа, кратные 16. Проверь себя, работая в паре.', '</p>\n\n<p class="text">а) Пользуясь числовым лучом, составь множество двузначных чисел, кратных 16.</p>\n\n<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica71-nomer9.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 71, номер 9, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 71, номер 9, год 2022."/>\n</div>\n\n<p class="text">б) Выполни деление с остатком:</p>\n\n<p class="description-text">\n37 : 16      49 : 16      68 : 16      82 : 16</p>\n\n<p class="text">в) Выучи двузначные числа, кратные 16. Проверь себя, работая в паре.</p>', 'а) {16; 32; 48; 64; 80; 96; 112; 128; 144; 160} б) 37 : 16 = 2 + 5     32 : 16 = 2, 37 – 32 = 5     49 : 16 = 3 + 1     48 : 16 = 3, 49 – 48 = 1     68 : 16 = 4 + 4     64 : 16 = 4, 68 – 64 = 4     82 : 16 = 5 + 2     80 : 16 = 5, 82 – 80 = 2 в) 16, 32, 48, 64, 80, 96, 112, 128, 144, 160.', '<p><span>а) {16; 32; 48; 64; 80; 96; 112; 128; 144; 160}</span>\n<span>б) 37 : 16 = 2 + 5</span>\n<span>    32 : 16 = 2, 37 – 32 = 5</span>\n<span>    49 : 16 = 3 + 1</span>\n<span>    48 : 16 = 3, 49 – 48 = 1</span>\n<span>    68 : 16 = 4 + 4</span>\n<span>    64 : 16 = 4, 68 – 64 = 4</span>\n<span>    82 : 16 = 5 + 2</span>\n<span>    80 : 16 = 5, 82 – 80 = 2</span>\n<span>в) 16, 32, 48, 64, 80, 96, 112, 128, 144, 160.</span></p>', '', '', TRUE, '[{"letter":"а","condition":"Пользуясь числовым лучом, составь множество двузначных чисел, кратных 16.","solution":"{16; 32; 48; 64; 80; 96; 112; 128; 144; 160}"},{"letter":"б","condition":"Выполни деление с остатком: 37 : 16      49 : 16      68 : 16      82 : 16","solution":"37 : 16 = 2 + 5     32 : 16 = 2, 37 – 32 = 5     49 : 16 = 3 + 1     48 : 16 = 3, 49 – 48 = 1     68 : 16 = 4 + 4     64 : 16 = 4, 68 – 64 = 4     82 : 16 = 5 + 2     80 : 16 = 5, 82 – 80 = 2"},{"letter":"в","condition":"Выучи двузначные числа, кратные 16. Проверь себя, работая в паре.","solution":"16, 32, 48, 64, 80, 96, 112, 128, 144, 160."}]'::jsonb, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-71/')
    RETURNING id INTO v_task_id;

