    VALUES (v_task_id, v_textbook_id, 3, 'ecd8d9a3cff16d8a22028ebcc41039b7d8e1f6d9472f612853256fbb3389a269', '16,37,49,68,82', NULL, 'а) пользуясь числовым лучом, составь множество двузначных чисел, кратных 16. б) выполни деление с остатком:37:16      49:16      68:16      82:16 в) выучи двузначные числа, кратные 16. проверь себя, работая в паре');

    VALUES (v_textbook_id, 71, '10', 2, 'Вычисли. Расшифруй название птиц. Найди о них информацию в энциклопедии или Интернете.', '</p>\n\n<p class="text">Вычисли. Расшифруй название птиц. Найди о них информацию в энциклопедии или Интернете.</p>\n\n<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica71-nomer10.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 71, номер 10, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 71, номер 10, год 2022."/>\n</div>', '72 – 37 = 35           49 : 7 · 8 = 56          7 · 9 – 8 · 4 = 63 – 32 = 31 500 – 475 = 25       6 · 8 : 4 = 12            54 : 6 + 9 · 8 = 9 + 72 = 81 18 · 4 + 0 = 72        64 : 8 · 12 = 96        35 · 2 – 38 : 2 = 70 – 19 = 51 25 · 5 – 0 = 125      96 : 24 · 20 = 80      94 : 2 + 70 : 14 = 47 + 5 = 52', '<p><span>72 – 37 = 35           49 : 7 · 8 = 56          7 · 9 – 8 · 4 = 63 – 32 = 31</span>\n<span>500 – 475 = 25       6 · 8 : 4 = 12            54 : 6 + 9 · 8 = 9 + 72 = 81</span>\n<span>18 · 4 + 0 = 72        64 : 8 · 12 = 96        35 · 2 – 38 : 2 = 70 – 19 = 51</span>\n<span>25 · 5 – 0 = 125      96 : 24 · 20 = 80      94 : 2 + 70 : 14 = 47 + 5 = 52</span></p>\n\n<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica71-nomer10-1.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 71, номер 10, год 2022, ответ." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 71, номер 10, год 2022, ответ."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-71/')
    RETURNING id INTO v_task_id;

