    VALUES (v_textbook_id, 71, '11', 3, 'А – множество натуральных чисел, меньших 9, но больших или равных 5. Запиши множество А с помощью фигурных скобок.', '</p>\n\n<p class="text">А – множество натуральных чисел, меньших 9, но больших или равных 5. Запиши множество А с помощью фигурных скобок.</p>', 'А = {5, 6, 7, 8}', '<p>А = {5, 6, 7, 8}</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-71/')
