    VALUES (v_textbook_id, 71, '12', 4, 'На какие части можно разбить множество всех слов русского языка? Можно ли его разбить на части: «существительные» и «слова, которые начинаются с буквы М»? Почему?', '</p>\n\n<p class="text">На какие части можно разбить множество всех слов русского языка? Можно ли его разбить на части: «существительные» и «слова, которые начинаются с буквы М»? Почему?</p>', 'Множество всех слов русского языка можно разбить на слова начинающиеся с буквы «А» и так далее по алфавиту, на слова содержащие четыре буквы менее или более ... . Можно его разбить на части: «существительные» и «слова, которые начинаются с буквы М». Потому что существительные слов множество и есть слова относящиеся к другим частям речи, есть множество слов начинающиеся с буквы «М» и с других букв русского алфавита.', '<p>Множество всех слов русского языка можно разбить на слова начинающиеся с буквы «А» и так далее по алфавиту, на слова содержащие четыре буквы менее или более ... . Можно его разбить на части: «существительные» и «слова, которые начинаются с буквы М». Потому что существительные слов множество и есть слова относящиеся к другим частям речи, есть множество слов начинающиеся с буквы «М» и с других букв русского алфавита.</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-71/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '60f0de169baee6211558f2b2da7641e5189efeab5baf4e4328330a46e7ad054f', NULL, '["раз"]'::jsonb, 'на какие части можно разбить множество всех слов русского языка? можно ли его разбить на части:"существительные" и "слова, которые начинаются с буквы м"? почему');

    VALUES (v_textbook_id, 72, '1', 0, 'Запиши числа: а) девять тысяч триста пять; б) девять тысяч тридцать пять; в) девять тысяч триста пятьдесят; г) восемьдесят тысяч пятнадцать; д) девятьсот две тысячи восемь; е) шесть миллионов двадцать четыре тысячи восемьсот девять; ж) триста пять миллионов пятьсот шестьдесят тысяч восемьсот; з) двенадцать миллиардов четыреста двадцать миллионов триста сорок семь тысяч сто семьдесят пять.', '</p>\n\n<p class="text">Запиши числа:</p>\n\n<p class="description-text">\n<span>а) девять тысяч триста пять;</span>\n<span>б) девять тысяч тридцать пять;</span>\n<span>в) девять тысяч триста пятьдесят;</span>\n<span>г) восемьдесят тысяч пятнадцать;</span>\n<span>д) девятьсот две тысячи восемь;</span>\n<span>е) шесть миллионов двадцать четыре тысячи восемьсот девять;</span>\n<span>ж) триста пять миллионов пятьсот шестьдесят тысяч восемьсот;</span>\n<span>з) двенадцать миллиардов четыреста двадцать миллионов триста сорок семь тысяч сто семьдесят пять.</span></p>', 'а) 9305; б) 9035; в) 9350; г) 80015; д) 902008; е) 6024809; ж) 305560800; з) 12420347175.', '<p><span>а) 9305;</span>\n<span>б) 9035;</span>\n<span>в) 9350;</span>\n<span>г) 80015;</span>\n<span>д) 902008;</span>\n<span>е) 6024809;</span>\n<span>ж) 305560800;</span>\n<span>з) 12420347175.</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-72/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '1875e40168719b95cc561096fb0d4cbda2de98e8944bfc0f4b2f02cb55f852f0', NULL, NULL, 'запиши числа:а) девять тысяч триста пять; б) девять тысяч тридцать пять; в) девять тысяч триста пятьдесят; г) восемьдесят тысяч пятнадцать; д) девятьсот две тысячи восемь; е) шесть миллионов двадцать четыре тысячи восемьсот девять; ж) триста пять миллионов пятьсот шестьдесят тысяч восемьсот; з) двенадцать миллиардов четыреста двадцать миллионов триста сорок семь тысяч сто семьдесят пять');

    VALUES (v_textbook_id, 72, '2', 1, 'а) Прочитай числа. Сколько единиц в разряде десятков у чисел первого столбика? Сколько в каждом всего десятков? 43        43000      400030 430      40300      40003000 403      40030      400300000 б) Сколько единиц в разряде сотен тысяч у чисел третьего столбика? Сколько в каждом всего сотен тысяч? в) Запиши числа второй строки в виде суммы разрядных слагаемых. Сделай вывод.', '</p>\n\n<p class="text">а) Прочитай числа. Сколько единиц в разряде десятков у чисел первого столбика? Сколько в каждом всего десятков?</p>\n\n<p class="description-text">\n<span>43        43000      400030</span>\n<span>430      40300      40003000</span>\n<span>403      40030      400300000</span></p>\n\n<p class="text"><span>б) Сколько единиц в разряде сотен тысяч у чисел третьего столбика? Сколько в каждом всего сотен тысяч?</span>\n<span>в) Запиши числа второй строки в виде суммы разрядных слагаемых. Сделай вывод.</span></p>', 'а) Сорок три                      сорок три тысячи              четыреста тысяч тридцать Четыреста тридцать   сорок тысяч триста           сорок миллионов три тысячи Четыреста три              сорок тысяч тридцать      четыреста миллионов триста тысяч 3 единицы 43 десятка б) 4 единицы. 4 сотни тысяч. в) 400 + 30      40000 + 300      40000000 + 3000 Разрядное слагаемое – это количество единиц в данном разряде.', '<p><span>а)</span>\n<span>Сорок три                      сорок три тысячи              четыреста тысяч тридцать</span>\n<span>Четыреста тридцать   сорок тысяч триста           сорок миллионов три тысячи</span>\n<span>Четыреста три              сорок тысяч тридцать      четыреста миллионов триста тысяч</span>\n<span>3 единицы</span>\n<span>43 десятка</span>\n<span>б) 4 единицы. 4 сотни тысяч.</span>\n<span>в) 400 + 30      40000 + 300      40000000 + 3000</span>\n<span>Разрядное слагаемое – это количество единиц в данном разряде.</span></p>', '', '', TRUE, '[{"letter":"а","condition":"Прочитай числа. Сколько единиц в разряде десятков у чисел первого столбика? Сколько в каждом всего десятков? 43        43000      400030 430      40300      40003000 403      40030      400300000","solution":"Сорок три                      сорок три тысячи              четыреста тысяч тридцать Четыреста тридцать   сорок тысяч триста           сорок миллионов три тысячи Четыреста три              сорок тысяч тридцать      четыреста миллионов триста тысяч 3 единицы 43 десятка"},{"letter":"б","condition":"Сколько единиц в разряде сотен тысяч у чисел третьего столбика? Сколько в каждом всего сотен тысяч?","solution":"4 единицы. 4 сотни тысяч."},{"letter":"в","condition":"Запиши числа второй строки в виде суммы разрядных слагаемых. Сделай вывод.","solution":"400 + 30      40000 + 300      40000000 + 3000 Разрядное слагаемое – это количество единиц в данном разряде."}]'::jsonb, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-72/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '0bc0d6220274932e6fc76e662ddebd2eadd87eea8ee756138545553d74b2b8d2', '43,403,430,40030,40300,43000,400030,40003000,400300000', '["столбик","раз"]'::jsonb, 'а) прочитай числа. сколько единиц в разряде десятков у чисел первого столбика? сколько в каждом всего десятков? 43        43000      400030 430      40300      40003000 403      40030      400300000 б) сколько единиц в разряде сотен тысяч у чисел третьего столбика? сколько в каждом всего сотен тысяч? в) запиши числа второй строки в виде суммы разрядных слагаемых. сделай вывод');

    VALUES (v_textbook_id, 73, '3', 0, 'Сосчитай сумму. В каких разрядах отсутствуют единицы? а) 8000 + 400 + 30 + 5      б) 900000 + 70000 + 500     30000 + 6000 + 80 + 1      4000000 + 9000 + 80', '</p>\n\n<p class="text">Сосчитай сумму. В каких разрядах отсутствуют единицы?</p>\n\n<p class="description-text">\n<span>а) 8000 + 400 + 30 + 5      б) 900000 + 70000 + 500</span>\n<span>    30000 + 6000 + 80 + 1      4000000 + 9000 + 80</span></p>', 'а) 8000 + 400 + 30 + 5 = 8435     30000 + 6000 + 80 + 1 = 36081 – в разряде сотен отсутствуют единицы. б) 900000 + 70000 + 500 = 970500 – в разрядах десяток и единиц отсутствуют единицы.     4000000 + 9000 + 80 = 4009080 – в разрядах сотен, десяток и единиц отсутствуют единицы.', '<p><span>а) 8000 + 400 + 30 + 5 = 8435</span>\n<span>    30000 + 6000 + 80 + 1 = 36081 – в разряде сотен отсутствуют единицы.</span>\n<span>б) 900000 + 70000 + 500 = 970500 – в разрядах десяток и единиц отсутствуют единицы.</span>\n<span>    4000000 + 9000 + 80 = 4009080 – в разрядах сотен, десяток и единиц отсутствуют единицы.</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-73/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '948e10282190b49468dd72e027642f56b6919a10405c4ee357e64e475c55b1ae', '1,5,30,80,400,500,6000,8000,9000,30000', '["раз"]'::jsonb, 'сосчитай сумму. в каких разрядах отсутствуют единицы? а) 8000+400+30+5      б) 900000+70000+500     30000+6000+80+1      4000000+9000+80');

    VALUES (v_textbook_id, 73, '4', 1, 'Запиши числа в виде суммы разрядных слагаемых: 42 075      200 097      384 794      7 056 448', '</p>\n\n<p class="text">Запиши числа в виде суммы разрядных слагаемых:</p>\n\n<p class="description-text">\n42 075      200 097      384 794      7 056 448</p>', '40000 + 2000 + 70 + 5 200000 + 90 + 7 300000 + 80000 + 4000 + 700 + 90 + 4 7000000 + 50000 + 6000 + 400 + 40 + 8', '<p><span>40000 + 2000 + 70 + 5</span>\n<span>200000 + 90 + 7</span>\n<span>300000 + 80000 + 4000 + 700 + 90 + 4</span>\n<span>7000000 + 50000 + 6000 + 400 + 40 + 8</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-73/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, 'bb3d773f2dc2d9baecb11ac2181e758a2ce9b58815441aa2b2d7fc2f1989e6e0', '7,42,056,075,097,200,384,448,794', '["раз"]'::jsonb, 'запиши числа в виде суммы разрядных слагаемых:42 075      200 097      384 794      7 056 448');

    VALUES (v_textbook_id, 73, '5', 2, 'БЛИЦтурнир а) На одном сеансе в кинотеатре побывали а человек, а на другом – на 70 человек меньше. Сколько всего человек побывали на обоих сеансах? б) В первом пансионате отдыхает b человек, а во втором – в 3 раза больше. На сколько меньше отдыхающих в первом пансионате, чем во втором? в) В автобусе ехало n человек. На остановке вышли c человек, а вошли d человек. Сколько человек стало в автобусе? г) Выставку детских рисунков за 3 дня посетили а человек. В первый день её посетили b человек, а во второй день – в 2 раза больше. Сколько человек посетили выставку в третий день? д) В пяти одинаковых автобусах можно разместить х человек. Сколько человек можно разместить в восьми таких автобусах?', '</p>\n\n<p class="text"><span><b>БЛИЦтурнир</b></span>\n<span>а) На одном сеансе в кинотеатре побывали <b>а</b> человек, а на другом – на 70 человек меньше. Сколько всего человек побывали на обоих сеансах?</span>\n<span>б) В первом пансионате отдыхает <b>b</b> человек, а во втором – в 3 раза больше. На сколько меньше отдыхающих в первом пансионате, чем во втором?</span>\n<span>в) В автобусе ехало <b>n</b> человек. На остановке вышли <b>c</b> человек, а вошли <b>d</b> человек. Сколько человек стало в автобусе?</span>\n<span>г) Выставку детских рисунков за 3 дня посетили <b>а</b> человек. В первый день её посетили <b>b</b> человек, а во второй день – в 2 раза больше. Сколько человек посетили выставку в третий день?</span>\n<span>д) В пяти одинаковых автобусах можно разместить <b>х</b> человек. Сколько человек можно разместить в восьми таких автобусах?</span></p>', 'а) а + а – 70 = 2а – 70 (человек)      Ответ: 2а – 70 всего человек побывали на обоих сеансах. б) 3b – b = 2b      Ответ: на 2b меньше отдыхающих в первом пансионате, чем во втором. в) n – c + d (человек)      Ответ: n – c + d человек стало в автобусе. г) a – b – 2b = а – 3b (человек)      Ответ: а – 3b человек посетили выставку в третий день. д) 8 : х : 5 = х : 40 (человек)      Ответ: х : 40 человек можно разместить в восьми таких автобусах.', '<p><span>а) а + а – 70 = 2а – 70 (человек)</span>\n<span>    <b>Ответ:</b> 2а – 70 всего человек побывали на обоих сеансах.</span>\n<span>б) 3b – b = 2b</span>\n<span>    <b>Ответ:</b> на 2b меньше отдыхающих в первом пансионате, чем во втором.</span>\n<span>в) n – c + d (человек)</span>\n<span>    <b>Ответ:</b> n – c + d человек стало в автобусе.</span>\n<span>г) a – b – 2b = а – 3b (человек)</span>\n<span>    <b>Ответ:</b> а – 3b человек посетили выставку в третий день.</span>\n<span>д) 8 : х : 5 = х : 40 (человек)</span>\n<span>    <b>Ответ:</b> х : 40 человек можно разместить в восьми таких автобусах.</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-73/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, 'a9d5f736d00634f10d8658908606c04d0a8b665f53c4087e2fe258d1e146cc6a', '2,3,70', '["больше","меньше","раз","раза"]'::jsonb, 'блицтурнир а) на одном сеансе в кинотеатре побывали а человек, а на другом-на 70 человек меньше. сколько всего человек побывали на обоих сеансах? б) в первом пансионате отдыхает b человек, а во втором-в 3 раза больше. на сколько меньше отдыхающих в первом пансионате, чем во втором? в) в автобусе ехало n человек. на остановке вышли c человек, а вошли d человек. сколько человек стало в автобусе? г) выставку детских рисунков за 3 дня посетили а человек. в первый день её посетили b человек, а во второй день-в 2 раза больше. сколько человек посетили выставку в третий день? д) в пяти одинаковых автобусах можно разместить х человек. сколько человек можно разместить в восьми таких автобусах');

    VALUES (v_textbook_id, 73, '6', 3, 'Как найти целое? Как найти часть? Составь все возможные равенства из чисел: 251, 319, 570.', '</p>\n\n<p class="text">Как найти целое? Как найти часть? Составь все возможные равенства из чисел: 251, 319, 570.</p>', '251 + 319 = 570 570 : 251 = 2 + 68      570 : 319 = 1 + 251', '<p><span>251 + 319 = 570</span>\n<span>570 : 251 = 2 + 68      570 : 319 = 1 + 251</span></p>\n\n<div class="img-wrapper-460">\n<img width="240" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica73-nomer6.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 73, номер 6, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 73, номер 6, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-73/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, 'solution', 0, NULL, 'https://gdz-raketa.ru/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica73-nomer6.jpg', 'peterson/3/part1/page73/task6_solution_0.jpg', '');

    VALUES (v_task_id, v_textbook_id, 3, 'bdbb4a73fc7868fcfd4df721442a567068bf6a26fa246edd23b2715025a92d32', '251,319,570', NULL, 'как найти целое? как найти часть? составь все возможные равенства из чисел:251, 319, 570');

    VALUES (v_textbook_id, 73, '7', 4, 'Реши уравнения с комментированием и сделай проверку: х – 374 = 546      687 + х = 814      432 – х = 396', '</p>\n\n<p class="text">Реши уравнения с комментированием и сделай проверку:</p>\n\n<p class="description-text">\nх – 374 = 546      687 + х = 814      432 – х = 396</p>', 'х – 374 = 546 х = 546 + 374', '<p><span>х – 374 = 546</span>\n<span>х = 546 + 374</span></p>\n\n<div class="img-wrapper-460">\n<img width="100" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica73-nomer7.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 73, номер 7, год 2022, ответ." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 73, номер 7, год 2022, ответ."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-73/')
    RETURNING id INTO v_task_id;

