    VALUES (v_textbook_id, 73, '8', 5, 'Составь программу действий и вычисли: а) (17 + 43) : 2 – 9 · 8 : 4 + 70 : (7 + 7) б) 96 : 2 : 12 + 15 · (78 : 13) – (33 + 54) : 3', '</p>\n\n<p class="text">Составь программу действий и вычисли:</p>\n\n<p class="description-text">\n<span>а) (17 + 43) : 2 – 9 · 8 : 4 + 70 : (7 + 7)</span>\n<span>б) 96 : 2 : 12 + 15 · (78 : 13) – (33 + 54) : 3</span></p>', 'а) (17 + 43) : 2 – 9 · 8 : 4 + 70 : (7 + 7) = 17     17 + 43 = 60     60 : 2 = 30     7 + 7 = 14     70 : 14 = 5     9 · 8 = 72     72 : 4 = 18     30 – 18 = 12     12 + 5 = 17 б) 96 : 2 : 12 + 15 · (78 : 13) – (33 + 54) : 3 = 65     96 : 2 = 48     48 : 12 = 4     78 : 13 = 6     15 · 6 = 90     33 + 54 = 87     87 : 3 = 29     4 + 90 = 94     94 – 29 = 65', '<p><span>а) (17 + 43) : 2 – 9 · 8 : 4 + 70 : (7 + 7) = 17</span>\n<span>    17 + 43 = 60</span>\n<span>    60 : 2 = 30</span>\n<span>    7 + 7 = 14</span>\n<span>    70 : 14 = 5</span>\n<span>    9 · 8 = 72</span>\n<span>    72 : 4 = 18</span>\n<span>    30 – 18 = 12</span>\n<span>    12 + 5 = 17</span>\n<br/>\n<span>б) 96 : 2 : 12 + 15 · (78 : 13) – (33 + 54) : 3 = 65</span>\n<span>    96 : 2 = 48</span>\n<span>    48 : 12 = 4</span>\n<span>    78 : 13 = 6</span>\n<span>    15 · 6 = 90</span>\n<span>    33 + 54 = 87</span>\n<span>    87 : 3 = 29</span>\n<span>    4 + 90 = 94</span>\n<span>    94 – 29 = 65</span></p>\n\n<div class="img-wrapper-460">\n<img width="100" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica73-nomer8.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 73, номер 8, год 2022, ответ." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 73, номер 8, год 2022, ответ."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-73/')
    RETURNING id INTO v_task_id;

