    VALUES (v_textbook_id, 73, '9', 6, 'Найди значения выражений (20 + х) : 2 и 20 + х : 2, если х = 8, 12, 26, 42. Что ты замечаешь? Как это можно объяснить?', '</p>\n\n<p class="text">Найди значения выражений (20 + х) : 2 и 20 + х : 2, если х = 8, 12, 26, 42. Что ты замечаешь? Как это можно объяснить?</p>', 'х = 8, (20 + 8) : 2 = 14 и 20 + 8 : 2 = 24 х = 12, (20 + 12) : 2 = 16 и 20 + 12 : 2 = 26 х = 26, (20 + 26) : 2 = 23 и 20 + 26 : 2 = 33 х = 42, (20 + 42) : 2 = 31 и 20 + 42 : 2 = 41 Результаты получаются с разницей на 10. Наличие или отсутствие скобок меняет порядок вычислений, поэтому есть разница в том сумму или только часть суммы делить.', '<p><span>х = 8, (20 + 8) : 2 = 14 и 20 + 8 : 2 = 24</span>\n<span>х = 12, (20 + 12) : 2 = 16 и 20 + 12 : 2 = 26</span>\n<span>х = 26, (20 + 26) : 2 = 23 и 20 + 26 : 2 = 33</span>\n<span>х = 42, (20 + 42) : 2 = 31 и 20 + 42 : 2 = 41</span>\n<span>Результаты получаются с разницей на 10. Наличие или отсутствие скобок меняет порядок вычислений, поэтому есть разница в том сумму или только часть суммы делить.</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-73/')
    RETURNING id INTO v_task_id;

