    VALUES (v_task_id, v_textbook_id, 3, 'a31fd6403be0d99ae6064db44269bdde4f880094637431cc33e4f774006a9daf', '7', '["найди","раз"]'::jsonb, 'а) прочитай числа. сколько единиц у этих чисел в разряде сотен миллионов? сколько всего в них сотен миллионов? б) найди число, в разряде десятков тысяч которого стоит цифра 7. запиши его в виде суммы разрядных слагаемых');

    VALUES (v_textbook_id, 74, '2', 1, 'Найди разряды, в которых отсутствуют единицы. Запиши цифрами числа: а) 24 тыс. 715 ед.      г) 2 млн 3 тыс. 18 ед. б) 4 тыс. 5 ед.             д) 17 млн 623 ед. в) 812 тыс. 34 ед.      е) 9 млн 4 тыс. 7 ед.', '</p>\n\n<p class="text">Найди разряды, в которых отсутствуют единицы. Запиши цифрами числа:</p>\n\n<p class="description-text">\n<span>а) 24 тыс. 715 ед.      г) 2 млн 3 тыс. 18 ед.</span>\n<span>б) 4 тыс. 5 ед.             д) 17 млн 623 ед.</span>\n<span>в) 812 тыс. 34 ед.      е) 9 млн 4 тыс. 7 ед.</span></p>', 'а) отсутствуют единиц в разряде сотен, 24715. б) отсутствуют единиц в разряде сотен, десятков, 4005. в) отсутствуют единиц в разряде сотен, 812034. г) отсутствуют единиц в разряде сотен, десятков, 2003018. д) отсутствуют единиц в разряде сотен, десятков и единиц, 17000623. е) отсутствуют единиц в разряде сотен, десятков, 9004007.', '<p><span>а) отсутствуют единиц в разряде сотен, 24715.</span>\n<span>б) отсутствуют единиц в разряде сотен, десятков, 4005.</span>\n<span>в) отсутствуют единиц в разряде сотен, 812034.</span>\n<span>г) отсутствуют единиц в разряде сотен, десятков, 2003018.</span>\n<span>д) отсутствуют единиц в разряде сотен, десятков и единиц, 17000623.</span>\n<span>е) отсутствуют единиц в разряде сотен, десятков, 9004007.</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-74/')
