    VALUES (v_textbook_id, 74, '4', 3, 'Что ты уже умеешь делать с многозначными числами? Чему надо научиться? Попробуй сложить и вычесть два многозначных числа по своему выбору. Сделай вывод.', '</p>\n\n<p class="text">Что ты уже умеешь делать с многозначными числами? Чему надо научиться? Попробуй сложить и вычесть два многозначных числа по своему выбору. Сделай вывод.</p>', 'Уже умею складывать и вычитать многозначные числа. 247543 + 3467 = 251010', '<p><span>Уже умею складывать и вычитать многозначные числа.</span>\n<span>247543 + 3467 = 251010</span></p>\n\n<div class="img-wrapper-460">\n<img width="190" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica74-nomer4.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 74, номер 4, год 2022, ответ." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 74, номер 4, год 2022, ответ."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-74/')
