    VALUES (v_textbook_id, 75, '8', 3, 'Реши уравнения с комментированием: х : 25 = 80      960 : х = 4      35 · х = 700', '</p>\n\n<p class="text">Реши уравнения с комментированием:</p>\n\n<p class="description-text">\nх : 25 = 80      960 : х = 4      35 · х = 700</p>', 'х : 25 = 80 Что бы найти делимое х нужно частное умножить на делитель х = 25 · 80 х = 2000 960 : х = 4 Что бы найти делитель х нужно делимое разделить на частное х = 960 : 4 х = 240 35 · х = 700 Что бы найти неизвестное слагаемое произведения х нужно произведение разделить на известное слагаемое х = 700 : 35 х = 20', '<p><span>х : 25 = 80</span>\n<span>Что бы найти делимое х нужно частное умножить на делитель</span>\n<span>х = 25 · 80</span>\n<span>х = 2000</span>   \n<span>960 : х = 4</span>\n<span>Что бы найти делитель х нужно делимое разделить на частное</span>\n<span>х = 960 : 4</span>\n<span>х = 240</span>   \n<span>35 · х = 700</span>\n<span>Что бы найти неизвестное слагаемое произведения х нужно произведение разделить на известное слагаемое</span>\n<span>х = 700 : 35</span>\n<span>х = 20</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-75/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '148fec48d5cfdf06d385817a35104079463709827524f24a8413abfd9242d37c', '4,25,35,80,700,960', '["реши"]'::jsonb, 'реши уравнения с комментированием:х:25=80      960:х=4      35*х=700');

    VALUES (v_textbook_id, 75, '9', 4, 'БЛИЦтурнир а) Банан стоит а р., а ананас на b р. дороже. Во сколько раз банан дешевле ананаса? б) На с р. можно купить 5 кг яблок. Сколько рублей надо заплатить за 8 кг таких же яблок? в) На с р. можно купить 5 кг яблок. Сколько килограммов таких яблок можно купить на d рублей? г) Стол стоит х р., а стул – у р. Сколько стоят 2 таких стола и 8 стульев? д) Карандаш стоит а р. Сколько надо заплатить за 2 коробки таких карандашей, если в одной из них m штук, а в другой – n штук карандашей? е) Оля истратила b р., а осталось у неё в 2 раза больше, чем она истратила. Сколько было денег у Оли вначале?', '</p>\n\n<p class="text"><span><b>БЛИЦтурнир</b></span>\n<span>а) Банан стоит <b>а</b> р., а ананас на <b>b</b> р. дороже. Во сколько раз банан дешевле ананаса?</span>\n<span>б) На <b>с</b> р. можно купить 5 кг яблок. Сколько рублей надо заплатить за 8 кг таких же яблок?</span>\n<span>в) На <b>с</b> р. можно купить 5 кг яблок. Сколько килограммов таких яблок можно купить на <b>d</b> рублей?</span>\n<span>г) Стол стоит <b>х</b> р., а стул – <b>у</b> р. Сколько стоят 2 таких стола и 8 стульев?</span>\n<span>д) Карандаш стоит <b>а</b> р. Сколько надо заплатить за 2 коробки таких карандашей, если в одной из них <b>m</b> штук, а в другой – <b>n</b> штук карандашей?</span>\n<span>е) Оля истратила <b>b</b> р., а осталось у неё в 2 раза больше, чем она истратила. Сколько было денег у Оли вначале?</span></p>', 'а) а : (а + b) (раз)      Ответ: в а : (а + b) раз банан дешевле ананаса. б) (с : 5) · 8 (р)      Ответ: (с : 5) · 8 рублей надо заплатить за 8 кг таких же яблок. в) d : (с : 5) (кг)      Ответ: d : (с : 5) килограммов таких яблок можно купить на d рублей. г) 2х + 8у (р.)      Ответ: 2х + 8у рублей стоят 2 таких стола и 8 стульев. д) а(n + m) (р.)      Ответ: а(n + m) рублей надо заплатить за 2 коробки таких карандашей, если в одной из них m штук, а в другой – n штук карандашей. е) b + 2b = 3b (р.)      Ответ: 3b рублей было у Оли вначале.', '<p><span>а) а : (а + b) (раз)</span>\n<span>    <b>Ответ:</b> в а : (а + b) раз банан дешевле ананаса.</span>\n<span>б) (с : 5) · 8 (р)</span>\n<span>    <b>Ответ:</b> (с : 5) · 8 рублей надо заплатить за 8 кг таких же яблок.</span>\n<span>в) d : (с : 5) (кг)</span>\n<span>    <b>Ответ:</b> d : (с : 5) килограммов таких яблок можно купить на d рублей.</span>\n<span>г) 2х + 8у (р.)</span>\n<span>    <b>Ответ:</b> 2х + 8у рублей стоят 2 таких стола и 8 стульев.</span>\n<span>д) а(n + m) (р.)</span>\n<span>    <b>Ответ:</b> а(n + m) рублей надо заплатить за 2 коробки таких карандашей, если в одной из них  m штук, а в другой – n штук карандашей.</span>\n<span>е) b + 2b = 3b (р.)</span>\n<span>    <b>Ответ:</b> 3b рублей было у Оли вначале.</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-75/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '6da5f9301f6121fafb0cbc5108237513b1d63f1d9568ee493b1889cbd4a194ce', '2,5,8', '["больше","раз","раза"]'::jsonb, 'блицтурнир а) банан стоит а р., а ананас на b р. дороже. во сколько раз банан дешевле ананаса? б) на с р. можно купить 5 кг яблок. сколько рублей надо заплатить за 8 кг таких же яблок? в) на с р. можно купить 5 кг яблок. сколько килограммов таких яблок можно купить на d рублей? г) стол стоит х р., а стул-у р. сколько стоят 2 таких стола и 8 стульев? д) карандаш стоит а р. сколько надо заплатить за 2 коробки таких карандашей, если в одной из них m штук, а в другой-n штук карандашей? е) оля истратила b р., а осталось у неё в 2 раза больше, чем она истратила. сколько было денег у оли вначале');

    VALUES (v_textbook_id, 75, '10', 5, 'Какие трёхзначные числа можно составить из цифр 0, 3, 5, если цифры в записи числа: а) не повторяются; б) могут повторяться? Сколько таких чисел?', '</p>\n\n<p class="text">Какие трёхзначные числа можно составить из цифр 0, 3, 5, если цифры в записи числа: а) не повторяются; б) могут повторяться? Сколько таких чисел?</p>', 'а) 350, 530, б) 300, 500, 333, 555, 355, 353, 535, 355, 533, 503, 505, 303, 305, 330, 550, 335. 16 чисел.', '<p><span>а) 350, 530,</span>\n<span>б) 300, 500, 333, 555, 355, 353, 535, 355, 533, 503, 505, 303, 305, 330, 550, 335. 16 чисел.</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-75/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, 'c19fe0e5c00e6d2a1da55c0f389bfade54c0dfe891210c9cc6d05a3b97935294', '0,3,5', NULL, 'какие трёхзначные числа можно составить из цифр 0, 3, 5, если цифры в записи числа:а) не повторяются; б) могут повторяться? сколько таких чисел');

    VALUES (v_textbook_id, 76, '1', 0, 'Разбей числа на классы и прочитай их: а) 5075; б) 20068; в) 418093; г) 540780; д) 8012505; е) 36015724; ж) 29300006; з) 756818042; и) 9560002729.', '</p>\n\n<p class="text">Разбей числа на классы и прочитай их:</p>\n\n<p class="description-text">\n<span>а) 5075; б) 20068; в) 418093; г) 540780; д) 8012505;</span>\n<span>е) 36015724; ж) 29300006; з) 756818042; и) 9560002729.</span></p>', 'а) 5075: 5 – класс тысяч, 075 – класс единиц, пять тысяч семьдесят пять; б) 20068: 20 – класс тысяч, 068 – класс единиц, двадцать тысяч шестьдесят восемь; в) 418093: 418 – класс тысяч, 093 – класс единиц, четыреста восемнадцать тысяч девяносто три; г) 540780: 540 – класс тысяч, 780 – класс единиц, пятьсот сорок тысяч семьсот восемьдесят; д) 8012505: 8 – класс миллионов, 012 – класс тысяч, 505 – класс единиц, восемь миллионов двенадцать тысяч пятьсот пять; е) 36015724: 36 – класс миллионов, 015 – класс тысяч, 724 – класс единиц; ж) 29300006: 29 – класс миллионов, 300 – класс тысяч, 006 – класс единиц, двадцать девять миллионов триста тысяч шесть; з) 756818042: 756 – класс миллионов, 818 – класс тысяч, 042 – класс единиц, семьсот пятьдесят шесть миллионов восемьсот восемнадцать тысяч сорок два; и) 9560002729: 9 – класс миллиардов, 560 – класс миллионов, 002 – класс единиц, 729 – класс единиц, девять миллиардов пятьсот шестьдесят миллионов две тысячи семьсот двадцать девять.', '<p><span>а) 5075: 5 – класс тысяч, 075 – класс единиц, пять тысяч семьдесят пять;</span>\n<span>б) 20068: 20 – класс тысяч, 068 – класс единиц, двадцать тысяч шестьдесят восемь;</span>\n<span>в) 418093: 418 – класс тысяч, 093 – класс единиц, четыреста восемнадцать тысяч девяносто три;</span>\n<span>г) 540780: 540 – класс тысяч, 780 – класс единиц, пятьсот сорок тысяч семьсот восемьдесят;</span>\n<span>д) 8012505: 8 – класс миллионов, 012 – класс тысяч, 505 – класс единиц, восемь миллионов двенадцать тысяч пятьсот пять;</span>\n<span>е) 36015724: 36 – класс миллионов, 015 – класс тысяч, 724 – класс единиц;</span>\n<span>ж) 29300006: 29 – класс миллионов, 300 – класс тысяч, 006 – класс единиц, двадцать девять миллионов триста тысяч шесть;</span>\n<span>з) 756818042: 756 – класс миллионов, 818 – класс тысяч, 042 – класс единиц, семьсот пятьдесят шесть миллионов восемьсот восемнадцать тысяч сорок два;</span> \n<span>и) 9560002729: 9 – класс миллиардов, 560 – класс миллионов, 002 – класс единиц, 729 – класс единиц, девять миллиардов пятьсот шестьдесят миллионов две тысячи семьсот двадцать девять.</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-76/')
    RETURNING id INTO v_task_id;

