    VALUES (v_textbook_id, 76, '3', 2, 'Вычисли. Проверь результаты с помощью калькулятора. а) 2956307 + 18769 в) 85297 + 3644905 б) 4600805 – 576095 г) 10000000 – 93918', '</p>\n\n<p class="text">Вычисли. Проверь результаты с помощью калькулятора.</p>\n\n<p class="description-text">\n<span>а) 2956307 + 18769 в) 85297 + 3644905</span>\n<span>б) 4600805 – 576095 г) 10000000 – 93918</span></p>', 'а) 2956307 + 18769 = 2975076', '<p>а) 2956307 + 18769 = 2975076</p>\n\n<div class="img-wrapper-460">\n<img width="220" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica76-nomer3.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 76, номер 3, год 2022, ответ." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 76, номер 3, год 2022, ответ."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-76/')
