    VALUES (v_textbook_id, 76, '5', 4, 'Реши задачи, составляя выражения. Сравни их. Что ты замечаешь? Как называют такие задачи? а) Из 24 м ткани сшили 8 одинаковых скатертей. Сколько ткани потребуется для пошива 15 таких скатертей? б) Из 24 м ткани сшили 8 одинаковых скатертей. Сколько таких скатертей можно сшить из 45 м ткани?', '</p>\n\n<p class="text">Реши задачи, составляя выражения. Сравни их. Что ты замечаешь? Как называют такие задачи?</p>\n\n<p class="description-text">\n<span>а) Из 24 м ткани сшили 8 одинаковых скатертей. Сколько ткани потребуется для пошива 15 таких скатертей?</span>\n<span>б) Из 24 м ткани сшили 8 одинаковых скатертей. Сколько таких скатертей можно сшить из 45 м ткани?</span></p>', 'а) 24 : 8 · 15 = 3 · 15 = 45 (м)v      Ответ: 45 метров ткани потребуется для пошива 15 таких скатертей.v б) 45 : 24 : 8 = 15 (штук)v      Ответ: 15 таких скатертей можно сшить из 45 м ткани.v     Взаимно – обратными друг другу.', '<p><span>а) 24 : 8 · 15 = 3 · 15 = 45 (м)v\n<span>    <b>Ответ:</b> 45 метров ткани потребуется для пошива 15 таких скатертей.v\n<span>б) 45 : 24 : 8 = 15 (штук)v\n<span>    <b>Ответ:</b> 15 таких скатертей можно сшить из 45 м ткани.v\n<span>    Взаимно – обратными друг другу.</span></span></span></span></span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-76/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '56d2c8f730fa3b8dc78668c301ebe03c3f32a6174b78db5c9e14e2e26ed0ab7b', '8,15,24,45', '["реши","сравни"]'::jsonb, 'реши задачи, составляя выражения. сравни их. что ты замечаешь? как называют такие задачи? а) из 24 м ткани сшили 8 одинаковых скатертей. сколько ткани потребуется для пошива 15 таких скатертей? б) из 24 м ткани сшили 8 одинаковых скатертей. сколько таких скатертей можно сшить из 45 м ткани');

    VALUES (v_textbook_id, 76, '6', 5, 'Придумай задачи по выражениям: а) (60 : 6) · 4; б) 72 : (48 : 6).', '</p>\n\n<p class="text">Придумай задачи по выражениям:</p>\n\n<p class="description-text">\nа) (60 : 6) · 4; б) 72 : (48 : 6).</p>', 'а) (60 : 6) · 4 = 40 (м)     Из 60 м ткани сшили 6 одинаковых скатертей. Сколько ткани потребуется для пошива 4 таких скатертей?; б) 72 : (48 : 6) = 9 (штук)     Из 48 м ткани сшили 6 одинаковых скатертей. Сколько таких скатертей можно сшить из 72 м ткани?', '<p><span>а) (60 : 6) · 4 = 40 (м)</span>\n<span>    Из 60 м ткани сшили 6 одинаковых скатертей. Сколько ткани потребуется для пошива 4 таких скатертей?;</span>\n<span>б) 72 : (48 : 6) = 9 (штук)</span>\n<span>    Из 48 м ткани сшили 6 одинаковых скатертей. Сколько таких скатертей можно сшить из 72 м ткани?</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-76/')
    RETURNING id INTO v_task_id;

