    VALUES (v_textbook_id, 76, '8', 7, 'а) Пользуясь числовым лучом, составь множество двузначных чисел, кратных 17. б) Выполни деление с остатком: 38 : 17      56 : 17      70 : 17      91 : 17 в) Выучи двузначные числа, кратные 17. Проверь себя, работая в паре.', '</p>\n\n<p class="text">а) Пользуясь числовым лучом, составь множество двузначных чисел, кратных 17.</p>\n\n<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica76-nomer8.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 76, номер 8, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 76, номер 8, год 2022."/>\n</div>\n\n<p class="text">б) Выполни деление с остатком:</p>\n\n<p class="description-text">\n38 : 17      56 : 17      70 : 17      91 : 17</p>\n\n<p class="text">в) Выучи двузначные числа, кратные 17. Проверь себя, работая в паре.</p>', 'а) {17; 34; 51; 68; 85; 102; 119; 136; 153; 170} б) 38 : 17 = 2 + 4     34 : 17 = 2, 38 – 34 = 4     56 : 17 = 3 + 5     51 : 17 = 3, 56 – 51 = 5     70 : 17 = 4 + 2     68 : 17 = 4, 70 – 68 = 2     91 : 17 = 5 + 6     85 : 17 = 5, 91 – 85 = 6 в) 17, 34, 51, 68, 85, 102, 119, 136, 153, 170', '<p><span>а) {17; 34; 51; 68; 85; 102; 119; 136; 153; 170}</span>\n<span>б) 38 : 17 = 2 + 4</span>\n<span>    34 : 17 = 2, 38 – 34 = 4</span>\n<span>    56 : 17 = 3 + 5</span>\n<span>    51 : 17 = 3, 56 – 51 = 5</span>\n<span>    70 : 17 = 4 + 2</span>\n<span>    68 : 17 = 4, 70 – 68 = 2</span>\n<span>    91 : 17 = 5 + 6</span>\n<span>    85 : 17 = 5, 91 – 85 = 6</span>\n<span>в) 17, 34, 51, 68, 85, 102, 119, 136, 153, 170</span></p>', '', '', TRUE, '[{"letter":"а","condition":"Пользуясь числовым лучом, составь множество двузначных чисел, кратных 17.","solution":"{17; 34; 51; 68; 85; 102; 119; 136; 153; 170}"},{"letter":"б","condition":"Выполни деление с остатком: 38 : 17      56 : 17      70 : 17      91 : 17","solution":"38 : 17 = 2 + 4     34 : 17 = 2, 38 – 34 = 4     56 : 17 = 3 + 5     51 : 17 = 3, 56 – 51 = 5     70 : 17 = 4 + 2     68 : 17 = 4, 70 – 68 = 2     91 : 17 = 5 + 6     85 : 17 = 5, 91 – 85 = 6"},{"letter":"в","condition":"Выучи двузначные числа, кратные 17. Проверь себя, работая в паре.","solution":"17, 34, 51, 68, 85, 102, 119, 136, 153, 170"}]'::jsonb, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-76/')
    RETURNING id INTO v_task_id;

