    VALUES (v_task_id, v_textbook_id, 3, '7a0de280f99a219b3daf5bf106ff912ad7990934e98b1fb018e31c387b8ea4da', '17,38,56,70,91', NULL, 'а) пользуясь числовым лучом, составь множество двузначных чисел, кратных 17. б) выполни деление с остатком:38:17      56:17      70:17      91:17 в) выучи двузначные числа, кратные 17. проверь себя, работая в паре');

    VALUES (v_textbook_id, 77, '9', 0, 'Cравни, не вычисляя. Обоснуй свой ответ. 264 · 98     95 · 264            7 · (39 + 2)     7 · 2 + 7 · 39 (7 · 15) · 4     7 · (4 · 15)      (9 + 14) · 8     8 · 9 + 12 · 8', '</p>\n\n<p class="text">Cравни, не вычисляя. Обоснуй свой ответ.</p>\n\n<p class="description-text">\n<span>264 · 98 <span class="okon">   </span> 95 · 264            7 · (39 + 2) <span class="okon">   </span> 7 · 2 + 7 · 39</span>\n<span>(7 · 15) · 4 <span class="okon">   </span> 7 · (4 · 15)      (9 + 14) · 8 <span class="okon">   </span> 8 · 9 + 12 · 8</span></p>', '264 · 98 ˃ 95 · 264 – 98 больше 95 (7 · 15) · 4 = 7 · (4 · 15) – множители равны 7 · (39 + 2) = 7 · 2 + 7 · 39 – при раскрытии скобок получается равенство (9 + 14) · 8 ˃ 8 · 9 + 12 · 8 – при раскрытии скобок один из множителе слагаемого суммы больше на 14 – 12 = 2.', '<p><span>264 · 98 ˃ 95 · 264 – 98 больше 95</span>\n<span>(7 · 15) · 4 = 7 · (4 · 15) – множители равны</span>\n<span>7 · (39 + 2) = 7 · 2 + 7 · 39 – при раскрытии скобок получается равенство</span>\n<span>(9 + 14) · 8 ˃ 8 · 9 + 12 · 8 – при раскрытии скобок один из множителе слагаемого суммы больше на 14 – 12 = 2.</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-77/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '65e82e905dd518c32e96c10465c22a058b2bafcb2cf504f4facf741e150409a3', '2,4,7,8,9,12,14,15,39,95', NULL, 'cравни, не вычисляя. обоснуй свой ответ. 264*98     95*264            7*(39+2)     7*2+7*39 (7*15)*4     7*(4*15)      (9+14)*8     8*9+12*8');

    VALUES (v_textbook_id, 77, '10', 1, 'Вычисли. Наложи прозрачную плёнку и соедини ответы по порядку. Что получилось? 1. (71 – 19) : 13      6. 42 · 2 – 25 · 3         11. (58 + 26) : 14 2. (19 + 9) · 3          7. 15 · 5 + 50 : 2         12. 24 : 6 + 36 3. 100 – 16 : 4         8. (75 – 74) · 5 · 9      13. 91 : 13 · 8 : 14 4. (44 + 33) : 7         9. 6 · (72 – 32) : 8      14. 80 : 16 · 9 : 15 5. (36 + 48) : 12      10. 32 + 48 : 8 · 3       15. 72 : 12 · 9 : 27', '</p>\n\n<p class="text">Вычисли. Наложи прозрачную плёнку и соедини ответы по порядку. Что получилось?</p>\n\n<p class="description-text">\n<span>1. (71 – 19) : 13      6. 42 · 2 – 25 · 3         11. (58 + 26) : 14</span>\n<span>2. (19 + 9) · 3          7. 15 · 5 + 50 : 2         12. 24 : 6 + 36</span>\n<span>3. 100 – 16 : 4         8. (75 – 74) · 5 · 9      13. 91 : 13 · 8 : 14</span>\n<span>4. (44 + 33) : 7         9. 6 · (72 – 32) : 8      14. 80 : 16 · 9 : 15</span>\n<span>5. (36 + 48) : 12      10. 32 + 48 : 8 · 3       15. 72 : 12 · 9 : 27</span></p>\n\n<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica77-nomer10.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 77, номер 10, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 77, номер 10, год 2022."/>\n</div>', '1. (71 – 19) : 13 = 4         6. 42 · 2 – 25 · 3 = 9           11. (58 + 26) : 14 = 6 2. (19 + 9) · 3 = 84           7. 15 · 5 + 50 : 2 = 100      12. 24 : 6 + 36 = 40 3. 100 – 16 : 4 = 96          8. (75 – 74) · 5 · 9 = 45      13. 91 : 13 · 8 : 14 = 4 4. (44 + 33) : 7 = 11         9. 6 · (72 – 32) : 8 = 30      14. 80 : 16 · 9 : 15 = 3 5. (36 + 48) : 12 = 7         10. 32 + 48 : 8 · 3 = 50      15. 72 : 12 · 9 : 27 = 2', '<p><span>1. (71 – 19) : 13 = 4         6. 42 · 2 – 25 · 3 = 9           11. (58 + 26) : 14 = 6</span>\n<span>2. (19 + 9) · 3 = 84           7. 15 · 5 + 50 : 2 = 100      12. 24 : 6 + 36 = 40</span>\n<span>3. 100 – 16 : 4 = 96          8. (75 – 74) · 5 · 9 = 45      13. 91 : 13 · 8 : 14 = 4</span>\n<span>4. (44 + 33) : 7 = 11         9. 6 · (72 – 32) : 8 = 30      14. 80 : 16 · 9 : 15 = 3</span>\n<span>5. (36 + 48) : 12 = 7         10. 32 + 48 : 8 · 3 = 50      15. 72 : 12 · 9 : 27 = 2</span></p>\n\n<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica77-nomer10-1.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 77, номер 10, год 2022, ответ." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 77, номер 10, год 2022, ответ."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-77/')
