    VALUES (v_textbook_id, 77, '11', 2, 'Используя связь между числами первой строки, найди неизвестное число во второй строке:', '</p>\n\n<p class="text">Используя связь между числами первой строки, найди неизвестное число во второй строке:</p>\n\n<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica77-nomer11.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 77, номер 11, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 77, номер 11, год 2022."/>\n</div>', 'а) 60 = 18 + 42, 26 + 19 = 45 б) 73 – 35 = 38, 65 – 17 = 48 в) 12 · 4 = 48, 23 · 5 = 115', '<p><span>а) 60 = 18 + 42, 26 + 19 = 45</span>\n<span>б) 73 – 35 = 38, 65 – 17 = 48</span>\n<span>в) 12 · 4 = 48, 23 · 5 = 115</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-77/')
