    VALUES (v_textbook_id, 77, '12', 3, 'Составь множество двузначных чисел, в записи которых используются лишь цифры 2, 5 и 8. Найди пересечение этого множества с множеством чётных чисел.', '</p>\n\n<p class="text">Составь множество двузначных чисел, в записи которых используются лишь цифры 2, 5 и 8. Найди пересечение этого множества  с множеством чётных чисел.</p>', '22, 25, 55, 52, 28, 58, 88, 85, 82. {22; 52; 28; 58; 88; 82}.', '<p>22, 25, 55, 52, 28, 58, 88, 85, 82. {22; 52; 28; 58; 88; 82}.</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-77/')
