    VALUES (v_textbook_id, 78, '1', 0, 'Прочитай числа. Сколько единиц у каждого из них в разряде десятков тысяч? Сколько всего десятков тысяч?', '</p>\n\n<p class="text">Прочитай числа. Сколько единиц у каждого из них в разряде десятков тысяч? Сколько всего десятков тысяч?</p>\n\n<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica78-nomer1.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 78, номер 1, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 78, номер 1, год 2022."/>\n</div>', 'Шесть миллиардов девять миллионов девятьсот шестнадцать тысяч четыреста восемьдесят, 1 – в разряде десятков тысяч, 16 – всего десятков тысяч. Тридцать два миллиарда семьсот тридцать миллионов двадцать, 0 – единиц в десятков тысяч, 00 – всего десятков тысяч. Девяносто три миллиарда один миллион восемьдесят две тысячи пятьсот шестьдесят четыре, 8 – единиц в десятках тысяч, 82 – всего десятков тысяч. Восемьсот миллиардов двадцать шесть миллионов семьсот сорок тысяч пять, 4 – единицы в десятках тысяч, 40 – всего десятков тысяч.', '<p><span>Шесть миллиардов девять миллионов девятьсот шестнадцать тысяч четыреста восемьдесят, 1 – в разряде десятков тысяч, 16 – всего десятков тысяч.</span>\n<span>Тридцать два миллиарда семьсот тридцать миллионов двадцать, 0 – единиц в десятков тысяч, 00 – всего десятков тысяч.</span>\n<span>Девяносто три миллиарда один миллион восемьдесят две тысячи пятьсот шестьдесят четыре, 8 – единиц в десятках тысяч, 82 – всего десятков тысяч.</span>\n<span>Восемьсот миллиардов двадцать шесть миллионов семьсот сорок тысяч пять, 4 – единицы в десятках тысяч, 40 – всего десятков тысяч.</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-78/')
    RETURNING id INTO v_task_id;

