    VALUES (v_textbook_id, 78, '5', 4, 'Вырази числа в указанных единицах счёта: а) 5070 в тысячах и десятках; б) 24803 в тысячах и единицах; в) 6319000 в миллионах и тысячах; г) 31584702 в миллионах, тысячах и единицах; д) 49305064 в сотнях тысяч, сотнях и единицах; е) 58120900 в миллионах, тысячах и десятках.', '</p>\n\n<p class="text">Вырази числа в указанных единицах счёта:</p>\n\n<p class="description-text">\n<span>а) 5070 в тысячах и десятках;</span>\n<span>б) 24803 в тысячах и единицах;</span>\n<span>в) 6319000 в миллионах и тысячах;</span>\n<span>г) 31584702 в миллионах, тысячах и единицах;</span>\n<span>д) 49305064 в сотнях тысяч, сотнях и единицах;</span>\n<span>е) 58120900 в миллионах, тысячах и десятках.</span></p>', 'а) 5070 = 5 тыс. и 7 дес.; б) 24803 = 24 тыс. и 803 ед.; в) 6319000 = 6 млн и 319 тыс.; г) 31584702 = 31 млн, 584 тыс. и 702 ед.; д) 49305064 = 493 сот. тыс., 50 сот. и 64 ед.; е) 58120900 = 58 млн, 120 тыс. и 90 дес..', '<p><span>а) 5070 = 5 тыс. и 7 дес.;</span>\n<span>б) 24803 = 24 тыс. и 803 ед.;</span>\n<span>в) 6319000 = 6 млн и 319 тыс.;</span>\n<span>г) 31584702 = 31 млн, 584 тыс. и 702 ед.;</span>\n<span>д) 49305064 = 493 сот. тыс., 50 сот. и 64 ед.;</span>\n<span>е) 58120900 = 58 млн, 120 тыс. и 90 дес..</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-78/')
