    VALUES (v_textbook_id, 79, '6', 0, 'Вырази числа в тысячах и единицах, а длины – в километрах и метрах. Что ты замечаешь? а) 6328      б) 25043      в) 88808      г) 975004     6328 м       25043 м       88808 м      975004 м', '</p>\n\n<p class="text">Вырази числа в тысячах и единицах, а длины – в километрах и метрах. Что ты замечаешь?</p>\n\n<p class="description-text">\n<span>а) 6328      б) 25043      в) 88808      г)  975004</span>\n<span>    6328 м       25043 м       88808 м      975004 м</span></p>', 'а) 6 тыс. 328 ед.      б) 25 тыс. 43 ед.      в) 88 тыс. 808 ед.      г) 975 тыс. 4 ед.     6 км 328 м                25км 43 м                 88 км 808 м               975 км 4 м Выражая числа в тысячах и единицах, и длины – в километрах и метрах заметно, что соответствующие числа и длины одинаково выражаются.', '<p><span>а) 6 тыс. 328 ед.      б) 25 тыс. 43 ед.      в) 88 тыс. 808 ед.      г) 975 тыс. 4 ед.</span>\n<span>    6 км 328 м                25км 43 м                 88 км 808 м               975 км 4 м</span>\n<br/>\n<span>Выражая числа в тысячах и единицах, и длины – в километрах и метрах заметно, что соответствующие числа и длины одинаково выражаются.</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-79/')
