    VALUES (v_textbook_id, 79, '7', 1, 'Запиши цифрами числа, а длины вырази в метрах. Сравни примеры каждого столбика. Что ты замечаешь? а) 4 тыс. 17 ед.      б) 37 тыс. 258 ед.      в) 752 тыс. 9 ед.      г) 94 тыс.     4 км 17 м                37 км 258 м                752 км 9 м               94 км', '</p>\n\n<p class="text">Запиши цифрами числа, а длины вырази в метрах. Сравни примеры каждого столбика. Что ты замечаешь?</p>\n\n<p class="description-text">\n<span>а) 4 тыс. 17 ед.      б) 37 тыс. 258 ед.      в) 752 тыс. 9 ед.      г) 94 тыс.</span>\n<span>    4 км 17 м                37 км 258 м                752 км 9 м               94 км</span></p>', 'а) 4017      б) 37258      в) 752009      г) 94000     4017 м       37258 м       752009 м      94000 м Записывая цифрами числа, а длины выражая в метрах заметно, что соответствующие числа и длины одинаково записываются.', '<p><span>а) 4017      б) 37258      в) 752009      г) 94000</span>\n<span>    4017 м       37258 м       752009 м      94000 м</span>\n<br/>\n<span>Записывая цифрами числа, а длины выражая в метрах заметно, что соответствующие числа и длины одинаково записываются.</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-79/')
