    VALUES (v_textbook_id, 79, '9', 3, 'Запиши и прочитай наибольшее семизначное число и наименьшее десятизначное число. Какие числа им предшествуют? Какие числа за ними следуют?', '</p>\n\n<p class="text">Запиши и прочитай наибольшее семизначное число и наименьшее десятизначное число. Какие числа им предшествуют? Какие числа за ними следуют?</p>', '9999999 – девять миллионов девятьсот девяносто девять тысяч девятьсот девяносто девять, 9999998, 10000000. 1000000000 – один миллиард, 999999999, 1000000001.', '<p><span>9999999 – девять миллионов девятьсот девяносто девять тысяч девятьсот девяносто девять, 9999998, 10000000.</span>\n<span>1000000000 – один миллиард, 999999999, 1000000001.</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-79/')
