    VALUES (v_textbook_id, 79, '10', 4, 'а) Стороны прямоугольного участка земли равны 90 м и 15 м. Найди площадь этого участка. б) Площадь прямоугольника 70 дм 2 , а его ширина – 5 дм. На сколько дециметров длина прямоугольника больше его ширины?', '</p>\n\n<p class="text"><span>а) Стороны прямоугольного участка земли равны 90 м и 15 м. Найди площадь этого участка.</span>\n<span>б) Площадь прямоугольника 70 дм<sup>2</sup>, а его ширина – 5 дм. На сколько дециметров длина прямоугольника больше его ширины?</span></p>', 'а) 90 · 15 = 1350 (м 2 )      Ответ: 1350 м 2 площадь этого участка. б) 70 : 5 = 14 (дм) – длина     14 – 5 = 9 (дм)      Ответ: на 9 дециметров длина прямоугольника больше его ширины.', '<p><span>а) 90 · 15 = 1350 (м<sup>2</sup>)</span>\n<span>    <b>Ответ:</b> 1350 м<sup>2</sup> площадь этого участка.</span>\n<span>б) 70 : 5 = 14 (дм) – длина</span>\n<span>    14 – 5 = 9 (дм)</span>\n<span>    <b>Ответ:</b> на 9 дециметров длина прямоугольника больше его ширины.</span></p>', '', '', TRUE, '[{"letter":"а","condition":"Стороны прямоугольного участка земли равны 90 м и 15 м. Найди площадь этого участка.","solution":"90 · 15 = 1350 (м 2 )      Ответ: 1350 м 2 площадь этого участка."},{"letter":"б","condition":"Площадь прямоугольника 70 дм 2 , а его ширина – 5 дм. На сколько дециметров длина прямоугольника больше его ширины?","solution":"70 : 5 = 14 (дм) – длина     14 – 5 = 9 (дм)      Ответ: на 9 дециметров длина прямоугольника больше его ширины."}]'::jsonb, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-79/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '896f8720ba8b4b5822c75123c3c5b9b9dd67399b2ea29666cbbfe8bda1576b02', '2,5,15,70,90', '["найди","площадь","больше"]'::jsonb, 'а) стороны прямоугольного участка земли равны 90 м и 15 м. найди площадь этого участка. б) площадь прямоугольника 70 дм 2 , а его ширина-5 дм. на сколько дециметров длина прямоугольника больше его ширины');

    VALUES (v_textbook_id, 79, '11', 5, 'Реши уравнения с комментированием, сделай проверку: 26 · х = 52      78 : х = 3      х · 17 = 51      х : 240 = 4', '</p>\n\n<p class="text">Реши уравнения с комментированием, сделай проверку:</p>\n\n<p class="description-text">\n26 · х = 52      78 : х = 3      х · 17 = 51      х : 240 = 4</p>', '26 · х = 52 Что бы найти один из множителей х разделим произведение на известный множитель х = 52 : 26 х = 2 Проверка: 26 · 2 = 52 78 : х = 3 Что бы найти делитель х разделим делимое на частное х = 78 : 3 х = 26 Проверка: 78 : 26 = 3 х · 17 = 51 что бы найти множитель х разделим произведение на известный множитель х = 51 : 17 х = 3 Проверка: 3 · 17 = 51 х : 240 = 4 что бы найти делимое х умножим частное на делитель х = 240 · 4 х = 960 Проверка: 960 : 240 = 4', '<p><span>26 · х = 52</span>\n<span>Что бы найти один из множителей х разделим произведение на известный множитель</span>\n<span>х = 52 : 26</span>\n<span>х = 2</span>\n<span><b>Проверка:</b> 26 · 2 = 52</span>\n<span>78 : х = 3</span>\n<span>Что бы найти делитель х разделим делимое на частное</span>\n<span>х = 78 : 3</span>\n<span>х = 26</span>\n<span><b>Проверка:</b> 78 : 26 = 3</span>\n<span>х · 17 = 51</span>\n<span>что бы найти множитель х разделим произведение на известный множитель</span>\n<span>х = 51 : 17</span>\n<span>х = 3</span>\n<span><b>Проверка:</b> 3 · 17 = 51</span>\n<span>х : 240 = 4</span>\n<span>что бы найти делимое х умножим частное на делитель</span>\n<span>х = 240 · 4</span>\n<span>х = 960</span>\n<span><b>Проверка:</b> 960 : 240 = 4</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-79/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, 'f2cf7d42835f9b1eca5d4db999bb5001388745c25403ff5d6948bf94d1cb188b', '3,4,17,26,51,52,78,240', '["реши"]'::jsonb, 'реши уравнения с комментированием, сделай проверку:26*х=52      78:х=3      х*17=51      х:240=4');

