    VALUES (v_textbook_id, 79, '13', 7, 'А – множество городов России, В – множество городов Европы. Что представляет собой множество А ∩ В? Назови несколько элементов этого множества.', '</p>\n\n<p class="text">А – множество городов России, В – множество городов Европы. Что представляет собой множество А ∩ В? Назови несколько элементов этого множества.</p>', 'Множество городов принадлежащих России и Европе. Например: Калининград.', '<p>Множество городов принадлежащих России и Европе. Например: Калининград.</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-79/')
