    VALUES (v_textbook_id, 79, '14', 8, 'Найди множество трёхзначных чисел, в записи которых используются только цифры 1 и 3 (вместе или по отдельности). Чему равна разность наибольшего и наименьшего из этих чисел?', '</p>\n\n<p class="text">Найди  множество трёхзначных чисел, в записи которых используются только цифры 1 и 3 (вместе или по отдельности). Чему равна разность наибольшего и наименьшего из этих чисел?</p>', '100, 101, 111, 103, 133, 300, 301, 303, 313, 333. 333 – 100 = 233.', '<p>100, 101, 111, 103, 133, 300, 301, 303, 313, 333. 333 – 100 = 233.</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-79/')
    RETURNING id INTO v_task_id;

