    VALUES (v_textbook_id, 80, '2', 1, 'Прочитай числа и определи, сколько единиц каждого разряда в них содержится: а) 5378; б) 32609; в) 940615. Для каждого из этих чисел определи, сколько всего в нём единиц, десятков, сотен, тысяч, десятков тысяч.', '</p>\n\n<p class="text"><span>Прочитай числа и определи, сколько единиц каждого разряда в них содержится: а) 5378; б) 32609; в) 940615.</span>\n<span>Для каждого из этих чисел определи, сколько всего в нём единиц, десятков, сотен, тысяч, десятков тысяч.</span></p>', 'а) пять тысяч триста семьдесят восемь, 5378 единиц, 57 десятков, 53 сотни, 5 тысяч и 5 единиц класса тысяч, 3 сотни класса единиц, 7 десятков класса единиц, 8 единиц класса единиц; б) тридцать две тысячи шестьсот девять, 32609 единиц, 320 десятков, 326 сотен, 32 тысяч и 3 десятка класса тысяч, 2 единицы класса тысяч, 6 сотен класса единиц и 9 единиц класса единиц; в) девятьсот сорок тысяч шестьсот пятнадцать, 940615 единиц, 9401 десятков, 9406 сотни, 940 тысяч и 9 сотен класса тысяч, 4 десятка класса тысяч, 6 сотне класса единиц, 1 десяток класса единиц, 5 единиц класса единиц.', '<p><span>а) пять тысяч триста семьдесят восемь, 5378 единиц, 57 десятков, 53 сотни, 5 тысяч и 5 единиц класса тысяч, 3 сотни класса единиц, 7 десятков класса единиц, 8 единиц класса единиц;</span>\n<span>б) тридцать две тысячи шестьсот девять, 32609 единиц, 320 десятков, 326 сотен, 32 тысяч и 3 десятка класса тысяч, 2 единицы класса тысяч, 6 сотен класса единиц и 9 единиц класса единиц;</span>\n<span>в) девятьсот сорок тысяч шестьсот пятнадцать, 940615 единиц, 9401 десятков, 9406 сотни, 940 тысяч и 9 сотен класса тысяч, 4 десятка класса тысяч, 6 сотне класса единиц, 1 десяток класса единиц, 5 единиц класса единиц.</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-80/')
    RETURNING id INTO v_task_id;

