    VALUES (v_textbook_id, 80, '3', 2, 'Вырази число 2003916 в указанных единицах счёта: а) в миллионах, тысячах и единицах; б) в десятках тысяч, сотнях и единицах.', '</p>\n\n<p class="text">Вырази число 2003916 в указанных единицах счёта:</p>\n\n<p class="description-text">\n<span>а) в миллионах, тысячах и единицах;</span>\n<span>б) в десятках тысяч, сотнях и единицах.</span></p>', 'а) 2 млн 3 тыс. 916; б) 200 дес. тыс. 39 сот. 16 ед.', '<p><span>а) 2 млн 3 тыс. 916;</span>\n<span>б) 200 дес. тыс. 39 сот. 16 ед.</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-80/')
