    VALUES (v_textbook_id, 80, '4', 3, 'Объясни решение примеров. Как выполнить вычитание многозначных чисел, когда в разрядах уменьшаемого не хватает единиц?', '</p>\n\n<p class="text">Объясни решение примеров. Как выполнить вычитание многозначных чисел, когда в разрядах уменьшаемого не хватает единиц?</p>\n\n<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica80-nomer4.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 80, номер 4, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 80, номер 4, год 2022."/>\n</div>', 'Что бы выполнить вычитание многозначных чисел, когда в разрядах уменьшаемого не хватает единиц, нужно занимать у соседней слева цифры 1 до тех пор, пока не дойдет до цифры отличной от 0. Причем добавляется к имеющейся цифре в качестве единицы десяток и уже тогда вычитать.', '<p>Что бы выполнить вычитание многозначных чисел, когда в разрядах уменьшаемого не хватает единиц, нужно занимать у соседней слева цифры 1 до тех пор, пока не дойдет до цифры отличной от 0. Причем добавляется к имеющейся цифре в качестве единицы десяток и уже тогда вычитать.</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-80/')
    RETURNING id INTO v_task_id;

