    VALUES (v_textbook_id, 80, '5', 4, 'Найди значения выражений. Проверь с помощью калькулятора. а) 4000 – 257 б) 50000 – 12400 в) 710096 + 99939 г) 302034 – 5626 д) 26105002 – 297307 е) 8297 + 1994758', '</p>\n\n<p class="text">Найди значения выражений. Проверь с помощью калькулятора.</p>\n\n<p class="description-text">\n<span>а) 4000 – 257</span>\n<span>б) 50000 – 12400</span>\n<span>в) 710096 + 99939</span>\n<span>г) 302034 – 5626</span>\n<span>д) 26105002 – 297307</span>\n<span>е) 8297 + 1994758</span></p>', 'а) 4000 – 257 = 3743', '<p>а) 4000 – 257 = 3743</p>\n\n<div class="img-wrapper-460">\n<img width="130" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica80-nomer5.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 80, номер 5, год 2022, ответ." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 80, номер 5, год 2022, ответ."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-80/')
