    VALUES (v_textbook_id, 80, '6', 5, 'Реши уравнения. Сделай проверку с помощью калькулятора. х – 3066 = 72527      15470 – х = 8315      х + 824 = 2000', '</p>\n\n<p class="text">Реши уравнения. Сделай проверку с помощью калькулятора.</p>\n\n<p class="description-text">\nх – 3066 = 72527      15470 – х = 8315      х + 824 = 2000</p>', 'х – 3066 = 72527 х = 72527 + 3066', '<p><span>х – 3066 = 72527</span>\n<span>х = 72527 + 3066</span></p>\n\n<div class="img-wrapper-460">\n<img width="160" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica80-nomer6.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 80, номер 6, год 2022, ответ." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 80, номер 6, год 2022, ответ."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-80/')
