    VALUES (v_textbook_id, 80, '7', 6, 'В первых трёх классах Таня записала в свой словарь 1274 английских слова. Из них 82 слова она записала в первом классе, а во втором классе – в 4 раза больше слов, чем в первом. Сколько слов записала Таня в свой словарь в третьем классе?', '</p>\n\n<p class="text">В первых трёх классах Таня записала в свой словарь 1274 английских слова. Из них 82 слова она записала в первом классе, а во втором классе – в 4 раза больше слов, чем в первом. Сколько слов записала Таня в свой словарь в третьем классе?</p>\n\n<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica80-nomer7.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 80, номер 7, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 80, номер 7, год 2022."/>\n</div>', '1274 – 82 – 82 · 4 = 1192 – 328 = 864', '<p>1274 – 82 – 82 · 4 = 1192 – 328 = 864</p>\n\n<div class="img-wrapper-460">\n<img width="130" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica80-nomer7-1.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 80, номер 7, год 2022, ответ." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 80, номер 7, год 2022, ответ."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-80/')
