    VALUES (v_textbook_id, 81, '9', 0, 'Викторина «В мире птиц» 1) Вычисли. Расшифруй название птицы – строителя, которая вьёт гнёзда, похожие на чулки. 2) Пользуясь алгоритмом, найди значения х . Расшифруй название птицы, которая вообще не вьёт гнёзда, а выкапывает норки в земле.', '</p>\n\n<p class="text"><span><b>Викторина «В мире птиц»</b></span>\n<span>1) Вычисли. Расшифруй название птицы – строителя, которая вьёт гнёзда, похожие на чулки.</span></p>\n\n<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica81-nomer9.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 81, номер 9, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 81, номер 9, год 2022."/>\n</div>\n\n<p class="text">2) Пользуясь алгоритмом, найди значения <b>х</b>. Расшифруй название птицы, которая вообще не вьёт гнёзда, а выкапывает норки в земле.</p>\n\n<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica81-nomer9-1.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 81, номер 9, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 81, номер 9, год 2022."/>\n</div>', '', '<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica81-nomer9-2.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 81, номер 9, год 2022, ответ." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 81, номер 9, год 2022, ответ."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-81/')
    RETURNING id INTO v_task_id;

