    VALUES (v_textbook_id, 81, '12', 3, 'Старинные задачи – шутки а) Шла баба в Москву и повстречала 3 мужиков. Каждый из них нёс по мешку, в каждом мешке по коту. Сколько всего существ направлялось в Москву? б) Длина бревна 5 аршин. В одну минуту от этого бревна отпиливают по одному аршину. Через сколько минут будет распилено всё бревно?', '</p>\n\n<p class="text"><span><b>Старинные задачи – шутки</b></span>\n<span>а) Шла баба в Москву и повстречала 3 мужиков. Каждый из них нёс по мешку, в каждом мешке по коту. Сколько всего существ направлялось в Москву?</span>\n<span>б) Длина бревна 5 аршин. В одну минуту от этого бревна отпиливают по одному аршину. Через сколько минут будет распилено всё бревно?</span></p>', 'а) всего одно существо направлялось в Москву. б) Через 4 минут будет распилено всё бревно.', '<p><span>а) всего одно существо направлялось в Москву.</span>\n<span>б) Через 4 минут будет распилено всё бревно.</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-81/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '1c2f36953f1d87de0a9c242a416ba23d5fad2c370cb2aecb7b23cf53ba0df2fe', '3,5', NULL, 'старинные задачи-шутки а) шла баба в москву и повстречала 3 мужиков. каждый из них нёс по мешку, в каждом мешке по коту. сколько всего существ направлялось в москву? б) длина бревна 5 аршин. в одну минуту от этого бревна отпиливают по одному аршину. через сколько минут будет распилено всё бревно');

    VALUES (v_textbook_id, 82, '1', 0, '(Устно.) Вычисли удобным способом: 23 + 24 + 25 + 26 + 27      (36 + 25) + 75 + (64 + 100) Какие свойства сложения помогли упростить вычисления? Можно ли распространить их на многозначные числа? Почему?', '</p>\n\n<p class="text">(Устно.) Вычисли удобным способом:</p>\n\n<p class="description-text">\n23 + 24 + 25 + 26 + 27      (36 + 25) + 75 + (64 + 100)</p>\n\n<p class="text">Какие свойства сложения помогли упростить вычисления? Можно ли распространить их на многозначные числа? Почему?</p>', '23 + 24 + 25 + 26 + 27 = 50 + 50 + 25 = 125 (36 + 25) + 75 + (64 + 100) = 100 + 36 + 64 + 100 = 100 + 200 = 300 Переместительное и сочетательное свойство сложения. Сложение многозначных чисел выполняется точно так же.', '<p><span>23 + 24 + 25 + 26 + 27 = 50 + 50 + 25 = 125</span>\n<span>(36 + 25) + 75 + (64 + 100) = 100 + 36 + 64 + 100 = 100 + 200 = 300</span>\n<span>Переместительное и сочетательное свойство сложения. Сложение  многозначных чисел выполняется точно так же.</span></p>', 'Справка Для многозначных чисел сохраняются все изученные ранее свойства и правила действий с числами (правила порядка действий, свойства арифметических действий и т. д.).', '<div class="recomended-block">\n<span class="title">Справка</span>\n<p><b class="black">Для многозначных чисел сохраняются все изученные ранее свойства и правила действий с числами</b> (правила порядка действий, свойства арифметических действий и т. д.).</p>\n</div>', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-82/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '9b232ccf474ff10b6c01d5650425268e8dfdf97d1131f79a0c207c8026f22d8f', '23,24,25,26,27,36,64,75,100', '["вычисли"]'::jsonb, '(устно.) вычисли удобным способом:23+24+25+26+27      (36+25)+75+(64+100) какие свойства сложения помогли упростить вычисления? можно ли распространить их на многозначные числа? почему');

    VALUES (v_textbook_id, 82, '2', 1, '(Устно.) Вычисли удобным способом. Обоснуй свой ответ. а) 71300 + 2996 + 4 + 700 б) 9998 + 405 + 2 + 95 + 2500 в) (18607 + 458) – 17607 г) 32584 – (32564 + 19)', '</p>\n\n<p class="text">(Устно.) Вычисли удобным способом. Обоснуй свой ответ.</p>\n\n<p class="description-text">\n<span>а) 71300 + 2996 + 4 + 700</span>\n<span>б) 9998 + 405 + 2 + 95 + 2500</span>\n<span>в) (18607 + 458) – 17607</span>\n<span>г) 32584 – (32564 + 19)</span></p>', 'а) 71300 + 2996 + 4 + 700 = 3000 + 72000 = 75000 б) 9998 + 405 + 2 + 95 + 2500 = 10000 + 500 + 2500 = 13000 в) (18607 + 458) – 17607 = 1000 + 458 = 1458 г) 32584 – (32564 + 19) = 20 + 19 = 39 Используя переместительное и сочетательное свойство можно вычислять устно.', '<p><span>а) 71300 + 2996 + 4 + 700 = 3000 + 72000 = 75000</span>\n<span>б) 9998 + 405 + 2 + 95 + 2500 = 10000 + 500 + 2500 = 13000</span>\n<span>в) (18607 + 458) – 17607 = 1000 + 458 = 1458</span>\n<span>г) 32584 – (32564 + 19) = 20 + 19 = 39</span>\n<span>Используя переместительное и сочетательное свойство можно вычислять устно.</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-82/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '4f30b7ce3ea450911040a1902c0c5d75628c2d7abe516eaee7cbb21d519bcd72', '2,4,19,95,405,458,700,2500,2996,9998', '["вычисли"]'::jsonb, '(устно.) вычисли удобным способом. обоснуй свой ответ. а) 71300+2996+4+700 б) 9998+405+2+95+2500 в) (18607+458)-17607 г) 32584-(32564+19)');

    VALUES (v_textbook_id, 82, '3', 2, 'Вычисли. Проверь результаты с помощью калькулятора. а) 55796208 + 603917      б) 41002600 – 25624', '</p>\n\n<p class="text">Вычисли. Проверь результаты с помощью калькулятора.</p>\n\n<p class="description-text">\nа) 55796208 + 603917      б) 41002600 – 25624</p>', 'а) 55796208 + 603917 = 56400125', '<p>а) 55796208 + 603917 = 56400125</p>\n\n<div class="img-wrapper-460">\n<img width="230" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica82-nomer3.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 82, номер 3, год 2022, ответ." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 82, номер 3, год 2022, ответ."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-82/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, 'solution', 0, NULL, 'https://gdz-raketa.ru/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica82-nomer3.jpg', 'peterson/3/part1/page82/task3_solution_0.jpg', '');

    VALUES (v_task_id, v_textbook_id, 3, '76d6ccb3ad5330bef9e2a3d6740198944b140754f229104afa9e79762240cd3f', '25624,603917,41002600,55796208', '["вычисли"]'::jsonb, 'вычисли. проверь результаты с помощью калькулятора. а) 55796208+603917      б) 41002600-25624');

    VALUES (v_textbook_id, 82, '4', 3, 'При каких значениях букв верны равенства: а + 16504 = 16504      34290 + b = 34290      7009072 – с = 0 Назови свойства сложения и вычитания с нулём.', '</p>\n\n<p class="text">При каких значениях букв верны равенства:</p>\n\n<p class="description-text">\nа + 16504 = 16504      34290 + b = 34290      7009072 – с = 0</p>\n\n<p class="text">Назови свойства сложения и вычитания с нулём.</p>', 'а + 16504 = 16504 а = 16504 – 16504 а = 0 34290 + b = 34290 b = 34290 – 34290 b = 0 7009072 – с = 0 с = 7009072 + 0 с = 7009072 Свойство нуля при сложении. Если к числу прибавить нуль, получится само число.', '<p><span>а + 16504 = 16504</span>\n<span>а = 16504 – 16504</span>\n<span>а = 0</span>\n<span>34290 + b = 34290</span>\n<span>b = 34290 – 34290</span>\n<span>b = 0</span>\n<span>7009072 – с = 0</span>\n<span>с = 7009072 + 0</span>\n<span>с = 7009072</span>\n<span>Свойство нуля при сложении. Если к числу прибавить нуль, получится само число.</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-82/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '7eb5d51df2f893e49522bfab7cbb39a36fb7e270cfb395525b0d5aee4d839cd5', '0,16504,34290,7009072', NULL, 'при каких значениях букв верны равенства:а+16504=16504      34290+b=34290      7009072-с=0 назови свойства сложения и вычитания с нулём');

    VALUES (v_textbook_id, 82, '5', 4, 'Составь выражение и найди его значение: а) Из числа 67546 вычесть сумму чисел 5624 и 14976. б) Разность чисел 80000 и 46980 увеличить на 7589.', '</p>\n\n<p class="text">Составь выражение и найди его значение:</p>\n\n<p class="description-text">\n<span>а) Из числа 67546 вычесть сумму чисел 5624 и 14976.</span>\n<span>б) Разность чисел 80000 и 46980 увеличить на 7589.</span></p>', 'а) 67546 – (5624 + 14976) = 67546 – 20600 = 46946', '<p>а) 67546 – (5624 + 14976) = 67546 – 20600 = 46946</p>\n\n<div class="img-wrapper-460">\n<img width="320" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica82-nomer5.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 82, номер 5, год 2022, ответ." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 82, номер 5, год 2022, ответ."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-82/')
    RETURNING id INTO v_task_id;

