    VALUES (v_task_id, v_textbook_id, 3, '89525ad665a21286a7c5d4fe8b198138fc6ef1946e049aacf5dba2e2f4305d1a', '5624,7589,14976,46980,67546,80000', '["найди","разность","раз"]'::jsonb, 'составь выражение и найди его значение:а) из числа 67546 вычесть сумму чисел 5624 и 14976. б) разность чисел 80000 и 46980 увеличить на 7589');

    VALUES (v_textbook_id, 82, '6', 5, 'Составь программу действий. Что ты замечаешь? 1) a : (b – c) · d + k · (m : n) 2) а : b – с · (d + k · m) : n 3) а : (b – с · d) + k · m : n 4) (а : b – с) · d + k · (m : n)', '</p>\n\n<p class="text">Составь программу действий. Что ты замечаешь?</p>\n\n<p class="description-text">\n<span>1) a : (b – c) · d + k · (m : n)</span>\n<span>2) а : b – с · (d + k · m) : n</span>\n<span>3) а : (b – с · d) + k · m : n</span>\n<span>4) (а : b – с) · d + k · (m : n)</span></p>', '1) a : (b – c) · d + k · (m : n)     b – c     a : (b – c)     a : (b – c) · d     m : n     k · (m : n) 2) а : b – с · (d + k · m) : n     k · m     d + k · m     с · (d + k · m)     с · (d + k · m) : n     а : b 3) а : (b – с · d) + k · m : n     с · d     b – с · d     а : (b – с · d)     k · m     k · m : n 4) (а : b – с) · d + k · (m : n)     а : b     (а : b – с)     (а : b – с) · d     m : n     k · (m : n)', '<p><span>1) a : (b – c) · d + k · (m  :  n)</span>\n<span>    b – c</span>\n<span>    a : (b – c)</span>\n<span>    a : (b – c) · d</span>\n<span>    m  :  n</span>\n<span>    k · (m  :  n)</span>\n<span>2) а : b – с · (d + k · m) : n</span>\n<span>    k · m</span>\n<span>    d + k · m</span>\n<span>    с · (d + k · m)</span>\n<span>    с · (d + k · m) : n</span>\n<span>    а : b</span>\n<span>3) а : (b – с · d) + k · m : n</span>\n<span>    с · d</span>\n<span>    b – с · d</span>\n<span>    а : (b – с · d)</span>\n<span>    k · m</span>\n<span>    k · m : n</span>\n<span>4) (а : b – с) · d + k · (m : n)</span>\n<span>    а : b</span>\n<span>    (а : b – с)</span>\n<span>    (а : b – с) · d</span>\n<span>    m : n</span>\n<span>    k · (m : n)</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-82/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, 'e00c913271665a83597bdc149095cc3e3716c19b4b8a543f8f46900cf7b6b6da', '1,2,3,4', NULL, 'составь программу действий. что ты замечаешь? 1) a:(b-c)*d+k*(m:n) 2) а:b-с*(d+k*m):n 3) а:(b-с*d)+k*m:n 4) (а:b-с)*d+k*(m:n)');

    VALUES (v_textbook_id, 82, '7', 6, 'Составь программу действий и вычисли: а) 100000 – (5020 + 72396) – 2973 б) (206400 – 40287) – (50266 + 103924)', '</p>\n\n<p class="text">Составь программу действий и вычисли:</p>\n\n<p class="description-text">\n<span>а) 100000 – (5020 + 72396) – 2973</span>\n<span>б) (206400 – 40287) – (50266 + 103924)</span></p>', 'а) 100000 – (5020 + 72396) – 2973 = 19611     5020 + 72396 = 77416', '<p><span>а) 100000 – (5020 + 72396) – 2973 = 19611</span>\n<span>    5020 + 72396 = 77416</span></p>\n\n<div class="img-wrapper-460">\n<img width="140" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica82-nomer7.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 82, номер 7, год 2022, ответ." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 82, номер 7, год 2022, ответ."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-82/')
    RETURNING id INTO v_task_id;

