    VALUES (v_task_id, v_textbook_id, 3, '04a4d521b73ccc8b72f6b8027054ec6cba56a134eeead13359a8e0ea2bfe2f71', '2973,5020,40287,50266,72396,100000,103924,206400', '["вычисли"]'::jsonb, 'составь программу действий и вычисли:а) 100000-(5020+72396)-2973 б) (206400-40287)-(50266+103924)');

    VALUES (v_textbook_id, 82, '8', 7, 'В трёх школах учится 3600 человек. В первой школе учится 1265 человек, а во второй школе – на 348 человек больше, чем в первой. Сколько учеников в третьей школе? На сколько учеников в третьей школе меньше, чем в первой?', '</p>\n\n<p class="text">В трёх школах учится 3600 человек. В первой школе учится 1265 человек, а во второй школе – на 348 человек больше, чем в первой. Сколько учеников в третьей школе? На сколько учеников в третьей школе меньше, чем в первой?</p>', '3600 – 1265 – (1265 + 348) = 3600 – 1265 – 1613 = 1987 – 1265 = 722 1265 – 722 = 543 Ответ: 722 учеников в третьей школе, на 543 ученика в третьей школе меньше, чем в первой.', '<p><span>3600 – 1265 – (1265 + 348) = 3600 – 1265 – 1613 = 1987 – 1265 = 722</span>\n<span>1265 – 722 = 543</span>\n<span><b>Ответ:</b> 722 учеников в третьей школе, на 543 ученика в третьей школе меньше, чем в первой.</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-82/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '980391f3171931e458b48da2523c8100ab9171c398aee897de10ca041f01af86', '348,1265,3600', '["больше","меньше"]'::jsonb, 'в трёх школах учится 3600 человек. в первой школе учится 1265 человек, а во второй школе-на 348 человек больше, чем в первой. сколько учеников в третьей школе? на сколько учеников в третьей школе меньше, чем в первой');

    VALUES (v_textbook_id, 83, '9', 0, 'а) Пользуясь числовым лучом, составь множество двузначных чисел, кратных 18. б) Выполни деление с остатком: 39 : 18      55 : 18      62 : 18      76 : 18 в) Выучи двузначные числа, кратные 18. Проверь себя, работая в паре.', '</p>\n\n<p class="text">а) Пользуясь числовым лучом, составь множество двузначных чисел, кратных 18.</p>\n\n<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica83-nomer9.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 83, номер 9, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 83, номер 9, год 2022."/>\n</div>\n\n<p class="text">б) Выполни деление с остатком:</p>\n\n<p class="description-text">\n39 : 18      55 : 18      62 : 18      76 : 18</p>\n\n<p class="text">в) Выучи двузначные числа, кратные 18. Проверь себя, работая в паре.</p>', 'а) {18; 36; 54; 72; 90; 108; 126; 144; 162; 180} б) 39 : 18 = 2 + 3     39 – 36 = 3     55 : 18 = 3 + 1     55 – 54 = 1     62 : 18 = 3 + 8     62 – 54 = 8     76 : 18 = 4 + 4     76 – 72 = 4 в) 18, 36, 54, 72, 90, 108, 126, 144, 162, 180.', '<p><span>а) {18; 36; 54; 72; 90; 108; 126; 144; 162; 180}</span>\n<span>б) 39 : 18 = 2 + 3</span>\n<span>    39 – 36 = 3</span>\n<span>    55 : 18 = 3 + 1</span>\n<span>    55 – 54 = 1</span>\n<span>    62 : 18 = 3 + 8</span>\n<span>    62 – 54 = 8</span>\n<span>    76 : 18 = 4 + 4</span>\n<span>    76 – 72 = 4</span>\n<span>в) 18, 36, 54, 72, 90, 108, 126, 144, 162, 180.</span></p>', '', '', TRUE, '[{"letter":"а","condition":"Пользуясь числовым лучом, составь множество двузначных чисел, кратных 18.","solution":"{18; 36; 54; 72; 90; 108; 126; 144; 162; 180}"},{"letter":"б","condition":"Выполни деление с остатком: 39 : 18      55 : 18      62 : 18      76 : 18","solution":"39 : 18 = 2 + 3     39 – 36 = 3     55 : 18 = 3 + 1     55 – 54 = 1     62 : 18 = 3 + 8     62 – 54 = 8     76 : 18 = 4 + 4     76 – 72 = 4"},{"letter":"в","condition":"Выучи двузначные числа, кратные 18. Проверь себя, работая в паре.","solution":"18, 36, 54, 72, 90, 108, 126, 144, 162, 180."}]'::jsonb, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-83/')
    RETURNING id INTO v_task_id;

