    VALUES (v_task_id, v_textbook_id, 3, '86d38f22df48af559e8800bae1ba8ea974eaa71563e98ec127a8d8b3a3e356e7', '18,39,55,62,76', NULL, 'а) пользуясь числовым лучом, составь множество двузначных чисел, кратных 18. б) выполни деление с остатком:39:18      55:18      62:18      76:18 в) выучи двузначные числа, кратные 18. проверь себя, работая в паре');

    VALUES (v_textbook_id, 83, '10', 1, 'Вычисли. Расшифруй и отгадай загадку:', '</p>\n\n<p class="text">Вычисли. Расшифруй и отгадай загадку:</p>\n\n<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica83-nomer10.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 83, номер 10, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 83, номер 10, год 2022."/>\n</div>', 'Т – 38 : 2 = 19        В – 34 · 2 = 68      З - (96 – 26) : 14 = 5 У – 75 : 3 = 25        Е – 24 · 3 = 72      О – (63 – 35) : 7 = 4 Б – 68 : 4 = 17        Д – 19 · 4 = 76      Г – 25 · 1 + 25 : 25 = 26 К – 96 : 6 = 16        Ё – 18 · 5 = 90      А – 36 : 1 – 24 · 0 = 36 И – 60 : 5 = 12       Р – 12 · 7 = 84      Л – 80 : 2 + 80 : 40 = 42 П – 36 : 18 = 2       С – 28 · 2 = 56      Ы – 72 – 48 : 6 · 3 = 48 Ш – 99 : 9 = 11      Ъ – 9 + 9 = 18      Н – 4 · (23 – 8) : 10 = 6', '<p><span>Т – 38 : 2 = 19        В – 34 · 2 = 68      З - (96 – 26) : 14 = 5</span>\n<span>У – 75 : 3 = 25        Е – 24 · 3 = 72      О – (63 – 35) : 7 = 4</span>\n<span>Б – 68 : 4 = 17        Д – 19 · 4 = 76      Г – 25 · 1 + 25 : 25 = 26</span>\n<span>К – 96 : 6 = 16        Ё – 18 · 5 = 90      А – 36 : 1 – 24 · 0 = 36</span>\n<span>И – 60 : 5 = 12       Р – 12 · 7 = 84      Л – 80 : 2 + 80 : 40 = 42</span>\n<span>П – 36 : 18 = 2       С – 28 · 2 = 56      Ы – 72 – 48 : 6 · 3 = 48</span>\n<span>Ш – 99 : 9 = 11      Ъ – 9 + 9 = 18      Н – 4 · (23 – 8) : 10 = 6</span></p>\n\n<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica83-nomer10-1.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 83, номер 10, год 2022, ответ." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 83, номер 10, год 2022, ответ."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-83/')
    RETURNING id INTO v_task_id;

