    VALUES (v_textbook_id, 84, '11', 0, 'Сравни выражения: а – 25     а – 205 42 + b     b + 24 306 – с     360 – с 270 : d     27 : d 81 · х     х · 83 – х у : 52     у : 2', '</p>\n\n<p class="text">Сравни выражения:</p>\n\n<p class="description-text">\n<span>а – 25 <span class="okon">   </span> а – 205</span>\n<span>42 + b <span class="okon">   </span> b + 24</span>\n<span>306 – с <span class="okon">   </span> 360 – с</span>\n<span>270 : d <span class="okon">   </span> 27 : d</span>\n<span>81 · х <span class="okon">   </span> х · 83 – х</span>\n<span>у : 52 <span class="okon">   </span> у : 2</span></p>', 'а – 25 ˃ а – 205 42 + b ˃ b + 24 306 – с ˂ 360 – с 270 : d ˃ 27 : d 81 · х ˂ х · 83 – х у : 52 ˂ у : 2', '<p><span>а – 25 ˃ а – 205</span>\n<span>42 + b ˃ b + 24</span>\n<span>306 – с ˂ 360 – с</span>\n<span>270 : d ˃ 27 : d</span>\n<span>81 · х ˂ х · 83 – х</span>\n<span>у : 52 ˂ у : 2</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-84/')
    RETURNING id INTO v_task_id;

