    VALUES (v_textbook_id, 84, '12', 1, 'а) Длина прямоугольника 17 дм, а ширина на 8 дм меньше длины. Найди площадь и периметр этого прямоугольника. б) Площадь прямоугольника равна 290 см 2 , а его длина – 29 см. Чему равен периметр этого прямоугольника? в) Найди площадь квадрата, периметр которого равен 36 м.', '</p>\n\n<p class="text"><span>а) Длина прямоугольника 17 дм, а ширина на 8 дм меньше длины. Найди площадь и периметр этого прямоугольника.</span>\n<span>б) Площадь прямоугольника равна 290 см<sup>2</sup>, а его длина – 29 см. Чему равен периметр этого прямоугольника?</span>\n<span>в) Найди площадь квадрата, периметр которого равен 36 м.</span></p>', 'а) 17 · (17 – 8) = 17 · 9 = 153 (дм 2 ), 2 · 17 + 2 · (17 – 8) = 34 + 18 = 52 (дм)      Ответ: 153 дм 2 площадь, 52 дм периметр прямоугольника. б) 290 : 29 = 10 (дм), 2 · 10 + 2 · 29 = 20 + 58 = 78 (дм)      Ответ: 78 дм периметр прямоугольника. в) 36 : 4 = 9 (м), 9 · 9 = 81 (м 2 )      Ответ: 81 м 2 площадь квадрата.', '<p><span>а) 17 · (17 – 8) = 17 · 9 = 153 (дм<sup>2</sup>), 2 · 17 + 2 · (17 – 8) = 34 + 18 = 52 (дм)</span>\n<span>    <b>Ответ:</b> 153 дм<sup>2</sup> площадь, 52 дм периметр прямоугольника.</span>\n<span>б) 290 : 29 = 10 (дм), 2 · 10 + 2 · 29 = 20 + 58 = 78 (дм)</span>\n<span>    <b>Ответ:</b> 78 дм периметр прямоугольника.</span>\n<span>в) 36 : 4 = 9 (м), 9 · 9 = 81 (м<sup>2</sup>)</span>\n<span>    <b>Ответ:</b> 81 м<sup>2</sup> площадь квадрата.</span></p>', '', '', TRUE, '[{"letter":"а","condition":"Длина прямоугольника 17 дм, а ширина на 8 дм меньше длины. Найди площадь и периметр этого прямоугольника.","solution":"17 · (17 – 8) = 17 · 9 = 153 (дм 2 ), 2 · 17 + 2 · (17 – 8) = 34 + 18 = 52 (дм)      Ответ: 153 дм 2 площадь, 52 дм периметр прямоугольника."},{"letter":"б","condition":"Площадь прямоугольника равна 290 см 2 , а его длина – 29 см. Чему равен периметр этого прямоугольника?","solution":"290 : 29 = 10 (дм), 2 · 10 + 2 · 29 = 20 + 58 = 78 (дм)      Ответ: 78 дм периметр прямоугольника."},{"letter":"в","condition":"Найди площадь квадрата, периметр которого равен 36 м.","solution":"36 : 4 = 9 (м), 9 · 9 = 81 (м 2 )      Ответ: 81 м 2 площадь квадрата."}]'::jsonb, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-84/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '8408b05bce16acd9748941c5f5626e3ae8e4b128e9f5db88b737b364da1e7f02', '2,8,17,29,36,290', '["найди","периметр","площадь","меньше"]'::jsonb, 'а) длина прямоугольника 17 дм, а ширина на 8 дм меньше длины. найди площадь и периметр этого прямоугольника. б) площадь прямоугольника равна 290 см 2 , а его длина-29 см. чему равен периметр этого прямоугольника? в) найди площадь квадрата, периметр которого равен 36 м');

    VALUES (v_textbook_id, 84, '13', 2, 'Конверт стоит 5 рублей, а марка – m рублей, где m > 5. 1) Верно ли, что конверт дороже марки на m – 5 рублей? 2) Верно ли, что 4 конверта и 6 марок стоят m · 6 + 20 рублей? 3) Могут ли 3 конверта и 2 марки стоить 38 рублей?', '</p>\n\n<p class="text">Конверт стоит 5 рублей, а марка – <b>m</b> рублей, где m &gt; 5.</p>\n\n<p class="description-text">\n<span>1) Верно ли, что конверт дороже марки на m – 5 рублей?</span>\n<span>2) Верно ли, что 4 конверта и 6 марок стоят m · 6 + 20 рублей?</span>\n<span>3) Могут ли 3 конверта и 2 марки стоить 38 рублей?</span></p>', '1) не верно 2) возможно 3) не могут', '<p><span>1) не верно</span>\n<span>2) возможно</span>\n<span>3) не могут</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-84/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '89dfea8c8c4e8ed05e877ca02eefe146733321fc1454adb29a1d40a466df7c39', '1,2,3,4,5,6,20,38', NULL, 'конверт стоит 5 рублей, а марка-m рублей, где m>5. 1) верно ли, что конверт дороже марки на m-5 рублей? 2) верно ли, что 4 конверта и 6 марок стоят m*6+20 рублей? 3) могут ли 3 конверта и 2 марки стоить 38 рублей');

    VALUES (v_textbook_id, 84, '14', 3, 'К – множество кругов, С – множество фигур синего цвета. Что представляет собой пересечение этих множеств С ∩ К?', '</p>\n\n<p class="text">К – множество кругов, С – множество фигур синего цвета. Что представляет собой пересечение этих множеств С ∩ К?</p>', 'Множество кругов синего цвета.', '<p>Множество кругов синего цвета.</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-84/')
    RETURNING id INTO v_task_id;

