    VALUES (v_textbook_id, 84, '15', 4, 'По диаграмме Эйлера – Венна определи, какие знаки пропущены: ∈, ∉, ⊂ или ⊄. Сделай записи в тетради.', '</p>\n\n<p class="text">По диаграмме Эйлера – Венна определи, какие знаки пропущены: ∈, ∉, ⊂ или ⊄. Сделай записи в тетради.</p>\n\n<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica84-nomer15.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 84, номер 15, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 84, номер 15, год 2022."/>\n</div>', '2 ∈ A      B ⊂ A 2 ∉ B      C ⊂ A 2 ∈ D      D ⊂ C 2 ∉ E      E ⊄ A', '<p><span>2 ∈ A      B ⊂ A</span>\n<span>2 ∉ B      C ⊂ A</span>\n<span>2 ∈ D      D ⊂ C</span>\n<span>2 ∉ E      E ⊄ A</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-84/')
    RETURNING id INTO v_task_id;

