    VALUES (v_textbook_id, 84, '16', 5, 'Старинные задачи а) Летела стая гусей: один гусь впереди, а два позади; один позади и два впереди; один между двумя и три в ряд. Сколько было гусей? б) Коля и его сестра Шура хвалились своими успехами в арифметике. Отец сказал: «Хвалиться может каждый. А вот попробуйте решить мои задачи». И дал детям по записке. Коля прочитал: «Если к моим деньгам прибавить их половину, то получится 81 рубль. Сколько у меня денег?». А Шура прочитала: «Если мама положит в кошелёк ещё треть денег, находящихся в нём, то в кошельке станет 68 рублей. Сколько денег в кошельке?». Но ни Коля, ни Шура задачи решить не смогли. Не поможешь ли ты в их затруднительном положении?', '</p>\n\n<p class="text"><span><b>Старинные задачи</b></span>\n<span>а) Летела стая гусей: один гусь впереди, а два позади; один позади и два впереди; один между двумя и три в ряд. Сколько было гусей?</span>\n<span>б) Коля и его сестра Шура хвалились своими успехами в арифметике. Отец сказал: «Хвалиться может каждый. А вот попробуйте решить мои задачи». И дал детям по записке.</span>\n<span>Коля прочитал: «Если к моим деньгам прибавить их половину, то получится 81 рубль. Сколько у меня денег?».</span>\n<span>А Шура прочитала: «Если мама положит в кошелёк ещё треть денег, находящихся в нём, то в кошельке станет 68 рублей. Сколько денег в кошельке?».</span>\n<span>Но ни Коля, ни Шура задачи решить не смогли. Не поможешь ли ты в их затруднительном положении?</span></p>', 'а) три гуся б) Для Коли: 81 : 3 · 2 = 54 (р.) у папы.      Ответ: 54 рубля.     Для Шуры: 68 : 2 · 3 = 102 (р.) в кошельке.      Ответ: 102 рубля.', '<p><span>а) три гуся</span>\n<span>б) Для Коли: 81 : 3 · 2 = 54 (р.) у папы.</span>\n<span>    <b>Ответ:</b> 54 рубля.</span>\n<span>    Для Шуры: 68 : 2 · 3 = 102 (р.) в кошельке.</span>\n<span>    <b>Ответ:</b> 102 рубля.</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-84/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '3302545ee6cfb0d00f79ecae24a18ba012e3db205681514158395b30d5c71a6e', '68,81', '["реши"]'::jsonb, 'старинные задачи а) летела стая гусей:один гусь впереди, а два позади; один позади и два впереди; один между двумя и три в ряд. сколько было гусей? б) коля и его сестра шура хвалились своими успехами в арифметике. отец сказал:"хвалиться может каждый. а вот попробуйте решить мои задачи". и дал детям по записке. коля прочитал:"если к моим деньгам прибавить их половину, то получится 81 рубль. сколько у меня денег?". а шура прочитала:"если мама положит в кошелёк ещё треть денег, находящихся в нём, то в кошельке станет 68 рублей. сколько денег в кошельке?". но ни коля, ни шура задачи решить не смогли. не поможешь ли ты в их затруднительном положении');

