    VALUES (v_textbook_id, 85, '6', 5, 'По железной дороге от Бреста до Москвы 1099 км, от Москвы до Екатеринбурга – 1667 км, от Екатеринбурга до Новосибирска – 1524 км, а от Новосибирска до Иркутска – 1851 км. Чему равно расстояние от Бреста до Иркутска по этой железной дороге?', '</p>\n\n<p class="text">По железной дороге от Бреста до Москвы 1099 км, от Москвы до Екатеринбурга – 1667 км, от Екатеринбурга до Новосибирска – 1524 км, а от Новосибирска до Иркутска – 1851 км. Чему равно расстояние от Бреста до Иркутска по этой железной дороге?</p>\n\n<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica85-nomer6.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 85, номер 6, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 85, номер 6, год 2022."/>\n</div>', '1099 + 1667 + 1524 + 1851 = 2950 + 3191 = 6141 (км) Ответ: 6141 километров расстояние от Бреста до Иркутска по этой железной дороге.', '<p><span>1099 + 1667 + 1524 + 1851 = 2950 + 3191 = 6141 (км)</span>\n<span><b>Ответ:</b> 6141 километров расстояние от Бреста до Иркутска по этой железной дороге.</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-85/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, 'condition', 0, NULL, 'https://gdz-raketa.ru/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica85-nomer6.jpg', 'peterson/3/part1/page85/task6_condition_0.jpg', '');

    VALUES (v_task_id, v_textbook_id, 3, '97dcff69f2e76451d16832faaae2827465c7731093bbda3ccd301feec679b44b', '1099,1524,1667,1851', '["равно"]'::jsonb, 'по железной дороге от бреста до москвы 1099 км, от москвы до екатеринбурга-1667 км, от екатеринбурга до новосибирска-1524 км, а от новосибирска до иркутска-1851 км. чему равно расстояние от бреста до иркутска по этой железной дороге');

    VALUES (v_textbook_id, 85, '7', 6, 'Реши уравнения с комментированием и сделай проверку: х : 72 = 10      600 : х = 100      х · 10 = 350      540 : х = 54', '</p>\n\n<p class="text">Реши уравнения с комментированием и сделай проверку:</p>\n\n<p class="description-text">\nх : 72 = 10      600 : х = 100      х · 10 = 350      540 : х = 54</p>', 'х : 72 = 10 Чтобы найти делимое х перемножим частное с делителем. х = 72 · 10 х = 720 Проверка: 720 : 72 = 10 600 : х = 100 Чтобы найти делитель х разделим делимое на частное. х = 600 : 100 х = 6 Проверка: 600 : 6 = 100 х · 10 = 350 что бы найти один из множителей х произведения разделим произведение на известный множитель. х = 350 : 10 х = 35 Проверка: 35 · 10 = 350 540 : х = 54 Чтобы найти делитель разделим делимое на частное. х = 540 : 54 х = 10 Проверка: 540 : 10 = 54', '<p><span>х : 72 = 10</span>\n<span>Чтобы найти делимое х перемножим частное с делителем.</span>\n<span>х = 72 · 10</span>\n<span>х = 720</span>\n<span><b>Проверка:</b> 720 : 72 = 10</span>\n<br/>\n<span>600 : х = 100</span>\n<span>Чтобы найти делитель х разделим делимое на частное.</span>\n<span>х = 600 : 100</span>\n<span>х = 6</span>\n<span><b>Проверка:</b> 600 : 6 = 100</span>\n<br/>\n<span>х · 10 = 350</span>\n<span>что бы найти один из множителей х произведения разделим произведение на известный множитель.</span>\n<span>х = 350 : 10</span>\n<span>х = 35</span>\n<span><b>Проверка:</b> 35 · 10 = 350</span>\n<br/>\n<span>540 : х = 54</span>\n<span>Чтобы найти делитель разделим делимое на частное.</span>\n<span>х = 540 : 54</span>\n<span>х = 10</span>\n<span><b>Проверка:</b> 540 : 10 = 54</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-85/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, 'ec9895d8d64b64316deadbf5a419491ea8d2abd7adb8e266206b8ea300e0d124', '10,54,72,100,350,540,600', '["реши"]'::jsonb, 'реши уравнения с комментированием и сделай проверку:х:72=10      600:х=100      х*10=350      540:х=54');

    VALUES (v_textbook_id, 85, '8', 7, 'Длина прямоугольника равна 12 см, а ширина – в 2 раза меньше длины. Найди площадь квадрата с тем же периметром, что и у данного прямоугольника.', '</p>\n\n<p class="text">Длина прямоугольника равна 12 см, а ширина – в 2 раза меньше длины. Найди площадь квадрата с тем же периметром, что и у данного прямоугольника.</p>\n\n<div class="img-wrapper-460">\n<img width="290" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica85-nomer8.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 85, номер 8, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 85, номер 8, год 2022."/>\n</div>', '12 : 2 = 6 (см) – ширина. 12 · 2 + 6 · 2 = 24 + 12 = 36 (см) – периметр прямоугольника. 36 : 4 = 9 (см) – сторона квадрата. 92 = 81 (см 2 ) Ответ: 81 см 2 площадь квадрата.', '<p><span>12 : 2 = 6 (см) – ширина.</span>\n<span>12 · 2 + 6 · 2 = 24 + 12 = 36 (см) – периметр прямоугольника.</span>\n<span>36 : 4 = 9 (см) – сторона квадрата.</span>\n<span>92 = 81 (см<sup>2</sup>)</span>\n<span><b>Ответ:</b> 81 см<sup>2</sup> площадь квадрата.</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-85/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, 'condition', 0, NULL, 'https://gdz-raketa.ru/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica85-nomer8.jpg', 'peterson/3/part1/page85/task8_condition_0.jpg', '');

    VALUES (v_task_id, v_textbook_id, 3, '49c15e8cc405976854c6ee4aa63cf74bdbd4768d355bcb29a3a6138123bd6bc2', '2,12', '["найди","периметр","площадь","меньше","раз","раза"]'::jsonb, 'длина прямоугольника равна 12 см, а ширина-в 2 раза меньше длины. найди площадь квадрата с тем же периметром, что и у данного прямоугольника');

    VALUES (v_textbook_id, 85, '9', 8, 'Нарисуй прямую АВ и отметь на ней точку С. Сколько образовалось лучей? Назови их.', '</p>\n\n<p class="text">Нарисуй прямую АВ и отметь на ней точку С. Сколько образовалось лучей? Назови их.</p>\n\n<div class="img-wrapper-460">\n<img width="190" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica85-nomer9.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 85, номер 9, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 85, номер 9, год 2022."/>\n</div>', '', '<div class="img-wrapper-460">\n<img width="310" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica85-nomer9-1.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 85, номер 9, год 2022, ответ." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 85, номер 9, год 2022, ответ."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-85/')
