    VALUES (v_task_id, v_textbook_id, 3, '9b2ab1da7841d52163860dba34d05fa50354c4316b71902f562ad2a3212724a4', NULL, '["раз"]'::jsonb, 'нарисуй прямую ав и отметь на ней точку с. сколько образовалось лучей? назови их');

    VALUES (v_textbook_id, 86, '10', 0, 'Что общего в выражениях: а · 15 + а      5 · (3 · b)      7 · а + 8 · а На какие группы их можно разбить?', '</p>\n\n<p class="text">Что общего в выражениях:</p>\n\n<p class="description-text">\nа · 15 + а      5 · (3 · b)      7 · а + 8 · а</p>\n\n<p class="text">На какие группы их можно разбить?</p>', 'Общего в выражениях наличие переменной и числа 15, или полученного в результате раскрытия скобок или образования скобок: а · 15 + а 5 · (3 · b) = 15 · 5b 7 · а + 8 · а = a · (7 + 8) = 15a Их можно разбить на 2 группы: 1 группа произведение со сложением а · 15 + а      7 · а + 8 · а и 2 группа только произведение 5 · (3 · b).', '<p><span>Общего в выражениях наличие переменной и числа 15, или полученного в результате раскрытия скобок или образования скобок: а · 15 + а</span>\n<span>5 · (3 · b) = 15 · 5b</span>\n<span>7 · а + 8 · а = a · (7 + 8) = 15a</span>\n<span>Их можно разбить на 2 группы: 1 группа произведение со сложением</span>\n<span>а · 15 + а      7 · а + 8 · а</span>\n<span>и 2 группа только произведение</span>\n<span>5 · (3 · b).</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-86/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, 'fdee42a0a2dca77c7b5eb4bc2e032ce063fb2205b866a0addd6133874c2f25b5', '3,5,7,8,15', '["раз"]'::jsonb, 'что общего в выражениях:а*15+а      5*(3*b)      7*а+8*а на какие группы их можно разбить');

    VALUES (v_textbook_id, 86, '11', 1, 'БЛИЦтурнир а) С одной грядки собрали а кабачков, а с другой – b кабачков. Их разложили в корзины по 10 кабачков в каждую. Сколько корзин потребовалось? б) Папа привёз для сада саженцы яблонь. После того как посадили 2 ряда по n яблонь в каждом, осталось ещё m саженцев. Сколько саженцев яблонь привёз папа?', '</p>\n\n<p class="text"><span><b>БЛИЦтурнир</b></span>\n<span>а) С одной грядки собрали <b>а</b> кабачков, а с другой – <b>b</b> кабачков. Их разложили в корзины по 10 кабачков в каждую. Сколько корзин потребовалось?</span>\n<span>б) Папа привёз для сада саженцы яблонь. После того как посадили 2 ряда по <b>n</b> яблонь в каждом, осталось ещё <b>m</b> саженцев. Сколько саженцев яблонь привёз папа?</span></p>', 'а) (а + b) : 10      Ответ: (а + b) : 10 корзин потребовалось. б) 2n + m      Ответ: 2n + m саженцев яблонь привёз папа.', '<p><span>а) (а + b) : 10</span>\n<span>    <b>Ответ:</b> (а + b) : 10 корзин потребовалось.</span>\n<span>б) 2n + m</span>\n<span>    <b>Ответ:</b> 2n + m саженцев яблонь привёз папа.</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-86/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '718061390ca6961a472aa1394ba51313a5e1047350c1bbb79c837d8ffd6eedaf', '2,10', '["раз"]'::jsonb, 'блицтурнир а) с одной грядки собрали а кабачков, а с другой-b кабачков. их разложили в корзины по 10 кабачков в каждую. сколько корзин потребовалось? б) папа привёз для сада саженцы яблонь. после того как посадили 2 ряда по n яблонь в каждом, осталось ещё m саженцев. сколько саженцев яблонь привёз папа');

    VALUES (v_textbook_id, 86, '12', 2, 'Выполни действия. Что общего в примерах каждого столбика? 6 · 8      54 : 9      24 · 3      58 : 2      96 : 16      37 : 4 7 · 5      42 : 7      5 · 18      87 : 3      96 : 12      73 : 8', '</p>\n\n<p class="text">Выполни действия. Что общего в примерах каждого столбика?</p>\n\n<p class="description-text">\n<span>6 · 8      54 : 9      24 · 3      58 : 2      96 : 16      37 : 4</span>\n<span>7 · 5      42 : 7      5 · 18      87 : 3      96 : 12      73 : 8</span></p>', '6 · 8 = 48, 7 · 5 = 35 – табличное умножение. 54 : 9 = 6, 42 : 7 = 6 – табличное деление. 24 · 3 = 72, 5 · 18 = 90 – умножение двузначное и однозначное. 58 : 2 = 29, 87 : 3 = 29 – деление двузначного на однозначное число с одинаковым результатом. 96 : 16 = 6, 96 : 12 = 8 – деление двузначного на двузначное число. 37 : 4 = 9 + 1, 73 : 8 = 9 + 1 – деление с остатком с одинаковым результатом.', '<p><span>6 · 8 = 48, 7 · 5 = 35 – табличное умножение.</span>\n<span>54 : 9 = 6, 42 : 7 = 6 – табличное деление.</span>\n<span>24 · 3 = 72, 5 · 18 = 90 – умножение двузначное и однозначное.</span>\n<span>58 : 2 = 29, 87 : 3 = 29 – деление двузначного на однозначное число с одинаковым результатом.</span>\n<span>96 : 16 = 6, 96 : 12 = 8 – деление двузначного на двузначное число.</span>\n<span>37 : 4 = 9 + 1, 73 : 8 = 9 + 1 – деление с остатком с одинаковым результатом.</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-86/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, 'a68e19f769476b67bd1757eb4e83f2de21de022afbbf2f0ac9fd45a585b4328b', '2,3,4,5,6,7,8,9,12,16', '["столбик"]'::jsonb, 'выполни действия. что общего в примерах каждого столбика? 6*8      54:9      24*3      58:2      96:16      37:4 7*5      42:7      5*18      87:3      96:12      73:8');

    VALUES (v_textbook_id, 86, '13', 3, 'Вычисли. Расшифруй названия птиц. Найди о них информацию в энциклопедии или Интернете.', '</p>\n\n<p class="text">Вычисли. Расшифруй названия птиц. Найди о них информацию в энциклопедии или Интернете.</p>\n\n<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica86-nomer13.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 86, номер 13, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 86, номер 13, год 2022."/>\n</div>', 'К – 80 : 5 + 28 = 16 + 28 = 44 А – 4 · 16 – 38 = 64 – 38 = 26 Н – 68 : (13 – 9) = 68 : 4 = 17 Б – (49 + 29) : 6 = 78 : 6 = 13 М – 18 + 32 : 2 = 18 + 16 = 34 Е – (18 + 32) : 2 = 50 : 2 = 25 Ч – 100 – 18 · 3 = 100 – 54 = 46 Т – (100 – 18) · 3 = 82 · 3 = 246 Г – 91 : 13 · 10 = 7 · 10 = 70 О – 8 · (72 : 24) = 8 · 3 = 24 Л – 60 : 3 – 75 : 5 = 20 – 15 = 5 Ы – 42 : 3 + 27 · 3 = 14 + 9 = 23', '<p><span>К – 80 : 5 + 28 = 16 + 28 = 44</span>\n<span>А – 4 · 16 – 38 = 64 – 38 = 26</span>\n<span>Н – 68 : (13 – 9) = 68 : 4 = 17</span>\n<span>Б – (49 + 29) : 6 = 78 : 6 = 13</span>\n<span>М – 18 + 32 : 2 = 18 + 16 = 34</span>\n<span>Е – (18 + 32) : 2 = 50 : 2 = 25</span>\n<span>Ч – 100 – 18 · 3 = 100 – 54 = 46</span>\n<span>Т – (100 – 18) · 3 = 82 · 3 = 246</span>\n<span>Г – 91 : 13 · 10 = 7 · 10 = 70</span>\n<span>О – 8 · (72 : 24) = 8 · 3 = 24</span>\n<span>Л – 60 : 3 – 75 : 5 = 20 – 15 = 5</span>\n<span>Ы – 42 : 3 + 27 · 3 = 14 + 9 = 23</span></p>\n\n<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica86-nomer13-1.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 86, номер 13, год 2022, ответ." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 86, номер 13, год 2022, ответ."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-86/')
    RETURNING id INTO v_task_id;

