    VALUES (v_task_id, 'solution', 0, NULL, 'https://gdz-raketa.ru/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica86-nomer13-1.jpg', 'peterson/3/part1/page86/task13_solution_0.jpg', '');

