    VALUES (v_textbook_id, 87, '5', 4, 'Выполни действия. Проверь результаты с помощью калькулятора. а) 20000 – 2075 б) 906020 – 99804 в) 2940759 + 83246 г) 5200740 – 260938', '</p>\n\n<p class="text">Выполни действия. Проверь результаты с помощью калькулятора.</p>\n\n<p class="description-text">\n<span>а) 20000 – 2075</span>\n<span>б) 906020 – 99804</span>\n<span>в) 2940759 + 83246</span>\n<span>г) 5200740 – 260938</span></p>', 'а) 20000 – 2075 = 17925', '<p>а) 20000 – 2075 = 17925</p>\n\n<div class="img-wrapper-460">\n<img width="150" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica87-nomer5.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 87, номер 5, год 2022, ответ." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 87, номер 5, год 2022, ответ."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-87/')
