    VALUES (v_textbook_id, 87, '6', 5, 'Ширина прямоугольника 9 дм, а длина – на 2 дм больше. Найди площадь квадрата с тем же периметром, что и у данного прямоугольника.', '</p>\n\n<p class="text">Ширина прямоугольника 9 дм, а длина – на 2 дм больше. Найди площадь квадрата с тем же периметром, что и у данного прямоугольника.</p>', '9 + 2 = 11 (дм) – длина. 11 · 2 + 9 · 2 = 22 + 18 = 40 (дм) – периметр прямоугольника. 40 : 4 = 10 (дм) – сторона квадрата. 10 2 = 100 (дм 2 ). Ответ: 100 дм 2 площадь квадрата.', '<p><span>9 + 2 = 11 (дм) – длина.</span>\n<span>11 · 2 + 9 · 2 = 22 + 18 = 40 (дм) – периметр прямоугольника.</span>\n<span>40 : 4 = 10 (дм) – сторона квадрата.</span>\n<span>10<sup>2</sup> = 100 (дм<sup>2</sup>).</span>\n<span><b>Ответ:</b> 100 дм<sup>2</sup> площадь квадрата.</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-87/')
    RETURNING id INTO v_task_id;

