    VALUES (v_textbook_id, 87, '7', 6, 'Реши уравнения с комментированием и сделай проверку: 520 : х = 40      х · 38 = 760      х : 23 = 400', '</p>\n\n<p class="text">Реши уравнения с комментированием и сделай проверку:</p>\n\n<p class="description-text">\n520 : х = 40      х · 38 = 760      х : 23 = 400</p>', '520 : х = 40 Чтобы найти делитель х разделим делимое на частное. х = 520 : 40 х = 13 Проверка: 520 : 13 = 40 х · 38 = 760 Что бы найти множитель х разделим произведение на известный множитель. х = 760 : 38 х = 20 Проверка: 20 · 38 = 760 х : 23 = 400 Что бы найти делимое х умножим делитель на частное. х = 400 · 23 х = 9200 Проверка: 9200 : 23 = 400', '<p><span>520 : х = 40</span>\n<span>Чтобы найти делитель х разделим делимое на частное.</span>\n<span>х = 520 : 40</span>\n<span>х = 13</span>\n<span><b>Проверка:</b> 520 : 13 = 40</span>\n<br/>\n<span>х · 38 = 760</span>\n<span>Что бы найти множитель х разделим произведение на известный множитель.</span>\n<span>х = 760 : 38</span>\n<span>х = 20</span>\n<span><b>Проверка:</b> 20 · 38 = 760</span>\n<br/>\n<span>х : 23 = 400</span>\n<span>Что бы найти делимое х умножим делитель на частное.</span>\n<span>х = 400 · 23</span>\n<span>х = 9200</span>\n<span><b>Проверка:</b> 9200 : 23 = 400</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-87/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '0c26fc238115328c769feb14755cf87b2ecb92fa82d6df15cfdc13e4f51cc48c', '23,38,40,400,520,760', '["реши"]'::jsonb, 'реши уравнения с комментированием и сделай проверку:520:х=40      х*38=760      х:23=400');

    VALUES (v_textbook_id, 87, '8', 7, 'Выполни деление с остатком и сделай проверку: а) 15 : 9      б) 32 : 6      в) 57 : 4      г) 73 : 14', '</p>\n\n<p class="text">Выполни деление с остатком и сделай проверку:</p>\n\n<p class="description-text">\nа) 15 : 9      б) 32 : 6      в) 57 : 4      г) 73 : 14</p>', 'а) 15 : 9 = 1 + 6', '<p>а) 15 : 9 = 1 + 6</p>\n\n<div class="img-wrapper-460">\n<img width="70" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica87-nomer8.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 87, номер 8, год 2022, ответ." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 87, номер 8, год 2022, ответ."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-87/')
