    VALUES (v_task_id, v_textbook_id, 3, 'ab1991123693f8efbb93ff7f64bb4d2539f5e630f759b0dccb215bf7edc030a7', '4,6,9,14,15,32,57,73', NULL, 'выполни деление с остатком и сделай проверку:а) 15:9      б) 32:6      в) 57:4      г) 73:14');

    VALUES (v_textbook_id, 87, '9', 8, 'БЛИЦтурнир а) Дети собрали 4 банки малины по d кг в каждой банке. На варенье израсходовали с кг. Сколько килограммов малины ещё осталось? б) Мама купила а яблок. Из них b яблок были ещё зелёные, и она их отложила. Остальные яблоки она разделила поровну между четырьмя детьми. Сколько яблок досталось каждому ребёнку?', '</p>\n\n<p class="text"><span><b>БЛИЦтурнир</b></span>\n<span>а) Дети собрали 4 банки малины по <b>d</b> кг в каждой банке. На варенье израсходовали <b>с</b> кг. Сколько килограммов малины ещё осталось?</span>\n<span>б) Мама купила <b>а</b> яблок. Из них <b>b</b> яблок были ещё зелёные, и она их отложила. Остальные яблоки она разделила поровну между четырьмя детьми. Сколько яблок досталось каждому ребёнку?</span></p>', 'а) 4d – с      Ответ: 4d – с килограммов малины ещё осталось. б) (а – b) : 4      Ответ: (а – b) : 4 яблок досталось каждому ребёнку.', '<p><span>а) 4d – с</span>\n<span>    <b>Ответ:</b> 4d – с килограммов малины ещё осталось.</span>\n<span>б) (а – b) : 4</span>\n<span>    <b>Ответ:</b> (а – b) : 4 яблок досталось каждому ребёнку.</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-87/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '4e92cddaf20ea17ea527a78ab8c764ac46b95500832b3bdfba0f430af2fec76a', '4', '["раздели","раз"]'::jsonb, 'блицтурнир а) дети собрали 4 банки малины по d кг в каждой банке. на варенье израсходовали с кг. сколько килограммов малины ещё осталось? б) мама купила а яблок. из них b яблок были ещё зелёные, и она их отложила. остальные яблоки она разделила поровну между четырьмя детьми. сколько яблок досталось каждому ребёнку');

    VALUES (v_textbook_id, 88, '10', 0, 'Запиши множества с помощью фигурных скобок или знака ∅: а) А – множество летних месяцев года; б) В – множество пальцев одной руки; в) D – множество крылатых зайцев; г) F – множество делителей числа 12; д) Е – множество двузначных чисел, кратных 15; е) С – множество букв в слове «математика».', '</p>\n\n<p class="text">Запиши множества с помощью фигурных скобок или знака ∅:</p>\n\n<p class="description-text">\n<span>а) А – множество летних месяцев года;</span>\n<span>б) В – множество пальцев одной руки;</span>\n<span>в) D – множество крылатых зайцев;</span>\n<span>г) F – множество делителей числа 12;</span>\n<span>д) Е – множество двузначных чисел, кратных 15;</span>\n<span>е) С – множество букв в слове «математика».</span></p>', 'а) А = {июнь; июль; август} б) В = {мизинец; безымянный; средний; указательный; большой} в) D = {0} г) F ={12; 24; 36; 48; 60; 72; 84; 96} д) Е = {15; 30; 45; 60; 75; 90} е) С = {м; а; т; е; м; а; т; и; к; а}', '<p><span>а) А = {июнь; июль; август}</span>\n<span>б) В = {мизинец; безымянный; средний; указательный; большой}</span>\n<span>в) D = {0}</span>\n<span>г) F ={12; 24; 36; 48; 60; 72; 84; 96}</span>\n<span>д) Е = {15; 30; 45; 60; 75; 90}</span>\n<span>е) С = {м; а; т; е; м; а; т; и; к; а}</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-88/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '822faa6e4f5424c8f059603002f9f1bc2f845e8e9766454ff81543d016222cf3', '12,15', NULL, 'запиши множества с помощью фигурных скобок или знака ∅:а) а-множество летних месяцев года; б) в-множество пальцев одной руки; в) d-множество крылатых зайцев; г) f-множество делителей числа 12; д) е-множество двузначных чисел, кратных 15; е) с-множество букв в слове "математика"');

    VALUES (v_textbook_id, 88, '11', 1, 'Составь программу действий и вычисли: а) (80 : 4 – 60 : 30) · 5 + 96 : 3      б) 56 : 4 + 2 · (120 : 6 – 80 : 20)', '</p>\n\n<p class="text">Составь программу действий и вычисли:</p>\n\n<p class="description-text">\nа) (80 : 4 – 60 : 30) · 5 + 96 : 3      б) 56 : 4 + 2 · (120 : 6 – 80 : 20)</p>', 'а) (80 : 4 – 60 : 30) · 5 + 96 : 3 = 122     80 : 4 = 20     60 : 30 = 2     20 – 2 = 18     18 · 5 = 90     96 : 3 = 32     90 + 32 = 122 б) 56 : 4 + 2 · (120 : 6 – 80 : 20) = 46     120 : 6 = 20     80 : 20 = 4     20 – 4 = 16     2 · 16 = 32     56 : 4 = 14     14 + 32 = 46', '<p><span>а) (80 : 4 – 60 : 30) · 5 + 96 : 3 = 122</span>\n<span>    80 : 4 = 20</span>\n<span>    60 : 30 = 2</span>\n<span>    20 – 2 = 18</span>\n<span>    18 · 5 = 90</span>\n<span>    96 : 3 = 32</span>\n<span>    90 + 32 = 122</span>\n<span>б) 56 : 4 + 2 · (120 : 6 – 80 : 20) = 46</span>\n<span>    120 : 6 = 20</span>\n<span>    80 : 20 = 4</span>\n<span>    20 – 4 = 16</span>\n<span>    2 · 16 = 32</span>\n<span>    56 : 4 = 14</span>\n<span>    14 + 32 = 46</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-88/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, 'e4c577985d27e52cd2c8117558697aade9159d88039f45397330c0bb46e99379', '2,3,4,5,6,20,30,56,60,80', '["вычисли"]'::jsonb, 'составь программу действий и вычисли:а) (80:4-60:30)*5+96:3      б) 56:4+2*(120:6-80:20)');

    VALUES (v_textbook_id, 88, '12', 2, 'Найди на рисунке все пары пересекающихся прямых. Имеются ли на этом рисунке параллельные прямые, перпендикулярные прямые?', '</p>\n\n<p class="text">Найди на рисунке все пары пересекающихся прямых. Имеются ли на этом рисунке параллельные прямые, перпендикулярные прямые?</p>\n\n<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica88-nomer12.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 88, номер 12, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 88, номер 12, год 2022."/>\n</div>', 'b и d, c и d, b и c – если продлить. а и b параллельны, b и с перпендикулярные.', '<p>b и d, c и d, b и c – если продлить. а и b параллельны, b и с перпендикулярные.</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-88/')
    RETURNING id INTO v_task_id;

