    VALUES (v_textbook_id, 88, '13', 3, 'Известно, что 25 · 12 = 300. Используя данное равенство, найди значения выражений: 300 : 25      25 · 13      25 · 11      12 · 24 300 : 12      13 · 25      11 · 25      24 · 12', '</p>\n\n<p class="text">Известно, что 25 · 12 = 300. Используя данное равенство, найди значения выражений:</p>\n\n<p class="description-text">\n<span>300 : 25      25 · 13      25 · 11      12 · 24</span>\n<span>300 : 12      13 · 25      11 · 25      24 · 12</span></p>', '300 : 25 = 12      25 · 13 = 325      25 · 11 = 275      12 · 24 = 288 300 : 12 = 25      13 · 25 = 325      11 · 25 = 275      24 · 12 = 288', '<p><span>300 : 25 = 12      25 · 13 = 325      25 · 11 = 275      12 · 24 = 288</span>\n<span>300 : 12 = 25      13 · 25 = 325      11 · 25 = 275      24 · 12 = 288</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-88/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '2111293398a3c3662031f704eaddb4972115e746737156efc2b3ddf13d9346b4', '11,12,13,24,25,300', '["найди"]'::jsonb, 'известно, что 25*12=300. используя данное равенство, найди значения выражений:300:25      25*13      25*11      12*24 300:12      13*25      11*25      24*12');

    VALUES (v_textbook_id, 88, '14', 4, 'Где надо поставить скобки, чтобы равенства стали верными? а) 90 : 2 · 5 – 5 = 0 б) 60 : 5 – 2 · 7 = 70 в) 80 : 8 + 12 · 4 = 16 г) 40 : 2 · 4 + 2 · 5 = 20', '</p>\n\n<p class="text">Где надо поставить скобки, чтобы равенства стали верными?</p>\n\n<p class="description-text">\n<span>а) 90 : 2 · 5 – 5 = 0</span>\n<span>б) 60 : 5 – 2 · 7 = 70</span>\n<span>в) 80 : 8 + 12 · 4 = 16</span>\n<span>г) 40 : 2 · 4 + 2 · 5 = 20</span></p>', 'а) 90 : 2 · (5 – 5) = 0 б) (60 : 5 – 2) · 7 = 70 в) 80 : (8 + 12) · 4 = 16 г) 40 : (2 · 4 + 2) · 5 = 20', '<p><span>а) 90 : 2 · (5 – 5) = 0</span>\n<span>б) (60 : 5 – 2) · 7 = 70</span>\n<span>в) 80 : (8 + 12) · 4 = 16</span>\n<span>г) 40 : (2 · 4 + 2) · 5 = 20</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-88/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, 'bdd225bce0ab0068a74275725ac84b650f3b80a2128f9903a4f2b9fc9e825e62', '0,2,4,5,7,8,12,16,20,40', NULL, 'где надо поставить скобки, чтобы равенства стали верными? а) 90:2*5-5=0 б) 60:5-2*7=70 в) 80:8+12*4=16 г) 40:2*4+2*5=20');

    VALUES (v_textbook_id, 88, '15', 5, 'Старинная задача Один господин встретил знакомую семью, состоящую из деда, отца и сына, и спросил, сколько им лет. «Нам всем вместе 100 лет», – ответил за всех дед. Тогда господин спросил отца: «Скажите же, сколько вам лет?» – «Мне вместе с сыном 45 лет, – ответил отец, – а сын на 25 лет моложе меня». Так любопытному господину и не пришлось узнать, сколько лет каждому из них. Не сообразишь ли ты?', '</p>\n\n<p class="text"><span><b>Старинная задача</b></span>\n<span>Один господин встретил знакомую семью, состоящую из деда, отца и сына, и спросил, сколько им лет. «Нам всем вместе 100 лет», – ответил за всех дед. Тогда господин спросил отца: «Скажите же, сколько вам лет?» – «Мне вместе с сыном 45 лет, – ответил отец, – а сын на 25 лет моложе меня». Так любопытному господину и не пришлось узнать, сколько лет каждому из них. Не сообразишь ли ты?</span></p>', 'Деду 55 лет, отцу 35 лет, сыну 10 лет.', '<p>Деду 55 лет, отцу 35 лет, сыну 10 лет.</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-88/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '93a7e75eeca800be43c2669aed08c1e5dd7f1eb07ac0dc9df646232508674593', '25,45,100', '["раз"]'::jsonb, 'старинная задача один господин встретил знакомую семью, состоящую из деда, отца и сына, и спросил, сколько им лет. "нам всем вместе 100 лет",-ответил за всех дед. тогда господин спросил отца:"скажите же, сколько вам лет?"-"мне вместе с сыном 45 лет,-ответил отец,-а сын на 25 лет моложе меня". так любопытному господину и не пришлось узнать, сколько лет каждому из них. не сообразишь ли ты');

    VALUES (v_textbook_id, 89, '1', 0, 'а) Прочитай равенства разными способами и объясни их смысл: a · b = b · a      (a · b) · c = a · (b · c) б) Вспомни правило умножения на 10 и на 100. Вычисли: 5 · 10      5 · 100 Установи с помощью свойств умножения, сохранится ли это правило при умножении на 1000, 10000 и т. д. Сделай вывод.', '</p>\n\n<p class="text">а) Прочитай равенства разными способами и объясни их смысл:</p>\n\n<p class="description-text">\na · b = b · a      (a · b) · c = a · (b · c)</p>\n\n<p class="text">б) Вспомни правило умножения на 10 и на 100. Вычисли:</p>\n\n<p class="description-text">\n5 · 10      5 · 100</p>\n\n<p class="text">Установи с помощью свойств умножения, сохранится ли это правило при умножении на 1000, 10000 и т. д. Сделай вывод.</p>', 'а) если поменять множители местами произведение не измениться. Если поменять местами множители в скобках и за скобками, то произведение не измениться. б) 5 · 10 = 50      5 · 100 = 500     5 · 1000 = 5000      5 · 10000 = 50000 или 1000 · 5 = 5000      10000 · 5 = 50000     Сохранится это правило при умножении на 1000, 10000.', '<p><span>а) если поменять множители местами произведение не измениться. Если поменять местами множители в скобках и за скобками, то произведение не измениться.</span>\n<span>б) 5 · 10 = 50      5 · 100 = 500</span>\n    5 · 1000 = 5000      5 · 10000 = 50000 или 1000 · 5 = 5000      10000 · 5 = 50000\n<span>    Сохранится это правило при умножении на 1000, 10000.</span></p>', 'Умножение числа на 10, 100, 1000... При умножении числа на 10, 100, 1000 и т. д. можно приписать к этому числу справа соответственно 1 нуль, 2 нуля, 3 нуля и т. д.     · 10 =     0     · 100 =     00     · 1000 =     000 и т. д.', '<div class="recomended-block">\n<span class="title">Умножение числа на 10, 100, 1000...</span>\n<p>При умножении числа на 10, 100, 1000 и т. д. можно приписать к этому числу справа соответственно 1 нуль, 2 нуля, 3 нуля и т. д.<br/>\n<span class="okon">   </span> · 10 = <span class="okon">   </span>0<br/>\n<span class="okon">   </span> · 100 = <span class="okon">   </span>00<br/>\n<span class="okon">   </span> · 1000 = <span class="okon">   </span>000 и т. д.</p>\n</div>', TRUE, '[{"letter":"а","condition":"Прочитай равенства разными способами и объясни их смысл: a · b = b · a      (a · b) · c = a · (b · c)","solution":"если поменять множители местами произведение не измениться. Если поменять местами множители в скобках и за скобками, то произведение не измениться."},{"letter":"б","condition":"Вспомни правило умножения на 10 и на 100. Вычисли: 5 · 10      5 · 100 Установи с помощью свойств умножения, сохранится ли это правило при умножении на 1000, 10000 и т. д. Сделай вывод.","solution":"5 · 10 = 50      5 · 100 = 500     5 · 1000 = 5000      5 · 10000 = 50000 или 1000 · 5 = 5000      10000 · 5 = 50000     Сохранится это правило при умножении на 1000, 10000."}]'::jsonb, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-89/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '903697589179026aca24bc736c4912462e66d8bb24a691b76d78770b3ffdc1da', '5,10,100,1000,10000', '["вычисли","раз"]'::jsonb, 'а) прочитай равенства разными способами и объясни их смысл:a*b=b*a      (a*b)*c=a*(b*c) б) вспомни правило умножения на 10 и на 100. вычисли:5*10      5*100 установи с помощью свойств умножения, сохранится ли это правило при умножении на 1000, 10000 и т. д. сделай вывод');

    VALUES (v_textbook_id, 89, '2', 1, 'Вычисли устно: 36 · 10      70 · 10        10 · 300       8 · 1000        90 · 100 100 · 4      29 · 100      56 · 100      10000 · 3      1000 · 64', '</p>\n\n<p class="text">Вычисли устно:</p>\n\n<p class="description-text">\n<span>36 · 10      70 · 10        10 · 300       8 · 1000        90 · 100</span>\n<span>100 · 4      29 · 100      56 · 100      10000 · 3      1000 · 64</span></p>', '36 · 10 = 360 100 · 4 = 400 70 · 10 = 700 29 · 100 = 2900 10 · 300 = 3000 56 · 100 = 5600 8 · 1000 = 8000 10000 · 3 = 30000 90 · 100 = 9000 1000 · 64 = 64000', '<p><span>36 · 10 = 360</span>\n<span>100 · 4 = 400</span>\n<span>70 · 10 = 700</span>\n<span>29 · 100 = 2900</span>\n<span>10 · 300 = 3000</span>\n<span>56 · 100 = 5600</span>\n<span>8 · 1000 = 8000</span>\n<span>10000 · 3 = 30000</span>\n<span>90 · 100 = 9000</span>\n<span>1000 · 64 = 64000</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-89/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '9c37bd35f24a8535732d02460db9db0a5d4283516a6b3149d086829389c4893c', '3,4,8,10,29,36,56,64,70,90', '["вычисли"]'::jsonb, 'вычисли устно:36*10      70*10        10*300       8*1000        90*100 100*4      29*100      56*100      10000*3      1000*64');

    VALUES (v_textbook_id, 89, '3', 2, 'Вычисли произведения и прочитай полученные числа: а) 172 · 100         д) 840 · 1000 б) 3500 · 10         е) 2700 · 1000 в) 1000 · 460      ж) 10 · 50000 г) 58 · 1000          з) 40200 · 10000', '</p>\n\n<p class="text">Вычисли произведения и прочитай полученные числа:</p>\n\n<p class="description-text">\n<span>а) 172 · 100         д) 840 · 1000</span>\n<span>б) 3500 · 10         е) 2700 · 1000</span>\n<span>в) 1000 · 460      ж) 10 · 50000</span>\n<span>г) 58 · 1000          з) 40200 · 10000</span></p>', 'а) 172 · 100 = 17200 семнадцать тысяч двести. б) 3500 · 10 = 35000 тридцать пять тысяч. в) 1000 · 460 = 460000 четыреста шестьдесят тысяч. г) 58 · 1000 = 58000 пятьдесят восемь тысяч. д) 840 · 1000 = 840000 восемьсот сорок тысяч. е) 2700 · 1000 = 2700000 два миллиона семьсот тысяч. ж) 10 · 50000 = 500000 пятьсот тысяч. з) 40200 · 10000 = 402000000 четыреста два миллиона.', '<p><span>а) 172 · 100 = 17200 семнадцать тысяч двести.</span>\n<span>б) 3500 · 10 = 35000 тридцать пять тысяч.</span>\n<span>в) 1000 · 460 = 460000 четыреста шестьдесят тысяч.</span>\n<span>г) 58 · 1000 = 58000 пятьдесят восемь тысяч.</span>\n<span>д) 840 · 1000 = 840000 восемьсот сорок тысяч.</span>\n<span>е) 2700 · 1000 = 2700000 два миллиона семьсот тысяч.</span>\n<span>ж) 10 · 50000 = 500000 пятьсот тысяч.</span>\n<span>з) 40200 · 10000 = 402000000 четыреста два миллиона.</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-89/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '9550d3708b5f93b8e7fd056971d1bfb496be23f7dd13353ed54c2e041b5bb623', '10,58,100,172,460,840,1000,2700,3500,10000', '["вычисли"]'::jsonb, 'вычисли произведения и прочитай полученные числа:а) 172*100         д) 840*1000 б) 3500*10         е) 2700*1000 в) 1000*460      ж) 10*50000 г) 58*1000          з) 40200*10000');

    VALUES (v_textbook_id, 89, '4', 3, 'Найди значения выражений: а) 95 · 100      в) 100 · 320        д) 74 · 10000       ж) 1000 · 6000 б) 10 · 400      г) 245 · 1000      е) 1800 · 1000      з) 20500 · 100', '</p>\n\n<p class="text">Найди значения выражений:</p>\n\n<p class="description-text">\n<span>а) 95 · 100      в) 100 · 320        д) 74 · 10000       ж) 1000 · 6000</span>\n<span>б) 10 · 400      г) 245 · 1000      е) 1800 · 1000      з) 20500 · 100</span></p>', 'а) 95 · 100 = 9500 б) 10 · 400 = 4000 в) 100 · 320 = 32000 г) 245 · 1000 = 245000 д) 74 · 10000 = 740000 е) 1800 · 1000 = 1800000 ж) 1000 · 6000 = 6000000 з) 20500 · 100 = 2050000', '<p><span>а) 95 · 100 = 9500</span>\n<span>б) 10 · 400 = 4000</span>\n<span>в) 100 · 320 = 32000</span>\n<span>г) 245 · 1000 = 245000</span>\n<span>д) 74 · 10000 = 740000</span>\n<span>е) 1800 · 1000 = 1800000</span>\n<span>ж) 1000 · 6000 = 6000000</span>\n<span>з) 20500 · 100 = 2050000</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-89/')
