    VALUES (v_textbook_id, 89, '5', 4, 'а) Запиши подряд пять раз цифру 7. Прочитай получившееся число. б) Запиши подряд три раза число 80. Какое число получилось? в) Какое число получится, если записать число 287 четыре раза подряд?', '</p>\n\n<p class="text"><span>а) Запиши подряд пять раз цифру 7. Прочитай получившееся число.</span>\n<span>б) Запиши подряд три раза число 80. Какое число получилось?</span>\n<span>в) Какое число получится, если записать число 287 четыре раза подряд?</span></p>', 'а) 77777 семьдесят семь тысяч семьсот семьдесят семь. б) 808080 восемьсот восемь тысяч восемьдесят. в) 287287287287 двести восемьдесят семь миллиардов двести восемьдесят семь миллионов двести восемьдесят семь тысяч двести восемьдесят семь.', '<p><span>а) 77777 семьдесят семь тысяч семьсот семьдесят семь.</span>\n<span>б) 808080 восемьсот восемь тысяч восемьдесят.</span>\n<span>в) 287287287287 двести восемьдесят семь миллиардов двести восемьдесят семь миллионов двести восемьдесят семь тысяч двести восемьдесят семь.</span></p>', '', '', TRUE, '[{"letter":"а","condition":"Запиши подряд пять раз цифру 7. Прочитай получившееся число.","solution":"77777 семьдесят семь тысяч семьсот семьдесят семь."},{"letter":"б","condition":"Запиши подряд три раза число 80. Какое число получилось?","solution":"808080 восемьсот восемь тысяч восемьдесят."},{"letter":"в","condition":"Какое число получится, если записать число 287 четыре раза подряд?","solution":"287287287287 двести восемьдесят семь миллиардов двести восемьдесят семь миллионов двести восемьдесят семь тысяч двести восемьдесят семь."}]'::jsonb, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-89/')
    RETURNING id INTO v_task_id;

