    VALUES (v_textbook_id, 90, '7', 0, 'Реши первый пример каждого столбика письменно, а остальные – устно:     870 305 + 62 915      607 435 – 5236     875306 + 62915        607436 – 5236     875305 + 62914        607435 – 5237     875306 + 62914        607436 – 5237', '</p>\n\n<p class="text">Реши первый пример каждого столбика письменно, а остальные – устно:</p>\n\n<p class="description-text">\n<span>    870 305 + 62 915      607 435 – 5236</span>\n<span>    875306 + 62915        607436 – 5236</span>\n<span>    875305 + 62914        607435 – 5237</span>\n<span>    875306 + 62914        607436 – 5237</span></p>', '', '<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica90-nomer7.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 90, номер 7, год 2022, ответ." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 90, номер 7, год 2022, ответ."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-90/')
