    VALUES (v_textbook_id, 90, '9', 2, 'а) Расстояние от дома до школы 920 м, а от дома до стадиона – 1400 м. На сколько метров расстояние от дома до школы меньше, чем расстояние от дома до стадиона? б) В трёх посёлках 18200 жителей. В первом посёлке живёт 4570 человек, а во втором – на 1635 человек больше, чем в первом. Сколько человек живёт в третьем посёлке?', '</p>\n\n<p class="text"><span>а) Расстояние от дома до школы 920 м, а от дома до стадиона – 1400 м. На сколько метров расстояние от дома до школы меньше, чем расстояние от дома до стадиона?</span>\n<span>б) В трёх посёлках 18200 жителей. В первом посёлке живёт 4570 человек, а во втором – на 1635 человек больше, чем в первом. Сколько человек живёт в третьем посёлке?</span></p>', 'а) 1400 – 920 = 480 (м)      Ответ: на 480 метров расстояние от дома до школы меньше, чем расстояние от дома до стадиона. б) 18200 – (4570 + 1635) = 18200 – 6205 = 11995 (чел.)      Ответ: 11995 человек живёт в третьем посёлке.', '<p><span>а) 1400 – 920 = 480 (м)</span>\n<span>    <b>Ответ:</b> на 480 метров расстояние от дома до школы меньше, чем расстояние от дома до стадиона.</span>\n<span>б) 18200 – (4570 + 1635) = 18200 – 6205 = 11995 (чел.)</span>\n<span>    <b>Ответ:</b> 11995 человек живёт в третьем посёлке.</span></p>', '', '', TRUE, '[{"letter":"а","condition":"Расстояние от дома до школы 920 м, а от дома до стадиона – 1400 м. На сколько метров расстояние от дома до школы меньше, чем расстояние от дома до стадиона?","solution":"1400 – 920 = 480 (м)      Ответ: на 480 метров расстояние от дома до школы меньше, чем расстояние от дома до стадиона."},{"letter":"б","condition":"В трёх посёлках 18200 жителей. В первом посёлке живёт 4570 человек, а во втором – на 1635 человек больше, чем в первом. Сколько человек живёт в третьем посёлке?","solution":"18200 – (4570 + 1635) = 18200 – 6205 = 11995 (чел.)      Ответ: 11995 человек живёт в третьем посёлке."}]'::jsonb, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-90/')
    RETURNING id INTO v_task_id;

