    VALUES (v_textbook_id, 90, '10', 3, 'Найди значения х . Расположи их в порядке убывания – и ты узнаешь название одной из самых красивых птиц наших лесов.', '</p>\n\n<p class="text">Найди значения <b>х</b>. Расположи их в порядке убывания – и ты узнаешь название одной из самых красивых птиц наших лесов.</p>\n\n<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica90-nomer10.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 90, номер 10, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 90, номер 10, год 2022."/>\n</div>', '', '<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica90-nomer10-1.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 90, номер 10, год 2022, ответ." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 90, номер 10, год 2022, ответ."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-90/')
    RETURNING id INTO v_task_id;

