    VALUES (v_textbook_id, 90, '12', 5, 'Старинная задача Торговка, сидя на рынке, соображала: «Если бы к моим яблокам прибавить половину их да ещё десяток, то у меня была бы целая сотня!» Сколько яблок у неё было?', '</p>\n\n<p class="text"><span><b>Старинная задача</b></span>\n<span>Торговка, сидя на рынке, соображала: «Если бы к моим яблокам прибавить половину их да ещё десяток, то у меня была бы целая сотня!» Сколько яблок у неё было?</span></p>', '100 = 10 + 2х 2х = 90 х = 45 (яб.) Ответ: 45 яблок было у торговки.', '<p><span>100 = 10 + 2х</span>\n<span>2х = 90</span>\n<span>х = 45 (яб.)</span>\n<span><b>Ответ:</b> 45 яблок было у торговки.</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-90/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '5956d18fd380a01697935c89bb7901e646f8d3e9348f5e96e444e74a486692b7', NULL, NULL, 'старинная задача торговка, сидя на рынке, соображала:"если бы к моим яблокам прибавить половину их да ещё десяток, то у меня была бы целая сотня!" сколько яблок у неё было');

    VALUES (v_textbook_id, 91, '1', 0, 'а) Допиши в тетради равенства, выражающие свойства умножения. Назови эти свойства и объясни их смысл. а · b = ...      (а · b) · c = ... б) Объясни, как выполнено умножение круглых чисел: 6000 · 300 = (6 · 1000) · (3 · 100) = (6 · 3) · (1000 · 100) = 18 · 100000 = 1800000 Как это можно сделать быстрее? Сделай вывод.', '</p>\n\n<p class="text">а) Допиши в тетради равенства, выражающие свойства умножения. Назови эти свойства и объясни их смысл.</p>\n\n<p class="description-text">\nа · b = ...      (а · b) · c = ...</p>\n\n<p class="text">б) Объясни, как выполнено умножение круглых чисел:</p>\n\n<p class="description-text">\n6000 · 300 = (6 · 1000) · (3 · 100) = (6 · 3) · (1000 · 100) = 18 · 100000 = 1800000</p>\n\n<p class="text">Как это можно сделать быстрее? Сделай вывод.</p>', 'а) а · b = b · а – переместительное свойство умножения. Произведение не меняется от переменны мест множителей. (а · b) · c = а · (b · с) – сочетательное свойство умножения. Произведение на скобку не меняется при перемене мест множителей.', '<p><span>а) а · b = b · а – переместительное свойство умножения. Произведение не меняется от переменны мест множителей.</span>\n<span>(а · b) · c = а · (b · с) – сочетательное свойство умножения. Произведение на скобку не меняется при перемене мест множителей.</span></p>', 'Умножение круглых чисел Круглые числа можно умножить, не глядя на нули, а затем приписать справа столько нулей, сколько в обоих множителях вместе.', '<div class="recomended-block">\n<span class="title">Умножение круглых чисел</span>\n<p>Круглые числа можно умножить, не глядя на нули, а затем приписать справа столько нулей, сколько в обоих множителях вместе.</p>\n\n<div class="img-wrapper-460">\n<img width="310" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica91-recomended-block.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 91, рекомендательный блок, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 91, рекомендательный блок, год 2022."/>\n</div>', TRUE, '[{"letter":"а","condition":"Допиши в тетради равенства, выражающие свойства умножения. Назови эти свойства и объясни их смысл. а · b = ...      (а · b) · c = ...","solution":"а · b = b · а – переместительное свойство умножения. Произведение не меняется от переменны мест множителей. (а · b) · c = а · (b · с) – сочетательное свойство умножения. Произведение на скобку не меняется при перемене мест множителей."},{"letter":"б","condition":"Объясни, как выполнено умножение круглых чисел: 6000 · 300 = (6 · 1000) · (3 · 100) = (6 · 3) · (1000 · 100) = 18 · 100000 = 1800000 Как это можно сделать быстрее? Сделай вывод.","solution":""}]'::jsonb, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-91/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '7050a48df709a6d3ab1d1fc9998b4407bbc24d469e97621675a88cfe382fe14e', '3,6,18,100,300,1000,6000,100000,1800000', NULL, 'а) допиши в тетради равенства, выражающие свойства умножения. назови эти свойства и объясни их смысл. а*b=...      (а*b)*c=... б) объясни, как выполнено умножение круглых чисел:6000*300=(6*1000)*(3*100)=(6*3)*(1000*100)=18*100000=1800000 как это можно сделать быстрее? сделай вывод');

    VALUES (v_textbook_id, 91, '2', 1, 'Найди значения произведений: а) 30 · 50      в) 8 · 300      д) 800 · 8       ж) 60 · 400 б) 70 · 90      г) 600 · 5      е) 3 · 7000      з) 200 · 900', '</p>\n\n<p class="text">Найди значения произведений:</p>\n\n<p class="description-text">\n<span>а) 30 · 50      в) 8 · 300      д) 800 · 8       ж) 60 · 400</span>\n<span>б) 70 · 90      г) 600 · 5      е) 3 · 7000      з) 200 · 900</span></p>', 'а) 30 · 50 = 1500 б) 70 · 90 = 6300 в) 8 · 300 = 2400 г) 600 · 5 = 3000 д) 800 · 8 = 6400 е) 3 · 7000 = 21000 ж) 60 · 400 = 24000 з) 200 · 900 = 180000', '<p><span>а) 30 · 50 = 1500</span>\n<span>б) 70 · 90 = 6300</span>\n<span>в) 8 · 300 = 2400</span>\n<span>г) 600 · 5 = 3000</span>\n<span>д) 800 · 8 = 6400</span>\n<span>е) 3 · 7000 = 21000</span>\n<span>ж) 60 · 400 = 24000</span>\n<span>з) 200 · 900 = 180000</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-91/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '184a296b38145fbbf7504192c20f7ea09d911b85f7dd7cc62d7aa301247867ef', '3,5,8,30,50,60,70,90,200,300', '["найди"]'::jsonb, 'найди значения произведений:а) 30*50      в) 8*300      д) 800*8       ж) 60*400 б) 70*90      г) 600*5      е) 3*7000      з) 200*900');

    VALUES (v_textbook_id, 91, '3', 2, 'Выполни действия: а) 90 · 400      в) 3000 · 20      д) 160 · 500       ж) 80000 · 40 б) 7 · 8000      г) 600 · 900      е) 2000 · 350      з) 15 · 600000', '</p>\n\n<p class="text">Выполни действия:</p>\n\n<p class="description-text">\n<span>а) 90 · 400      в) 3000 · 20      д) 160 · 500       ж) 80000 · 40</span>\n<span>б) 7 · 8000      г) 600 · 900      е) 2000 · 350      з) 15 · 600000</span></p>', 'а) 90 · 400 = 36000 б) 7 · 8000 = 56000 в) 3000 · 20 = 60000 г) 600 · 900 = 540000 д) 160 · 500 = 80000 е) 2000 · 350 = 700000 ж) 80000 · 40 = 3200000 з) 15 · 600000 = 9000000', '<p><span>а) 90 · 400 = 36000</span>\n<span>б) 7 · 8000 = 56000</span>\n<span>в) 3000 · 20 = 60000</span>\n<span>г) 600 · 900 = 540000</span>\n<span>д) 160 · 500 = 80000</span>\n<span>е) 2000 · 350 = 700000</span>\n<span>ж) 80000 · 40 = 3200000</span>\n<span>з) 15 · 600000 = 9000000</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-91/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '0416bafe903f39421828cbd3fb0b837654be7cd287909279bbb4acc0897f394b', '7,15,20,40,90,160,350,400,500,600', NULL, 'выполни действия:а) 90*400      в) 3000*20      д) 160*500       ж) 80000*40 б) 7*8000      г) 600*900      е) 2000*350      з) 15*600000');

    VALUES (v_textbook_id, 91, '4', 3, 'Объясни, как выполнено умножение круглых чисел в столбик: Выполни умножение в столбик: а) 940 · 400      б) 7600 · 70      в) 470 · 5000      г) 38000 · 800', '</p>\n\n<p class="text">Объясни, как выполнено умножение круглых чисел в столбик:</p>\n\n<div class="img-wrapper-460">\n<img width="390" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica91-nomer4.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 91, номер 4, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 91, номер 4, год 2022."/>\n</div>\n\n<p class="text">Выполни умножение в столбик:</p>\n\n<p class="description-text">\nа) 940 · 400      б) 7600 · 70      в) 470 · 5000      г) 38000 · 800</p>', 'При умножении круглых чисел в столбик числа записывают и умножают, не глядя на нули. Затем к результату приписывают справа столько нулей, сколько в обоих множителях вместе. а) 940 · 400 = 376000', '<p><span>При умножении круглых чисел в столбик числа записывают и умножают, не глядя на нули. Затем к результату приписывают справа столько нулей, сколько в обоих множителях вместе.</span>\n<br/>\n<span>а) 940 · 400 = 376000</span></p>\n\n<div class="img-wrapper-460">\n<img width="150" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica91-nomer4-1.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 91, номер 4, год 2022, ответ." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 91, номер 4, год 2022, ответ."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-91/')
