    VALUES (v_textbook_id, 91, '6', 5, 'Запиши и прочти: а) наименьшее трёхзначное число; б) наибольшее четырёхзначное число; в) наименьшее пятизначное число; г) наибольшее шестизначное число. Какие числа им предшествуют? Какие числа за ними следуют?', '</p>\n\n<p class="text">Запиши и прочти:</p>\n\n<p class="description-text">\nа) наименьшее трёхзначное число; б) наибольшее четырёхзначное число; в) наименьшее пятизначное число; г) наибольшее шестизначное число.</p>\n\n<p class="text">Какие числа им предшествуют? Какие числа за ними следуют?</p>', 'а) 100 – сто, 99, 101 б) 9999 – девять тысяч девятьсот девяносто девять, 9998, 10000 в) 10000 – десять тысяч, 9999, 10001 г) 999999 – девятьсот девяносто девять тысяч девятьсот девяносто девять, 999998, 1000000', '<p><span>а) 100 – сто, 99, 101</span>\n<span>б) 9999 – девять тысяч девятьсот девяносто девять, 9998, 10000</span>\n<span>в) 10000 – десять тысяч, 9999, 10001</span>\n<span>г) 999999 – девятьсот девяносто девять тысяч девятьсот девяносто девять, 999998, 1000000</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-91/')
    RETURNING id INTO v_task_id;

