    VALUES (v_textbook_id, 92, '7', 0, 'Выполни действия: а) 21000 – 15849          д) 52 : 4           и) 50 : 6 б) 86010 – 4356            е) 520 : 4         к) 34 : 8 в) 873284 + 36970      ж) 520 : 40       л) 59 : 7 г) 615972 – 244018      з) 52 : 13        м) 31 : 9', '</p>\n\n<p class="text">Выполни действия:</p>\n\n<p class="description-text">\n<span>а) 21000 – 15849          д) 52 : 4           и) 50 : 6</span>\n<span>б) 86010 – 4356            е) 520 : 4         к) 34 : 8</span>\n<span>в) 873284 + 36970      ж) 520 : 40       л) 59 : 7</span>\n<span>г) 615972 – 244018      з) 52 : 13        м) 31 : 9</span></p>', 'а) 21000 – 15849 = 5151', '<p>а) 21000 – 15849 = 5151</p>\n\n<div class="img-wrapper-460">\n<img width="150" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica92-nomer7.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 92, номер 7, год 2022, ответ." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 92, номер 7, год 2022, ответ."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-92/')
