    VALUES (v_textbook_id, 92, '8', 1, 'БЛИЦтурнир а) Турист прошёл за 3 дня а км, причём в первый день он прошёл b км, а во второй день – с км. Сколько километров прошёл турист в третий день? б) Лена нашла m грибов, а Коля – n грибов. Из них k грибов оказались несъедобными. Сколько съедобных грибов нашли Лена и Коля? в) В автобусе ехали d пассажиров. На остановке х пассажиров вышли, а у пассажиров вошли. Сколько пассажиров стало в автобусе?', '</p>\n\n<p class="text"><span><b>БЛИЦтурнир</b></span>\n<span>а) Турист прошёл за 3 дня <b>а</b> км, причём в первый день он прошёл <b>b</b> км, а во второй день – <b>с</b> км. Сколько километров прошёл турист в третий день?</span>\n<span>б) Лена нашла <b>m</b> грибов, а Коля – <b>n</b> грибов. Из них <b>k</b> грибов оказались несъедобными. Сколько съедобных грибов нашли Лена и Коля?</span>\n<span>в) В автобусе ехали <b>d</b> пассажиров. На остановке <b>х</b> пассажиров вышли, а <b>у</b> пассажиров вошли. Сколько пассажиров стало в автобусе?</span></p>', 'а) а – (b + с)      Ответ: а – (b + с) километров прошёл турист в третий день. б) (m + n) – k      Ответ: (m + n) – k съедобных грибов нашли Лена и Коля. в) d – х + у      Ответ: d – х + у пассажиров стало в автобусе.', '<p><span>а) а – (b + с)</span>\n<span>    <b>Ответ:</b> а – (b + с) километров прошёл турист в третий день.</span>\n<span>б) (m + n) – k</span>\n<span>    <b>Ответ:</b> (m + n) – k съедобных грибов нашли Лена и Коля.</span>\n<span>в) d – х + у</span>\n<span>    <b>Ответ:</b> d – х + у пассажиров стало в автобусе.</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-92/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, 'ea3c3fb5e331f236fec3d23e9adbd530f650c95b587455667a1812e719535848', '3', NULL, 'блицтурнир а) турист прошёл за 3 дня а км, причём в первый день он прошёл b км, а во второй день-с км. сколько километров прошёл турист в третий день? б) лена нашла m грибов, а коля-n грибов. из них k грибов оказались несъедобными. сколько съедобных грибов нашли лена и коля? в) в автобусе ехали d пассажиров. на остановке х пассажиров вышли, а у пассажиров вошли. сколько пассажиров стало в автобусе');

    VALUES (v_textbook_id, 92, '9', 2, 'Найди значения выражений. Проверь с помощью калькулятора. а) 14006 – (20300 – 8012)      б) 259600 – (967 + 53878) – 14695', '</p>\n\n<p class="text">Найди значения выражений. Проверь с помощью калькулятора.</p>\n\n<p class="description-text">\nа) 14006 – (20300 – 8012)      б) 259600 – (967 + 53878) – 14695</p>', 'а) 14006 – (20300 – 8012) = 14006 – 12288 = 1718', '<p>а) 14006 – (20300 – 8012)  = 14006 – 12288 = 1718</p>\n\n<div class="img-wrapper-460">\n<img width="300" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica92-nomer9.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 92, номер 9, год 2022, ответ." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 92, номер 9, год 2022, ответ."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-92/')
    RETURNING id INTO v_task_id;

