    VALUES (v_task_id, v_textbook_id, 3, 'd9cc19d8e3b9d144d861ec0f7700d51708a9a1350c6586974750967df80e369f', '967,8012,14006,14695,20300,53878,259600', '["найди"]'::jsonb, 'найди значения выражений. проверь с помощью калькулятора. а) 14006-(20300-8012)      б) 259600-(967+53878)-14695');

    VALUES (v_textbook_id, 92, '10', 3, 'Реши уравнения с комментированием и сделай проверку: х : 40 = 600      720000 : х = 900      х · 100 = 3500000', '</p>\n\n<p class="text">Реши уравнения с комментированием и сделай проверку:</p>\n\n<p class="description-text">\nх : 40 = 600      720000 : х = 900      х · 100 = 3500000</p>', 'х : 40 = 600 Чтобы найти делимое х надо умножить частное на делитель. х = 600 · 40 х = 24000 Проверка: 24000 : 40 = 600 720000 : х = 900 Чтобы найти делитель х надо делимое разделить на частное. х = 720000 : 900 х = 800 Проверка: 720000 : 800 = 900 х · 100 = 3500000 Чтобы найти неизвестный множитель х надо произведение разделить на известный множитель. х = 3500000 : 100 х = 35000 Проверка: 35000 · 100 = 3500000', '<p><span>х : 40 = 600</span>\n<span>Чтобы найти делимое х надо умножить частное на делитель.</span>\n<span>х = 600 · 40</span>\n<span>х = 24000</span>\n<span><b>Проверка:</b> 24000 : 40 = 600</span>\n<br/>\n<span>720000 : х = 900</span>  \n<span>Чтобы найти делитель х надо делимое разделить на частное.</span>\n<span>х = 720000 : 900</span>\n<span>х = 800</span>\n<span><b>Проверка:</b> 720000 : 800 = 900</span>\n<br/>\n<span>х · 100 = 3500000</span>\n<span>Чтобы найти неизвестный множитель х надо произведение разделить на известный множитель.</span>\n<span>х = 3500000 : 100</span>\n<span>х = 35000</span>\n<span><b>Проверка:</b> 35000 · 100 = 3500000</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-92/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '619cc2cb0aba5708cfe41c1368993f992138d3471f716d7a826ee62174e15e16', '40,100,600,900,720000,3500000', '["реши"]'::jsonb, 'реши уравнения с комментированием и сделай проверку:х:40=600      720000:х=900      х*100=3500000');

    VALUES (v_textbook_id, 92, '11', 4, 'Задачи – шутки а) Сколько концов у 4 палок, у 5 палок, у 5 с половиной палок? б) Раздели на бумаге число двенадцать на две равные части так, чтобы одна из частей была семь. в) Как разделить 188 на две равные части, чтобы в каждой из них получилось 100?', '</p>\n\n<p class="text"><span><b>Задачи – шутки</b></span>\n<span>а) Сколько концов у 4 палок, у 5 палок, у 5 с половиной палок?</span>\n<span>б) Раздели на бумаге число двенадцать на две равные части так, чтобы одна из частей была семь.</span>\n<span>в) Как разделить 188 на две равные части, чтобы в каждой из них получилось 100?</span></p>', 'а) у каждой палки два конца, поэтому 2 · 4 = 8 концов у 4 палок, 2 · 5 = 10 концов у 5 палок, 2 · 6 = 12 концов у 5 с половиной палок. б) ХII Разделили на бумаге число двенадцать на две равные части так, что одна из частей получилась VII семь. в) 188 разделили 188 на две равные части так, что в каждой из них получилось 100.', '<p><span>а) у каждой палки два конца, поэтому 2 · 4 = 8 концов у 4 палок, 2 · 5 = 10 концов у 5 палок, 2 · 6 = 12 концов у 5 с половиной палок.</span>\n<span>б) ХII Разделили на бумаге число двенадцать на две равные части так, что одна из частей получилась VII семь.</span>\n<span>в) 188 разделили 188 на две равные части так, что в каждой из них получилось 100.</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-92/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '6b8bb0c099ee799ca14ba1d33c40602c6bca485bfd14d3fb3e359819c1c5c5d7', '4,5,100,188', '["раздели","раз"]'::jsonb, 'задачи-шутки а) сколько концов у 4 палок, у 5 палок, у 5 с половиной палок? б) раздели на бумаге число двенадцать на две равные части так, чтобы одна из частей была семь. в) как разделить 188 на две равные части, чтобы в каждой из них получилось 100');

