    VALUES (v_textbook_id, 93, '3', 2, 'Автомобилист проехал от Москвы до Самары 1138 км, а от Самары до Томска – 2894 км. Чему равно расстояние от Москвы до Томска через Самару? На сколько километров расстояние от Москвы до Самары меньше, чем расстояние от Самары до Томска?', '</p>\n\n<p class="text">Автомобилист проехал от Москвы до Самары 1138 км, а от Самары до Томска – 2894 км. Чему равно расстояние от Москвы до Томска через Самару? На сколько километров расстояние от Москвы до Самары меньше, чем расстояние от Самары до Томска?</p>\n\n<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica93-nomer3.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 93, номер 3, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 93, номер 3, год 2022."/>\n</div>', '1138 + 2894 = 4032 (км) 2894 – 1138 = 1756 (км) Ответ: 4032 километра от Москвы до Томска через Самару. На 1756 километров расстояние от Москвы до Самары меньше, чем расстояние от Самары до Томска.', '<p><span>1138 + 2894 = 4032 (км)</span>\n<span>2894 – 1138 = 1756 (км)</span>\n<span><b>Ответ:</b> 4032 километра от Москвы до Томска через Самару. На 1756  километров расстояние от Москвы до Самары меньше, чем расстояние от Самары до Томска.</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-93/')
    RETURNING id INTO v_task_id;

