    VALUES (v_textbook_id, 93, '6', 5, 'БЛИЦтурнир а) В банку входит k литров воды, а в ведро – в 4 раза больше. Сколько литров воды входит в ведро? б) Мама купила себе на платье b м ткани, а на платье дочке – в 3 раза меньше. На сколько метров мамин отрез ткани длиннее, чем у дочки? в) Блузка стоит d р., а свитер на 240 р. дороже. Во сколько раз блузка дешевле, чем свитер?', '</p>\n\n<p class="text"><span><b>БЛИЦтурнир</b></span>\n<span>а) В банку входит <b>k</b> литров воды, а в ведро – в 4 раза больше. Сколько литров воды входит в ведро?</span>\n<span>б) Мама купила себе на платье <b>b</b> м ткани, а на платье дочке – в 3 раза меньше. На сколько метров мамин отрез ткани длиннее, чем у дочки?</span>\n<span>в) Блузка стоит <b>d</b> р., а свитер на 240 р. дороже. Во сколько раз блузка дешевле, чем свитер?</span></p>', 'а) 4k      Ответ: 4k литров воды входит в ведро. б) b – b : 3      Ответ: на b – b : 3 метров мамин отрез ткани длиннее, чем у дочки. в) (d + 240) : d      Ответ: в (d + 240) : d раз блузка дешевле, чем свитер.', '<p><span>а) 4k</span>\n<span>    <b>Ответ:</b> 4k литров воды входит в ведро.</span>\n<span>б) b – b : 3</span>\n<span>    <b>Ответ:</b> на b – b : 3 метров мамин отрез ткани длиннее, чем у дочки.</span>\n<span>в) (d + 240) : d</span>\n<span>    <b>Ответ:</b> в (d + 240) :  d раз блузка дешевле, чем свитер.</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-93/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '51b4a7d64a13870fc80389d279659b6965fd0aa629b98ce91022285187218b3b', '3,4,240', '["больше","меньше","раз","раза"]'::jsonb, 'блицтурнир а) в банку входит k литров воды, а в ведро-в 4 раза больше. сколько литров воды входит в ведро? б) мама купила себе на платье b м ткани, а на платье дочке-в 3 раза меньше. на сколько метров мамин отрез ткани длиннее, чем у дочки? в) блузка стоит d р., а свитер на 240 р. дороже. во сколько раз блузка дешевле, чем свитер');

