    VALUES (v_textbook_id, 94, '8', 0, 'Выполни действия: а) 2349 + 34758 б) 40210 – 5643 в) 800500 – 64916 г) 3219686 + 1780314 д) 324 · 100 е) 1000 · 85 ж) 970 · 10000 з) 100 · 530000 и) 2600 : 100 к) 38000 : 10 л) 450000 : 10 м) 500000 : 100', '</p>\n\n<p class="text">Выполни действия:</p>\n\n<p class="description-text">\n<span>а) 2349 + 34758</span>\n<span>б) 40210 – 5643</span>\n<span>в) 800500 – 64916</span>\n<span>г) 3219686 + 1780314</span>\n<span>д) 324 · 100</span>\n<span>е) 1000 · 85</span>\n<span>ж) 970 · 10000</span>\n<span>з) 100 · 530000</span>\n<span>и) 2600 : 100</span>\n<span>к) 38000 : 10</span>\n<span>л) 450000 : 10</span>\n<span>м) 500000 : 100</span></p>', 'а) 2349 + 34758 = 37107 б) 40210 – 5643 = 45853 в) 800500 – 64916 = 865416 г) 3219686 + 1780314 = 5000000 д) 324 · 100 = 32400 е) 1000 · 85 = 85000 ж) 970 · 10000 = 9700000 з) 100 · 530000 = 53000000 и) 2600 : 100 = 26 к) 38000 : 10 = 3800 л) 450000 : 10 = 45000 м) 500000 : 100 = 5000', '<p><span>а) 2349 + 34758 = 37107</span>\n<span>б) 40210 – 5643 = 45853</span>\n<span>в) 800500 – 64916 = 865416</span>\n<span>г) 3219686 + 1780314 = 5000000</span>\n<span>д) 324 · 100 = 32400</span>\n<span>е) 1000 · 85 = 85000</span>\n<span>ж) 970 · 10000 = 9700000</span>\n<span>з) 100 · 530000 = 53000000</span>\n<span>и) 2600 : 100 = 26</span>\n<span>к) 38000 : 10 = 3800</span>\n<span>л) 450000 : 10 = 45000</span>\n<span>м) 500000 : 100 = 5000</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-94/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, 'f7b6def3ee1f89ff81c33be276861b1f51ff21c6a21dd88ce7b550796493cb72', '10,85,100,324,970,1000,2349,2600,5643,10000', NULL, 'выполни действия:а) 2349+34758 б) 40210-5643 в) 800500-64916 г) 3219686+1780314 д) 324*100 е) 1000*85 ж) 970*10000 з) 100*530000 и) 2600:100 к) 38000:10 л) 450000:10 м) 500000:100');

    VALUES (v_textbook_id, 94, '9', 1, 'а) Площадь прямоугольника равна 140 см 2 , а его длина – 20 см. Чему равен периметр этого прямоугольника? б) Измерь в метрах длину и ширину классной комнаты. Найди площадь её пола, потолка и общую площадь стен.', '</p>\n\n<p class="text"><span>а) Площадь прямоугольника равна 140 см<sup>2</sup>, а его длина – 20 см. Чему равен периметр этого прямоугольника?</span>\n<span>б) Измерь в метрах длину и ширину классной комнаты. Найди площадь её пола, потолка и общую площадь стен.</span></p>', 'а) 140 = х · 20     х = 140 : 20     х = 7 (см)     Р = 2(7 + 20)     Р = 54 (см)      Ответ: 54 сантиметрам равен периметр прямоугольника. б) 4 м – ширина, 4 м – длина     4 · 4 = 16 (м 2 )     16 · 4 = 64 (м 2 )      Ответ: 16м 2 площадь её пола, потолка и 64 м 2 общая площадь стен.', '<p><span>а) 140 = х · 20</span>\n<span>    х = 140 : 20</span>\n<span>    х = 7 (см)</span>\n<span>    Р = 2(7 + 20)</span>\n<span>    Р = 54 (см)</span>\n<span>    <b>Ответ:</b> 54 сантиметрам равен периметр прямоугольника.</span>\n<span>б) 4 м – ширина, 4 м – длина</span>\n<span>    4 · 4 = 16 (м<sup>2</sup>)</span>\n<span>    16 · 4 = 64 (м<sup>2</sup>)</span>\n<span>    <b>Ответ:</b> 16м<sup>2</sup> площадь её пола, потолка и 64 м<sup>2</sup> общая площадь стен.</span></p>', '', '', TRUE, '[{"letter":"а","condition":"Площадь прямоугольника равна 140 см 2 , а его длина – 20 см. Чему равен периметр этого прямоугольника?","solution":"140 = х · 20     х = 140 : 20     х = 7 (см)     Р = 2(7 + 20)     Р = 54 (см)      Ответ: 54 сантиметрам равен периметр прямоугольника."},{"letter":"б","condition":"Измерь в метрах длину и ширину классной комнаты. Найди площадь её пола, потолка и общую площадь стен.","solution":"4 м – ширина, 4 м – длина     4 · 4 = 16 (м 2 )     16 · 4 = 64 (м 2 )      Ответ: 16м 2 площадь её пола, потолка и 64 м 2 общая площадь стен."}]'::jsonb, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-94/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, 'aa8284685d0249c094dcf0d1882d5244e5cd33a131d22064baa1133098f5ea26', '2,20,140', '["найди","периметр","площадь"]'::jsonb, 'а) площадь прямоугольника равна 140 см 2 , а его длина-20 см. чему равен периметр этого прямоугольника? б) измерь в метрах длину и ширину классной комнаты. найди площадь её пола, потолка и общую площадь стен');

    VALUES (v_textbook_id, 94, '10', 2, 'а) Пользуясь числовым лучом, составь множество двузначных чисел, кратных 19. б) Выполни деление с остатком: 25 : 19      40 : 19      54 : 19      77 : 19      91 : 19 в) Выучи двузначные числа, кратные 19. Проверь себя, работая в паре.', '</p>\n\n<p class="text">а) Пользуясь числовым лучом, составь множество двузначных чисел, кратных 19.</p>\n\n<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica94-nomer10.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 94, номер 10, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 94, номер 10, год 2022."/>\n</div>\n\n<p class="text">б) Выполни деление с остатком:</p>\n\n<p class="description-text">\n25 : 19      40 : 19      54 : 19      77 : 19      91 : 19</p>\n\n<p class="text">в) Выучи двузначные числа, кратные 19. Проверь себя, работая в паре.</p>', 'а) {19; 38; 57; 76; 95; 114; 133; 152; 171; 190} б) 25 : 19 = 1 + 6      40 : 19 = 2 + 2      54 : 19 = 2 + 16      77 : 19 = 4 + 1      91 : 19 = 4 + 15 в) 19, 38, 57, 76, 95, 114, 133, 152, 171, 190.', '<p><span>а) {19; 38; 57; 76; 95; 114; 133; 152; 171; 190}</span>\n<span>б) 25 : 19 = 1 + 6      40 : 19 = 2 + 2      54 : 19 = 2 + 16      77 : 19 = 4 + 1      91 : 19 = 4 + 15</span>\n<span>в) 19, 38, 57, 76, 95, 114, 133, 152, 171, 190.</span></p>', '', '', TRUE, '[{"letter":"а","condition":"Пользуясь числовым лучом, составь множество двузначных чисел, кратных 19.","solution":"{19; 38; 57; 76; 95; 114; 133; 152; 171; 190}"},{"letter":"б","condition":"Выполни деление с остатком: 25 : 19      40 : 19      54 : 19      77 : 19      91 : 19","solution":"25 : 19 = 1 + 6      40 : 19 = 2 + 2      54 : 19 = 2 + 16      77 : 19 = 4 + 1      91 : 19 = 4 + 15"},{"letter":"в","condition":"Выучи двузначные числа, кратные 19. Проверь себя, работая в паре.","solution":"19, 38, 57, 76, 95, 114, 133, 152, 171, 190."}]'::jsonb, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-94/')
    RETURNING id INTO v_task_id;

