    VALUES (v_textbook_id, 94, '11', 3, 'Игра «Математические горки» Сосчитай суммы. Какая из этих сумм больше?', '</p>\n\n<p class="text"><span><b>Игра «Математические горки»</b></span>\n<span>Сосчитай суммы. Какая из этих сумм больше?</span></p>\n\n<div class="img-wrapper-460">\n<img width="350" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica94-nomer11.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 94, номер 11, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 94, номер 11, год 2022."/>\n</div>', '', '<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica94-nomer11-1.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 94, номер 11, год 2022, ответ." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 94, номер 11, год 2022, ответ."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-94/')
