    VALUES (v_textbook_id, 94, '12', 4, 'Расположи 2 элемента в множествах А, В и С так, чтобы каждое из них содержало соответственно: а) по 2 элемента; б) 2, 2 и 1 элемент; в) 2, 1 и 1 элемент; г) 2, 1 и 0 элементов; д) 2, 2 и 0 элементов; е) по 1 элементу.', '</p>\n\n<p class="text">Расположи 2 элемента в множествах А, В и С так, чтобы каждое из них содержало соответственно:</p>\n\n<p class="description-text">\n<span>а) по 2 элемента;</span>\n<span>б) 2, 2 и 1 элемент;</span>\n<span>в) 2, 1 и 1 элемент;</span>\n<span>г) 2, 1 и 0 элементов;</span>\n<span>д) 2, 2 и 0 элементов;</span>\n<span>е) по 1 элементу.</span></p>\n\n<div class="img-wrapper-460">\n<img width="200" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica94-nomer12.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 94, номер 12, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 94, номер 12, год 2022."/>\n</div>', '', '<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica94-nomer12-1.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 94, номер 12, год 2022, ответ." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 94, номер 12, год 2022, ответ."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-94/')
