    VALUES (v_textbook_id, 95, '1', 0, 'Найди неизвестную операцию. Какие операции называют взаимно обратными?', '</p>\n\n<p class="text">Найди неизвестную операцию. Какие операции называют взаимно обратными?</p>\n\n<div class="img-wrapper-460">\n<img width="340" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica95-nomer1.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 95, номер 1, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 95, номер 1, год 2022."/>\n</div>', '4 + 5 = 9                  6 · 2 = 12 9 – 5 = 4                  12 : 2 = 6 Вычитание – это арифметическое действие, обратное к сложению, деление – действие, обратное к умножению.', '<p><span>4 + 5 = 9                  6 · 2 = 12</span>\n<span>9 – 5 = 4                  12 : 2 = 6</span>\n<span>Вычитание – это арифметическое действие, обратное к сложению, деление – действие, обратное к умножению.</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-95/')
    RETURNING id INTO v_task_id;

