    VALUES (v_task_id, v_textbook_id, 3, '8e5c417d45e5d39d14060e2b41b182e4746b7fafcdc3cf1d2e52239573f62dcb', NULL, '["найди"]'::jsonb, 'найди неизвестную операцию. какие операции называют взаимно обратными');

    VALUES (v_textbook_id, 95, '2', 1, 'а) Вспомни правило деления на 10 и на 100. Вычисли: 360 : 10      800 : 100 б) Используя схемы, выполни деление на 1000, на 10000: Что ты замечаешь? Сделай вывод.', '</p>\n\n<p class="text">а) Вспомни правило деления на 10 и на 100. Вычисли:</p>\n\n<p class="description-text">\n360 : 10      800 : 100</p>\n\n<p class="text">б) Используя схемы, выполни деление на 1000, на 10000:</p>\n\n<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica95-nomer2.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 95, номер 2, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 95, номер 2, год 2022."/>\n</div>\n\n<p class="text">Что ты замечаешь? Сделай вывод.</p>', 'а) 360 : 10 = 36               800 : 100 = 8 б) 28000 : 1000 = 28      600000 : 10000 = 60 При делении числа на 10, 100, 1000 и т. д. можно отбросить справа соответственно 1 нуль, 2 нуля, 3 нуля и т. д.', '<p><span>а) 360 : 10 = 36               800 : 100 = 8</span>\n<span>б) 28000 : 1000 = 28      600000 : 10000 = 60</span>\n<span>При делении числа на 10, 100, 1000 и т. д. можно отбросить справа соответственно 1 нуль, 2 нуля, 3 нуля и т. д.</span></p>', 'Деление числа на 10, 100, 1000... При делении числа на 10, 100, 1000 и т. д. можно отбросить справа соответственно 1 нуль, 2 нуля, 3 нуля и т. д.     0 : 10 =         00 : 100 =         000 : 1000 =     И т. д.', '<div class="recomended-block">\n<span class="title">Деление числа на 10, 100, 1000...</span>\n<p>При делении числа на 10, 100, 1000 и т. д. можно отбросить справа соответственно 1 нуль, 2 нуля, 3 нуля и т. д.<br/>\n<br/>\n<span class="okon">   </span>0 : 10 = <span class="okon">   </span><br/>\n<span class="okon">   </span>00 : 100 = <span class="okon">   </span><br/>\n<span class="okon">   </span>000 : 1000 = <span class="okon">   </span> И т. д.</p>\n</div>', TRUE, '[{"letter":"а","condition":"Вспомни правило деления на 10 и на 100. Вычисли: 360 : 10      800 : 100","solution":"360 : 10 = 36               800 : 100 = 8"},{"letter":"б","condition":"Используя схемы, выполни деление на 1000, на 10000: Что ты замечаешь? Сделай вывод.","solution":"28000 : 1000 = 28      600000 : 10000 = 60 При делении числа на 10, 100, 1000 и т. д. можно отбросить справа соответственно 1 нуль, 2 нуля, 3 нуля и т. д."}]'::jsonb, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-95/')
    RETURNING id INTO v_task_id;

