    VALUES (v_textbook_id, 95, '3', 2, 'Выполни действия: а) 5600 : 10     8400 : 100     42000 : 1000 б) 60000 : 10     75000 : 100     290000 : 1000 в) 170000 : 1000     9800000 : 10000     3250000 : 100', '</p>\n\n<p class="text">Выполни действия:</p>\n\n<p class="description-text">\n<span>а) 5600 : 10</span>\n<span>    8400 : 100</span>\n<span>    42000 : 1000</span>\n<br/>\n<span>б) 60000 : 10</span>\n<span>    75000 : 100</span>\n<span>    290000 : 1000</span>\n<br/>\n<span>в) 170000 : 1000</span>\n<span>    9800000 : 10000</span>\n<span>    3250000 : 100</span></p>', 'а) 5600 : 10 = 560     8400 : 100 = 84     42000 : 1000 = 42 б) 60000 : 10 = 6000     75000 : 100 = 750     290000 : 1000 = 290 в) 170000 : 1000 = 170     9800000 : 10000 = 980     3250000 : 100 = 32500', '<p><span>а) 5600 : 10 = 560</span>\n<span>    8400 : 100 = 84</span>\n<span>    42000 : 1000 = 42</span>\n<br/>\n<span>б) 60000 : 10 = 6000</span>\n<span>    75000 : 100 = 750</span>\n<span>    290000 : 1000 = 290</span>\n<br/>\n<span>в) 170000 : 1000  = 170</span>\n<span>    9800000 : 10000 = 980</span>\n<span>    3250000 : 100 = 32500</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-95/')
