    VALUES (v_textbook_id, 95, '4', 3, 'Вычисли. Составь и реши следующий пример:', '</p>\n\n<p class="text">Вычисли. Составь и реши следующий пример:</p>\n\n<div class="img-wrapper-460">\n<img width="320" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica95-nomer4.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 95, номер 4, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 95, номер 4, год 2022."/>\n</div>', '250 : 10 = 25 3000 : 100 = 30 35000 : 1000 = 35 550 : 10 = 55 4400 : 100 = 44 33000 : 1000 = 33', '<p><span>250 : 10 = 25</span>\n<span>3000 : 100 = 30</span>\n<span>35000 : 1000 = 35</span>\n<br/>\n<span>550 : 10 = 55</span>\n<span>4400 : 100 = 44</span>\n<span>33000 : 1000 = 33</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-95/')
