    VALUES (v_textbook_id, 95, '5', 4, 'Найди значения выражений. Что ты замечаешь? 9 · 90      800 · 8      70 · 700      6 · 60000 Какой пример может быть следующим? Обоснуй свой ответ.', '</p>\n\n<p class="text">Найди значения выражений. Что ты замечаешь?</p>\n\n<p class="description-text">\n9 · 90      800 · 8      70 · 700      6 · 60000</p>\n\n<p class="text">Какой пример может быть следующим? Обоснуй свой ответ.</p>', '9 · 90 = 810      800 · 8 = 6400      70 · 700 = 49000      6 · 60000 = 360000 Табличные значения с добавлением нулей по убыванию, 5 · 500000 = 2500000 – следующий пример, таким образом продолжение по убыванию в таблице умножения и прибавляя нули.', '<p><span>9 · 90 = 810      800 · 8 = 6400      70 · 700 = 49000      6 · 60000 = 360000</span>\n<span>Табличные значения с добавлением нулей по убыванию, 5 · 500000 = 2500000 – следующий пример, таким образом продолжение по убыванию в таблице умножения и прибавляя нули.</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-95/')
    RETURNING id INTO v_task_id;

