    VALUES (v_textbook_id, 96, '7', 1, 'Костя дома делал уроки 135 минут. Из них 25 минут он вспоминал, что задали, и 36 минут мечтал о мороженом. Затем он искал ручку половину того времени, что мечтал, а остальное время делал задания. Сколько времени ушло у Кости на выполнение заданий?', '</p>\n\n<p class="text">Костя дома делал уроки 135 минут. Из них 25 минут он вспоминал, что задали, и 36 минут мечтал о мороженом. Затем он искал ручку половину того времени, что мечтал, а остальное время делал задания. Сколько времени ушло у Кости на выполнение заданий?</p>\n\n<div class="img-wrapper-460">\n<img width="390" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica96-nomer7.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 96, номер 7, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 96, номер 7, год 2022."/>\n</div>', '135 – 25 – 36 – 36 : 2 = 110 – 36 – 18 = 110 – 18 = 92 (мин.) Ответ: 92 минуты ушло у Кости на выполнение заданий.', '<p><span>135 – 25 – 36 – 36 : 2 = 110 – 36 – 18 = 110 – 18 = 92 (мин.)</span>\n<span><b>Ответ:</b> 92 минуты ушло у Кости на выполнение заданий.</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-96/')
    RETURNING id INTO v_task_id;

