    VALUES (v_task_id, v_textbook_id, 3, '48ca934c612526a5628d1d00123b5edfba6c8b68a3a51cbf1aa8f7d18bdd3cb7', '25,36,135', NULL, 'костя дома делал уроки 135 минут. из них 25 минут он вспоминал, что задали, и 36 минут мечтал о мороженом. затем он искал ручку половину того времени, что мечтал, а остальное время делал задания. сколько времени ушло у кости на выполнение заданий');

    VALUES (v_textbook_id, 96, '8', 2, 'Реши уравнения и сделай проверку: х : 700 = 8000      630 : х = 9      х · 60 = 480', '</p>\n\n<p class="text">Реши уравнения и сделай проверку:</p>\n\n<p class="description-text">\nх : 700 = 8000      630 : х = 9      х · 60 = 480</p>', 'х : 700 = 8000 х = 8000 · 700 х = 5600000 Проверка: 5600000 : 700 = 8000 630 : х = 9 х = 630 : 9 х = 70 Проверка: 630 : 70 = 9 х · 60 = 480 х = 480 : 60 х = 8 Проверка: 8 · 60 = 480', '<p><span>х : 700 = 8000</span>\n<span>х = 8000 · 700</span>\n<span>х = 5600000</span>\n<span><b>Проверка:</b> 5600000 : 700 = 8000</span>\n<br/>\n<span>630 : х = 9</span>\n<span>х = 630 : 9</span>\n<span>х = 70</span>\n<span><b>Проверка:</b> 630 : 70 = 9</span>\n<br/>\n<span>х · 60 = 480</span>\n<span>х = 480 : 60</span>\n<span>х = 8</span>\n<span><b>Проверка:</b> 8 · 60 = 480</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-96/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '91841a42697bc3854945ae4d2c3dad587291f1118aace9849d7ce5da94f9fba4', '9,60,480,630,700,8000', '["реши"]'::jsonb, 'реши уравнения и сделай проверку:х:700=8000      630:х=9      х*60=480');

    VALUES (v_textbook_id, 96, '9', 3, 'Реши задачи. Что в них общего и чем они различаются? Придумай свои задачи на разные виды деления. а) В классе 28 человек. Они разбились на 4 равные группы. Сколько человек в каждой группе? б) В классе 28 человек. Они разбились на группы по 4 человека в каждой. Сколько получилось групп?', '</p>\n\n<p class="text">Реши задачи. Что в них общего и чем они различаются? Придумай свои задачи на разные виды деления.</p>\n\n<p class="description-text">\n<span>а) В классе 28 человек. Они разбились на 4 равные группы. Сколько человек в каждой группе?</span>\n<span>б) В классе 28 человек. Они разбились на группы по 4 человека в каждой. Сколько получилось групп?</span></p>', 'а) 28 : 4 = 7 (чел.)      Ответ: 7 человек в каждой группе.     В классе 48 человек. Они разбились на 6 равные группы. Сколько человек в каждой группе? б) 28 : 4 = 7 (гр.)      Ответ: 7 получилось групп.     В классе 48 человек. Они разбились на группы по 6 человека в каждой. Сколько получилось групп?     В них общего – одни и те же числа и чем они различаются – того что получили в результате.', '<p><span>а) 28 : 4 = 7 (чел.)</span>\n<span>    <b>Ответ:</b> 7 человек в каждой группе.</span>\n<span>    В классе 48 человек. Они разбились на 6 равные группы. Сколько человек в каждой группе?</span>\n<span>б) 28 : 4 = 7 (гр.)</span>\n<span>    <b>Ответ:</b> 7 получилось групп.</span>\n<span>    В классе 48 человек. Они разбились на группы по 6 человека в каждой. Сколько получилось групп?</span>\n<span>    В них общего – одни и те же числа и чем они различаются – того что получили в результате.</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-96/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, 'd36b05938beceb1062ff1b494fdc5d4283350a89136c8e168efd103bf18d4890', '4,28', '["реши","раз"]'::jsonb, 'реши задачи. что в них общего и чем они различаются? придумай свои задачи на разные виды деления. а) в классе 28 человек. они разбились на 4 равные группы. сколько человек в каждой группе? б) в классе 28 человек. они разбились на группы по 4 человека в каждой. сколько получилось групп');

    VALUES (v_textbook_id, 96, '10', 4, 'На диаграмме отмечены элементы множеств А и В. Запиши с помощью фигурных скобок, из каких элементов состоят множества А, В, А ∩ В, А ∪ В.', '</p>\n\n<p class="text">На диаграмме отмечены элементы множеств А и В. Запиши с помощью фигурных скобок, из каких элементов состоят множества А, В, А ∩ В, А ∪ В.</p>\n\n<div class="img-wrapper-460">\n<img width="290" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica96-nomer10.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 96, номер 10, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 96, номер 10, год 2022."/>\n</div>', '', '<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica96-nomer10-1.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 96, номер 10, год 2022, ответ." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 96, номер 10, год 2022, ответ."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-96/')
    RETURNING id INTO v_task_id;

