    VALUES (v_textbook_id, 96, '11', 5, 'Найди значения выражений: а) 80590 – 4825      б) 925070 + (30602 – 7384)', '</p>\n\n<p class="text">Найди значения выражений:</p>\n\n<p class="description-text">\nа) 80590 – 4825      б) 925070 + (30602 – 7384)</p>', 'а) 80590 – 4825 = 75765', '<p>а) 80590 – 4825 = 75765</p>\n\n<div class="img-wrapper-460">\n<img width="130" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica96-nomer11.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 96, номер 11, год 2022, ответ." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 96, номер 11, год 2022, ответ."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-96/')
