    VALUES (v_task_id, v_textbook_id, 3, '65cd257108bef15df6e77808cbdb9325613083fe2f205191709431ac3c742ec7', '4825,7384,30602,80590,925070', '["найди"]'::jsonb, 'найди значения выражений:а) 80590-4825      б) 925070+(30602-7384)');

    VALUES (v_textbook_id, 96, '12', 6, 'Начерти два луча, пересечением которых являются: а) точка; б) отрезок; в) луч; г) пустое множество.', '</p>\n\n<p class="text">Начерти два луча, пересечением которых являются:</p>\n\n<p class="description-text">\nа) точка; б) отрезок; в) луч; г) пустое множество.</p>', '', '<div class="img-wrapper-460">\n<img width="300" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica96-nomer12.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 96, номер 12, год 2022, ответ." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 96, номер 12, год 2022, ответ."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-96/')
