    VALUES (v_textbook_id, 96, '13', 7, 'Чайнворд 1. Многоугольник. 2. Группа цифр в записи числа. 3. Наименьшее трёхзначное число. 4. Геометрическая фигура. 5. Прямоугольник с равными сторонами. 6. Наименьшее четырёхзначное число. 7. Старая русская мера длины. 8. Знак, показывающий отсутствие единиц какого – либо разряда.', '</p>\n\n<p class="text"><span><b>Чайнворд</b></span>\n<span>1. Многоугольник.</span>\n<span>2. Группа цифр в записи числа.</span>\n<span>3. Наименьшее трёхзначное число.</span>\n<span>4. Геометрическая фигура.</span>\n<span>5. Прямоугольник с равными сторонами.</span>\n<span>6. Наименьшее четырёхзначное число.</span>\n<span>7. Старая русская мера длины.</span>\n<span>8. Знак, показывающий отсутствие единиц какого – либо разряда.</span></p>\n\n<div class="img-wrapper-460">\n<img width="200" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica96-nomer13.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 96, номер 13, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 96, номер 13, год 2022."/>\n</div>', '1. Четырехугольник 2. класс 3. сто 4. отрезок 5. квадрат 6. тысяча 7. аршин 8. ноль', '<p><span>1. Четырехугольник</span>\n<span>2. класс</span>\n<span>3. сто</span>\n<span>4. отрезок</span>\n<span>5. квадрат</span>\n<span>6. тысяча</span>\n<span>7. аршин</span>\n<span>8. ноль</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-96/')
    RETURNING id INTO v_task_id;

