    VALUES (v_task_id, v_textbook_id, 3, '6185d07be4abb02c0f4e7c472df6fe78c81662c410f484d537ebcda7e3c83400', '1,2,3,4,5,6,7,8', '["сторона","меньше","раз"]'::jsonb, 'чайнворд 1. многоугольник. 2. группа цифр в записи числа. 3. наименьшее трёхзначное число. 4. геометрическая фигура. 5. прямоугольник с равными сторонами. 6. наименьшее четырёхзначное число. 7. старая русская мера длины. 8. знак, показывающий отсутствие единиц какого-либо разряда');

    VALUES (v_textbook_id, 97, '1', 0, 'Закончи решение примеров и сравни их: а) 36 : 4 = ?     360 : 40 = 36 д. : 4 д. = ?     3600 : 400 = 36 с. : 4 с. = ?     36000 : 4000 = 36 т. : 4 т. = ? б) 54 : 9 = ?     540 : 9 = 54 д. : 9 = ?     5400 : 9 = 54 с. : 9 = ?     54000 : 9 = 54 т. : 9 = ? Сделай вывод.', '</p>\n\n<p class="text">Закончи решение примеров и сравни их:</p>\n\n<p class="description-text">\n<span>а) 36 : 4 = ?</span>\n<span>    360 : 40 = 36 д. : 4 д. = ?</span>\n<span>    3600 : 400 = 36 с. : 4 с. = ?</span>\n<span>    36000 : 4000 = 36 т. : 4 т. = ?</span>\n<br/>\n<span>б) 54 : 9 = ?</span>\n<span>    540 : 9 = 54 д. : 9 = ?</span>\n<span>    5400 : 9 = 54 с. : 9 = ?</span>\n<span>    54000 : 9 = 54 т. : 9 = ?</span></p>\n\n<p class="text">Сделай вывод.</p>', 'а) 36 : 4 = 9     360 : 40 = 36 д. : 4 д. = 9 д.     3600 : 400 = 36 с. : 4 с. = 9 с.     36000 : 4000 = 36 т. : 4 т. = 9 т. б) 54 : 9 = 6     540 : 9 = 54 д. : 9 = 6 д.     5400 : 9 = 54 с. : 9 = 6 с.     54000 : 9 = 54 т. : 9 = 6 т. Можно сделать вывод, что несмотря на единицы измерения если числа одни и те же, то и результат будет тем же числом.', '<p><span>а) 36 : 4 = 9</span>\n<span>    360 : 40 = 36 д. : 4 д. = 9 д.</span>\n<span>    3600 : 400 = 36 с. : 4 с. = 9 с.</span>\n<span>    36000 : 4000 = 36 т. : 4 т. = 9 т.</span>\n<br/>\n<span>б) 54 : 9 = 6</span>\n<span>    540 : 9 = 54 д. : 9 = 6 д.</span>\n<span>    5400 : 9 = 54 с. : 9 = 6 с.</span>\n<span>    54000 : 9 = 54 т. : 9 = 6 т.</span>\n<br/>\n<span>Можно сделать вывод, что несмотря на единицы измерения если числа одни и те же, то и результат будет тем же числом.</span></p>', 'Деление круглых чисел Правило 1 При делении круглых чисел (без остатка) можно отбросить в делимом и делителе поровну нулей.                      0ØØ :     ØØ =     0 :     Правило 2 При делении круглых чисел (без остатка) можно отбросить в делимом нули справа, а потом приписать их к частному.                      00 :     = (     :     )00', '<div class="recomended-block">\n<span class="title">Деление круглых чисел</span>\n<p><b class="black">Правило 1</b><br/>\nПри делении круглых чисел (без остатка) можно отбросить в делимом и делителе поровну нулей.<br/>\n                <span class="okon">   </span>0ØØ : <span class="okon">   </span>ØØ = <span class="okon">   </span>0 : <span class="okon">   </span><br/>\n<b class="black">Правило 2</b><br/>\nПри делении круглых чисел (без остатка) можно отбросить в делимом нули справа, а потом приписать их к частному.<br/>\n                <span class="okon">   </span>00 : <span class="okon">   </span> = (<span class="okon">   </span> : <span class="okon">   </span>)00</p>\n</div>', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-97/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '108d7b973d0a0713d8aefc04dbbdf98185e49c18b8d3e3a4c6f2aa2b1ad87d5e', '4,9,36,40,54,360,400,540,3600,4000', '["сравни"]'::jsonb, 'закончи решение примеров и сравни их:а) 36:4=?     360:40=36 д.:4 д.=?     3600:400=36 с.:4 с.=?     36000:4000=36 т.:4 т.=? б) 54:9=?     540:9=54 д.:9=?     5400:9=54 с.:9=?     54000:9=54 т.:9=? сделай вывод');

    VALUES (v_textbook_id, 97, '2', 1, 'Выбери правило и сосчитай. Сделай записи по образцу. Образец: 42 0ØØ : 7ØØ = 420 : 7 = 60 а) 240 : 60     360 : 90     5600 : 700     28 000 : 4000 б) 4500 : 5     6300 : 70     72 000 : 80     180 000 : 2000 в) 3000 : 500     1400 : 20     27 000 : 3000     480 000 : 600', '</p>\n\n<p class="text">Выбери правило и сосчитай. Сделай записи по образцу.</p>\n\n<p class="description-text">\n<b>Образец:</b> 42 0ØØ : 7ØØ = 420 : 7 = 60</p>\n\n<p class="description-text">\n<span>а)  240 : 60</span>\n<span>    360 : 90</span>\n<span>    5600 : 700</span>\n<span>    28 000 : 4000</span>\n<br/>\n<span>б) 4500 : 5</span>\n<span>    6300 : 70</span>\n<span>    72 000 : 80</span>\n<span>    180 000 : 2000</span>\n<br/>\n<span>в) 3000 : 500</span>\n<span>    1400 : 20</span>\n<span>    27 000 : 3000</span>\n<span>    480 000 : 600</span></p>', 'а) 24Ø : 6Ø = 24 : 6 = 4     36Ø : 9Ø = 36 : 9 = 4     56ØØ : 7ØØ = 56 : 7 = 8     28 ØØØ : 4ØØØ = 28 : 4 = 7 в) 30ØØ : 5ØØ = 30 : 5 = 6     140Ø : 2Ø = 14 : 2 = 7     27 ØØØ : 3ØØØ = 27 : 3 = 9     480 0ØØ : 6ØØ = 4800 : 6 = 800 б) 4500 : 5 = 900     630Ø : 7Ø = 63 : 7 = 9     72 00Ø : 8Ø = 7200 : 8 = 900     180 ØØØ : 2ØØØ = 180 : 2 = 90', '<p><span>а) 24Ø : 6Ø = 24 : 6 = 4</span>\n<span>    36Ø : 9Ø = 36 : 9 = 4</span>\n<span>    56ØØ : 7ØØ = 56 : 7 = 8</span>\n<span>    28 ØØØ : 4ØØØ = 28 : 4 = 7</span>\n<br/>\n<span>в) 30ØØ : 5ØØ = 30 : 5 = 6</span>\n<span>    140Ø : 2Ø = 14 : 2 = 7</span>\n<span>    27 ØØØ : 3ØØØ = 27 : 3 = 9</span>\n<span>    480 0ØØ : 6ØØ = 4800 : 6 = 800</span>\n<br/>\n<span>б) 4500 : 5 = 900</span>\n<span>    630Ø : 7Ø = 63 : 7 = 9</span>\n<span>    72 00Ø : 8Ø = 7200 : 8 = 900</span>\n<span>    180 ØØØ : 2ØØØ = 180 : 2 = 90</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-97/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '94aabefc64013a49cc2bdf933deed238c422a74b9e6ae825406c91d49bf66d45', '0,000,5,7,20,27,28,42,60,70', '["раз"]'::jsonb, 'выбери правило и сосчитай. сделай записи по образцу. образец:42 0øø:7øø=420:7=60 а) 240:60     360:90     5600:700     28 000:4000 б) 4500:5     6300:70     72 000:80     180 000:2000 в) 3000:500     1400:20     27 000:3000     480 000:600');

    VALUES (v_textbook_id, 97, '3', 2, 'Выполни деление и обоснуй свой ответ: a) 3500 : 70 б) 6400 : 800 в) 500 : 50 г) 54000 : 60 д) 560000 : 80 е) 490000 : 700 ж) 10000 : 5000 з) 20000 : 400', '</p>\n\n<p class="text">Выполни деление и обоснуй свой ответ:</p>\n\n<p class="description-text">\n<span>a) 3500 : 70</span>\n<span>б) 6400 : 800</span>\n<span>в) 500 : 50</span>\n<span>г) 54000 : 60</span>\n<span>д) 560000 : 80</span>\n<span>е) 490000 : 700</span>\n<span>ж) 10000 : 5000</span>\n<span>з) 20000 : 400</span></p>', 'а) 3500 : 70 = 50 б) 6400 : 800 = 8 в) 500 : 50 = 10 г) 54000 : 60 = 900 д) 560000 : 80 = 7000 е) 490000 : 700 = 700 ж) 10000 : 5000 = 2 з) 20000 : 400 = 50 При делении круглых чисел (без остатка) можно отбросить в делимом и делителе поровну нулей.', '<p><span>а) 3500 : 70 = 50</span>\n<span>б) 6400 : 800 = 8</span>\n<span>в) 500 : 50 = 10</span>\n<span>г) 54000 : 60 = 900</span>\n<span>д) 560000 : 80 = 7000</span>\n<span>е) 490000 : 700 = 700</span>\n<span>ж) 10000 : 5000 = 2</span>\n<span>з) 20000 : 400 = 50</span>\n<br/>\n<span>При делении круглых чисел (без остатка) можно отбросить в делимом и делителе поровну нулей.</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-97/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '2465b5a48b68f2d26fbcb98e6485d399585ce81506ae34219950438afed7f34c', '50,60,70,80,400,500,700,800,3500,5000', NULL, 'выполни деление и обоснуй свой ответ:a) 3500:70 б) 6400:800 в) 500:50 г) 54000:60 д) 560000:80 е) 490000:700 ж) 10000:5000 з) 20000:400');

    VALUES (v_textbook_id, 97, '4', 3, 'Реши уравнения с комментированием и сделай проверку: х : 80 = 800      2500 : х = 500      х · 40 = 1600', '</p>\n\n<p class="text">Реши уравнения с комментированием и сделай проверку:</p>\n\n<p class="description-text">\nх : 80 = 800      2500 : х = 500      х · 40 = 1600</p>', 'х : 80 = 800 Что бы найти делимое х надо частное умножить на делитель. х = 800 · 80 х = 64000 Проверка: 64000 : 80 = 800 2500 : х = 500 Что бы найти делитель х надо делимое разделить на частное. х = 2500 : 500 х = 5 Проверка: 2500 : 5 = 500 х · 40 = 1600 Что бы найти множитель х надо произведение разделить на известный множитель. х = 1600 : 40 х = 40 Проверка: 40 · 40 = 1600', '<p><span>х : 80 = 800</span>\n<span>Что бы найти делимое х надо частное умножить на делитель.</span>\n<span>х = 800 · 80</span>\n<span>х = 64000</span>\n<span><b>Проверка:</b> 64000 : 80 = 800</span>\n<br/>\n<span>2500 : х = 500</span>\n<span>Что бы найти делитель х надо делимое разделить на частное.</span>\n<span>х = 2500 : 500</span>\n<span>х = 5</span>\n<span><b>Проверка:</b> 2500 : 5 = 500</span>\n<br/>\n<span>х · 40 = 1600</span>\n<span>Что бы найти множитель х надо произведение разделить на известный множитель.</span>\n<span>х = 1600 : 40</span>\n<span>х = 40</span>\n<span><b>Проверка:</b> 40 · 40 = 1600</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-97/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '1da55e635732d002918abc3ef0676cb906750781a7ca0c65b5374b87f8f82a5c', '40,80,500,800,1600,2500', '["реши"]'::jsonb, 'реши уравнения с комментированием и сделай проверку:х:80=800      2500:х=500      х*40=1600');

