    VALUES (v_textbook_id, 98, '7', 1, 'Чему равен периметр треугольника со сторонами а см, b см и с см? Найди ответ при а = 456, b = 718, с = 932.', '</p>\n\n<p class="text">Чему равен периметр треугольника со сторонами <b>а</b> см, <b>b</b> см и <b>с</b> см? Найди ответ при а = 456, b = 718, с = 932.</p>', '', '<div class="img-wrapper-460">\n<img width="300" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica98-nomer7.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 98, номер 7, год 2022, ответ." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 98, номер 7, год 2022, ответ."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-98/')
