    VALUES (v_textbook_id, 98, '8', 2, 'Первая сторона треугольника равна 20 м, вторая – в 4 раза больше первой, а третья – на 12 м меньше второй. Чему равен периметр этого треугольника?', '</p>\n\n<p class="text">Первая сторона треугольника равна 20 м, вторая – в 4 раза больше первой, а третья – на 12 м меньше второй. Чему равен периметр этого треугольника?</p>', '20 + 20 · 4 + 20 · 4 – 12 = 8 + 80 + 80 = 168 (м) Ответ: 168 метров периметр треугольника.', '<p><span>20 + 20 · 4 + 20 · 4 – 12 = 8 + 80 + 80 = 168 (м)</span>\n<span><b>Ответ:</b> 168 метров периметр треугольника.</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-98/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, 'afff1c28f0fca9167c6bf50544d4f48698b24c94eb2e80fb852b4e914e514d2d', '4,12,20', '["периметр","сторона","больше","меньше","раз","раза"]'::jsonb, 'первая сторона треугольника равна 20 м, вторая-в 4 раза больше первой, а третья-на 12 м меньше второй. чему равен периметр этого треугольника');

    VALUES (v_textbook_id, 98, '9', 3, 'Найди периметр и площадь закрашенной фигуры. Сравни их с периметром и площадью прямоугольника ABCD.', '</p>\n\n<p class="text">Найди периметр и площадь закрашенной фигуры. Сравни их с периметром и площадью прямоугольника ABCD.</p>\n\n<div class="img-wrapper-460">\n<img width="300" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica98-nomer9.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 98, номер 9, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 98, номер 9, год 2022."/>\n</div>', '2((3 + 2) + (4 + 5)) = 2(5 + 9) = 28 (дм) – периметр прямоугольника ABCD. 3 + 4 + 5 + 2 + (2 + 3) + (4 + 5) = 14 + 5 + 9 = 28 (дм) – периметр закрещенной фигуры. Периметр закрещенной фигуры равен периметру прямоугольника ABCD. (2 + 3) · (4 + 5) = 5 · 9 = 45 (дм 2 ) – площадь прямоугольника ABCD. 3 · 4 + (2 + 3) · 5 = 12 + 25 = 37 (дм 2 ) – площадь закрашенной фигуры. Площадь закрашенной фигуры меньше на 8 дм 2 площадь прямоугольника ABCD.', '<p><span>2((3 + 2) + (4 + 5)) = 2(5 + 9) = 28 (дм) – периметр прямоугольника ABCD.</span>\n<span>3 + 4 + 5 + 2 + (2 + 3) + (4 + 5) = 14 + 5 + 9 = 28 (дм) – периметр закрещенной фигуры.</span>\n<span>Периметр закрещенной фигуры равен периметру прямоугольника ABCD.</span>\n<span>(2 + 3) · (4 + 5) = 5 · 9 = 45 (дм<sup>2</sup>) – площадь прямоугольника ABCD.</span>\n<span>3 · 4 + (2 + 3) · 5 = 12 + 25 = 37 (дм<sup>2</sup>) – площадь закрашенной фигуры.</span>\n<span>Площадь закрашенной фигуры меньше на 8 дм<sup>2</sup> площадь прямоугольника ABCD.</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-98/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, 'condition', 0, NULL, 'https://gdz-raketa.ru/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica98-nomer9.jpg', 'peterson/3/part1/page98/task9_condition_0.jpg', '');

    VALUES (v_task_id, v_textbook_id, 3, '33ccb9d3ee28826fd992fc525ea25b603b5f3bb8a8a2feaa4a4fc8b4a31e452a', NULL, '["найди","сравни","периметр","площадь"]'::jsonb, 'найди периметр и площадь закрашенной фигуры. сравни их с периметром и площадью прямоугольника abcd');

    VALUES (v_textbook_id, 98, '10', 4, 'Выполни действия: а) 250 · 1000     78000 : 100 б) 130 · 700     40000 · 15 в) 17 : 15     59 : 14 г) 9507 – 819     5648 + 4352', '</p>\n\n<p class="text">Выполни действия:</p>\n\n<p class="description-text">\n<span>а) 250 · 1000</span>\n<span>    78000 : 100</span>\n<span>б) 130 · 700</span>\n<span>    40000 · 15</span>\n<span>в) 17 : 15</span>\n<span>    59 : 14</span>\n<span>г) 9507 – 819</span>\n<span>    5648 + 4352</span></p>', 'а) 250 · 1000 = 250000     78000 : 100 = 780 б) 130 · 700 = 91000     40000 · 15 = 600000 в) 17 : 15 = 1 + 2     59 : 14 = 4 + 3 г) 9507 – 819 = 8688', '<p><span>а) 250 · 1000 = 250000</span>\n<span>    78000 : 100 = 780</span>\n<br/>\n<span>б) 130 · 700 = 91000</span>\n<span>    40000 · 15 = 600000</span>\n<br/>\n<span>в) 17 : 15 = 1 + 2</span>\n<span>    59 : 14 = 4 + 3</span>\n<br/>\n<span>г) 9507 – 819 = 8688</span></p>\n\n<div class="img-wrapper-460">\n<img width="110" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica98-nomer10.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 98, номер 10, год 2022, ответ." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 98, номер 10, год 2022, ответ."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-98/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, 'solution', 0, NULL, 'https://gdz-raketa.ru/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica98-nomer10.jpg', 'peterson/3/part1/page98/task10_solution_0.jpg', '');

    VALUES (v_task_id, v_textbook_id, 3, 'ffd63e088cc76eeb1fedb0de3e19f4196278a9310f32625509a9c2c39601d4f9', '14,15,17,59,100,130,250,700,819,1000', NULL, 'выполни действия:а) 250*1000     78000:100 б) 130*700     40000*15 в) 17:15     59:14 г) 9507-819     5648+4352');

    VALUES (v_textbook_id, 98, '11', 5, 'Объясни, почему каждое выражение может быть лишним: а · 2 + 95      44 : 4 + 4      58 + 6      31 – 7 · 3', '</p>\n\n<p class="text">Объясни, почему каждое выражение может быть лишним:</p>\n\n<p class="description-text">\nа · 2 + 95      44 : 4 + 4      58 + 6      31 – 7 · 3</p>', 'а · 2 + 95 – содержит множитель а. 44 : 4 + 4 – содержит деление. 58 + 6 – нет деления или умножения. 31 – 7 · 3 – содержит вычитание.', '<p><span>а · 2 + 95 – содержит множитель а.</span>\n<span>44 : 4 + 4 – содержит деление.</span>\n<span>58 + 6 – нет деления или умножения.</span>\n<span>31 – 7 · 3 – содержит вычитание.</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-98/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '177b170def3962801d6bcbed4a0e7592fdbf4dc3584cc3e77959fa6734c533f5', '2,3,4,6,7,31,44,58,95', NULL, 'объясни, почему каждое выражение может быть лишним:а*2+95      44:4+4      58+6      31-7*3');

    VALUES (v_textbook_id, 98, '12', 6, 'Построй диаграмму Эйлера – Венна множеств А и В, отметь на ней их элементы. Найди множества А ∩ В и А ∪ В. Закрась на диаграмме А ∩ В и обведи А ∪ В', '</p>\n\n<div class="img-wrapper-460">\n<img width="270" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica98-nomer12.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 98, номер 12, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 98, номер 12, год 2022."/>\n</div>\n\n<p class="text">Построй диаграмму Эйлера – Венна множеств А и В, отметь на ней их элементы. Найди множества А ∩ В и А ∪ В. Закрась на диаграмме А ∩ В и обведи А ∪ В</p>', '', '<div class="img-wrapper-460">\n<img width="330" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica98-nomer12-1.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 98, номер 12, год 2022, ответ." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 98, номер 12, год 2022, ответ."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-98/')
    RETURNING id INTO v_task_id;

