    VALUES (v_textbook_id, 98, '13', 7, 'Выполни действия. Проверь результаты с помощью калькулятора. а) 600038 – 218053      б) (641265 + 8735) – 28472', '</p>\n\n<p class="text">Выполни действия. Проверь результаты с помощью калькулятора.</p>\n\n<p class="description-text">\nа) 600038 – 218053      б) (641265 + 8735) – 28472</p>', 'а) 600038 – 218053 = 381985', '<p>а) 600038 – 218053 = 381985</p>\n\n<div class="img-wrapper-460">\n<img width="150" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica98-nomer13.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 98, номер 13, год 2022, ответ." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 98, номер 13, год 2022, ответ."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-98/')
