    VALUES (v_textbook_id, 98, '14', 8, 'Возраст старика Хоттабыча записывается числом с разными цифрами. Известно, что: а) если первую и последнюю цифру зачеркнуть, то получится наименьшее из двузначных чисел, сумма цифр которых равна 13; б) первая цифра больше последней в 4 раза. Сколько лет Хоттабычу?', '</p>\n\n<p class="text">Возраст старика Хоттабыча записывается числом с разными цифрами. Известно, что:</p>\n\n<p class="description-text">\n<span>а) если первую и последнюю цифру зачеркнуть, то получится наименьшее из двузначных чисел, сумма цифр которых равна 13;</span>\n<span>б) первая цифра больше последней в 4 раза.</span></p>\n\n<p class="text">Сколько лет Хоттабычу?</p>', '4491 или 8492 лет Хоттабычу.', '<p>4491 или 8492 лет Хоттабычу.</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-98/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, 'd1f3d3071616b5c2637d0f18e682189a285374ee21378fb2255fc06f8fb51c4c', '4,13', '["сумма","больше","меньше","раз","раза"]'::jsonb, 'возраст старика хоттабыча записывается числом с разными цифрами. известно, что:а) если первую и последнюю цифру зачеркнуть, то получится наименьшее из двузначных чисел, сумма цифр которых равна 13; б) первая цифра больше последней в 4 раза. сколько лет хоттабычу');

    VALUES (v_textbook_id, 99, '1', 0, 'Запиши число 18 млрд 72 млн 2 тыс. 418 ед. Какая цифра стоит в разряде единиц миллионов этого числа? Сколько в нём всего миллионов?', '</p>\n\n<p class="text">Запиши число 18 млрд 72 млн 2 тыс. 418 ед. Какая цифра стоит в разряде единиц миллионов этого числа? Сколько в нём всего миллионов?</p>', '2 ед. млн, 72 всего миллиона.', '<p>2 ед. млн, 72 всего миллиона.</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-99/')
    RETURNING id INTO v_task_id;

