    VALUES (v_textbook_id, 99, '2', 1, 'Вычисли: а) 9000 : 1000 б) 75300000 : 100 в) 27000 : 90 г) 490000 : 7000 д) 3200000 : 800 е) 600000 : 1500', '</p>\n\n<p class="text">Вычисли:</p>\n\n<p class="description-text">\n<span>а) 9000 : 1000</span>\n<span>б) 75300000 : 100</span>\n<span>в) 27000 : 90</span>\n<span>г) 490000 : 7000</span>\n<span>д) 3200000 : 800</span>\n<span>е) 600000 : 1500</span></p>', 'а) 9000 : 1000 = 9 б) 75300000 : 100 = 753000 в) 27000 : 90 = 300 г) 490000 : 7000 = 70 д) 3200000 : 800 = 4000 е) 600000 : 1500 = 400', '<p><span>а) 9000 : 1000 = 9</span>\n<span>б) 75300000 : 100 = 753000</span>\n<span>в) 27000 : 90 = 300</span>\n<span>г) 490000 : 7000 = 70</span>\n<span>д) 3200000 : 800 = 4000</span>\n<span>е) 600000 : 1500 = 400</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-99/')
    RETURNING id INTO v_task_id;

