    VALUES (v_textbook_id, 99, '3', 2, 'Найди периметр и площадь закрашенной фигуры:', '</p>\n\n<p class="text">Найди периметр и площадь закрашенной фигуры:</p>\n\n<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica99-nomer3.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 99, номер 3, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 99, номер 3, год 2022."/>\n</div>', 'а) (16 + 2 + 4) + 6 + (16 + 4) + (6 + 2) = 22 + 6 + 20 + 8 = 30 + 26 = 56 (м) – периметр закрашенной фигуры.     16 · (2 + 6) + 4 · 6 = 16 · 8 + 24 = 128 + 24 = 152 (м 2 ) – площадь закрашенной фигуры. б) (14 + 2 + 6) + 5 + (6 + 14) + (2 + 5) = 22 + 5 + 20 + 7 = 54 (м) – периметр закрашенной фигуры.     14 · (2 + 5) + 6 · 5 = 14 · 7 + 30 = 98 + 30 = 128 (м 2 ) – площадь закрашенной фигуры.', '<p><span>а) (16 + 2 + 4) + 6 + (16 + 4) + (6 + 2) = 22 + 6 + 20 + 8 = 30 + 26 = 56 (м) – периметр закрашенной фигуры.</span>\n<span>    16 · (2 + 6) + 4 · 6 = 16 · 8 + 24 = 128 + 24 = 152 (м<sup>2</sup>) – площадь закрашенной фигуры.</span>\n<span>б) (14 + 2 + 6) + 5 + (6 + 14) + (2 + 5) = 22 + 5 + 20 + 7 = 54 (м) – периметр закрашенной фигуры.</span>\n<span>    14 · (2 + 5) + 6 · 5 = 14 · 7 + 30 = 98 + 30 = 128 (м<sup>2</sup>) – площадь закрашенной фигуры.</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-99/')
    RETURNING id INTO v_task_id;

