    VALUES (v_task_id, v_textbook_id, 3, '562128a15c3ce7f6753f24ca20661aa605d94f20c0c2de1db412cf154f0a02d4', NULL, '["найди","периметр","площадь"]'::jsonb, 'найди периметр и площадь закрашенной фигуры');

    VALUES (v_textbook_id, 99, '4', 3, 'Составь программу действий и вычисли: а) 64 : 4 + 3 · 9 · 7 – 91 : (28 : 4)      б) (69 · 2 – 6 · 8) : 5 + 170 · 3 : 10', '</p>\n\n<p class="text">Составь программу действий и вычисли:</p>\n\n<p class="description-text">\nа) 64 : 4 + 3 · 9 · 7 – 91 : (28 : 4)      б) (69 · 2 – 6 · 8) : 5 + 170 · 3 : 10</p>', 'а) 64 : 4 + 3 · 9 · 7 – 91 : (28 : 4) = 192     28 : 4 = 7     64 : 4 = 16     3 · 9 = 27     27 · 7 = 189     91 : 7 = 13     16 + 189 = 205     205 – 13 = 192 б) (69 · 2 – 6 · 8) : 5 + 170 · 3 : 10 = 69     69 · 2 = 138     6 · 8 = 48     138 – 48 = 90     90 : 5 = 18     170 · 3 = 510     510 : 10 = 51     18 + 51 = 69', '<p><span>а) 64 : 4 + 3 · 9 · 7 – 91 : (28 : 4) = 192</span>\n<span>    28 : 4 = 7</span>\n<span>    64 : 4 = 16</span>\n<span>    3 · 9 = 27</span>\n<span>    27 · 7 = 189</span>\n<span>    91 : 7 = 13</span>\n<span>    16 + 189 = 205</span>\n<span>    205 – 13 = 192</span>\n<br/>\n<span>б) (69 · 2 – 6 · 8) : 5 + 170 · 3 : 10 = 69</span>\n<span>    69 · 2 = 138</span>\n<span>    6 · 8 = 48</span>\n<span>    138 – 48 = 90</span>\n<span>    90 : 5 = 18</span>\n<span>    170 · 3 = 510</span>\n<span>    510 : 10 = 51</span>\n<span>    18 + 51 = 69</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-99/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '580037152cc44360d1fe3e74a2fd1e983566a57a1a71b1d7a823086ae34d449b', '2,3,4,5,6,7,8,9,10,28', '["вычисли"]'::jsonb, 'составь программу действий и вычисли:а) 64:4+3*9*7-91:(28:4)      б) (69*2-6*8):5+170*3:10');

    VALUES (v_textbook_id, 99, '5', 4, 'Реши уравнения с комментированием и сделай проверку: х – 9382 = 719      300000 – х = 47475      х + 116084 = 208003', '</p>\n\n<p class="text">Реши уравнения с комментированием и сделай проверку:</p>\n\n<p class="description-text">\nх – 9382 = 719      300000 – х = 47475      х + 116084 = 208003</p>', 'х – 9382 = 719 Что бы найти уменьшаемое х надо к вычитаемому прибавить разность х = 9382 + 719 х = 10101 Проверка: 10101 – 9382 = 719 300000 – х = 47475 Что бы найти вычитаемое х надо из уменьшаемого вычесть разность х = 300000 – 47475', '<p><span>х – 9382 = 719</span>\n<span>Что бы найти уменьшаемое х надо к вычитаемому прибавить разность</span>\n<span>х = 9382 + 719</span>\n<span>х = 10101</span>\n<span><b>Проверка:</b> 10101 – 9382 = 719</span>\n<br/>\n<span>300000 – х = 47475</span>   \n<span>Что бы найти вычитаемое х надо из уменьшаемого вычесть разность</span>\n<span>х = 300000 – 47475</span></p>\n\n<div class="img-wrapper-460">\n<img width="190" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica99-nomer5.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 99, номер 5, год 2022, ответ." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 99, номер 5, год 2022, ответ."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-99/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, 'solution', 0, NULL, 'https://gdz-raketa.ru/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica99-nomer5.jpg', 'peterson/3/part1/page99/task5_solution_0.jpg', '');

    VALUES (v_task_id, v_textbook_id, 3, 'cf7981d003f927834045c359aae0489237d511c90e58d01c25c7d278a1196a4a', '719,9382,47475,116084,208003,300000', '["реши"]'::jsonb, 'реши уравнения с комментированием и сделай проверку:х-9382=719      300000-х=47475      х+116084=208003');

    VALUES (v_textbook_id, 99, '6', 5, 'Прочитай выражения разными способами и вычисли. Что ты замечаешь? а) 73 – 13 · 5      б) 80 : 16 + 4      в) 15 · 4 – 3 · 2     (73 – 13) · 5        80 : (16 + 4)        15 · (4 – 3) · 2', '</p>\n\n<p class="text">Прочитай выражения разными способами и вычисли. Что ты замечаешь?</p>\n\n<p class="description-text">\n<span>а) 73 – 13 · 5      б) 80 : 16 + 4      в) 15 · 4 – 3 · 2</span>\n<span>    (73 – 13) · 5        80 : (16 + 4)        15 · (4 – 3) · 2</span></p>', 'а) 73 – 13 · 5 = 73 – 65 = 8     (73 – 13) · 5 = 60 · 5 = 300 б) 80 : 16 + 4 = 5 + 4 = 9     80 : (16 + 4) = 80 : 20 = 4 в) 15 · 4 – 3 · 2 = 60 – 6 = 54     15 · (4 – 3) · 2 = 30 · 1 = 30 При наличии скобок результат отличается если это же выражение без скобок.', '<p><span>а) 73 – 13 · 5 = 73 – 65 = 8</span>\n<span>    (73 – 13) · 5 = 60 · 5 = 300</span>\n<br/>\n<span>б) 80 : 16 + 4 = 5 + 4 = 9</span>\n<span>    80 : (16 + 4) = 80 : 20 = 4</span>\n<br/>\n<span>в) 15 · 4 – 3 · 2 = 60 – 6 = 54</span>\n<span>    15 · (4 – 3) · 2 = 30 · 1 = 30</span>\n<br/>\n<span>При наличии скобок результат отличается если это же выражение без скобок.</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-99/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, 'd4a03c8d3f732e43b91a2d07bd70cb0551eb82f3661487c5212eeb59815c8e6b', '2,3,4,5,13,15,16,73,80', '["вычисли","раз"]'::jsonb, 'прочитай выражения разными способами и вычисли. что ты замечаешь? а) 73-13*5      б) 80:16+4      в) 15*4-3*2     (73-13)*5        80:(16+4)        15*(4-3)*2');

    VALUES (v_textbook_id, 99, '7', 6, 'БЛИЦтурнир а) В одной банке 3 л сока. Сколько сока в k таких банках? б) b литров молока разлили в 2-литровые банки. Сколько таких банок потребовалось? в) с кг картошки разложили поровну в 4 мешка. Сколько килограммов картошки в каждом мешке? г) После того как израсходовали d кг муки, осталось муки в 5 раз больше, чем израсходовали. Сколько муки было вначале? д) х кг печенья разложили в коробки по 6 кг, а у кг – в коробки по 8 кг. Сколько всего коробок с печеньем получилось?', '</p>\n\n<p class="text"><span><b>БЛИЦтурнир</b></span>\n<span>а) В одной банке 3 л сока. Сколько сока в <b>k</b> таких банках?</span>\n<span>б) <b>b</b> литров молока разлили в 2-литровые банки. Сколько таких банок потребовалось?</span>\n<span>в) <b>с</b> кг картошки разложили поровну в 4 мешка. Сколько килограммов картошки в каждом мешке?</span>\n<span>г) После того как израсходовали <b>d</b> кг муки, осталось муки в 5 раз больше, чем израсходовали. Сколько муки было вначале?</span>\n<span>д) <b>х</b> кг печенья разложили в коробки по 6 кг, а <b>у</b> кг – в коробки по 8 кг. Сколько всего коробок с печеньем получилось?</span></p>', 'а) 3k сока      Ответ: 3k сока таких банках. б) b : 2 банки      Ответ: b : 2 таких банок потребовалось. в) с : 4 кг      Ответ: с : 4 килограммов картошки в каждом мешке. г) 5d кг муки      Ответ: 5d муки было вначале. д) 6х + 8у кг      Ответ: 6х + 8у всего коробок с печеньем получилось.', '<p><span>а) 3k сока</span>\n<span>    <b>Ответ:</b> 3k сока таких банках.</span>\n<span>б) b : 2 банки</span>\n<span>    <b>Ответ:</b> b : 2 таких банок потребовалось.</span>\n<span>в) с : 4 кг</span>\n<span>    <b>Ответ:</b> с : 4 килограммов картошки в каждом мешке.</span>\n<span>г) 5d кг муки</span>\n<span>    <b>Ответ:</b> 5d муки было вначале.</span>\n<span>д) 6х + 8у кг</span>\n<span>    <b>Ответ:</b> 6х + 8у всего коробок с печеньем получилось.</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-99/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, 'ac5dedc3c5123165ffd9c1f0a50bbdc46f01cb02c5bfe33e9f8b8c03aa85cea2', '2,3,4,5,6,8', '["больше","раз"]'::jsonb, 'блицтурнир а) в одной банке 3 л сока. сколько сока в k таких банках? б) b литров молока разлили в 2-литровые банки. сколько таких банок потребовалось? в) с кг картошки разложили поровну в 4 мешка. сколько килограммов картошки в каждом мешке? г) после того как израсходовали d кг муки, осталось муки в 5 раз больше, чем израсходовали. сколько муки было вначале? д) х кг печенья разложили в коробки по 6 кг, а у кг-в коробки по 8 кг. сколько всего коробок с печеньем получилось');

    VALUES (v_textbook_id, 100, '8', 0, 'Выполни действия: а) 10000 · 390           б) 2600 · 300      в) 96 : 19      г) 28075 + 6493     8020000 : 1000        72000 : 80           60 : 16          60000 – 4945', '</p>\n\n<p class="text">Выполни действия:</p>\n\n<p class="description-text">\n<span>а) 10000 · 390           б) 2600 · 300      в) 96 : 19      г) 28075 + 6493</span>\n<span>    8020000 : 1000        72000 : 80           60 : 16          60000 – 4945</span></p>', 'а) 10000 · 390 = 3900000     8020000 : 1000 = 8020 б) 2600 · 300 = 260000     72000 : 80 = 900 в) 96 : 19 = 5 + 1     60 : 16 = 3 + 12 г) 28075 + 6493 = 34568     60000 – 4945 = 55055', '<p><span>а) 10000 · 390 = 3900000</span>\n<span>    8020000 : 1000 = 8020</span>\n<br/>\n<span>б) 2600 · 300 = 260000</span>\n<span>    72000 : 80 = 900</span>\n<br/>\n<span>в) 96 : 19 = 5 + 1</span>\n<span>    60 : 16 = 3 + 12</span>\n<br/>\n<span>г) 28075 + 6493 = 34568</span>\n<span>    60000 – 4945 = 55055</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-100/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '52c166dd97624cbe610214301e8b9fd2904f7621f50f86ce2d9363b9bb457451', '16,19,60,80,96,300,390,1000,2600,4945', NULL, 'выполни действия:а) 10000*390           б) 2600*300      в) 96:19      г) 28075+6493     8020000:1000        72000:80           60:16          60000-4945');

    VALUES (v_textbook_id, 100, '9', 1, 'Пусть А – множество учащихся школы, В – множество учеников 3 «А» класса этой школы, С – множество мальчиков 3 «А» класса этой школы, D – множество отличников в этой школе. Какие из множеств являются подмножествами множества А, множества В? Нарисуй диаграмму Эйлера–Венна множеств А, B, C и D.', '</p>\n\n<p class="text">\n<span>Пусть</span>\n<span>А – множество учащихся школы,</span>\n<span>В – множество учеников 3 «А» класса этой школы,</span>\n<span>С – множество мальчиков 3 «А» класса этой школы,</span>\n<span>D – множество отличников в этой школе.</span>\n<span>Какие из множеств являются подмножествами множества А, множества В? Нарисуй диаграмму Эйлера–Венна множеств А, B, C и D.</span></p>', '', '<div class="img-wrapper-460">\n<img width="250" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica100-nomer9.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 100, номер 9, год 2022, ответ." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 100, номер 9, год 2022, ответ."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-100/')
    RETURNING id INTO v_task_id;

