    VALUES (v_task_id, v_textbook_id, 3, '74bda203c36cdb8ae1db8e2eac883118a683b4eeab55aff851d16a75333f7900', '3', NULL, 'пусть а-множество учащихся школы, в-множество учеников 3 "а" класса этой школы, с-множество мальчиков 3 "а" класса этой школы, d-множество отличников в этой школе. какие из множеств являются подмножествами множества а, множества в? нарисуй диаграмму эйлера-венна множеств а, b, c и d');

    VALUES (v_textbook_id, 100, '10', 2, 'Построй в тетради фигуру, равную данной. Чему равна её площадь в квадратных сантиметрах? В клеточках?', '</p>\n\n<p class="text">Построй в тетради фигуру, равную данной. Чему равна её площадь в квадратных сантиметрах? В клеточках?</p>\n\n<div class="img-wrapper-460">\n<img width="220" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica100-nomer10.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 100, номер 10, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 100, номер 10, год 2022."/>\n</div>', '', '<div class="img-wrapper-460">\n<img width="290" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica100-nomer10-1.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 100, номер 10, год 2022, ответ." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 100, номер 10, год 2022, ответ."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-100/')
