    VALUES (v_task_id, v_textbook_id, 3, 'a461775baffb69f366982aeb1e286a717e41e39367433a0eef424b1418c3a061', NULL, '["площадь"]'::jsonb, 'построй в тетради фигуру, равную данной. чему равна её площадь в квадратных сантиметрах? в клеточках');

    VALUES (v_textbook_id, 100, '11', 3, 'Четыре подруги пришли на каток, каждая со своим братом. Они разбились на пары и начали кататься. Оказалось, что в каждой паре «кавалер» выше «дамы» и никто не катается со своей сестрой. Самый высокий из компании – Юра Воробьёв, следующий по росту – Андрей Егоров, потом Люся Егорова, Серёжа Петров, Оля Петрова, Дима Крымов, Инна Крымова и Аня Воробьёва. Кто с кем катался?', '</p>\n\n<p class="text">Четыре подруги пришли на каток, каждая со своим братом. Они разбились на пары и начали кататься. Оказалось, что в каждой паре «кавалер» выше «дамы» и никто не катается со своей сестрой. Самый высокий из компании – Юра Воробьёв, следующий по росту – Андрей Егоров, потом Люся Егорова, Серёжа Петров, Оля Петрова, Дима Крымов, Инна Крымова и Аня Воробьёва. Кто с кем катался?</p>', 'Юра Воробьёв – Люся Егорова Андрей Егоров – Оля Петрова Серёжа Петров – Инна Крымова Дима Крымов – Аня Воробьёва', '<p><span>Юра Воробьёв – Люся Егорова</span>\n<span>Андрей Егоров – Оля Петрова</span>\n<span>Серёжа Петров – Инна Крымова</span>\n<span>Дима Крымов – Аня Воробьёва</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-100/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, 'de03bd5e5858115a7354accb248307f6214e85030803da000cd0bf3e1960c1fe', NULL, '["раз"]'::jsonb, 'четыре подруги пришли на каток, каждая со своим братом. они разбились на пары и начали кататься. оказалось, что в каждой паре "кавалер" выше "дамы" и никто не катается со своей сестрой. самый высокий из компании-юра воробьёв, следующий по росту-андрей егоров, потом люся егорова, серёжа петров, оля петрова, дима крымов, инна крымова и аня воробьёва. кто с кем катался');

