    VALUES (v_task_id, v_textbook_id, 3, '7fef3dd8ff5dba9059fe289a266a664a63469bf0e2a0587be78eb511b04a9a4f', '1', NULL, 'используя таблицу, ответь на вопросы:а) сколько в 1 километре метров, дециметров, сантиметров, миллиметров? б) сколько в 1 метре дециметров, сантиметров, миллиметров? в) сколько в 1 дециметре сантиметров, миллиметров? г) сколько в 1 сантиметре миллиметров? какое действие надо выполнить при переходе от бо´льших мерок к меньшим? а при обратном движении');

    VALUES (v_textbook_id, 101, '2', 1, 'Вырази в сантиметрах: а) 5 дм 3 см б) 7 м в) 6 м 8 дм 7 см г) 9 м 12 см д) 4 м 5 см е) 2 м 6 дм ж) 8 км з) 16 000 мм', '</p>\n\n<p class="text">Вырази в сантиметрах:</p>\n\n<p class="description-text">\n<span>а) 5 дм 3 см</span>\n<span>б) 7 м</span>\n<span>в) 6 м 8 дм 7 см</span>\n<span>г) 9 м 12 см</span>\n<span>д) 4 м 5 см</span>\n<span>е) 2 м 6 дм</span>\n<span>ж) 8 км</span>\n<span>з) 16 000 мм</span></p>', 'а) 5 дм 3 см = 53 см б) 7 м = 700 см в) 6 м 8 дм 7 см = 687 см г) 9 м 12 см = 912 см д) 4 м 5 см = 405 см е) 2 м 6 дм = 260 см ж) 8 км = 800000 см з) 16 000 мм = 1600 см', '<p><span>а) 5 дм 3 см = 53 см</span>\n<span>б) 7 м = 700 см</span>\n<span>в) 6 м 8 дм 7 см = 687 см</span>\n<span>г) 9 м 12 см = 912 см</span>\n<span>д) 4 м 5 см = 405 см</span>\n<span>е) 2 м 6 дм = 260 см</span>\n<span>ж) 8 км = 800000 см</span>\n<span>з) 16 000 мм = 1600 см</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-101/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '37c36279237498db4905635a23a8695b9e746bd9699c5d5fba40d7700853c873', '000,2,3,4,5,6,7,8,9,12', '["раз"]'::jsonb, 'вырази в сантиметрах:а) 5 дм 3 см б) 7 м в) 6 м 8 дм 7 см г) 9 м 12 см д) 4 м 5 см е) 2 м 6 дм ж) 8 км з) 16 000 мм');

    VALUES (v_textbook_id, 101, '3', 2, 'Вырази в миллиметрах: a) 3 см 9 мм б) 8 дм 3 мм в) 2 дм 5 см 7 мм г) 1 дм 8 см д) 5 м 82 см е) 4 м 2 дм 7 мм ж) 2 км з) 64 см', '</p>\n\n<p class="text">Вырази в миллиметрах:</p>\n\n<p class="description-text">\n<span>a) 3 см 9 мм</span>\n<span>б) 8 дм 3 мм</span>\n<span>в) 2 дм 5 см 7 мм</span>\n<span>г) 1 дм 8 см</span>\n<span>д) 5 м 82 см</span>\n<span>е) 4 м 2 дм 7 мм</span>\n<span>ж) 2 км</span>\n<span>з) 64 см</span></p>', 'а) 3 см 9 мм = 39 мм в) 2 дм 5 см 7 мм = 257 мм д) 5 м 82 см = 5820 мм б) 8 дм 3 мм = 803 мм г) 1 дм 8 см = 180 мм е) 4 м 2 дм 7 мм = 4207 мм ж) 2 км = 2000000 мм з) 64 см = 640 мм', '<p><span>а) 3 см 9 мм = 39 мм</span>\n<span>в) 2 дм 5 см 7 мм = 257 мм</span>\n<span>д) 5 м 82 см = 5820 мм</span>\n<span>б) 8 дм 3 мм = 803 мм</span>\n<span>г) 1 дм 8 см = 180 мм</span>\n<span>е) 4 м 2 дм 7 мм = 4207 мм</span>\n<span>ж) 2 км = 2000000 мм</span>\n<span>з) 64 см = 640 мм</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-101/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '7b1185c0858276502940f4e7383158f291f30b3d2e0e0d126a513db69daffce8', '1,2,3,4,5,7,8,9,64,82', '["раз"]'::jsonb, 'вырази в миллиметрах:a) 3 см 9 мм б) 8 дм 3 мм в) 2 дм 5 см 7 мм г) 1 дм 8 см д) 5 м 82 см е) 4 м 2 дм 7 мм ж) 2 км з) 64 см');

    VALUES (v_textbook_id, 101, '4', 3, 'Вырази в метрах: а) 4 км 700 м б) 6 км 18 м в) 12 км 50 м г) 1 км 4 м д) 280 дм е) 35000 см', '</p>\n\n<p class="text">Вырази в метрах:</p>\n\n<p class="description-text">\n<span>а) 4 км 700 м</span>\n<span>б) 6 км 18 м</span>\n<span>в) 12 км 50 м</span>\n<span>г) 1 км 4 м</span>\n<span>д) 280 дм</span>\n<span>е) 35000 см</span></p>', 'а) 4 км 700 м = 4700 м б) 6 км 18 м = 6018 м в) 12 км 50 м = 12050 м г) 1 км 4 м = 1004 м д) 280 дм = 28 м е) 35000 см = 350 м', '<p><span>а) 4 км 700 м = 4700 м</span>\n<span>б) 6 км 18 м = 6018 м</span>\n<span>в) 12 км 50 м = 12050 м</span>\n<span>г) 1 км 4 м = 1004 м</span>\n<span>д) 280 дм = 28 м</span>\n<span>е) 35000 см = 350 м</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-101/')
    RETURNING id INTO v_task_id;

