    VALUES (v_textbook_id, 101, '5', 4, 'Сравни: 3 м 7 см     6 дм 8 см 5 дм 30 мм     53 см 9 км 300 м     9030 м 7 м 86 см     78 дм 5 см', '</p>\n\n<p class="text">Сравни:</p>\n\n<p class="description-text">\n<span>3 м 7 см <span class="okon">   </span> 6 дм 8 см</span>\n<span>5 дм 30 мм <span class="okon">   </span> 53 см</span>\n<span>9 км 300 м <span class="okon">   </span> 9030 м</span>\n<span>7 м 86 см <span class="okon">   </span> 78 дм 5 см</span></p>', '3 м 7 см ˃ 6 дм 8 см 5 дм 30 мм = 53 см 9 км 300 м ˃ 9030 м 7 м 86 см ˃ 78 дм 5 см', '<p><span>3 м 7 см ˃ 6 дм 8 см</span>\n<span>5 дм 30 мм = 53 см</span>\n<span>9 км 300 м ˃ 9030 м</span>\n<span>7 м 86 см ˃ 78 дм 5 см</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-101/')
