    VALUES (v_textbook_id, 102, '6', 0, 'Выполни действия: а) 5 м 94 см + 6 дм 8 см      в) 9 м 6 дм 5 см – 5 м 8 см б) 7 м 2 дм – 42 дм 3 см      г) 34 дм – 2 м 37 см', '</p>\n\n<p class="text">Выполни действия:</p>\n\n<p class="description-text">\n<span>а) 5 м 94 см + 6 дм 8 см      в) 9 м 6 дм 5 см – 5 м 8 см</span>\n<span>б) 7 м 2 дм – 42 дм 3 см      г) 34 дм – 2 м 37 см</span></p>', 'а) 5 м 94 см + 6 дм 8 см = 594 см + 68 см = 662 см', '<p>а) 5 м 94 см + 6 дм 8 см = 594 см + 68 см = 662 см</p>\n\n<div class="img-wrapper-460">\n<img width="100" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica102-nomer6.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 102, номер 6, год 2022, ответ." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 102, номер 6, год 2022, ответ."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-102/')
