    VALUES (v_textbook_id, 102, '7', 1, 'а) Из 24 мотков шерсти связали 3 одинаковые кофты. Сколько мотков шерсти потребуется, чтобы связать 8 таких кофт? б) Из 14 м ткани сшили 7 одинаковых юбок. Сколько таких юбок можно сшить из 30 м ткани?', '</p>\n\n<p class="text"><span>а) Из 24 мотков шерсти связали 3 одинаковые кофты. Сколько мотков шерсти потребуется, чтобы связать 8 таких кофт?</span>\n<span>б) Из 14 м ткани сшили 7 одинаковых юбок. Сколько таких юбок можно сшить из 30 м ткани?</span></p>', 'а) 24 : 3 · 8 = 8 · 8 = 64 (мотков)      Ответ: 64 мотков шерсти потребуется, чтобы связать 8 таких кофт. б) 30 : 14 : 7 = 30 : 2 = 15 (юбок)      Ответ: 15 таких юбок можно сшить из 30 м ткани.', '<p><span>а) 24 : 3 · 8 = 8 · 8 = 64 (мотков)</span>\n<span>    <b>Ответ:</b> 64 мотков шерсти потребуется, чтобы связать 8 таких кофт.</span>\n<span>б) 30 : 14 : 7 = 30 : 2 = 15 (юбок)</span>\n<span>    <b>Ответ:</b> 15 таких юбок можно сшить из 30 м ткани.</span></p>', '', '', TRUE, '[{"letter":"а","condition":"Из 24 мотков шерсти связали 3 одинаковые кофты. Сколько мотков шерсти потребуется, чтобы связать 8 таких кофт?","solution":"24 : 3 · 8 = 8 · 8 = 64 (мотко"},{"letter":"б","condition":"Из 14 м ткани сшили 7 одинаковых юбок. Сколько таких юбок можно сшить из 30 м ткани?","solution":"30 : 14 : 7 = 30 : 2 = 15 (юбок)      Ответ: 15 таких юбок можно сшить из 30 м ткани."},{"letter":"в","condition":"","solution":"Ответ: 64 мотков шерсти потребуется, чтобы связать 8 таких кофт."}]'::jsonb, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-102/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, 'b10bc3d61f5c1e00e1b0624759db5c677ed78285c59f91956d9118a09dbf03fa', '3,7,8,14,24,30', NULL, 'а) из 24 мотков шерсти связали 3 одинаковые кофты. сколько мотков шерсти потребуется, чтобы связать 8 таких кофт? б) из 14 м ткани сшили 7 одинаковых юбок. сколько таких юбок можно сшить из 30 м ткани');

    VALUES (v_textbook_id, 102, '8', 2, 'Составь выражения и найди их значения: а) Уменьшаемое 208400, вычитаемое выражено разностью чисел 18000 и 9762. б) Из разности чисел 720048 и 97256 вычесть сумму чисел 36809 и 250249. в) К сумме чисел 777777 и 66666 прибавить разность чисел 111111 и 99999.', '</p>\n\n<p class="text">Составь выражения и найди их значения:</p>\n\n<p class="description-text">\n<span>а) Уменьшаемое 208400, вычитаемое выражено разностью чисел 18000 и 9762.</span>\n<span>б) Из разности чисел 720048 и 97256 вычесть сумму чисел 36809 и 250249.</span>\n<span>в) К сумме чисел 777777 и 66666 прибавить разность чисел 111111 и 99999.</span></p>', 'а) 208400 – (18000 – 9762) = 208400 – 8238 = 200162', '<p>а) 208400 – (18000 – 9762) = 208400 – 8238 = 200162</p>\n\n<div class="img-wrapper-460">\n<img width="170" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica102-nomer8.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 102, номер 8, год 2022, ответ." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 102, номер 8, год 2022, ответ."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-102/')
    RETURNING id INTO v_task_id;

