    VALUES (v_task_id, v_textbook_id, 3, '21a2dbef78ec3426c10c1acef028d0e471bc6d34144719fb9587433b18f74f5f', '9762,18000,36809,66666,97256,99999,111111,208400,250249,720048', '["найди","разность","уменьшаемое","вычитаемое","раз"]'::jsonb, 'составь выражения и найди их значения:а) уменьшаемое 208400, вычитаемое выражено разностью чисел 18000 и 9762. б) из разности чисел 720048 и 97256 вычесть сумму чисел 36809 и 250249. в) к сумме чисел 777777 и 66666 прибавить разность чисел 111111 и 99999');

    VALUES (v_textbook_id, 102, '9', 3, 'БЛИЦтурнир а) Петя прошёл полем а км, а лесом – в 2 раза меньше. Сколько всего километров прошёл Петя полем и лесом? б) Аня шла в школу b мин, а возвращалась домой с мин. На сколько меньше времени она затратила на дорогу в школу, чем на дорогу домой? в) Первая перемена длится n мин, вторая – на 5 мин дольше первой. А третья перемена в 2 раза короче первой. Сколько времени длятся все эти три перемены вместе? г) Учительница принесла в класс х тетрадей. Из них у тетрадей она отложила, а остальные раздала поровну 20 ученикам. Сколько тетрадей получил каждый ученик? д) В буфет привезли а кг конфет. В течение 3 дней расходовали по b кг конфет в день. Сколько килограммов конфет ещё осталось?', '</p>\n\n<p class="text"><span><b>БЛИЦтурнир</b></span>\n<span>а) Петя прошёл полем <b>а</b> км, а лесом – в 2 раза меньше.  Сколько  всего  километров  прошёл Петя полем и лесом?</span>\n<span>б) Аня шла в школу <b>b</b> мин, а возвращалась домой <b>с</b> мин. На сколько меньше времени она затратила на дорогу в школу, чем на дорогу домой?</span>\n<span>в) Первая перемена длится <b>n</b> мин, вторая – на 5 мин дольше первой. А третья перемена в 2 раза короче первой. Сколько времени длятся все эти три перемены вместе?</span>\n<span>г) Учительница принесла в класс <b>х</b> тетрадей. Из них <b>у</b> тетрадей она отложила, а остальные раздала поровну 20 ученикам. Сколько тетрадей получил каждый ученик?</span>\n<span>д) В буфет привезли <b>а</b> кг конфет. В течение 3 дней расходовали по <b>b</b> кг конфет в день. Сколько килограммов конфет ещё осталось?</span></p>', 'а) а + а : 2 км      Ответ: а + а : 2 всего километров прошёл Петя полем и лесом. б) b – с мин      Ответ: на b – с меньше времени она затратила на дорогу в школу, чем на дорогу домой. в) n + (n – 5) + n : 2 мин      Ответ: n + (n – 5) + n : 2 времени длятся все эти три перемены вместе. г) (х – у) : 20 тетрадей      Ответ: (х – у) : 20 тетрадей получил каждый ученик. д) а - 3b кг      Ответ: а – 3b килограммов конфет ещё осталось.', '<p><span>а) а + а : 2 км</span>\n<span>    <b>Ответ:</b> а + а : 2 всего  километров  прошёл Петя полем и лесом.</span>\n<span>б) b – с мин</span>\n<span>    <b>Ответ:</b> на b – с меньше времени она затратила на дорогу в школу, чем на дорогу домой.</span>\n<span>в) n + (n – 5) + n : 2 мин</span>\n<span>    <b>Ответ:</b> n + (n – 5) + n : 2 времени длятся все эти три перемены вместе.</span>\n<span>г) (х – у) : 20 тетрадей</span>\n<span>    <b>Ответ:</b> (х – у) : 20 тетрадей получил каждый ученик.</span>\n<span>д) а - 3b кг</span>\n<span>    <b>Ответ:</b> а – 3b килограммов конфет ещё осталось.</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-102/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '7fc8f50abb1dc337fba3aa254c72deda5c5891144d66e9278274007a2042d70f', '2,3,5,20', '["меньше","раз","раза"]'::jsonb, 'блицтурнир а) петя прошёл полем а км, а лесом-в 2 раза меньше. сколько всего километров прошёл петя полем и лесом? б) аня шла в школу b мин, а возвращалась домой с мин. на сколько меньше времени она затратила на дорогу в школу, чем на дорогу домой? в) первая перемена длится n мин, вторая-на 5 мин дольше первой. а третья перемена в 2 раза короче первой. сколько времени длятся все эти три перемены вместе? г) учительница принесла в класс х тетрадей. из них у тетрадей она отложила, а остальные раздала поровну 20 ученикам. сколько тетрадей получил каждый ученик? д) в буфет привезли а кг конфет. в течение 3 дней расходовали по b кг конфет в день. сколько килограммов конфет ещё осталось');

    VALUES (v_textbook_id, 102, '10', 4, 'Реши уравнения с комментированием и сделай проверку: х + 518 = 9004      х – 768 = 32      57100 – х = 236', '</p>\n\n<p class="text">Реши уравнения с комментированием и сделай проверку:</p>\n\n<p class="description-text">\nх + 518 = 9004      х – 768 = 32      57100 – х = 236</p>', 'х + 518 = 9004 Чтобы найти слагаемое х надо из суммы вычесть известное слагаемое. х = 9004 – 518', '<p><span>х + 518 = 9004</span>\n<span>Чтобы найти слагаемое х надо из суммы вычесть известное слагаемое.</span>\n<span>х = 9004 – 518</span></p>\n\n<div class="img-wrapper-460">\n<img width="120" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica102-nomer10.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 102, номер 10, год 2022, ответ." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 102, номер 10, год 2022, ответ."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-102/')
    RETURNING id INTO v_task_id;

