    VALUES (v_task_id, v_textbook_id, 3, '25bf3aaa9310b52fb9574f6bc500575081c761a757b30973794473a0d45eab83', '32,236,518,768,9004,57100', '["реши"]'::jsonb, 'реши уравнения с комментированием и сделай проверку:х+518=9004      х-768=32      57100-х=236');

    VALUES (v_textbook_id, 103, '11', 0, 'На зиму Медвежонок заготовил три бочонка мёда. В первом бочонке было 72 кг, во втором бочонке – в 3 раза меньше, чем в первом, а в третьем – на 68 кг больше, чем во втором. Сколько килограммов мёда заготовил Медвежонок на зиму?', '</p>\n\n<p class="text">На зиму Медвежонок заготовил три бочонка мёда. В первом бочонке было 72 кг, во втором бочонке – в 3 раза меньше, чем в первом, а в третьем – на 68 кг больше, чем во втором. Сколько килограммов мёда заготовил Медвежонок на зиму?</p>\n\n<div class="img-wrapper-460">\n<img width="340" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica103-nomer11.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 103, номер 11, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 103, номер 11, год 2022."/>\n</div>', '72 + (72 : 3) + (72 : 3 + 68) = 72 + 26 + 94 = 72 + 120 = 192 (кг) Ответ: 192 килограммов мёда заготовил Медвежонок на зиму.', '<p><span>72 + (72 : 3) + (72 : 3 + 68) = 72 + 26 + 94 = 72 + 120 = 192 (кг)</span>\n<span><b>Ответ:</b> 192 килограммов мёда заготовил Медвежонок на зиму.</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-103/')
    RETURNING id INTO v_task_id;

