    VALUES (v_task_id, v_textbook_id, 3, '9022d863305b742d2794d751f1f9eac752e1c8c18d1eb01903aef64a6e60b928', '3,68,72', '["больше","меньше","раз","раза"]'::jsonb, 'на зиму медвежонок заготовил три бочонка мёда. в первом бочонке было 72 кг, во втором бочонке-в 3 раза меньше, чем в первом, а в третьем-на 68 кг больше, чем во втором. сколько килограммов мёда заготовил медвежонок на зиму');

    VALUES (v_textbook_id, 103, '12', 1, 'а) Составь выражение, значение которого равно 150. б) Составь произведение суммы и разности, значение которого равно 24.', '</p>\n\n<p class="text"><span>а) Составь выражение, значение которого равно 150.</span>\n<span>б) Составь произведение суммы и разности, значение которого равно 24.</span></p>', 'а) 100 + 50 = 150 б) (1 + 0) · (24 – 0) = 24', '<p><span>а) 100 + 50 = 150</span>\n<span>б) (1 + 0) · (24 – 0) = 24</span></p>', '', '', TRUE, '[{"letter":"а","condition":"Составь выражение, значение которого равно 150.","solution":"100 + 50 = 150"},{"letter":"б","condition":"Составь произведение суммы и разности, значение которого равно 24.","solution":"(1 + 0) · (24 – 0) = 24"}]'::jsonb, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-103/')
