    VALUES (v_textbook_id, 103, '13', 2, 'Вычисли. Наложи прозрачную плёнку и соедини ответы по порядку. Что получилось?', '</p>\n\n<p class="text">Вычисли. Наложи прозрачную плёнку и соедини ответы по порядку. Что получилось?</p>\n\n<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica103-nomer13.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 103, номер 13, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 103, номер 13, год 2022."/>\n</div>', '1. 45800 : 100 · 10 = 4580 2. 1000 · 24 : 100 = 240 3. 600 · 10 : 1000 = 6 4. 3600 : 10 · 100 = 36000 5. 52 · 1000 : 100 = 520 6. 90 · 40 = 3600 7. 5 · 80 = 400 8. 600 · 8 = 4800 9. 9 · 700 = 6300 10. 60 · 50 = 3000 11. 810 : 90 = 9 12. 2800 : 700 = 4 13. 3500 : 50 = 70 14. 1800 : 900 = 2 15. 420 : 70 = 6', '<p><span>1. 45800 : 100 · 10 = 4580</span>\n<span>2. 1000 · 24 : 100 = 240</span>\n<span>3. 600 · 10 : 1000 = 6</span>\n<span>4. 3600 : 10 · 100 = 36000</span>\n<span>5. 52 · 1000 : 100 = 520</span>\n<span>6. 90 · 40 = 3600</span>\n<span>7. 5 · 80 = 400</span>\n<span>8. 600 · 8 = 4800</span>\n<span>9. 9 · 700 = 6300</span>\n<span>10. 60 · 50 = 3000</span>\n<span>11. 810 : 90 = 9</span>\n<span>12. 2800 : 700 = 4</span>\n<span>13. 3500 : 50 = 70</span>\n<span>14. 1800 : 900 = 2</span>\n<span>15. 420 : 70 = 6</span></p>\n\n<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica103-nomer13-1.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 103, номер 13, год 2022, ответ." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 103, номер 13, год 2022, ответ."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-103/')
    RETURNING id INTO v_task_id;

