    VALUES (v_textbook_id, 103, '14', 3, 'Запиши множество всех четырёхзначных чисел, у которых: а) все цифры одинаковые; б) сумма цифр равна 3.', '</p>\n\n<p class="text">Запиши множество всех четырёхзначных чисел, у которых:</p>\n\n<p class="description-text">\n<span>а) все цифры одинаковые;</span>\n<span>б) сумма цифр равна 3.</span></p>', 'а) 1111, 2222, 3333, 4444, 5555, 6666, 7777, 8888, 9999 б) 1002, 1011, 1020, 1101, 1110, 1200', '<p><span>а) 1111, 2222, 3333, 4444, 5555, 6666, 7777, 8888, 9999</span>\n<span>б) 1002, 1011, 1020, 1101, 1110, 1200</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-103/')
    RETURNING id INTO v_task_id;

