    VALUES (v_textbook_id, 104, '1', 0, 'Определи по схеме, сколько миллиметров в 1 дециметре? Сколько дециметров в 1 километре? Что означают стрелки? Как преобразовать единицы длины?', '</p>\n\n<p class="text">Определи по схеме, сколько миллиметров в 1 дециметре? Сколько дециметров в 1 километре?</p>\n\n<div class="img-wrapper-460">\n<img width="350" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica104-nomer1.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 104, номер 1, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 104, номер 1, год 2022."/>\n</div>\n\n<p class="text">Что означают стрелки? Как преобразовать единицы длины?</p>', '1 дм = 100 мм, 1 км = 10000 дм, указывают в какую сторону нужно совершать действие, для преобразования единицы длины нужно при переходе к меньшим меркам выполнять умножение, а при переходе к бо́льшим меркам – деление.', '<p>1 дм = 100 мм, 1 км = 10000 дм, указывают в какую сторону нужно совершать действие, для преобразования единицы длины нужно при переходе к меньшим меркам выполнять умножение, а при переходе к бо́льшим меркам – деление.</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-104/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, 'condition', 0, NULL, 'https://gdz-raketa.ru/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica104-nomer1.jpg', 'peterson/3/part1/page104/task1_condition_0.jpg', '');

    VALUES (v_task_id, v_textbook_id, 3, '943441845ff9facce1ab7cf1e44c2372b37e43dac33638b6d33a41bc7db1c85c', '1', '["раз"]'::jsonb, 'определи по схеме, сколько миллиметров в 1 дециметре? сколько дециметров в 1 километре? что означают стрелки? как преобразовать единицы длины');

    VALUES (v_textbook_id, 104, '2', 1, 'Вырази в указанных единицах измерения. Что ты замечаешь? а) 205 =     д.     ед.     205 см =     дм.     см.     205 мм =     см.     мм. б) 8020 =     тыс.     ед.     8020 м =     км.     м.     8020 мм =     м.     мм.', '</p>\n\n<p class="text">Вырази в указанных единицах измерения. Что ты замечаешь?</p>\n\n<p class="description-text">\n<span>а) 205 = <span class="okon">   </span> д. <span class="okon">   </span> ед.</span>\n<span>    205 см = <span class="okon">   </span> дм. <span class="okon">   </span> см.</span>\n<span>    205 мм = <span class="okon">   </span> см. <span class="okon">   </span> мм.</span>\n<br/>\n<span>б) 8020 = <span class="okon">   </span> тыс. <span class="okon">   </span> ед.</span>\n<span>    8020 м = <span class="okon">   </span> км. <span class="okon">   </span> м.</span>\n<span>    8020 мм = <span class="okon">   </span> м. <span class="okon">   </span> мм.</span></p>', 'а) 205 = 20 д. 5 ед.     205 см = 20 дм. 5 см.     205 мм = 20 см. 5 мм. б) 8020 = 8 тыс. 20 ед.     8020 м = 8 км. 20 м.     8020 мм = 8 м. 20 мм.', '<p><span>а) 205 = 20 д. 5 ед.</span>\n<span>    205 см = 20 дм. 5 см.</span>\n<span>    205 мм = 20 см. 5 мм.</span>\n<br/>\n<span>б) 8020 = 8 тыс. 20 ед.</span>\n<span>    8020 м = 8 км. 20 м.</span>\n<span>    8020 мм = 8 м. 20 мм.</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-104/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, 'b1220996c476214c76e109294612d9eaa0b158f28032df3bc911d0653386e3ef', '205,8020', '["раз"]'::jsonb, 'вырази в указанных единицах измерения. что ты замечаешь? а) 205=    д.     ед.     205 см=    дм.     см.     205 мм=    см.     мм. б) 8020=    тыс.     ед.     8020 м=    км.     м.     8020 мм=    м.     мм');

    VALUES (v_textbook_id, 104, '3', 2, 'Вырази: а) в сантиметрах: 40 мм; 3 дм 6 см; 58 м; 2 м 3 см; б) в миллиметрах: 7 см; 1 см 5 мм; 4 дм; 6 дм 2 мм; в) метрах: 3 км; 5 км 14 м; 82 км 5 м; 9000 см.', '</p>\n\n<p class="text">Вырази:</p>\n\n<p class="description-text">\n<span>а) в сантиметрах: 40 мм; 3 дм 6 см; 58 м; 2 м 3 см;</span>\n<span>б) в миллиметрах: 7 см; 1 см 5 мм; 4 дм; 6 дм 2 мм;</span>\n<span>в) метрах: 3 км; 5 км 14 м; 82 км 5 м; 9000 см.</span></p>', 'а) 40 мм = 4 см; 3 дм 6 см = 36 см; 58 м = 5800 см; 2 м 3 см = 203 см; б) 7 см = 70 мм; 1 см 5 мм = 15 мм; 4 дм = 400 мм; 6 дм 2 мм = 602 мм; в) 3 км = 3000 м; 5 км 14 м = 5014 м; 82 км 5 м = 82005 м; 9000 см = 90 м.', '<p><span>а) 40 мм = 4 см; 3 дм 6 см = 36 см; 58 м = 5800 см; 2 м 3 см = 203 см;</span>\n<span>б) 7 см = 70 мм; 1 см 5 мм = 15 мм; 4 дм = 400 мм; 6 дм 2 мм = 602 мм;</span>\n<span>в) 3 км = 3000 м; 5 км 14 м = 5014 м; 82 км 5 м = 82005 м; 9000 см = 90 м.</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-104/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '5e84af6ccca6caf91fdbc5373c14e4b2f7729cbc6b8fb5d60fd0d4aa01749215', '1,2,3,4,5,6,7,14,40,58', '["раз"]'::jsonb, 'вырази:а) в сантиметрах:40 мм; 3 дм 6 см; 58 м; 2 м 3 см; б) в миллиметрах:7 см; 1 см 5 мм; 4 дм; 6 дм 2 мм; в) метрах:3 км; 5 км 14 м; 82 км 5 м; 9000 см');

    VALUES (v_textbook_id, 104, '4', 3, 'Выполни действия: а) 4 дм 2 см + 9 см 6 мм б) 3 м – 2 дм 5 см в) 1 км 3 м – 89 м г) 5 дм 9 см 3 мм + 47 мм д) 7 м 2 дм 5 см + 24 м 72 см е) 6 км – 4 км 32 м ж) 90 м 2 см – 6 м 4 дм 2 см з) 2 дм 98 мм + 4 м 2 мм', '</p>\n\n<p class="text">Выполни действия:</p>\n\n<p class="description-text">\n<span>а) 4 дм 2 см + 9 см 6 мм</span>\n<span>б) 3 м – 2 дм 5 см</span>\n<span>в) 1 км 3 м – 89 м</span>\n<span>г) 5 дм 9 см 3 мм + 47 мм</span>\n<span>д) 7 м 2 дм 5 см + 24 м 72 см</span>\n<span>е) 6 км – 4 км 32 м</span>\n<span>ж) 90 м 2 см – 6 м 4 дм 2 см</span>\n<span>з) 2 дм 98 мм + 4 м 2 мм</span></p>', 'а) 4 дм 2 см + 9 см 6 мм = 51 см 6 мм б) 3 м – 2 дм 5 см = 2 м 7 дм 5 см в) 1 км 3 м – 89 м = 914 м г) 5 дм 9 см 3 мм + 47 мм = 5 дм 14 см д) 7 м 2 дм 5 см + 24 м 72 см = 31 м 97 см е) 6 км – 4 км 32 м = 1 км 968 м ж) 90 м 2 см – 6 м 4 дм 2 см = 83 м 6 дм з) 2 дм 98 мм + 4 м 2 мм = 4 м 3 дм', '<p><span>а) 4 дм 2 см + 9 см 6 мм = 51 см 6 мм</span>\n<span>б) 3 м – 2 дм 5 см = 2 м 7 дм 5 см</span>\n<span>в) 1 км 3 м – 89 м = 914 м</span>\n<span>г) 5 дм 9 см 3 мм + 47 мм = 5 дм 14 см</span>\n<span>д) 7 м 2 дм 5 см + 24 м 72 см = 31 м 97 см</span>\n<span>е) 6 км – 4 км 32 м = 1 км 968 м</span>\n<span>ж) 90 м 2 см – 6 м 4 дм 2 см = 83 м 6 дм</span>\n<span>з) 2 дм 98 мм + 4 м 2 мм = 4 м 3 дм</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-104/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, 'fa62a2def4a320aba7e8639255b5606e45e53ea871af83aa734c5480b8b77378', '1,2,3,4,5,6,7,9,24,32', NULL, 'выполни действия:а) 4 дм 2 см+9 см 6 мм б) 3 м-2 дм 5 см в) 1 км 3 м-89 м г) 5 дм 9 см 3 мм+47 мм д) 7 м 2 дм 5 см+24 м 72 см е) 6 км-4 км 32 м ж) 90 м 2 см-6 м 4 дм 2 см з) 2 дм 98 мм+4 м 2 мм');

    VALUES (v_textbook_id, 104, '5', 4, 'Прочитай выражения разными способами:                   а + 3 · b и (а + 3) · b Найди их значения, если а = 5, b = 10. Что ты замечаешь?', '</p>\n\n<p class="text">Прочитай выражения разными способами:</p>\n\n<p class="description-text">\n                  а + 3 · b и (а + 3) · b</p>\n\n<p class="text">Найди их значения, если а = 5, b = 10. Что ты замечаешь?</p>', 'Сумма а и произведения 3 на b, произведение суммы а и 3 на b 5 + 3 · 10 = 35 (5 + 3) · 10 = 80 Результат различный, при наличии скобок меняется порядок выполнения действий.', '<p><span>Сумма а и произведения 3 на b, произведение суммы а и 3 на b</span>\n<span>5 + 3 · 10 = 35</span>\n<span>(5 + 3) · 10 = 80</span>\n<span>Результат различный, при наличии скобок меняется порядок выполнения действий.</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-104/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '28e44c016524efdf70c8c60ca7dd73860397b0aa086b394833a83118bd3d033e', '3,5,10', '["найди","раз"]'::jsonb, 'прочитай выражения разными способами:                  а+3*b и (а+3)*b найди их значения, если а=5, b=10. что ты замечаешь');

    VALUES (v_textbook_id, 104, '6', 5, 'БЛИЦтурнир а) У Гриши было d моделей машин, а моделей самолётов – на 8 меньше. Во сколько раз меньше моделей самолётов, чем машин, было у Гриши? б) В 3 одинаковых коробках b конфет. Сколько конфет в 7 таких коробках? в) В 4 одинаковых банках k литров варенья. Сколько банок нужно, чтобы разлить в них m литров варенья?', '</p>\n\n<p class="text"><span><b>БЛИЦтурнир</b></span>\n<span>а) У Гриши было <b>d</b> моделей машин, а моделей самолётов – на 8 меньше. Во сколько раз меньше моделей самолётов, чем машин, было у Гриши?</span>\n<span>б) В 3 одинаковых коробках <b>b</b> конфет. Сколько конфет в 7 таких коробках?</span>\n<span>в) В 4 одинаковых банках <b>k</b> литров варенья. Сколько банок нужно, чтобы разлить в них <b>m</b> литров варенья?</span></p>', 'а) d : (d – 8)      Ответ: в d : (d – 8) раз меньше моделей самолётов, чем машин, было у Гриши. б) b : 3 · 7      Ответ: b : 3 · 7 конфет в 7 таких коробках. в) m : k : 4      Ответ: m : k : 4 банок нужно, чтобы разлить в них m литров варенья.', '<p><span>а) d : (d – 8)</span>\n<span>    <b>Ответ:</b> в d : (d – 8) раз меньше моделей самолётов, чем машин, было у Гриши.</span>\n<span>б) b : 3 · 7</span>\n<span>    <b>Ответ:</b> b : 3 · 7 конфет в 7 таких коробках.</span>\n<span>в) m : k : 4</span>\n<span>    <b>Ответ:</b> m : k : 4 банок нужно, чтобы разлить в них m литров варенья.</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-104/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '1562dd948b7f179f6815d94b23a1a6e44778548d07d6bb08b5520f0656575bc9', '3,4,7,8', '["меньше","раз"]'::jsonb, 'блицтурнир а) у гриши было d моделей машин, а моделей самолётов-на 8 меньше. во сколько раз меньше моделей самолётов, чем машин, было у гриши? б) в 3 одинаковых коробках b конфет. сколько конфет в 7 таких коробках? в) в 4 одинаковых банках k литров варенья. сколько банок нужно, чтобы разлить в них m литров варенья');

    VALUES (v_textbook_id, 105, '7', 0, 'а) Отметь три точки А, В и С. Начерти треугольник АВС. Измерь его стороны и найди периметр. б) Выполни то же задание для четырёхугольника DЕFK.', '</p>\n\n<p class="text"><span>а) Отметь три точки А, В и С. Начерти треугольник АВС. Измерь его стороны и найди периметр.</span>\n<span>б) Выполни то же задание для четырёхугольника DЕFK.</span></p>', '', '<div class="img-wrapper-460">\n<img width="340" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica105-nomer7.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 105, номер 7, год 2022, ответ." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 105, номер 7, год 2022, ответ."/>', '', '', TRUE, '[{"letter":"а","condition":"Отметь три точки А, В и С. Начерти треугольник АВС. Измерь его стороны и найди периметр.","solution":""},{"letter":"б","condition":"Выполни то же задание для четырёхугольника DЕFK.","solution":""}]'::jsonb, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-105/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, 'solution', 0, NULL, 'https://gdz-raketa.ru/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica105-nomer7.jpg', 'peterson/3/part1/page105/task7_solution_0.jpg', '');

    VALUES (v_task_id, v_textbook_id, 3, '7dc743726e3f77453805549d56b80ccaac3aee5c5b0fbd27df4da6104be98ccf', NULL, '["найди","периметр"]'::jsonb, 'а) отметь три точки а, в и с. начерти треугольник авс. измерь его стороны и найди периметр. б) выполни то же задание для четырёхугольника dеfk');

    VALUES (v_textbook_id, 105, '8', 1, 'Известно, что АВ = 3 см 6 мм, ВС = 5 см 4 мм. Начерти отрезки АВ и ВС так, чтобы: 1) В ∈ АС      2) В ∉ АС В каждом из этих случаев сравни длину отрезка АС с суммой длин отрезков АВ и ВС. Что ты замечаешь? Как можно объяснить полученный результат?', '</p>\n\n<p class="text">Известно, что АВ = 3 см 6 мм, ВС = 5 см 4 мм. Начерти отрезки АВ и ВС так, чтобы:</p>\n\n<p class="description-text">\n1) В ∈ АС      2) В ∉ АС</p>\n\n<p class="text">В каждом из этих случаев сравни длину отрезка АС с суммой длин отрезков АВ и ВС. Что ты замечаешь? Как можно объяснить полученный результат?</p>', '1) AC = AB + BC = 3 см 6 мм + 5 см 4 мм = 8 см 10 мм = 9 см', '<p>1) AC = AB + BC = 3 см 6 мм + 5 см 4 мм = 8 см 10 мм = 9 см</p>\n\n<div class="img-wrapper-460">\n<img width="270" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica105-nomer8.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 105, номер 8, год 2022, ответ." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 105, номер 8, год 2022, ответ."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-105/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, 'solution', 0, NULL, 'https://gdz-raketa.ru/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica105-nomer8.jpg', 'peterson/3/part1/page105/task8_solution_0.jpg', '');

    VALUES (v_task_id, v_textbook_id, 3, 'd3f748a373e2ba60312112ccc6e3d062f9c2a219143a57c00db29f5565c81101', '1,2,3,4,5,6', '["сравни"]'::jsonb, 'известно, что ав=3 см 6 мм, вс=5 см 4 мм. начерти отрезки ав и вс так, чтобы:1) в ∈ ас      2) в ∉ ас в каждом из этих случаев сравни длину отрезка ас с суммой длин отрезков ав и вс. что ты замечаешь? как можно объяснить полученный результат');

    VALUES (v_textbook_id, 105, '9', 2, 'Выполни действия: а) 396579 + 83624 б) 530217 – 482635 в) 2039455 + 82167 + 714305 г) 7004210 – 34514 д) 7800 · 7 е) 820 · 800 ж) 90 · 6800 з) 95000 · 300 и) 3000 : 6 к) 2500 : 50 л) 200000 : 4000 м) 35000 : 700', '</p>\n\n<p class="text">Выполни действия:</p>\n\n<p class="description-text">\n<span>а) 396579 + 83624</span>\n<span>б) 530217 – 482635</span>\n<span>в) 2039455 + 82167 + 714305</span>\n<span>г) 7004210 – 34514</span>\n<span>д) 7800 · 7</span>\n<span>е) 820 · 800</span>\n<span>ж) 90 · 6800</span>\n<span>з) 95000 · 300</span>\n<span>и) 3000 : 6</span>\n<span>к) 2500 : 50</span>\n<span>л) 200000 : 4000</span>\n<span>м) 35000 : 700</span></p>', 'а) 396579 + 83624 = 480203', '<p>а) 396579 + 83624 = 480203</p>\n\n<div class="img-wrapper-460">\n<img width="200" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica105-nomer9.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 105, номер 9, год 2022, ответ." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 105, номер 9, год 2022, ответ."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-105/')
    RETURNING id INTO v_task_id;

