    VALUES (v_task_id, v_textbook_id, 3, 'efcb9b0e9e6d699151c60b76626273942f5fd7c0aca41f0362043eb3cfab900f', '6,7,50,90,300,700,800,820,2500,3000', NULL, 'выполни действия:а) 396579+83624 б) 530217-482635 в) 2039455+82167+714305 г) 7004210-34514 д) 7800*7 е) 820*800 ж) 90*6800 з) 95000*300 и) 3000:6 к) 2500:50 л) 200000:4000 м) 35000:700');

    VALUES (v_textbook_id, 105, '10', 3, 'Прочитай задачи. Можно ли их решить? Почему? а) Андрей купил 4 конфеты. Сколько денег он заплатил? б) Сколько платьев можно сшить из 60 м ткани? в) Игорю – 8 лет, а Денису – 10 лет. На сколько сантиметров Денис выше Игоря? Определи, каких данных недостает. Придумай для них значения и реши эти задачи.', '</p>\n\n<p class="text">Прочитай задачи. Можно ли их решить? Почему?</p>\n\n<p class="description-text">\n<span>а) Андрей купил 4 конфеты. Сколько денег он заплатил?</span>\n<span>б) Сколько платьев можно сшить из 60 м ткани?</span>\n<span>в) Игорю – 8 лет, а Денису – 10 лет. На сколько сантиметров Денис выше Игоря?</span></p>\n\n<p class="text">Определи, каких данных недостает. Придумай для них значения и реши эти задачи.</p>', 'а) если конфета стоила 50 рублей, тогда: 4 · 50 = 200 (рублей)      Ответ: 40 рублей всего заплатил Андрей. б) решить задачу нельзя, так как неизвестно сколько метров расходуется на одно платье. Если на одно платье расходуется 10 м ткани, тогда: 60 : 10 = 600 (платьев)      Ответ: 600 платьев можно сшить из 60 м ткани. в) решить задачу нельзя, так как не указан рост мальчиков. Пусть рост Игоря 2 м, а рост Дениса 2 м 50 см, тогда: 2 м 50 см – 2 м = 50 (см)      Ответ: на 50 сантиметров Денис выше Игоря.', '<p><span>а) если конфета стоила 50 рублей, тогда: 4 · 50 = 200 (рублей)</span>\n<span>    <b>Ответ:</b> 40 рублей всего заплатил Андрей.</span>\n<span>б) решить задачу нельзя, так как неизвестно сколько метров расходуется на одно платье. Если на одно платье расходуется 10 м ткани, тогда: 60 : 10 = 600 (платьев)</span>\n<span>    <b>Ответ:</b> 600 платьев можно сшить из 60 м ткани.</span>\n<span>в) решить задачу нельзя, так как не указан рост мальчиков. Пусть рост Игоря 2 м, а рост Дениса 2 м 50 см, тогда: 2 м 50 см – 2 м = 50 (см)</span>\n<span>    <b>Ответ:</b> на 50 сантиметров Денис выше Игоря.</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-105/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, 'dc841decb8c195e4c1d259f529c54d4041ab3f5122d2027397252100f109f335', '4,8,10,60', '["реши"]'::jsonb, 'прочитай задачи. можно ли их решить? почему? а) андрей купил 4 конфеты. сколько денег он заплатил? б) сколько платьев можно сшить из 60 м ткани? в) игорю-8 лет, а денису-10 лет. на сколько сантиметров денис выше игоря? определи, каких данных недостает. придумай для них значения и реши эти задачи');

    VALUES (v_textbook_id, 105, '11', 4, 'Составь программу действий и вычисли: а) 9 · 4 : 6 + (18 + 22) : 8 – 48 : (3 · 8 – 2 · 9) б) 5 · (30 – 7 · 3) – (50 – 18) : (28 : 7) + 81 : 9 · 7', '</p>\n\n<p class="text">Составь программу действий и вычисли:</p>\n\n<p class="description-text">\n<span>а) 9 · 4 : 6 + (18 + 22) : 8 – 48 : (3 · 8 – 2 · 9)</span>\n<span>б) 5 · (30 – 7 · 3) – (50 – 18) : (28 : 7) + 81 : 9 · 7</span></p>', 'а) 9 · 4 : 6 + (18 + 22) : 8 – 48 : (3 · 8 – 2 · 9) = 3     18 + 22 = 40     40 : 8 = 5     3 · 8 = 24     2 · 9 = 18     24 – 18 = 6     48 : 6 = 8     9 · 4 = 36     36 : 6 = 6     6 + 5 = 11     11 – 8 = 3 б) 5 · (30 – 7 · 3) – (50 – 18) : (28 : 7) + 81 : 9 · 7 = 100     7 · 3 = 21     30 – 21 = 9     5 · 9 = 45     50 – 18 = 32     28 : 7 = 4     32 : 4 = 8     81 : 9 = 9     9 · 7 = 63     45 – 8 = 37     37 + 63 = 100', '<p><span>а) 9 · 4 : 6 + (18 + 22) : 8 – 48 : (3 · 8 – 2 · 9) = 3</span>\n<span>    18 + 22 = 40</span>\n<span>    40 : 8 = 5</span>\n<span>    3 · 8 = 24</span>\n<span>    2 · 9 = 18</span>\n<span>    24 – 18 = 6</span>\n<span>    48 : 6 = 8</span>\n<span>    9 · 4 = 36</span>\n<span>    36 : 6 = 6</span>\n<span>    6 + 5 = 11</span>\n<span>    11 – 8 = 3</span>\n<span>б) 5 · (30 – 7 · 3) – (50 – 18) : (28 : 7) + 81 : 9 · 7 = 100</span>\n<span>    7 · 3 = 21</span>\n<span>    30 – 21 = 9</span>\n<span>    5 · 9 = 45</span>\n<span>    50 – 18 = 32</span>\n<span>    28 : 7 = 4</span>\n<span>    32 : 4 = 8</span>\n<span>    81 : 9 = 9</span>\n<span>    9 · 7 = 63</span>\n<span>    45 – 8 = 37</span>\n<span>    37 + 63 = 100</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-105/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '42deb9269f4310239e4900ff1c90e98c6f416519b00fb62fb081675d2f072dd9', '2,3,4,5,6,7,8,9,18,22', '["вычисли"]'::jsonb, 'составь программу действий и вычисли:а) 9*4:6+(18+22):8-48:(3*8-2*9) б) 5*(30-7*3)-(50-18):(28:7)+81:9*7');

    VALUES (v_textbook_id, 105, '12', 5, 'Какую фигуру надо поставить вместо знака вопроса?', '</p>\n\n<p class="text">Какую фигуру надо поставить вместо знака вопроса?</p>\n\n<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica105-nomer12.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 105, номер 12, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 105, номер 12, год 2022."/>\n</div>', '', '<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica105-nomer12-1.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 105, номер 12, год 2022, ответ." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 105, номер 12, год 2022, ответ."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-105/')
    RETURNING id INTO v_task_id;

