    VALUES (v_task_id, v_textbook_id, 3, '1f3e37d73a9d9dd9a6f5a72a5ad0c54ac01854e4a5f46b7c4cef47a699826fba', NULL, NULL, 'какую фигуру надо поставить вместо знака вопроса');

    VALUES (v_textbook_id, 106, '1', 0, 'Чему равна масса арбуза? Чему равна масса одного яблока (все яблоки имеют одинаковую массу)? Какие более мелкие, чем килограмм, единицы массы ты знаешь? Какие более крупные единицы?', '</p>\n\n<p class="text">Чему равна масса арбуза? Чему равна масса одного яблока (все яблоки имеют одинаковую массу)?</p>\n\n<div class="img-wrapper-460">\n<img width="320" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica106-nomer1.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 106, номер 1, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 106, номер 1, год 2022."/>\n</div>\n\n<p class="text">Какие более мелкие, чем килограмм, единицы массы ты знаешь? Какие более крупные единицы?</p>', 'Равна масса арбуза 2 + 1 + 5 = 8 (кг) Равна масса одного яблока 1000 : 5 = 200 (г) Более мелкая единица – грамм, более крупная единица – центнер и тонна.', '<p><span>Равна масса арбуза 2 + 1 + 5 = 8 (кг)</span>\n<span>Равна масса одного яблока 1000 : 5 = 200 (г)</span>\n<span>Более мелкая единица – грамм, более крупная единица – центнер и тонна.</span></p>', 'Единицы массы Для измерения массы предметов, кроме килограмма, используют более мелкую единицу – грамм , а также более крупные единицы – центнер и тонна . 1 кг = 1000 г      1 ц = 100 кг      1 т = 1000 кг Соотношение между единицами массы:', '<div class="recomended-block">\n<span class="title">Единицы массы</span>\n<p>Для измерения массы предметов, кроме килограмма, используют более мелкую единицу – <b class="black">грамм</b>, а также более крупные единицы – <b class="black">центнер</b> и <b class="black">тонна</b>.<br/>\n1 кг = 1000 г      1 ц = 100 кг      1 т = 1000 кг<br/>\nСоотношение между единицами массы:</p>\n\n<div class="img-wrapper-460">\n<img width="280" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica106-recomended-block.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 106, рекомендательный блок, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 106, рекомендательный блок, год 2022."/>\n</div>', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-106/')
    RETURNING id INTO v_task_id;

