    VALUES (v_task_id, v_textbook_id, 3, 'e20ddf9dd7cc81d888e7976b7c7af5dd7e366f04d84f0e0144f92605f1c1799f', NULL, NULL, 'чему равна масса арбуза? чему равна масса одного яблока (все яблоки имеют одинаковую массу)? какие более мелкие, чем килограмм, единицы массы ты знаешь? какие более крупные единицы');

    VALUES (v_textbook_id, 106, '2', 1, 'Определи, чему равна масса винограда и масса дыни:', '</p>\n\n<p class="text">Определи, чему равна масса винограда и масса дыни:</p>\n\n<div class="img-wrapper-460">\n<img width="400" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica106-nomer2.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 106, номер 2, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 106, номер 2, год 2022."/>\n</div>', 'Mасса винограда: 2 + 1 = 3 (кг), 3000 – 200 = 2800 (г) 2800 = 2 кг 800 г. Mасса дыни: 5 кг 600 г – 1 кг = 4 кг 600 г.', '<p><span>Mасса винограда: 2 + 1 = 3 (кг), 3000 – 200 = 2800 (г) 2800 = 2 кг 800 г.</span>\n<span>Mасса дыни: 5 кг 600 г – 1 кг = 4 кг 600 г.</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-106/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, 'condition', 0, NULL, 'https://gdz-raketa.ru/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica106-nomer2.jpg', 'peterson/3/part1/page106/task2_condition_0.jpg', '');

    VALUES (v_task_id, v_textbook_id, 3, '732248b0d19067c7d167ae974df5bf4f695045bbeae80d0f3f4721c6dd253421', NULL, NULL, 'определи, чему равна масса винограда и масса дыни');

    VALUES (v_textbook_id, 106, '3', 2, 'Вырази в килограммах: а) 6000 г        в) 3 ц      д) 4 т     ж) 4 ц 32 кг     и) 5 т 2 ц 8 кг б) 28000 г      г) 5 ц      е) 9 т      з) 18 ц 7 кг      к) 6 т 15 кг', '</p>\n\n<p class="text">Вырази в килограммах:</p>\n\n<p class="description-text">\n<span>а) 6000 г        в) 3 ц      д) 4 т     ж) 4 ц 32 кг     и) 5 т 2 ц 8 кг</span>\n<span>б) 28000 г      г) 5 ц      е) 9 т      з) 18 ц 7 кг      к) 6 т 15 кг</span></p>', 'а) 6000 г = 6 кг. б) 28000 г = 28 кг. в) 3 ц = 300 кг. г) 5 ц = 500 кг. д) 4 т = 4000 кг. е) 9 т = 9000 кг. ж) 4 ц 32 кг = 432 кг. з) 18 ц 7 кг = 18007 кг. и) 5 т 2 ц 8 кг = 5208 кг. к) 6 т 15 кг = 6015 кг.', '<p><span>а) 6000 г = 6 кг.</span>\n<span>б) 28000 г = 28 кг.</span>\n<span>в) 3 ц = 300 кг.</span>\n<span>г) 5 ц = 500 кг.</span>\n<span>д) 4 т = 4000 кг.</span>\n<span>е) 9 т = 9000 кг.</span>\n<span>ж) 4 ц 32 кг = 432 кг.</span>\n<span>з) 18 ц 7 кг = 18007 кг.</span>\n<span>и) 5 т 2 ц 8 кг = 5208 кг.</span>\n<span>к) 6 т 15 кг = 6015 кг.</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-106/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '3222028a9d5b624633dbd8be706a3a722c9ed56c634ae7d63262a96d17711960', '2,3,4,5,6,7,8,9,15,18', '["раз"]'::jsonb, 'вырази в килограммах:а) 6000 г        в) 3 ц      д) 4 т     ж) 4 ц 32 кг     и) 5 т 2 ц 8 кг б) 28000 г      г) 5 ц      е) 9 т      з) 18 ц 7 кг      к) 6 т 15 кг');

    VALUES (v_textbook_id, 106, '4', 3, 'Вырази в граммах: а) 4 кг      б) 127 кг      в) 5 кг 200 г      г) 5 кг 20 г      д) 5 кг 2 г', '</p>\n\n<p class="text">Вырази в граммах:</p>\n\n<p class="description-text">\nа) 4 кг      б) 127 кг      в) 5 кг 200 г      г) 5 кг 20 г      д) 5 кг 2 г</p>', 'а) 4 кг = 4000 г. б) 127 кг = 127000 г. в) 5 кг 200 г = 5200 г. г) 5 кг 20 г = 5020 г. д) 5 кг 2 г = 5002 г.', '<p><span>а) 4 кг = 4000 г.</span>\n<span>б) 127 кг = 127000 г.</span>\n<span>в) 5 кг 200 г = 5200 г.</span>\n<span>г) 5 кг 20 г = 5020 г.</span>\n<span>д) 5 кг 2 г = 5002 г.</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-106/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, 'ebd11d6afbf286b6661f853fb2f3ab99518deec276edafdbf4994f802ba0fc80', '2,4,5,20,127,200', '["раз"]'::jsonb, 'вырази в граммах:а) 4 кг      б) 127 кг      в) 5 кг 200 г      г) 5 кг 20 г      д) 5 кг 2 г');

    VALUES (v_textbook_id, 107, '5', 0, 'Вырази в килограммах и граммах: а) 9675 г      б) 14300 г      в) 7004 г      г) 5628 г', '</p>\n\n<p class="text">Вырази в килограммах и граммах:</p>\n\n<p class="description-text">\nа) 9675 г      б) 14300 г      в) 7004 г      г) 5628 г</p>', 'а) 9675 г = 9 кг 675 г. б) 14300 г = 14 кг 300 г. в) 7004 г = 7 кг 4 г. г) 5628 г = 5 кг 628 г.', '<p><span>а) 9675 г = 9 кг 675 г.</span>\n<span>б) 14300 г = 14 кг 300 г.</span>\n<span>в) 7004 г = 7 кг 4 г.</span>\n<span>г) 5628 г = 5 кг 628 г.</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-107/')
    RETURNING id INTO v_task_id;

