    VALUES (v_textbook_id, 107, '6', 1, 'Вырази в центнерах: а) 800 кг      б) 9000 кг      в) 36 т      г) 8 т 3 ц', '</p>\n\n<p class="text">Вырази в центнерах:</p>\n\n<p class="description-text">\nа) 800 кг      б) 9000 кг      в) 36 т      г) 8 т 3 ц</p>', 'а) 800 кг = 8 ц. б) 9000 кг = 90 ц. в) 36 т = 360 ц. г) 8 т 3 ц = 83 ц.', '<p><span>а) 800 кг = 8 ц.</span>\n<span>б) 9000 кг = 90 ц.</span>\n<span>в) 36 т = 360 ц.</span>\n<span>г) 8 т 3 ц = 83 ц.</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-107/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '48de5649ff69d541727b1afe6c372ac02ecf2ec5789ba63a604bf33550893f93', '3,8,36,800,9000', '["раз"]'::jsonb, 'вырази в центнерах:а) 800 кг      б) 9000 кг      в) 36 т      г) 8 т 3 ц');

    VALUES (v_textbook_id, 107, '7', 2, 'Вырази в тоннах: а) 30 ц      б) 50000 кг      в) 400 ц      г) 2000000 г', '</p>\n\n<p class="text">Вырази в тоннах:</p>\n\n<p class="description-text">\nа) 30 ц      б) 50000 кг      в) 400 ц      г) 2000000 г</p>', 'а) 30 ц = 3 т. б) 50000 кг = 50 т. в) 400 ц = 40 т. г) 2000000 г = 2 т.', '<p><span>а) 30 ц = 3 т.</span>\n<span>б) 50000 кг = 50 т.</span>\n<span>в) 400 ц = 40 т.</span>\n<span>г) 2000000 г = 2 т.</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-107/')
