    VALUES (v_textbook_id, 107, '8', 3, 'а) Самое крупное животное на Земле – голубой кит. Его масса 120 т. Во сколько раз кит тяжелее слона, масса которого 5 т? б) В одном куске колбасы 1 кг 300 г, а в другом – на 400 г меньше. Сколько колбасы в обоих кусках вместе?', '</p>\n\n<p class="text"><span>а) Самое крупное животное на Земле – голубой кит. Его масса 120 т. Во сколько раз кит тяжелее слона, масса которого 5 т?</span>\n<span>б) В одном куске колбасы 1 кг 300 г, а в другом – на 400 г меньше. Сколько колбасы в обоих кусках вместе?</span></p>', 'а) 120 : 5 = 24 (раз)      Ответ: в 24 раза кит тяжелее слона, масса которого 5 т. б) (1 кг 300 г – 400 г) + 1 кг 300 г = (1300 г – 400 г) + 1300 г = 900 г + 1300 г = 2200 г = 2 кг 200 г      Ответ: 2 кг 200 г колбасы в обоих кусках вместе.', '<p><span>а) 120 : 5 = 24 (раз)</span>\n<span>    <b>Ответ:</b> в 24 раза кит тяжелее слона, масса которого 5 т.</span>\n<span>б) (1 кг 300 г – 400 г) + 1 кг 300 г = (1300 г – 400 г) + 1300 г = 900 г + 1300 г = 2200 г = 2 кг 200 г</span>\n<span>    <b>Ответ:</b> 2 кг 200 г колбасы в обоих кусках вместе.</span></p>', '', '', TRUE, '[{"letter":"а","condition":"Самое крупное животное на Земле – голубой кит. Его масса 120 т. Во сколько раз кит тяжелее слона, масса которого 5 т?","solution":"120 : 5 = 24 (раз)      Ответ: в 24 раза кит тяжелее слона, масса которого 5 т."},{"letter":"б","condition":"В одном куске колбасы 1 кг 300 г, а в другом – на 400 г меньше. Сколько колбасы в обоих кусках вместе?","solution":"(1 кг 300 г – 400"},{"letter":"г","condition":"","solution":"+ 1 кг 300 г = (1300 г – 400"}]'::jsonb, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-107/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '1733dd279aa666a61e52c4e5e818b6ae3b50d47433e557f1849a823c631d59c5', '1,5,120,300,400', '["меньше","раз"]'::jsonb, 'а) самое крупное животное на земле-голубой кит. его масса 120 т. во сколько раз кит тяжелее слона, масса которого 5 т? б) в одном куске колбасы 1 кг 300 г, а в другом-на 400 г меньше. сколько колбасы в обоих кусках вместе');

    VALUES (v_textbook_id, 107, '9', 4, 'Вычисли устно. Что ты замечаешь? Где нарушена закономерность? 9 · 8         16 · 3        5 · 19        6 · 90            70 · 40 72 : 9      48 : 16      95 : 5        5400 : 6        2800 : 40 72 : 8      48 : 3        95 : 19      5400 : 90      2800 : 70', '</p>\n\n<p class="text">Вычисли устно. Что ты замечаешь? Где нарушена закономерность?</p>\n\n<p class="description-text">\n<span>9 · 8         16 · 3        5 · 19        6 · 90            70 · 40</span>\n<span>72 : 9      48 : 16      95 : 5        5400 : 6        2800 : 40</span>\n<span>72 : 8      48 : 3        95 : 19      5400 : 90      2800 : 70</span></p>', '9 · 8 = 72      16 · 3 = 48      5 · 19 = 95      6 · 90 = 540           70 · 40 = 2800 72 : 9 = 8      48 : 16 = 3      95 : 5 = 19      5400 : 6 = 900      2800 : 40 = 70 72 : 8 = 9      48 : 3 = 16      95 : 19 = 5      5400 : 90 = 60      2800 : 70 = 40 Можно произведение разделить сначала на один множитель, а затем на другой получается другой множитель. Заметно что В четвёртом столбце нарушена закономерность.', '<p><span>9 · 8 = 72      16 · 3 = 48      5 · 19 = 95      6 · 90 = 540           70 · 40 = 2800</span>\n<span>72 : 9 = 8      48 : 16 = 3      95 : 5 = 19      5400 : 6 = 900      2800 : 40 = 70</span>\n<span>72 : 8 = 9      48 : 3 = 16      95 : 19 = 5      5400 : 90 = 60      2800 : 70 = 40</span>\n<br/>\n<span>Можно произведение разделить сначала на один множитель, а затем на другой получается другой множитель. Заметно что В четвёртом столбце нарушена закономерность.</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-107/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '136cabfa8715e031f58de9222d376161cc1489454fc7e00bdf06eaf8329de916', '3,5,6,8,9,16,19,40,48,70', '["вычисли"]'::jsonb, 'вычисли устно. что ты замечаешь? где нарушена закономерность? 9*8         16*3        5*19        6*90            70*40 72:9      48:16      95:5        5400:6        2800:40 72:8      48:3        95:19      5400:90      2800:70');

    VALUES (v_textbook_id, 107, '10', 5, 'Реши примеры. Расположи ответы примеров в порядке возрастания. Расшифруй название животного и узнай о нём информацию.', '</p>\n\n<p class="text">Реши примеры. Расположи ответы примеров в порядке возрастания. Расшифруй название животного и узнай о нём информацию.</p>\n\n<div class="img-wrapper-460">\n<img width="360" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica107-nomer10.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 107, номер 10, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 107, номер 10, год 2022."/>\n</div>', 'Р – 420 : 6 = 70      Г – 40 · 5 = 200            С – 280 : 7 = 40 И – 160 : 2 = 80      К – 9 · 600 = 5400       Б – 800 : 2 = 400 П – 350 : 7 = 50      О – 80 · 60 = 4800      Н – 300 : 3 = 100 СПРИНГБОК – африканская антилопа из подсемейства настоящих антилоп.', '<p><span>Р – 420 : 6 = 70      Г – 40 · 5 = 200            С – 280 : 7 = 40</span>\n<span>И – 160 : 2 = 80      К – 9 · 600 = 5400       Б – 800 : 2 = 400</span>\n<span>П – 350 : 7 = 50      О – 80 · 60 = 4800      Н – 300 : 3 = 100</span>\n<br/>\n<span>СПРИНГБОК – африканская антилопа из подсемейства настоящих антилоп.</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-107/')
