    VALUES (v_textbook_id, 108, '2', 1, 'а) Вырази число 9274 в десятках и единицах; сотнях и единицах; тысячах и единицах. б) Вырази 9274 мм в сантиметрах и миллиметрах; дециметрах и миллиметрах; метрах и миллиметрах. в) Вырази 9274 кг в центнерах и килограммах; тоннах и килограммах. Что ты замечаешь?', '</p>\n\n<p class="text"><span>а) Вырази число 9274 в десятках и единицах; сотнях и единицах; тысячах и единицах.</span>\n<span>б) Вырази 9274 мм в сантиметрах и миллиметрах; дециметрах и миллиметрах; метрах и миллиметрах.</span>\n<span>в) Вырази 9274 кг в центнерах и килограммах; тоннах и килограммах.</span>\n<span>Что ты замечаешь?</span></p>', 'а) 927 дес. 4 ед., 92 сот. 74 ед., 9 тыс. 274 ед. б) 927 см 4 мм, 92 дц 74 мм, 9 м 274 мм. в) 92 ц 74 кг. 9 т 274 кг. Можно заметить что разложение на единицы измерения похожи.', '<p><span>а) 927 дес. 4 ед., 92 сот. 74 ед., 9 тыс. 274 ед.</span>\n<span>б) 927 см 4 мм, 92 дц 74 мм, 9 м 274 мм.</span>\n<span>в) 92 ц 74 кг. 9 т 274 кг.</span>\n<br/>\n<span>Можно заметить что разложение на единицы измерения похожи.</span></p>', '', '', TRUE, '[{"letter":"а","condition":"Вырази число 9274 в десятках и единицах; сотнях и единицах; тысячах и единицах.","solution":"927 дес. 4 ед., 92 сот. 74 ед., 9 тыс. 274 ед."},{"letter":"б","condition":"Вырази 9274 мм в сантиметрах и миллиметрах; дециметрах и миллиметрах; метрах и миллиметрах.","solution":"927 см 4 мм, 92 дц 74 мм, 9 м 274 мм."},{"letter":"в","condition":"Вырази 9274 кг в центнерах и килограммах; тоннах и килограммах. Что ты замечаешь?","solution":"92 ц 74 кг. 9 т 274 кг. Можно заметить что разложение на единицы измерения похожи."}]'::jsonb, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-108/')
