    VALUES (v_textbook_id, 108, '4', 3, 'Вырази в указанных единицах измерения: а) 30005 г = ... кг ... г      в) 5 ц 4 кг = ... кг      д) 9 т 28 кг = ... кг б) 12 кг 9 г = ... г             г) 70000 кг = ... т      е) 4 т 6 ц = ... кг', '</p>\n\n<p class="text">Вырази в указанных единицах измерения:</p>\n\n<p class="description-text">\n<span>а) 30005 г = ... кг ... г      в) 5 ц 4 кг = ... кг      д) 9 т 28 кг = ... кг</span>\n<span>б) 12 кг 9 г = ... г             г) 70000 кг = ... т      е) 4 т 6 ц = ... кг</span></p>', 'а) 30005 г = 30 кг 5 г      в) 5 ц 4 кг = 504 кг      д) 9 т 28 кг = 9028 кг б) 12 кг 9 г = 12009 г      г) 70000 кг = 70 т        е) 4 т 6 ц = 4600 кг', '<p><span>а) 30005 г = 30 кг 5 г      в) 5 ц 4 кг = 504 кг      д) 9 т 28 кг = 9028 кг</span>\n<span>б) 12 кг 9 г = 12009 г      г) 70000 кг = 70 т        е) 4 т 6 ц = 4600 кг</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-108/')
