    VALUES (v_textbook_id, 108, '5', 4, 'Выполни действия: а) 4 ц 7 кг + 2 т 98 кг б) 5 т – 9 ц 44 кг в) 7 кг 64 г – 5 кг 8 г г) 1 т 2 ц – 9 ц 64 кг', '</p>\n\n<p class="text">Выполни действия:</p>\n\n<p class="description-text">\n<span>а) 4 ц 7 кг + 2 т 98 кг</span>\n<span>б) 5 т – 9 ц 44 кг</span>\n<span>в) 7 кг 64 г – 5 кг 8 г</span>\n<span>г) 1 т 2 ц – 9 ц 64 кг</span></p>', 'а) 4 ц 7 кг + 2 т 98 кг = 2 т 5 ц 5 кг б) 5 т – 9 ц 44 кг = 4 т 56 кг в) 7 кг 64 г – 5 кг 8 г = 2 кг 56 г г) 1 т 2 ц – 9 ц 64 кг = 38 кг', '<p><span>а) 4 ц 7 кг + 2 т 98 кг = 2 т 5 ц 5 кг</span>\n<span>б) 5 т – 9 ц 44 кг = 4 т 56 кг</span>\n<span>в) 7 кг 64 г – 5 кг 8 г = 2 кг 56 г</span>\n<span>г) 1 т 2 ц – 9 ц 64 кг = 38 кг</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-108/')
    RETURNING id INTO v_task_id;

