    VALUES (v_textbook_id, 108, '6', 5, 'Сравни: 3 кг     999 г 15 кг 900 г     16 кг 400 г 7 т     8 ц 256 кг 14 ц 6 кг     5 т 2 кг', '</p>\n\n<p class="text">Сравни:</p>\n\n<p class="description-text">\n<span>3 кг <span class="okon">   </span> 999 г</span>\n<span>15 кг 900 г <span class="okon">   </span> 16 кг 400 г</span>\n<span>7 т <span class="okon">   </span> 8 ц 256 кг</span>\n<span>14 ц 6 кг <span class="okon">   </span> 5 т 2 кг</span></p>', '3 кг ˃ 999 г 15 кг 900 г < 16 кг 400 г 7 т ˃ 8 ц 256 кг 14 ц 6 кг < 5 т 2 кг', '<p><span>3 кг ˃ 999 г</span>\n<span>15 кг 900 г &lt; 16 кг 400 г</span>\n<span>7 т ˃ 8 ц 256 кг</span>\n<span>14 ц 6 кг &lt; 5 т 2 кг</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-108/')
