    VALUES (v_textbook_id, 108, '7', 6, 'БЛИЦтурнир а) В 5 наборах цветной бумаги всего k листов. Сколько листов бумаги в 7 таких наборах? б) Из b астр сделали 4 одинаковых букета. Сколько таких букетов можно сделать из d астр? в) В первый день около школы посадили n лип, а во второй – в 3 раза меньше. На сколько лип больше посадили в первый день, чем во второй? г) В корзинке a грибов, из них с белых. Во сколько раз белых грибов в этой корзинке меньше, чем остальных?', '</p>\n\n<p class="text"><span><b>БЛИЦтурнир</b></span>\n<span>а) В 5 наборах цветной бумаги всего <b>k</b> листов. Сколько листов бумаги в 7 таких наборах?</span>\n<span>б) Из <b>b</b> астр сделали 4 одинаковых букета. Сколько таких букетов можно сделать из <b></b>d астр?</span>\n<span>в) В первый день около школы посадили <b>n</b> лип, а во второй – в 3 раза меньше. На сколько лип больше посадили в первый день, чем во второй?</span>\n<span>г) В корзинке <b>a</b> грибов, из них <b>с</b> белых. Во сколько раз белых грибов в этой корзинке меньше, чем остальных?</span></p>', 'а) k : 5 · 7 (листов)      Ответ: k : 5 · 7 листов бумаги в 7 таких наборах. б) d : b : 4 (букета)      Ответ: d : b : 4 таких букетов можно сделать из d астр. в) n – 3 : n (раза)      Ответ: на n - 3 : n лип больше посадили в первый день, чем во второй. г) (a – с) : с (раз)      Ответ: в (a – с) : с раз белых грибов в этой корзинке меньше, чем остальных.', '<p><span>а) k : 5 · 7 (листов)</span>\n<span>    <b>Ответ:</b> k : 5 · 7 листов бумаги в 7 таких наборах.</span>\n<span>б) d : b : 4 (букета)</span>\n<span>    <b>Ответ:</b> d : b : 4 таких букетов можно сделать из d астр.</span>\n<span>в) n – 3 : n (раза)</span>\n<span>    <b>Ответ:</b> на n - 3 : n лип больше посадили в первый день, чем во второй.</span>\n<span>г) (a – с) : с (раз)</span>\n<span>    <b>Ответ:</b> в (a – с) : с раз белых грибов в этой корзинке меньше, чем остальных.</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-108/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '308eada38e6a5949cca3b75cc99d3d1287e9f8e084b0ac5d12315ae62e2f5f1c', '3,4,5,7', '["больше","меньше","раз","раза"]'::jsonb, 'блицтурнир а) в 5 наборах цветной бумаги всего k листов. сколько листов бумаги в 7 таких наборах? б) из b астр сделали 4 одинаковых букета. сколько таких букетов можно сделать из d астр? в) в первый день около школы посадили n лип, а во второй-в 3 раза меньше. на сколько лип больше посадили в первый день, чем во второй? г) в корзинке a грибов, из них с белых. во сколько раз белых грибов в этой корзинке меньше, чем остальных');

    VALUES (v_textbook_id, 109, '8', 0, 'а) На одной чашке весов лежит кусок сыра в 700 г, а на другой – гиря в 1 кг. Какие гири можно положить на первую чашку, чтобы весы были в равновесии? б) На одной чашке весов лежит арбуз массой 4 кг 800 г, а на другой – дыня массой 5 кг. Какими гирями можно их уравновесить? в) У продавца есть одна гиря в 100 г и две гири по 200 г. Какую ещё гирю ему нужно взять, чтобы получился килограмм?', '</p>\n\n<p class="text"><span>а) На одной чашке весов лежит кусок сыра в 700 г, а на другой – гиря в 1 кг. Какие гири можно положить на первую чашку, чтобы весы были в равновесии?</span>\n<span>б) На одной чашке весов лежит арбуз массой 4 кг 800 г, а на другой – дыня массой 5 кг. Какими гирями можно их уравновесить?</span>\n<span>в) У продавца есть одна гиря в 100 г и две гири по 200 г. Какую ещё гирю ему нужно взять, чтобы получился килограмм?</span></p>', 'а) 1 кг – 700 г = 1000 г – 700 г = 300 (г)      Ответ: гирей весом в 300 г можно их уравновесить. б) 1 кг - 100 г + 200 г = 1000 г – 300 г = 700 (г)      Ответ: ещё гирю в 700 г ему нужно взять, чтобы получился килограмм. в) 1 кг - (100 г + 200 г · 2) = 1000 г - 500г = 500 (г)      Ответ: нужно взять гирю в 500 г.', '<p><span>а) 1 кг – 700 г = 1000 г – 700 г = 300 (г)</span>\n<span>    <b>Ответ:</b> гирей весом в 300 г можно их уравновесить.</span>\n<span>б) 1 кг - 100 г + 200 г = 1000 г – 300 г = 700 (г)</span>\n<span>    <b>Ответ:</b> ещё гирю в 700 г ему нужно взять, чтобы получился килограмм.</span>\n<span>в) 1 кг - (100 г + 200 г · 2) = 1000 г - 500г = 500 (г)</span>\n<span>    <b>Ответ:</b> нужно взять гирю в 500 г.</span></p>', '', '', TRUE, '[{"letter":"а","condition":"На одной чашке весов лежит кусок сыра в 700 г, а на другой – гиря в 1 кг. Какие гири можно положить на первую чашку, чтобы весы были в равновесии?","solution":"1 кг – 700 г = 1000 г – 700 г = 300 ("},{"letter":"б","condition":"На одной чашке весов лежит арбуз массой 4 кг 800 г, а на другой – дыня массой 5 кг. Какими гирями можно их уравновесить?","solution":"1 кг - 100 г + 200 г = 1000 г – 300 г = 700 ("},{"letter":"в","condition":"У продавца есть одна гиря в 100 г и две гири по 200 г. Какую ещё гирю ему нужно взять, чтобы получился килограмм?","solution":"1 кг - (100 г + 200 г · 2) = 1000 г - 500г = 500 ("},{"letter":"г","condition":"","solution":"Ответ: гирей весом в 300 г можно их уравновесить."}]'::jsonb, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-109/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '7c3f9baad57b1ff43691ba0b617ecfb927498635d7c3e60447653e3e588454c0', '1,4,5,100,200,700,800', '["равно"]'::jsonb, 'а) на одной чашке весов лежит кусок сыра в 700 г, а на другой-гиря в 1 кг. какие гири можно положить на первую чашку, чтобы весы были в равновесии? б) на одной чашке весов лежит арбуз массой 4 кг 800 г, а на другой-дыня массой 5 кг. какими гирями можно их уравновесить? в) у продавца есть одна гиря в 100 г и две гири по 200 г. какую ещё гирю ему нужно взять, чтобы получился килограмм');

    VALUES (v_textbook_id, 109, '9', 1, 'а) Петя купил 1 кг 700 г винограда, а Вася – на 500 г больше. Сколько винограда купили они вместе? б) В двух мешках 78 кг 400 г муки. В первом мешке 35 кг 600 г муки. На сколько второй мешок тяжелее первого?', '</p>\n\n<p class="text"><span>а) Петя купил 1 кг 700 г винограда, а Вася – на 500 г больше. Сколько винограда купили они вместе?</span>\n<span>б) В двух мешках  78 кг 400 г муки. В первом мешке 35 кг 600 г муки. На сколько второй мешок тяжелее первого?</span></p>', 'а) 1 кг 700 г + 1 кг 700 г + 500 г = (1 кг + 1 кг) + (700 г + 700 г) + 500 г = 2 кг +1400 г + 500 г = 2 кг + 1900 г = 2 кг + 1 кг + 900 г = 3 кг 900 г      Ответ: 3 кг 900 г винограда купили они вместе. б) 78 кг 400 г – 35 кг 600 г = 42 кг 800 г – второй мешок,     42 кг 800 г – 35 кг 600 г = 7 кг 200 г      Ответ: на 7 кг 200 г второй мешок тяжелее первого.', '<p><span>а) 1 кг 700 г + 1 кг 700 г + 500 г = (1 кг + 1 кг) + (700 г + 700 г) + 500 г = 2 кг +1400 г + 500 г = 2 кг + 1900 г = 2 кг + 1 кг + 900 г = 3 кг 900 г</span>\n<span>    <b>Ответ:</b> 3 кг 900 г винограда купили они вместе.</span>\n<span>б) 78 кг 400 г – 35 кг 600 г = 42 кг 800 г – второй мешок,</span>\n<span>    42 кг 800 г – 35 кг 600 г = 7 кг 200 г</span>\n<span>    <b>Ответ:</b> на 7 кг 200 г второй мешок тяжелее первого.</span></p>', '', '', TRUE, '[{"letter":"а","condition":"Петя купил 1 кг 700 г винограда, а Вася – на 500 г больше. Сколько винограда купили они вместе?","solution":"1 кг 700 г + 1 кг 700 г + 500 г = (1 кг + 1 к"},{"letter":"б","condition":"В двух мешках 78 кг 400 г муки. В первом мешке 35 кг 600 г муки. На сколько второй мешок тяжелее первого?","solution":"78 кг 400 г – 35 кг 600 г = 42 кг 800 г – второй мешок,     42 кг 800 г – 35 кг 600 г = 7 кг 200 г      Ответ: на 7 кг 200 г второй мешок тяжелее первого."},{"letter":"г","condition":"","solution":"+ (700 г + 700"}]'::jsonb, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-109/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '9eb4e916fce1f9be9c12ee72fa1b307461a267e9e389a487959c1d5cda9187b5', '1,35,78,400,500,600,700', '["больше"]'::jsonb, 'а) петя купил 1 кг 700 г винограда, а вася-на 500 г больше. сколько винограда купили они вместе? б) в двух мешках 78 кг 400 г муки. в первом мешке 35 кг 600 г муки. на сколько второй мешок тяжелее первого');

    VALUES (v_textbook_id, 109, '10', 2, 'Реши уравнения с комментированием: х · 70 = 4900      х : 80 = 700      64000 : х = 40', '</p>\n\n<p class="text">Реши уравнения с комментированием:</p>\n\n<p class="description-text">\nх · 70 = 4900      х : 80 = 700      64000 : х = 40</p>', 'х · 70 = 4900 Чтобы найти множитель х надо произведение разделить на известный множитель. х = 4900 : 70 = 70 х : 80 = 700 Чтобы найти делимое х надо делитель умножить на частное. х = 80 · 700 х = 560000 64000 : х = 40 Чтобы найти делитель х надо делимое разделить на частоное. х = 64000 : 40 х = 1600', '<p><span>х · 70 = 4900</span>\n<span>Чтобы найти множитель х надо произведение разделить на известный множитель.</span>\n<span>х = 4900 : 70 = 70</span>\n<span>х : 80 = 700</span>\n<span>Чтобы найти делимое х надо делитель умножить на частное.</span>\n<span>х = 80 · 700</span>\n<span>х = 560000</span>\n<span>64000 : х = 40</span>\n<span>Чтобы найти делитель х надо делимое разделить на частоное.</span>\n<span>х = 64000 : 40</span>\n<span>х = 1600</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-109/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '4e2b72814e9703b6e6669e9df5b5f71747e4dcd10a8e0d0fb2a58cd7c4d527e3', '40,70,80,700,4900,64000', '["реши"]'::jsonb, 'реши уравнения с комментированием:х*70=4900      х:80=700      64000:х=40');

    VALUES (v_textbook_id, 109, '11', 3, 'Выполни действия: а) 380658 + 9542 б) 1800340 – 685539 в) 56387014 – 4914658 г) 5600 · 4 д) 9700 · 30 е) 90 · 800 ж) 28 : 8 з) 83 : 9 и) 75 : 7 к) 6300 : 700 л) 40000 : 80 м) 840000 : 210', '</p>\n\n<p class="text">Выполни действия:</p>\n\n<p class="description-text">\n<span>а) 380658 + 9542</span>\n<span>б) 1800340 – 685539</span>\n<span>в) 56387014 – 4914658</span>\n<span>г) 5600 · 4</span>\n<span>д) 9700 · 30</span>\n<span>е) 90 · 800</span>\n<span>ж) 28 : 8</span>\n<span>з) 83 : 9</span>\n<span>и) 75 : 7</span>\n<span>к) 6300 : 700</span>\n<span>л) 40000 : 80</span>\n<span>м) 840000 : 210</span></p>', 'а) 380658 + 9542 = 390200', '<p>а) 380658 + 9542 = 390200</p>\n\n<div class="img-wrapper-460">\n<img width="170" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica109-nomer11.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 109, номер 11, год 2022, ответ." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 109, номер 11, год 2022, ответ."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-109/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, 'solution', 0, NULL, 'https://gdz-raketa.ru/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica109-nomer11.jpg', 'peterson/3/part1/page109/task11_solution_0.jpg', '');

    VALUES (v_task_id, v_textbook_id, 3, 'c60a6eaa4e784d0bf3816c5966737fcee22b9a369a237f001f4edde545fbc891', '4,7,8,9,28,30,75,80,83,90', NULL, 'выполни действия:а) 380658+9542 б) 1800340-685539 в) 56387014-4914658 г) 5600*4 д) 9700*30 е) 90*800 ж) 28:8 з) 83:9 и) 75:7 к) 6300:700 л) 40000:80 м) 840000:210');

    VALUES (v_textbook_id, 109, '12', 4, 'В классе 25 учеников уже прочитали повесть о Малыше и Карлсоне, а 23 ученика – повесть о Винни – Пухе. Причём 18 человек прочитали обе эти повести. Сколько всего учеников в классе, если каждый ученик прочитал хотя бы одну из этих книг?', '</p>\n\n<p class="text">В классе 25 учеников уже прочитали повесть о Малыше и Карлсоне, а 23 ученика – повесть о Винни – Пухе. Причём 18 человек прочитали обе эти повести. Сколько всего учеников в классе, если каждый ученик прочитал хотя бы одну из этих книг?</p>\n\n<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica109-nomer12.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 109, номер 12, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 109, номер 12, год 2022."/>\n</div>', '25 + 23 = 48 (чел.) Ответ: 48 всего учеников в классе, если каждый ученик прочитал хотя бы одну из этих книг.', '<p><span>25 + 23 = 48 (чел.)</span>\n<span><b>Ответ:</b> 48 всего учеников в классе, если каждый ученик прочитал хотя бы одну из этих книг.</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-109/')
    RETURNING id INTO v_task_id;

