    VALUES (v_task_id, v_textbook_id, 3, '94ae147d6040e889559043530b75384f709f37fae4b837a1ba6079b9eed17ed0', '18,23,25', NULL, 'в классе 25 учеников уже прочитали повесть о малыше и карлсоне, а 23 ученика-повесть о винни-пухе. причём 18 человек прочитали обе эти повести. сколько всего учеников в классе, если каждый ученик прочитал хотя бы одну из этих книг');

    VALUES (v_textbook_id, 109, '13', 5, 'Подбери, если возможно, значения х, при которых верны равенства: х · х – 25 = 0      х · х + 1 = 0      (х – х) · 4 = 0 Всегда ли есть решение? Существует ли несколько решений?', '</p>\n\n<p class="text">Подбери, если возможно, значения х, при которых верны равенства:</p>\n\n<p class="description-text">\nх · х – 25 = 0      х · х + 1 = 0      (х – х) · 4 = 0</p>\n\n<p class="text">Всегда ли есть решение? Существует ли несколько решений?</p>', 'х · х – 25 = 0, при х = 5 х · х + 1 = 0, не существует (х – х) · 4 = 0, при = х = 0', '<p><span>х · х – 25 = 0, при х = 5</span>\n<span>х · х + 1 = 0, не существует</span>\n<span>(х – х) · 4 = 0, при = х = 0</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-109/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '80dd6a75f2d852a039248c1bfcca38c8a88f767f2f4333b007c6c88100b43504', '0,1,4,25', NULL, 'подбери, если возможно, значения х, при которых верны равенства:х*х-25=0      х*х+1=0      (х-х)*4=0 всегда ли есть решение? существует ли несколько решений');

    VALUES (v_textbook_id, 110, '1', 0, 'Прочитай число: 45630817294. Назови цифру в разряде сотен миллионов этого числа. Сколько в нём всего сотен миллионов?', '</p>\n\n<p class="text">Прочитай число: 45630817294. Назови цифру в разряде сотен миллионов этого числа. Сколько в нём всего сотен миллионов?</p>', 'Сорок пять миллиардов шестьсот тридцать миллионов восемьсот семнадцать тысяч двести девяносто четыре, 6 – цифра в разряде сотен миллионов этого числа, всего в нем 456 сотен миллионов.', '<p>Сорок пять миллиардов шестьсот тридцать миллионов восемьсот семнадцать тысяч двести девяносто четыре, 6 – цифра в разряде сотен миллионов этого числа, всего в нем 456 сотен миллионов.</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-110/')
    RETURNING id INTO v_task_id;

