    VALUES (v_textbook_id, 110, '2', 1, 'Запиши цифрами число: 5 млрд 36 тыс. 800 ед. Подчеркни цифру в разряде десятков тысяч. Сколько в нём всего десятков тысяч?', '</p>\n\n<p class="text">Запиши цифрами число: 5 млрд 36 тыс. 800 ед. Подчеркни цифру в разряде десятков тысяч. Сколько в нём всего десятков тысяч?</p>', '5000036800, всего 500003 десятка тысяч.', '<p>5000036800, всего 500003 десятка тысяч.</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-110/')
