    VALUES (v_textbook_id, 110, '3', 2, 'Выполни действия: а) 1000 · 240      в) 180 · 300      д) 78000 : 100      ж) 20000 : 4000 б) 90 · 600           г) 40 · 5000      е) 6300 : 90            з) 320000 : 160', '</p>\n\n<p class="text">Выполни действия:</p>\n\n<p class="description-text">\n<span>а) 1000 · 240      в) 180 · 300      д) 78000 : 100      ж) 20000 : 4000</span>\n<span>б) 90 · 600           г) 40 · 5000      е) 6300 : 90            з) 320000 : 160</span></p>', 'а) 1000 · 240 = 240000 б) 90 · 600 = 54000 в) 180 · 300 = 54000 г) 40 · 5000 = 200000 д) 78000 : 100 = 780 е) 6300 : 90 = 70 ж) 20000 : 4000 = 5 з) 320000 : 160 = 2000', '<p><span>а) 1000 · 240 = 240000</span>\n<span>б) 90 · 600 = 54000</span>\n<span>в) 180 · 300 = 54000</span>\n<span>г) 40 · 5000 = 200000</span>\n<span>д) 78000 : 100 = 780</span>\n<span>е) 6300 : 90 = 70</span>\n<span>ж) 20000 : 4000 = 5</span>\n<span>з) 320000 : 160 = 2000</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-110/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '46c3e2ca5395bf05319b73c49b75b9b70a5eff3c45a3c140858cf7559358d410', '40,90,100,160,180,240,300,600,1000,4000', NULL, 'выполни действия:а) 1000*240      в) 180*300      д) 78000:100      ж) 20000:4000 б) 90*600           г) 40*5000      е) 6300:90            з) 320000:160');

    VALUES (v_textbook_id, 110, '4', 3, 'Вырази в указанных единицах измерения: а) 8400 дм = ... м     5 дм 3 мм = ... мм     10 м 8 см = ... см     9 км 36 м = ... м б) 7000 г = ... кг     3 т 9 кг = ... кг     15000 кг = ... т     8302 кг = ... т ... ц ... кг', '</p>\n\n<p class="text">Вырази в указанных единицах измерения:</p>\n\n<p class="description-text">\n<span>а) 8400 дм = ... м</span>\n<span>    5 дм 3 мм = ... мм</span>\n<span>    10 м 8 см = ... см</span>\n<span>    9 км 36 м = ... м</span>\n<br/>\n<span>б) 7000 г = ... кг</span>\n<span>    3 т 9 кг = ... кг</span>\n<span>    15000 кг = ... т</span>\n<span>    8302 кг = ... т ... ц ... кг</span></p>', 'а) 8400 дм = 840 м     5 дм 3 мм = 503 мм     10 м 8 см = 1008 см     9 км 36 м = 9036 м б) 7000 г = 7 кг     3 т 9 кг = 3009 кг     15000 кг = 15 т     8302 кг = 8 т 3 ц 2 кг', '<p><span>а) 8400 дм = 840 м</span>\n<span>    5 дм 3 мм = 503 мм</span>\n<span>    10 м 8 см = 1008 см</span>\n<span>    9 км 36 м = 9036 м</span>\n<br/>\n<span>б) 7000 г = 7 кг</span>\n<span>    3 т 9 кг = 3009 кг</span>\n<span>    15000 кг = 15 т</span>\n<span>    8302 кг = 8 т 3 ц 2 кг</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-110/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, 'e3775a48782921cfe108b534d361feb94c6a5102bbb72ca584cabf532d57a942', '3,5,8,9,10,36,7000,8302,8400,15000', '["раз"]'::jsonb, 'вырази в указанных единицах измерения:а) 8400 дм=... м     5 дм 3 мм=... мм     10 м 8 см=... см     9 км 36 м=... м б) 7000 г=... кг     3 т 9 кг=... кг     15000 кг=... т     8302 кг=... т ... ц ... кг');

    VALUES (v_textbook_id, 110, '5', 4, 'БЛИЦтурнир а) Аня вышила а красных крестиков, а зелёных – в 4 раза больше. На сколько меньше красных крестиков, чем зелёных, вышила Аня? б) Длина прямоугольника b см, а ширина – на 24 см меньше. Во сколько раз длина прямоугольника больше его ширины? в) 4 одинаковых стула стоят m р. Сколько рублей надо заплатить за 6 таких стульев? г) На пошив 3 одинаковых платьев пошло d м ткани. Сколько таких платьев можно сшить из 72 м этой ткани?', '</p>\n\n<p class="text"><span><b>БЛИЦтурнир</b></span>\n<span>а) Аня вышила <b>а</b> красных крестиков, а зелёных – в 4 раза больше. На сколько меньше красных крестиков, чем зелёных, вышила Аня?</span>\n<span>б) Длина прямоугольника <b>b</b> см, а ширина – на 24 см меньше. Во сколько раз длина прямоугольника больше его ширины?</span>\n<span>в) 4 одинаковых стула стоят <b>m</b> р. Сколько рублей надо заплатить за 6 таких стульев?</span>\n<span>г) На пошив 3 одинаковых платьев пошло <b>d</b> м ткани. Сколько таких платьев можно сшить из 72 м этой ткани?</span></p>', 'а) а – 4а (крестиков)      Ответ: на а – 4а меньше красных крестиков, чем зелёных, вышила Аня. б) b : (b – 24) (см)      Ответ: в b : (b – 24) раз длина прямоугольника больше его ширины. в) m : 4 · 6 (р)      Ответ: m : 4 · 6 рублей надо заплатить за 6 таких стульев. г) 72 : 3 : d (платьев)      Ответ: 72 : 3 : d таких платьев можно сшить из 72 м этой ткани.', '<p><span>а) а – 4а (крестиков)</span>\n<span>    <b>Ответ:</b> на а – 4а меньше красных крестиков, чем зелёных, вышила Аня.</span>\n<span>б) b : (b – 24) (см)</span>\n<span>    <b>Ответ:</b> в b : (b – 24) раз длина прямоугольника больше его ширины.</span>\n<span>в) m : 4 · 6 (р)</span>\n<span>    <b>Ответ:</b> m : 4 · 6 рублей надо заплатить за 6 таких стульев.</span>\n<span>г) 72 : 3 : d (платьев)</span>\n<span>    <b>Ответ:</b> 72 : 3 : d таких платьев можно сшить из 72 м этой ткани.</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-110/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, 'ac460b9e332d8f0fdb9c3777014d814f611dbc77e47d771405318a6b245283b6', '3,4,6,24,72', '["больше","меньше","раз","раза"]'::jsonb, 'блицтурнир а) аня вышила а красных крестиков, а зелёных-в 4 раза больше. на сколько меньше красных крестиков, чем зелёных, вышила аня? б) длина прямоугольника b см, а ширина-на 24 см меньше. во сколько раз длина прямоугольника больше его ширины? в) 4 одинаковых стула стоят m р. сколько рублей надо заплатить за 6 таких стульев? г) на пошив 3 одинаковых платьев пошло d м ткани. сколько таких платьев можно сшить из 72 м этой ткани');

    VALUES (v_textbook_id, 110, '6', 5, 'Найди значения выражений. Проверь с помощью калькулятора. а) 2047639 – 459086 б) 305286 – 72058 в) (2316 + 8739) – (10210 – 6862) г) 400000 – (216319 + 98757) + 16086', '</p>\n\n<p class="text">Найди значения выражений. Проверь с помощью калькулятора.</p>\n\n<p class="description-text">\n<span>а) 2047639 – 459086</span>\n<span>б) 305286 – 72058</span>\n<span>в) (2316 + 8739) – (10210 – 6862)</span>\n<span>г) 400000 – (216319 + 98757) + 16086</span></p>', 'а) 2047639 – 459086 = 1588553', '<p>а) 2047639 – 459086 = 1588553</p>\n\n<div class="img-wrapper-460">\n<img width="200" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica110-nomer6.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 110, номер 6, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 110, номер 6, год 2022."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-110/')
    RETURNING id INTO v_task_id;

