    VALUES (v_task_id, v_textbook_id, 3, '168f6061a34e2df85e6969885b58be5c09c4c9fc72c1c006b6b370f1d17f8c97', '2316,6862,8739,10210,16086,72058,98757,216319,305286,400000', '["найди"]'::jsonb, 'найди значения выражений. проверь с помощью калькулятора. а) 2047639-459086 б) 305286-72058 в) (2316+8739)-(10210-6862) г) 400000-(216319+98757)+16086');

    VALUES (v_textbook_id, 110, '7', 6, 'Выполни действия: а) 8 дм 3 см 5 мм – 2 дм 6 мм б) 14 км 98 м + 902 м в) 4 кг 283 г – 2 кг 605 г г) 5 т – 6 ц 38 кг', '</p>\n\n<p class="text">Выполни действия:</p>\n\n<p class="description-text">\n<span>а) 8 дм 3 см 5 мм – 2 дм 6 мм</span>\n<span>б) 14 км 98 м + 902 м</span>\n<span>в) 4 кг 283 г – 2 кг 605 г</span>\n<span>г) 5 т – 6 ц 38 кг</span></p>', 'а) 8 дм 3 см 5 мм – 2 дм 6 мм = 6 дм 9 мм б) 14 км 98 м + 902 м = 15 км в) 4 кг 283 г – 2 кг 605 г = 1 кг 678 г г) 5 т – 6 ц 38 кг = 4 т 3 ц 62 кг', '<p><span>а) 8 дм 3 см 5 мм – 2 дм 6 мм = 6 дм 9 мм</span>\n<span>б) 14 км 98 м + 902 м = 15 км</span>\n<span>в) 4 кг 283 г – 2 кг 605 г = 1 кг 678 г</span>\n<span>г) 5 т – 6 ц 38 кг = 4 т 3 ц 62 кг</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-110/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '0d6748c47779f26bd66d34805034126ea26f50c0fc658c471b9b7f88f063a623', '2,3,4,5,6,8,14,38,98,283', NULL, 'выполни действия:а) 8 дм 3 см 5 мм-2 дм 6 мм б) 14 км 98 м+902 м в) 4 кг 283 г-2 кг 605 г г) 5 т-6 ц 38 кг');

    VALUES (v_textbook_id, 110, '8', 7, 'Имеются стандартные гири массой меньше 1 кг. Каким наименьшим возможным числом таких гирь можно взвесить предметы массой: а) 26 г; б) 94 г; в) 125 г; г) 347 г; д) 600 г; е) 870 г; ж) 950 г?', '</p>\n\n<p class="text">Имеются стандартные гири массой меньше 1 кг. Каким наименьшим возможным числом таких гирь можно взвесить предметы массой:</p>\n\n<p class="description-text">\nа) 26 г; б) 94 г; в) 125 г; г) 347 г; д) 600 г; е) 870 г; ж) 950 г?</p>', '1 г, 2 г, 5г, 20 г, 25 г, 50г, 100 г, 200г, 300 г, 500 г а) 26 = 25 + 1 б) 94 = 50 + 20 + 20 + 2 + 2 в) 125 = 100 + 25 г) 347 = 300 + 20 + 20 + 5 + 2 д) 600 = 100 + 500 е) 870 = 500 + 300 + 50 + 20 ж) 950 = 500 + 300 + 100 +50.', '<p><span>1 г, 2 г, 5г, 20 г, 25 г, 50г, 100 г, 200г, 300 г, 500 г</span>\n<br/>\n<span>а) 26 = 25 + 1</span>\n<span>б) 94 = 50 + 20 + 20 + 2 + 2</span>\n<span>в) 125 = 100 + 25</span>\n<span>г) 347 = 300 + 20 + 20 + 5 + 2</span>\n<span>д) 600 = 100 + 500</span>\n<span>е) 870 = 500 + 300 + 50 + 20</span>\n<span>ж) 950 = 500 + 300 + 100 +50.</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-110/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, 'db122a871fba1f3a5b98069c069412a899d02748b09bfacf4918ec8ea61d635b', '1,26,94,125,347,600,870,950', '["меньше"]'::jsonb, 'имеются стандартные гири массой меньше 1 кг. каким наименьшим возможным числом таких гирь можно взвесить предметы массой:а) 26 г; б) 94 г; в) 125 г; г) 347 г; д) 600 г; е) 870 г; ж) 950 г');

    VALUES (v_textbook_id, 111, '9', 0, 'Масса пустой миски равна 420 г. Найди по рисункам массу яблок и массу арбуза:', '</p>\n\n<p class="text">Масса пустой миски равна 420 г. Найди по рисункам массу яблок и массу арбуза:</p>\n\n<div class="img-wrapper-460">\n<img width="380" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica111-nomer9.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 111, номер 9, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 111, номер 9, год 2022."/>\n</div>', 'Яблоки: 3 кг + 1 кг + 100 г – 420 г = 3 кг 680 г Арбуз: 3 кг + 100 г + 200 г – 420 г = 2 кг 880 г Ответ: 3 кг 680 г масса яблок; 2 кг 880 г масса арбуза.', '<p><span>Яблоки: 3 кг + 1 кг + 100 г – 420 г  = 3 кг 680 г</span>\n<span>Арбуз: 3 кг + 100 г + 200 г – 420 г = 2 кг 880 г</span>\n<span><b>Ответ:</b> 3 кг 680 г масса яблок; 2 кг 880 г масса арбуза.</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-111/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, 'condition', 0, NULL, 'https://gdz-raketa.ru/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica111-nomer9.jpg', 'peterson/3/part1/page111/task9_condition_0.jpg', '');

    VALUES (v_task_id, v_textbook_id, 3, '5b5271c8a78a89eefd0c72157f0931427ee8677a687d9019a558173b35ccee1c', '420', '["найди"]'::jsonb, 'масса пустой миски равна 420 г. найди по рисункам массу яблок и массу арбуза');

    VALUES (v_textbook_id, 111, '10', 1, 'Реши уравнения с комментированием и сделай проверку: х · 50 = 350      х : 600 = 80      96000 : х = 600', '</p>\n\n<p class="text">Реши уравнения с комментированием и сделай проверку:</p>\n\n<p class="description-text">\nх · 50 = 350      х : 600 = 80      96000 : х = 600</p>', 'х · 50 = 350 Чтобы найти множитель х надо произведение разделить на известный множитель. х = 350 : 50 х = 7 Проверка: 7 · 50 = 350 х : 600 = 80 Чтобы найти делимое х надо делитель умножить на частное. х = 600 · 80 х = 48000 Проверка: 48000 : 600 = 80 96000 : х = 600 Чтобы найти делитель надо делимое разделить на частное. х = 96000 : 600 х = 160 Проверка: 96000 : 160 = 600', '<p><span>х · 50 = 350</span>\n<span>Чтобы найти множитель х надо произведение разделить на известный множитель.</span>\n<span>х = 350 : 50</span>\n<span>х = 7</span>\n<span><b>Проверка:</b> 7 · 50 = 350</span>\n<br/>\n<span>х : 600 = 80</span>\n<span>Чтобы найти делимое х надо делитель умножить на частное.</span>\n<span>х = 600 · 80</span>\n<span>х = 48000</span>\n<span><b>Проверка:</b> 48000 : 600 = 80</span>\n<br/>\n<span>96000 : х = 600</span>\n<span>Чтобы найти делитель надо делимое разделить на частное.</span>\n<span>х = 96000 : 600</span>\n<span>х = 160</span>\n<span><b>Проверка:</b> 96000 : 160 = 600</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-111/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '44608ec09dbc2ef5e9284111d72d19b71b01970e798bdadf086a70597f3a3d6c', '50,80,350,600,96000', '["реши"]'::jsonb, 'реши уравнения с комментированием и сделай проверку:х*50=350      х:600=80      96000:х=600');

    VALUES (v_textbook_id, 111, '11', 2, 'Найди объём фигур на рисунке, если объём каждого кубика равен 1 см 3 (кубическому сантиметру).', '</p>\n\n<p class="text">Найди объём фигур на рисунке, если объём каждого кубика равен 1 см<sup>3</sup> (кубическому сантиметру).</p>\n\n<div class="img-wrapper-460">\n<img width="350" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica111-nomer11.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 111, номер 11, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 111, номер 11, год 2022."/>\n</div>', '6 см 3 , 12 см 3 , 30 см 3 , 24 см 3 .', '<p>6 см<sup>3</sup>, 12 см<sup>3</sup>, 30 см<sup>3</sup>, 24 см<sup>3</sup>.</p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-111/')
    RETURNING id INTO v_task_id;

