    VALUES (v_task_id, v_textbook_id, 3, '754e39f5f969b06b38c3b11ee67c79a3aade7b62ce058311bcb2a7e5a532400a', '1,3', '["найди"]'::jsonb, 'найди объём фигур на рисунке, если объём каждого кубика равен 1 см 3 (кубическому сантиметру)');

    VALUES (v_textbook_id, 111, '12', 3, 'На лесной опушке собрались а зайчиков и b белочек, а остальных зверей – в 3 раза меньше, чем зайчиков и белочек вместе. Сколько всего зверей было на опушке? Составь выражение и найди его значение при а = 17 и b = 19.', '</p>\n\n<p class="text">На лесной опушке собрались а зайчиков и b белочек, а остальных зверей – в 3 раза меньше, чем зайчиков и белочек вместе. Сколько всего зверей было на опушке? Составь выражение и найди его значение при а = 17 и b = 19.</p>', '(a + b) : 3 + a + b (17 + 19) : 3 + 17 + 19 = 36 : 3 + 36 = 12 + 36 = 48 Ответ: 48 всего зверей было на опушке.', '<p><span>(a + b) : 3 + a + b</span>\n<span>(17 + 19) : 3 + 17 + 19 = 36 : 3 + 36 = 12 + 36 = 48</span>\n<span><b>Ответ:</b> 48 всего зверей было на опушке.</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-111/')
    RETURNING id INTO v_task_id;

    VALUES (v_task_id, v_textbook_id, 3, '6f15d303e69b9a40a52bbedbc06220ff1ab16987a3417a66054fe79ebaeb7913', '3,17,19', '["найди","меньше","раз","раза"]'::jsonb, 'на лесной опушке собрались а зайчиков и b белочек, а остальных зверей-в 3 раза меньше, чем зайчиков и белочек вместе. сколько всего зверей было на опушке? составь выражение и найди его значение при а=17 и b=19');

    VALUES (v_textbook_id, 111, '13', 4, 'Запиши с помощью фигурных скобок пересечение и объединение множеств А и В. Построй диаграмму Эйлера–Венна этих множеств. Раскрась на ней множество А ∩ В и обведи А ∪ В.', '</p>\n\n<div class="img-wrapper-460">\n<img width="280" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica111-nomer13.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 111, номер 13, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 111, номер 13, год 2022."/>\n</div>\n\n<p class="text">Запиши с помощью фигурных скобок пересечение и объединение множеств А и В. Построй диаграмму Эйлера–Венна этих множеств. Раскрась на ней множество А ∩ В и обведи А ∪ В.</p>', '', '<div class="img-wrapper-450">\n<img src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica111-nomer13-1.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 111, номер 13, год 2022, ответ." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 111, номер 13, год 2022, ответ."/>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-111/')
