    VALUES (v_textbook_id, 111, '14', 5, 'Задача-шутка Бримазище нашёл 96 шклидулок, а бримазёнок – на 64 шклидулки меньше. Сколько шклидулок нашли они вместе? Во сколько раз больше шклидулок нашёл бримазище, чем бримазёнок?', '</p>\n\n<p class="text"><span><b>Задача-шутка</b></span>\n<span>Бримазище нашёл 96 шклидулок, а бримазёнок – на 64 шклидулки меньше. Сколько шклидулок нашли они вместе? Во сколько раз больше шклидулок нашёл бримазище, чем бримазёнок?</span></p>\n\n<div class="img-wrapper-460">\n<img width="340" src="/images/gdz/matematika/3klass/uchebnik-peterson/chast1/stranica111-nomer14.jpg" title="Учебник по математике 3 класс Петерсон - Часть 1, станица 111, номер 14, год 2022." alt="Учебник по математике 3 класс Петерсон - Часть 1, станица 111, номер 14, год 2022."/>\n</div>', '96 + 96 – 64 = 96 + 32 = 128 (шклидулок) 96 : 32 = 3 (раза) Ответ: 128 шклидулок нашли они вместе, в 3 раза больше шклидулок нашёл бримазище, чем бримазёнок.', '<p><span>96 + 96 – 64 = 96 + 32 = 128 (шклидулок)</span>\n<span>96 : 32 = 3 (раза)</span>\n<span><b>Ответ:</b> 128 шклидулок нашли они вместе, в 3 раза больше шклидулок нашёл бримазище, чем бримазёнок.</span></p>', '', '', FALSE, NULL, 'https://gdz-raketa.ru/matematika/3-klass/peterson-uchebnik/1-chast-stranitsa-111/')
    RETURNING id INTO v_task_id;

